'use client'

import { useEffect, useState } from 'react'
import { listAllTenants, getTenantSiteStatus, deleteTenantSite, restartTenantSite } from '@/app/actions/admin-tenants'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'

interface Tenant {
  name: string
  subdomain: string
  company_name: string
  owner_email: string
  site_url: string
  status: string
  creation: string
}

export default function AdminTenantsPage() {
  const [tenants, setTenants] = useState<Tenant[]>([])
  const [loading, setLoading] = useState(true)
  const [siteStatuses, setSiteStatuses] = useState<Record<string, any>>({})

  useEffect(() => {
    loadTenants()
  }, [])

  async function loadTenants() {
    setLoading(true)
    const result = await listAllTenants()
    if (result.success && result.tenants) {
      setTenants(result.tenants)
      
      // Load site status for each tenant
      for (const tenant of result.tenants) {
        const status = await getTenantSiteStatus(tenant.site_url)
        setSiteStatuses(prev => ({ ...prev, [tenant.name]: status }))
      }
    }
    setLoading(false)
  }

  async function handleDelete(tenantName: string, siteUrl: string) {
    if (!confirm(`Delete tenant "${tenantName}" and all its data? This cannot be undone!`)) {
      return
    }

    const result = await deleteTenantSite(tenantName, siteUrl)
    if (result.success) {
      alert('Tenant deleted successfully')
      loadTenants()
    } else {
      alert(`Failed to delete: ${result.error}`)
    }
  }

  async function handleRestart(siteUrl: string) {
    const result = await restartTenantSite(siteUrl)
    if (result.success) {
      alert('Site cache cleared successfully')
    } else {
      alert(`Failed to restart: ${result.error}`)
    }
  }

  if (loading) {
    return <div className="p-8">Loading tenants...</div>
  }

  return (
    <div className="p-8 space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold">Tenant Management</h1>
          <p className="text-muted-foreground">Manage all tenant sites and databases</p>
        </div>
        <Button onClick={loadTenants}>Refresh</Button>
      </div>

      <div className="grid gap-4">
        {tenants.map(tenant => {
          const status = siteStatuses[tenant.name]
          return (
            <Card key={tenant.name}>
              <CardHeader>
                <div className="flex justify-between items-start">
                  <div>
                    <CardTitle>{tenant.company_name}</CardTitle>
                    <CardDescription>
                      <div className="space-y-1 mt-2">
                        <div><strong>Subdomain:</strong> {tenant.subdomain}</div>
                        <div><strong>Site URL:</strong> <a href={`https://${tenant.site_url}`} target="_blank" rel="noopener" className="text-blue-600 hover:underline">{tenant.site_url}</a></div>
                        <div><strong>Owner:</strong> {tenant.owner_email}</div>
                        <div><strong>Created:</strong> {new Date(tenant.creation).toLocaleDateString()}</div>
                      </div>
                    </CardDescription>
                  </div>
                  <Badge variant={tenant.status === 'active' ? 'default' : 'secondary'}>
                    {tenant.status}
                  </Badge>
                </div>
              </CardHeader>
              <CardContent>
                {status?.exists ? (
                  <div className="space-y-3">
                    <div className="text-sm">
                      <strong>Database:</strong> {status.database}
                    </div>
                    {status.apps && (
                      <div className="text-sm">
                        <strong>Apps:</strong> {status.apps.join(', ')}
                      </div>
                    )}
                    <div className="flex gap-2">
                      <Button size="sm" variant="outline" onClick={() => handleRestart(tenant.site_url)}>
                        Clear Cache
                      </Button>
                      <Button size="sm" variant="destructive" onClick={() => handleDelete(tenant.name, tenant.site_url)}>
                        Delete Site
                      </Button>
                    </div>
                  </div>
                ) : (
                  <div className="text-sm text-yellow-600">
                    ΓÜá∩╕Å Site not found in Frappe. May need manual cleanup.
                  </div>
                )}
              </CardContent>
            </Card>
          )
        })}
      </div>

      {tenants.length === 0 && (
        <Card>
          <CardContent className="py-8 text-center text-muted-foreground">
            No tenants found. Create one through the signup page.
          </CardContent>
        </Card>
      )}
    </div>
  )
}

"use client";

import { useEffect, useRef, useState, useMemo } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { PageHeader } from "@/components/page-header";

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
}

export default function AgentsPage() {
  const [showDebug, setShowDebug] = useState(false);
  const [debugLogs, setDebugLogs] = useState<string[]>([]);

  // Chat State
  const [messages, setMessages] = useState<Message[]>([
    {
      id: "1",
      role: "assistant",
      content: "Hello! I'm **AvarIQ**, your autonomous agent. I can help you manage Leads, Fleet, Customers, and Invoices.",
    },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const addDebugLog = (message: string) => {
    const timestamp = new Date().toLocaleTimeString();
    setDebugLogs((prev) => [...prev, `[${timestamp}] ${message}`]);
    console.log(`[DEBUG] ${message}`);
  };

  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInput(e.target.value);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessageContent = input;
    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content: userMessageContent,
    };

    setInput("");
    setMessages((prev) => [...prev, userMessage]);
    setIsLoading(true);
    addDebugLog(`≡ƒôñ Sending message: "${userMessageContent}"`);

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [{ role: "user", content: userMessageContent }],
          conversation_id: "",
          tenant_id: "master",
        }),
      });

      if (!response.ok) {
        throw new Error(`Failed to send message: ${response.statusText}`);
      }

      addDebugLog(`Γ£à Response received: ${response.status} ${response.statusText}`);

      // Initialize assistant message
      const assistantId = (Date.now() + 1).toString();
      setMessages((prev) => [...prev, { id: assistantId, role: "assistant", content: "" }]);

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (!reader) return;

      let assistantMessageContent = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) {
          addDebugLog(`Γ£à Message finished: ${assistantMessageContent.substring(0, 100)}...`);
          break;
        }

        const chunk = decoder.decode(value, { stream: true });
        assistantMessageContent += chunk;

        setMessages((prev) => {
          const newMessages = [...prev];
          const lastIndex = newMessages.length - 1;
          if (newMessages[lastIndex].role === "assistant") {
            newMessages[lastIndex] = {
              ...newMessages[lastIndex],
              content: assistantMessageContent
            };
          }
          return newMessages;
        });
      }

    } catch (err: any) {
      console.error("Chat error:", err);
      setError(err);
      addDebugLog(`Γ¥î Error: ${err.message}`);
      setMessages((prev) => [
        ...prev,
        { id: Date.now().toString(), role: "assistant", content: "Sorry, I'm having trouble connecting to the AI right now." },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCustomSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    handleSend();
  };

  // Calculate KPIs from messages
  const kpis = useMemo(() => {
    const totalQueries = messages.filter((m) => m.role === "user").length;
    const accuracy = 98; // Mock - would need real calculation
    const efficiencyBoost = totalQueries * 3.5; // Mock calculation

    return {
      totalQueries: totalQueries > 1000 ? `${(totalQueries / 1000).toFixed(1)}k` : totalQueries,
      accuracy: `${accuracy}%`,
      efficiencyBoost: `${Math.round(efficiencyBoost)}h`,
    };
  }, [messages]);

  return (
    <div className="bg-slate-50 dark:bg-midnight-blue text-slate-900 dark:text-slate-100 flex flex-col h-screen overflow-hidden">
      {/* Debug Toggle Button */}
      {showDebug && (
        <div className="fixed bottom-20 right-4 w-96 max-h-96 bg-black text-green-400 p-4 rounded-lg shadow-2xl overflow-y-auto font-mono text-xs z-50">
          <div className="flex justify-between items-center mb-2">
            <span className="font-bold">≡ƒÉ¢ DEBUG LOGS</span>
            <button
              onClick={() => setDebugLogs([])}
              className="text-red-400 hover:text-red-300"
            >
              Clear
            </button>
          </div>
          {debugLogs.map((log, i) => (
            <div key={i} className="mb-1 border-b border-green-900 pb-1">
              {log}
            </div>
          ))}
          {error && (
            <div className="mt-2 p-2 bg-red-900 text-red-200 rounded">ERROR: {error.message}</div>
          )}
        </div>
      )}

      {/* Header */}
      <PageHeader />

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* KPI Cards - Matching Leads Page Styling */}
        <section className="p-4 grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
          <div className="bg-[#111827] p-4 rounded-xl border border-slate-800 shadow-lg flex items-center justify-between transition-all hover:shadow-xl">
            <div>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.12em]">
                Total Queries
              </p>
              <h3 className="text-xl font-bold text-white mt-0.5">{kpis.totalQueries}</h3>
            </div>
            <div className="p-2 bg-slate-700/50 rounded-lg text-slate-300">
              <span className="material-symbols-outlined text-xl">query_stats</span>
            </div>
          </div>
          <div className="bg-[#111827] p-4 rounded-xl border border-slate-800 shadow-lg flex items-center justify-between transition-all hover:shadow-xl">
            <div>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.12em]">
                Accuracy
              </p>
              <h3 className="text-xl font-bold text-white mt-0.5">{kpis.accuracy}</h3>
            </div>
            <div className="p-2 bg-green-500/10 rounded-lg text-green-400">
              <span className="material-symbols-outlined text-xl">verified</span>
            </div>
          </div>
          <div className="bg-[#111827] p-4 rounded-xl border border-slate-800 shadow-lg flex items-center justify-between transition-all hover:shadow-xl">
            <div>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.12em]">
                Efficiency Boost
              </p>
              <h3 className="text-xl font-bold text-white mt-0.5">{kpis.efficiencyBoost}</h3>
            </div>
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400">
              <span className="material-symbols-outlined text-xl">trending_up</span>
            </div>
          </div>
        </section>

        {/* Chat Area with Sidebar */}
        <div className="flex-1 flex overflow-hidden">
          {/* Main Chat Area */}
          <div className="flex-1 overflow-y-auto p-5 custom-scrollbar space-y-5 flex flex-col items-center">
            <div className="w-full max-w-5xl space-y-4">
              {messages.map((m, index) => {
                const isUser = m.role === "user";
                const isFirstMessage = index === 0;

                if (isUser) {
                  return (
                    <div key={m.id} className="flex gap-5 justify-end">
                      <div className="space-y-1 max-w-[70%] text-right">
                        <p className="text-[8px] text-slate-400 font-bold uppercase tracking-wider">
                          Alex Thompson
                        </p>
                        <div className="bg-accent text-white px-4 py-2 rounded-xl rounded-tr-none shadow-md inline-block">
                          <p className="text-xs font-medium">{m.content}</p>
                        </div>
                      </div>
                    </div>
                  );
                }

                return (
                  <div key={m.id} className="flex gap-5">
                    <div className="w-12 h-12 rounded-2xl bg-midnight-blue flex-shrink-0 flex items-center justify-center p-2 shadow-lg border border-slate-700">
                      <svg
                        className="w-full h-full"
                        fill="none"
                        viewBox="0 0 100 100"
                        xmlns="http://www.w3.org/2000/svg"
                      >
                        <circle cx="50" cy="55" fill="white" r="35"></circle>
                        <circle cx="50" cy="55" fill="#0F172A" r="30"></circle>
                        <circle cx="40" cy="55" fill="white" r="5"></circle>
                        <circle cx="60" cy="55" fill="white" r="5"></circle>
                        <path
                          d="M45 65 Q50 68 55 65"
                          stroke="white"
                          strokeLinecap="round"
                          strokeWidth="2"
                        ></path>
                        <circle cx="50" cy="15" fill="white" r="6"></circle>
                        <rect fill="white" height="10" rx="2" width="4" x="48" y="20"></rect>
                      </svg>
                    </div>
                    <div className="space-y-4 flex-1">
                      {isFirstMessage && (
                        <div>
                          <h4 className="text-xs font-bold text-slate-900 dark:text-white mb-0.5">
                            AvarIQ Agent{" "}
                            <span className="text-[7px] text-slate-400 font-normal ml-1">
                              Just now
                            </span>
                          </h4>
                        </div>
                      )}
                      <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 p-4 rounded-xl rounded-tl-none shadow-sm">
                        <div className="prose prose-sm dark:prose-invert max-w-none text-slate-700 dark:text-slate-300 leading-relaxed text-xs">
                          <ReactMarkdown remarkPlugins={[remarkGfm]}>{m.content}</ReactMarkdown>
                        </div>
                      </div>
                      {isFirstMessage && (
                        <div className="space-y-2">
                          <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase ml-0.5 tracking-wider">
                            Try asking:
                          </p>
                          <div className="flex flex-wrap gap-1.5">
                            <button
                              onClick={() => {
                                setInput("Show me all leads");
                              }}
                              className="px-3 py-1.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:border-accent text-xs text-slate-600 dark:text-slate-300 rounded-full transition-all hover:shadow-md font-medium"
                            >
                              'Show me all leads'
                            </button>
                            <button
                              onClick={() => {
                                setInput("Find available 50T Cranes");
                              }}
                              className="px-3 py-1.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:border-accent text-xs text-slate-600 dark:text-slate-300 rounded-full transition-all hover:shadow-md font-medium"
                            >
                              'Find available 50T Cranes'
                            </button>
                            <button
                              onClick={() => {
                                setInput("Create a lead for Acme Corp");
                              }}
                              className="px-3 py-1.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:border-accent text-xs text-slate-600 dark:text-slate-300 rounded-full transition-all hover:shadow-md font-medium"
                            >
                              'Create a lead for Acme Corp'
                            </button>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}

              {/* Loading Indicator */}
              {isLoading && messages[messages.length - 1]?.role === "user" && (
                <div className="flex gap-5">
                  <div className="w-10 h-10 rounded-xl bg-midnight-blue flex-shrink-0 flex items-center justify-center p-1.5 shadow-md border border-slate-700">
                    <svg
                      className="w-full h-full"
                      fill="none"
                      viewBox="0 0 100 100"
                      xmlns="http://www.w3.org/2000/svg"
                    >
                      <circle cx="50" cy="55" fill="white" r="35"></circle>
                      <circle cx="50" cy="55" fill="#0F172A" r="30"></circle>
                      <circle cx="40" cy="55" fill="white" r="5"></circle>
                      <circle cx="60" cy="55" fill="white" r="5"></circle>
                      <path
                        d="M45 65 Q50 68 55 65"
                        stroke="white"
                        strokeLinecap="round"
                        strokeWidth="2"
                      ></path>
                      <circle cx="50" cy="15" fill="white" r="6"></circle>
                      <rect fill="white" height="10" rx="2" width="4" x="48" y="20"></rect>
                    </svg>
                  </div>
                  <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 p-6 rounded-2xl rounded-tl-none shadow-sm flex-1">
                    <p className="text-sm font-medium text-slate-700 dark:text-slate-300">
                      Fetching data from ERPNext Database...
                    </p>
                  </div>
                </div>
              )}

              <div ref={messagesEndRef} />
            </div>
          </div>

          {/* Sidebar */}
          <aside className="w-72 border-l border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-midnight-blue/20 p-5 hidden xl:block overflow-y-auto">
            <div className="flex items-center justify-between mb-5">
              <h4 className="font-bold text-[8px] dark:text-slate-300 uppercase tracking-[0.15em] text-slate-500">
                Action Preview
              </h4>
              <span className="material-symbols-outlined text-slate-400 text-sm">info</span>
            </div>
            <div className="space-y-4">
              <div className="p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700 shadow-sm">
                <p className="text-[7px] font-bold text-slate-400 uppercase mb-0.5 tracking-wider">
                  Source Module
                </p>
                <p className="text-xs font-semibold text-slate-900 dark:text-white">
                  CRM / Leads
                </p>
              </div>
              <div className="p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700 shadow-sm">
                <p className="text-[7px] font-bold text-slate-400 uppercase mb-0.5 tracking-wider">
                  Last Sync
                </p>
                <p className="text-xs font-semibold text-slate-900 dark:text-white">
                  2 minutes ago
                </p>
              </div>
              <div className="pt-5 mt-3 border-t border-slate-100 dark:border-slate-800">
                <h5 className="text-[7px] font-bold text-slate-400 uppercase mb-3 tracking-[0.08em]">
                  Quick Shortcuts
                </h5>
                <div className="space-y-1.5">
                  <button className="w-full flex items-center justify-between px-3 py-2 rounded-lg hover:bg-white dark:hover:bg-slate-800 border border-transparent hover:border-slate-200 dark:hover:border-slate-700 transition-all text-xs group">
                    <span className="font-medium text-slate-600 dark:text-slate-300 group-hover:text-accent text-xs">
                      Export as CSV
                    </span>
                    <span className="material-symbols-outlined text-slate-400 text-base group-hover:text-accent">
                      download
                    </span>
                  </button>
                  <button className="w-full flex items-center justify-between px-3 py-2 rounded-lg hover:bg-white dark:hover:bg-slate-800 border border-transparent hover:border-slate-200 dark:hover:border-slate-700 transition-all text-xs group">
                    <span className="font-medium text-slate-600 dark:text-slate-300 group-hover:text-accent text-xs">
                      Open in ERPNext
                    </span>
                    <span className="material-symbols-outlined text-slate-400 text-base group-hover:text-accent">
                      open_in_new
                    </span>
                  </button>
                </div>
              </div>
              <div className="p-3 bg-blue-50/50 dark:bg-blue-900/10 rounded-xl border border-blue-100 dark:border-blue-900/30">
                <h5 className="text-[7px] font-bold text-blue-600 dark:text-blue-400 uppercase mb-1.5 tracking-wider">
                  Agent Intelligence
                </h5>
                <p className="text-[10px] text-slate-600 dark:text-slate-400 leading-relaxed">
                  Based on current leads, I suggest prioritizing{" "}
                  <strong>Global Tech Corp</strong> due to high interest score (8.9/10).
                </p>
              </div>
            </div>
          </aside>
        </div>

        {/* Footer */}
        <footer className="p-4 bg-white dark:bg-midnight-blue border-t border-slate-200 dark:border-slate-800">
          <div className="max-w-5xl mx-auto">
            <form onSubmit={handleCustomSubmit}>
              <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-900/80 border border-slate-200 dark:border-slate-700 rounded-xl p-1.5 pr-1.5 shadow-inner focus-within:ring-2 focus-within:ring-accent/20 transition-all">
                <button
                  type="button"
                  className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors"
                >
                  <span className="material-symbols-outlined text-lg">attach_file</span>
                </button>
                <input
                  value={input}
                  onChange={handleInputChange}
                  className="flex-1 bg-transparent border-none focus:ring-0 text-xs text-slate-700 dark:text-slate-200 placeholder-slate-400 dark:placeholder-slate-500 py-2 outline-none"
                  placeholder="Type your request (e.g., 'Draft invoice for ACME corp')..."
                  type="text"
                  disabled={isLoading}
                />
                <button
                  type="submit"
                  disabled={isLoading || !input.trim()}
                  className="w-9 h-9 bg-accent hover:bg-blue-600 text-white rounded-lg flex items-center justify-center shadow-md transition-all active:scale-95 group disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <span className="material-symbols-outlined text-lg transition-transform group-hover:translate-x-0.5 group-hover:-translate-y-0.5">
                    send
                  </span>
                </button>
              </div>
            </form>
            <div className="flex items-center justify-between mt-3">
              <p className="text-[7px] text-slate-400 uppercase tracking-[0.25em] font-bold">
                AvarIQ v2.4 ΓÇó Enterprise Suite
              </p>
              <button
                onClick={() => setShowDebug(!showDebug)}
                className="text-[7px] text-slate-400 uppercase tracking-[0.08em] font-bold flex items-center gap-1 hover:text-slate-600 dark:hover:text-slate-200"
              >
                <span className="material-symbols-outlined text-xs">bug_report</span> Debug Mode
              </button>
            </div>
          </div>
        </footer>
      </main>
    </div>
  );
}

import { getBooking } from "@/app/actions/bookings"
import { getOperators } from "@/app/actions/operators"
import { getAssetInspections } from "@/app/actions/inspections"
import { frappeRequest } from "@/app/lib/api"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { ArrowLeft, Truck, User, HardHat, FileText, ClipboardCheck, CheckCircle2, Circle, ArrowRight } from "lucide-react"
import Link from "next/link"
import { MobilizeDialog } from "@/components/bookings/mobilize-dialog"
import { BookingActions } from "@/components/bookings/booking-actions"

export const dynamic = 'force-dynamic'

export default async function BookingDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = await params

    const booking = await getBooking(id)
    const operators = await getOperators()

    if (!booking) return <div className="p-8">Booking not found</div>

    const assetName = booking.po_no?.replace('RENT-', '') || booking.items?.[0]?.item_code || ''

    // Derive item_code: prefer from items child table; fall back to stripping timestamp from po_no
    // po_no format is "RENT-{itemCode}-{timestamp}" so strip prefix + suffix
    let itemCode = booking.items?.[0]?.item_code || ''
    if (!itemCode && booking.po_no?.startsWith('RENT-')) {
        const stripped = booking.po_no.replace(/^RENT-/, '')
        // Remove trailing -timestamp (13-digit epoch)
        itemCode = stripped.replace(/-\d{13}$/, '')
    }

    // Fetch linked inspections: by item_code AND by delivery notes for this sales order
    let inspections: any[] = []
    try {
        inspections = await getAssetInspections(itemCode, booking.name)
    } catch { /* ignore */ }

    // Extract operator from delivery note
    let assignedOperator = "";
    try {
        if (booking.per_delivered >= 100) {
            const deliveryNotes = await frappeRequest('frappe.client.get_list', 'GET', {
                doctype: 'Delivery Note',
                filters: `[["customer", "=", "${booking.customer}"], ["docstatus", "!=", 2]]`,
                fields: '["name", "instructions"]',
                order_by: 'creation desc',
                limit_page_length: 1
            }) as Array<{ name: string; instructions: string }>;

            if (deliveryNotes?.[0]?.instructions) {
                const match = deliveryNotes[0].instructions.match(/Operator:\s*(.+?)(?:\||$)/);
                if (match) assignedOperator = match[1].trim();
            }
        }
    } catch { /* ignore */ }

    const isMobilized = booking.per_delivered >= 100;
    const isReturned = booking.status === 'Completed';
    const isCompleted = booking.status === 'Completed' || booking.status === 'Cancelled';
    const hasInspection = inspections.length > 0;

    // Workflow steps
    const steps = [
        { label: 'Booked', done: true },
        { label: 'Operator', done: !!assignedOperator },
        { label: 'Inspected', done: hasInspection },
        { label: 'Mobilized', done: isMobilized },
        { label: 'Returned', done: isReturned },
    ]

    return (
        <div className="max-w-5xl mx-auto p-8 space-y-6">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between gap-4">
                <div className="flex items-center gap-4">
                    <Link href="/bookings">
                        <Button variant="ghost" size="icon"><ArrowLeft className="h-4 w-4" /></Button>
                    </Link>
                    <div>
                        <div className="flex items-center gap-3">
                            <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
                                Booking #{booking.name}
                            </h1>
                            <Badge
                                variant={isCompleted ? 'secondary' : booking.status === 'Draft' ? 'outline' : 'default'}
                                className={isReturned ? 'bg-green-100 text-green-700 hover:bg-green-100 border-green-200' : ''}
                            >
                                {booking.status}
                            </Badge>
                        </div>
                        <p className="text-slate-500">Created on {booking.transaction_date}</p>
                    </div>
                </div>

                {!isCompleted && (
                    <div className="flex gap-2">
                        {!isMobilized ? (
                            <MobilizeDialog booking={booking} operators={operators} />
                        ) : (
                            <BookingActions
                                bookingId={booking.name}
                                isMobilized={isMobilized}
                                isReturned={isReturned}
                                assetName={assetName}
                            />
                        )}
                    </div>
                )}

                {/* Show Create Invoice even after completion */}
                {isReturned && (
                    <div className="flex gap-2">
                        <BookingActions
                            bookingId={booking.name}
                            isMobilized={isMobilized}
                            isReturned={isReturned}
                            assetName={assetName}
                        />
                    </div>
                )}
            </div>

            {/* Workflow Progress Tracker */}
            <Card>
                <CardContent className="pt-6">
                    <div className="flex items-center justify-between max-w-xl mx-auto">
                        {steps.map((step, i) => (
                            <div key={step.label} className="flex items-center">
                                <div className="flex flex-col items-center gap-1.5">
                                    {step.done ? (
                                        <CheckCircle2 className="h-6 w-6 text-green-500" />
                                    ) : (
                                        <Circle className="h-6 w-6 text-slate-300" />
                                    )}
                                    <span className={`text-xs font-medium ${step.done ? 'text-green-700' : 'text-slate-400'}`}>
                                        {step.label}
                                    </span>
                                </div>
                                {i < steps.length - 1 && (
                                    <ArrowRight className={`h-4 w-4 mx-3 mb-5 ${step.done ? 'text-green-400' : 'text-slate-200'}`} />
                                )}
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>

            <div className="grid md:grid-cols-2 gap-6">
                {/* Rental Details */}
                <Card>
                    <CardHeader>
                        <CardTitle className="text-lg flex items-center gap-2">
                            <Truck className="h-5 w-5 text-blue-600" />
                            Rental Details
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex justify-between py-2 border-b border-slate-100 dark:border-slate-800">
                            <span className="text-slate-500">Asset / Item</span>
                            <span className="font-medium font-mono">{assetName}</span>
                        </div>
                        <div className="flex justify-between py-2 border-b border-slate-100 dark:border-slate-800">
                            <span className="text-slate-500">Start Date</span>
                            <span className="font-medium">{booking.transaction_date}</span>
                        </div>
                        {booking.items?.[0] && (
                            <div className="flex justify-between py-2 border-b border-slate-100 dark:border-slate-800">
                                <span className="text-slate-500">End Date</span>
                                <span className="font-medium">{booking.items[0].delivery_date}</span>
                            </div>
                        )}
                        <div className="flex justify-between py-2">
                            <span className="text-slate-500">Rate</span>
                            <span className="font-medium">Γé╣{booking.items?.[0]?.rate?.toLocaleString('en-IN')}</span>
                        </div>

                        <div className="mt-4 p-3 bg-slate-50 dark:bg-slate-900 rounded border border-slate-100 dark:border-slate-800">
                            <div className="flex justify-between items-center text-xs">
                                <span className="font-semibold text-slate-600 dark:text-slate-400">Logistics Status</span>
                                <span className={isMobilized ? (isReturned ? "text-blue-600 font-bold" : "text-green-600 font-bold") : "text-orange-500 font-bold"}>
                                    {isReturned ? "Returned" : isMobilized ? "On Site" : "Pending Dispatch"}
                                </span>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                <div className="space-y-6">
                    {/* Customer Info */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="text-lg flex items-center gap-2">
                                <User className="h-5 w-5 text-purple-600" />
                                Customer Info
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="flex justify-between py-2 border-b border-slate-100 dark:border-slate-800">
                                <span className="text-slate-500">Customer</span>
                                <span className="font-medium">{booking.customer_name}</span>
                            </div>
                            <div className="flex justify-between py-2">
                                <span className="text-slate-500">Total Value</span>
                                <span className="font-bold text-lg">Γé╣{booking.grand_total?.toLocaleString('en-IN')}</span>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Crew & Logistics (when mobilized) */}
                    {isMobilized && assignedOperator && (
                        <Card className="border-blue-200 dark:border-blue-900 bg-blue-50/30 dark:bg-blue-900/10">
                            <CardHeader>
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <HardHat className="h-5 w-5 text-orange-600" />
                                    Crew & Logistics
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <span className="text-slate-500 text-sm">Assigned Operator</span>
                                    <Badge variant="outline" className="bg-white dark:bg-slate-950 font-medium">
                                        {assignedOperator}
                                    </Badge>
                                </div>
                                <div className="flex items-center gap-2 text-xs text-slate-500 mt-2">
                                    <FileText className="h-3 w-3" />
                                    <span>Delivery Note Generated</span>
                                </div>
                            </CardContent>
                        </Card>
                    )}
                </div>
            </div>

            {/* Linked Inspections */}
            <Card>
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <CardTitle className="text-lg flex items-center gap-2">
                            <ClipboardCheck className="h-5 w-5 text-teal-600" />
                            Inspections
                        </CardTitle>
                        {!isCompleted && (
                            <Link href={`/inspections/new?booking=${booking.name}&asset=${encodeURIComponent(itemCode || assetName)}`}>
                                <Button variant="outline" size="sm">
                                    <ClipboardCheck className="h-4 w-4 mr-2" />
                                    New Inspection
                                </Button>
                            </Link>
                        )}
                    </div>
                </CardHeader>
                <CardContent>
                    {inspections.length === 0 ? (
                        <p className="text-sm text-slate-400 text-center py-4">No inspections recorded yet</p>
                    ) : (
                        <div className="divide-y">
                            {inspections.map((insp: any) => (
                                <Link key={insp.name} href={`/inspections/${insp.name}`} className="flex items-center justify-between py-3 hover:bg-slate-50 dark:hover:bg-slate-900/50 px-2 rounded transition-colors">
                                    <div>
                                        <p className="text-sm font-medium">{insp.inspection_type}</p>
                                        <p className="text-xs text-slate-500">{insp.report_date} ΓÇó By {insp.inspected_by}</p>
                                    </div>
                                    <Badge variant={insp.status === 'Accepted' ? 'default' : 'secondary'}
                                        className={insp.status === 'Accepted' ? 'bg-green-100 text-green-700' : ''}
                                    >
                                        {insp.status}
                                    </Badge>
                                </Link>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Quick Navigation */}
            <div className="flex gap-3 text-sm">
                <Link href={`/sales-orders/${encodeURIComponent(booking.name)}`} className="text-blue-600 hover:underline flex items-center gap-1">
                    <FileText className="h-3.5 w-3.5" />
                    View Sales Order
                </Link>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo } from "react"
import { searchItems, ensureItemGroups, getItemDetails } from "@/app/actions/invoices"
import { getItemRentalAnalytics } from "@/app/actions/bookings"
import { CreateItemDialog } from "@/components/catalogue/create-item-dialog"
import { EditItemDialog } from "@/components/catalogue/edit-item-dialog"
import { CreateBookingDialog } from "@/components/bookings/create-booking-dialog"
import { PageHeader } from "@/components/page-header"

interface Item {
  item_code: string
  item_name: string
  description: string
  item_group: string
  standard_rate?: number
  stock_qty?: number | null
  available: boolean
  is_stock_item?: number
}

interface ItemDetails extends Item {
  current_price?: number
  has_serial_no?: number
  has_batch_no?: number
  uom?: string
}

interface RentalAnalytics {
  totalRentals: number
  totalRevenue: number
  averageRentalDays: number
  recentRentals: any[]
}

export default function CataloguePage() {
  const [allItems, setAllItems] = useState<Item[]>([])
  const [selectedCategories, setSelectedCategories] = useState<Set<string>>(new Set(['All']))
  const [searchQuery, setSearchQuery] = useState('')
  const [minPrice, setMinPrice] = useState(0)
  const [maxPrice, setMaxPrice] = useState(5000)
  const [selectedItem, setSelectedItem] = useState<ItemDetails | null>(null)
  const [itemAnalytics, setItemAnalytics] = useState<RentalAnalytics | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [isLoadingDetails, setIsLoadingDetails] = useState(false)
  const [editingItem, setEditingItem] = useState<Item | null>(null)
  const [currentPage, setCurrentPage] = useState(1)
  const itemsPerPage = 4

  // Dynamically build categories from actual item groups
  const uniqueItemGroups = useMemo(() => {
    const groups = new Set(allItems.map(item => item.item_group))
    return ['All', ...Array.from(groups).sort()]
  }, [allItems])

  const categories = uniqueItemGroups

  // Load initial data
  useEffect(() => {
    async function loadData() {
      try {
        await ensureItemGroups()
        const items = await searchItems('')
        setAllItems(items)
      } catch (error) {
        console.error('Failed to load items:', error)
        setAllItems([])
      } finally {
        setIsLoading(false)
      }
    }
    loadData()
  }, [])

  // Filter items based on search, categories, and price
  const filteredItems: Item[] = useMemo(() => {
    let items = allItems;
    // If 'All' is selected, show all items
    if (selectedCategories.has('All')) {
      // No filtering by group
    } else if (selectedCategories.size > 0) {
      items = items.filter((item: Item) => selectedCategories.has(item.item_group));
    }
    // Filter by search query
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      items = items.filter((item: Item) =>
        item.item_name.toLowerCase().includes(query) ||
        item.item_code.toLowerCase().includes(query) ||
        item.description?.toLowerCase().includes(query)
      );
    }
    return items;
  }, [allItems, searchQuery, selectedCategories]);

  // Pagination logic
  const totalPages = Math.ceil(filteredItems.length / itemsPerPage);
  const paginatedItems = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage
    const endIndex = startIndex + itemsPerPage
    return filteredItems.slice(startIndex, endIndex)
  }, [filteredItems, currentPage])

  // Reset to page 1 when filtered items change
  useEffect(() => {
    setCurrentPage(1)
  }, [filteredItems])

  // Calculate summary stats
  const totalItems = allItems.length
  const availableItems = allItems.filter(item => item.available).length

  // Category counts
  const getCategoryCount = (category: string) => {
    if (category === 'All') return totalItems
    return allItems.filter(item => item.item_group === category).length
  }

  // Toggle category selection
  const toggleCategory = (category: string) => {
    const newSelected = new Set(selectedCategories)

    if (category === 'All') {
      setSelectedCategories(new Set(['All']))
    } else {
      newSelected.delete('All')
      if (newSelected.has(category)) {
        newSelected.delete(category)
      } else {
        newSelected.add(category)
      }

      if (newSelected.size === 0) {
        newSelected.add('All')
      }

      setSelectedCategories(newSelected)
    }
  }

  // Load item details for quick view
  const handleQuickView = async (itemCode: string) => {
    setIsLoadingDetails(true)
    try {
      const [details, analytics] = await Promise.all([
        getItemDetails(itemCode),
        getItemRentalAnalytics(itemCode)
      ])
      setSelectedItem(details)
      setItemAnalytics(analytics)
    } finally {
      setIsLoadingDetails(false)
    }
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background-light dark:bg-background-dark">
        <div className="max-w-[1600px] mx-auto p-8">
          <div className="animate-pulse space-y-6">
            <div className="h-8 bg-slate-200 dark:bg-slate-800 rounded w-1/4" />
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {[1, 2, 3].map(i => (
                <div key={i} className="h-24 bg-slate-200 dark:bg-slate-800 rounded-xl" />
              ))}
            </div>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-background-dark text-slate-900 dark:text-slate-100 flex flex-col overflow-hidden">
      {/* Header */}
      <PageHeader searchQuery={searchQuery} onSearchChange={setSearchQuery}>
        <CreateItemDialog />
      </PageHeader>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-8 bg-slate-50 dark:bg-background-dark custom-scrollbar">
        <div className="max-w-full mx-auto space-y-8">
          {/* KPI Cards - Matching Leads Dashboard Style */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-[#111827] p-7 rounded-2xl shadow-xl relative overflow-hidden flex flex-col justify-between min-h-[160px] border border-slate-800/50">
              <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-blue-500/10 to-transparent rounded-full -mr-16 -mt-16"></div>
              <div className="relative z-10">
                <div className="flex items-center justify-between mb-3">
                  <p className="text-[10px] uppercase font-bold tracking-[0.2em] text-slate-400">Total Items</p>
                  <div className="w-10 h-10 bg-blue-500/10 text-blue-400 flex items-center justify-center rounded-full ring-1 ring-blue-500/30">
                    <span className="material-symbols-outlined text-xl">inventory_2</span>
                  </div>
                </div>
                <h3 className="text-4xl font-bold text-white mb-1">{totalItems}</h3>
                <p className="text-sm text-slate-400">{categories.length - 1} categories</p>
              </div>
            </div>
            <div className="bg-[#111827] p-7 rounded-2xl shadow-xl relative overflow-hidden flex flex-col justify-between min-h-[160px] border border-slate-800/50">
              <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-emerald-500/10 to-transparent rounded-full -mr-16 -mt-16"></div>
              <div className="relative z-10">
                <div className="flex items-center justify-between mb-3">
                  <p className="text-[10px] uppercase font-bold tracking-[0.2em] text-slate-400">Available Now</p>
                  <div className="w-10 h-10 bg-emerald-500/10 text-emerald-400 flex items-center justify-center rounded-full ring-1 ring-emerald-500/30">
                    <span className="material-symbols-outlined text-xl">check_circle</span>
                  </div>
                </div>
                <h3 className="text-4xl font-bold text-white mb-1">{availableItems}</h3>
                <p className="text-sm text-slate-400">Ready to book</p>
              </div>
            </div>
            <div className="bg-[#111827] p-7 rounded-2xl shadow-xl relative overflow-hidden flex flex-col justify-between min-h-[160px] border border-slate-800/50">
              <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-purple-500/10 to-transparent rounded-full -mr-16 -mt-16"></div>
              <div className="relative z-10">
                <div className="flex items-center justify-between mb-3">
                  <p className="text-[10px] uppercase font-bold tracking-[0.2em] text-slate-400">Filtered Results</p>
                  <div className="w-10 h-10 bg-purple-500/10 text-purple-400 flex items-center justify-center rounded-full ring-1 ring-purple-500/30">
                    <span className="material-symbols-outlined text-xl">filter_alt</span>
                  </div>
                </div>
                <h3 className="text-4xl font-bold text-white mb-1">{filteredItems.length}</h3>
                <p className="text-sm text-slate-400">Showing {selectedCategories.has('All') ? 'All' : Array.from(selectedCategories).join(', ')}</p>
              </div>
            </div>
          </div>

          {/* Main Content Grid */}
          <div className="grid grid-cols-12 gap-8">
            {/* Left Sidebar - Filters */}
            <aside className="col-span-12 lg:col-span-3 xl:col-span-2 space-y-8">
              <div>
                <h5 className="text-[11px] uppercase font-bold tracking-widest text-slate-500 dark:text-slate-400 mb-4 border-b dark:border-slate-800 pb-2">Categories</h5>
                <div className="space-y-3">
                  {categories.map(category => (
                    <label key={category} className="flex items-center group cursor-pointer">
                      <input
                        checked={selectedCategories.has(category)}
                        onChange={() => toggleCategory(category)}
                        className="rounded border-slate-300 dark:border-slate-700 text-primary focus:ring-primary h-4 w-4"
                        type="checkbox"
                      />
                      <span className="ml-3 text-sm text-slate-700 dark:text-slate-300 group-hover:text-primary">{category}</span>
                      <span className="ml-auto text-xs text-slate-400">{getCategoryCount(category)}</span>
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <h5 className="text-[11px] uppercase font-bold tracking-widest text-slate-500 dark:text-slate-400 mb-4 border-b dark:border-slate-800 pb-2">Price Range</h5>
                <div className="flex items-center space-x-3 mb-4">
                  <div className="flex-1">
                    <label className="text-[10px] text-slate-400 mb-1 block">MIN</label>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">Γé╣</span>
                      <input
                        className="w-full pl-6 pr-3 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded text-sm"
                        type="text"
                        value={minPrice}
                        onChange={(e) => setMinPrice(parseInt(e.target.value) || 0)}
                      />
                    </div>
                  </div>
                  <div className="flex-1">
                    <label className="text-[10px] text-slate-400 mb-1 block">MAX</label>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">Γé╣</span>
                      <input
                        className="w-full pl-6 pr-3 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded text-sm"
                        type="text"
                        value={maxPrice}
                        onChange={(e) => setMaxPrice(parseInt(e.target.value) || 5000)}
                      />
                    </div>
                  </div>
                </div>
                <input
                  className="w-full"
                  type="range"
                  min="0"
                  max="5000"
                  value={maxPrice}
                  onChange={(e) => setMaxPrice(parseInt(e.target.value))}
                />
              </div>
            </aside>

            {/* Center - Items Grid */}
            <div className="col-span-12 lg:col-span-6 xl:col-span-7 space-y-6">
              <div className="space-y-4">
                <div className="relative">
                  <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">search</span>
                  <input
                    className="w-full pl-12 pr-4 py-2.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                    placeholder="Search items by name, code, or description..."
                    type="text"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <div className="flex flex-wrap gap-2">
                  {categories.map(category => {
                    const isActive = selectedCategories.has(category)
                    return (
                      <button
                        key={category}
                        onClick={() => toggleCategory(category)}
                        className={`px-4 py-1.5 rounded-full text-xs font-semibold flex items-center ${isActive
                            ? 'bg-midnight-blue text-white'
                            : 'bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-50 transition'
                          }`}
                      >
                        <span className="material-symbols-outlined text-sm mr-2">
                          {category === 'All' ? 'apps' : category === 'Heavy Equipment Rental' ? 'agriculture' : 'build'}
                        </span>
                        {category}
                      </button>
                    )
                  })}
                </div>
              </div>

              {/* Items Grid */}
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                {filteredItems.length === 0 ? (
                  <div className="col-span-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-12 text-center">
                    <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4">
                      <span className="material-symbols-outlined text-3xl text-slate-400">inventory_2</span>
                    </div>
                    <h3 className="text-lg font-semibold text-slate-900 dark:text-white mb-2">No items found</h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">
                      {allItems.length === 0
                        ? "Get started by adding your first item to the catalogue."
                        : "Try adjusting your filters or search query."}
                    </p>
                    {allItems.length === 0 && <CreateItemDialog />}
                  </div>
