export default function EditQuotationPage() {
  const [loading, setLoading] = useState(false)
  const [fetching, setFetching] = useState(true)
  const router = useRouter()
  const params = useParams()
  const quotationId = decodeURIComponent(params.id as string)

  // Rental mode state
  const [isRentalMode, setIsRentalMode] = useState(false)
  const [expandedItemId, setExpandedItemId] = useState<number | null>(null)

  // Header Fields
  const [quotationTo, setQuotationTo] = useState("Customer")
  const [partyName, setPartyName] = useState("")
  const [transactionDate, setTransactionDate] = useState("")
  const [validTill, setValidTill] = useState("")
  const [currency, setCurrency] = useState("INR")
  const [orderType, setOrderType] = useState("Sales")
  const [opportunityReference, setOpportunityReference] = useState("")

  // Items State
  const [items, setItems] = useState<QuotationItem[]>([
    {
      id: 1,
      item_code: "",
      item_name: "",
      description: "",
      qty: 1,
      rate: 0,
      amount: 0,
      is_rental: false,
      pricing_components: {
        base_cost: 0,
        accommodation_charges: 0,
        usage_charges: 0,
        fuel_charges: 0,
        elongation_charges: 0,
        risk_charges: 0,
        commercial_charges: 0,
        incidental_charges: 0,
        other_charges: 0,
      }
    }
  ])

  // Additional Fields
  const [paymentTermsTemplate, setPaymentTermsTemplate] = useState("")
  const [termsAndConditions, setTermsAndConditions] = useState("")
  const [taxTemplate, setTaxTemplate] = useState("")
  const [availableTaxTemplates, setAvailableTaxTemplates] = useState<Array<{ name: string, title: string }>>([])
  const [selectedTaxTemplateDetails, setSelectedTaxTemplateDetails] = useState<any>(null)
  // Company and Bank Info (for display only)
  const [companyInfo, setCompanyInfo] = useState<{ name: string, gstin: string } | null>(null)
  const [bankInfo, setBankInfo] = useState<{ bank: string, bank_account_no: string, branch_code: string } | null>(null)
  // Fetch tax templates, company details, and bank details on mount
  useEffect(() => {
    getTaxTemplates().then(templates => {
      setAvailableTaxTemplates(templates)
    })

    getCompanyDetails().then(data => {
      if (data) setCompanyInfo(data)
    })

    getBankDetails().then(data => {
      if (data) setBankInfo(data)
    })
  }, [])

  // Fetch selected tax template details when template changes
  useEffect(() => {
    if (taxTemplate && taxTemplate !== 'none') {
      getTaxTemplate(taxTemplate).then(details => {
        setSelectedTaxTemplateDetails(details)
      })
    } else {
      setSelectedTaxTemplateDetails(null)
    }
  }, [taxTemplate])

  // Fetch existing quotation data
  useEffect(() => {
    const fetchQuotation = async () => {
      try {
        const response = await fetch(`/api/quotations/${encodeURIComponent(quotationId)}`)
        const data = await response.json()

        if (data.quotation) {
          const q = data.quotation

          // Set header fields
          setQuotationTo(q.quotation_to || 'Customer')
          setPartyName(q.party_name || '')
          setTransactionDate(q.transaction_date || new Date().toISOString().split('T')[0])
          setValidTill(q.valid_till || '')
          setCurrency(q.currency || 'INR')
          setOrderType(q.order_type || 'Sales')
          setOpportunityReference(q.opportunity || '')

          // Set items
          if (q.items && q.items.length > 0) {
            const loadedItems = q.items.map((item: any, index: number) => {
              // Parse rental data
              const rentalData = item.custom_rental_data ?
                (typeof item.custom_rental_data === 'string' ? JSON.parse(item.custom_rental_data) : item.custom_rental_data) :
                null

              const isRental = item.custom_is_rental || item.is_rental || false

              return {
                id: index + 1,
                item_code: item.item_code || '',
                item_name: item.item_name || item.item_code || '',
                description: item.description || item.item_name || '',
                item_category: item.item_group,
                qty: item.qty || 1,
                rate: item.rate || 0,
                amount: (item.qty || 1) * (item.rate || 0),
                is_rental: isRental,
                rental_type: item.custom_rental_type || item.rental_type,
                rental_duration: item.custom_rental_duration || item.rental_duration,
                rental_start_date: item.custom_rental_start_date || item.rental_start_date,
                rental_end_date: item.custom_rental_end_date || item.rental_end_date,
                rental_start_time: item.custom_rental_start_time || item.rental_start_time,
                rental_end_time: item.custom_rental_end_time || item.rental_end_time,
                operator_included: item.custom_operator_included || item.operator_included || false,
                total_rental_cost: item.custom_total_rental_cost || item.total_rental_cost || 0,
                pricing_components: rentalData ? {
                  base_cost: rentalData.baseRentalCost || 0,
                  accommodation_charges: rentalData.accommodationCost || 0,
                  usage_charges: rentalData.usageCost || 0,
                  fuel_charges: rentalData.fuelCost || 0,
                  elongation_charges: rentalData.elongationCost || 0,
                  risk_charges: rentalData.riskCost || 0,
                  commercial_charges: rentalData.commercialCost || 0,
                  incidental_charges: rentalData.incidentalCost || 0,
                  other_charges: rentalData.otherCost || 0,
                } : item.pricing_components ? {
                  base_cost: item.pricing_components.base_cost || 0,
                  accommodation_charges: item.pricing_components.accommodation_charges || 0,
                  usage_charges: item.pricing_components.usage_charges || 0,
                  fuel_charges: item.pricing_components.fuel_charges || 0,
                  elongation_charges: item.pricing_components.elongation_charges || 0,
                  risk_charges: item.pricing_components.risk_charges || 0,
                  commercial_charges: item.pricing_components.commercial_charges || 0,
                  incidental_charges: item.pricing_components.incidental_charges || 0,
                  other_charges: item.pricing_components.other_charges || 0,
                } : {
                  base_cost: 0,
                  accommodation_charges: 0,
                  usage_charges: 0,
                  fuel_charges: 0,
                  elongation_charges: 0,
                  risk_charges: 0,
                  commercial_charges: 0,
                  incidental_charges: 0,
                  other_charges: 0,
                }
              }
            })
            setItems(loadedItems)

            // Enable rental mode if any item is rental
            if (loadedItems.some((item: QuotationItem) => item.is_rental)) {
              setIsRentalMode(true)
            }
          }

          // Set additional fields
          setPaymentTermsTemplate(q.payment_terms_template || '')
          setTermsAndConditions(q.terms || '')
          setTaxTemplate(q.taxes_and_charges || '')
        }
      } catch (error) {
        console.error('Error fetching quotation:', error)
        alert('Failed to load quotation data')
      } finally {
        setFetching(false)
      }
    }

    fetchQuotation()
  }, [quotationId])

  // Calculate totals
  const netTotal = items.reduce((sum, item) => sum + item.amount, 0)

  // Calculate taxes dynamically based on selected template
  const totalTaxes = selectedTaxTemplateDetails?.taxes?.reduce((sum: number, tax: any) => {
    return sum + (netTotal * (tax.rate || 0) / 100)
  }, 0) || 0

  const grandTotal = netTotal + totalTaxes

  // Item management functions
  const addItem = () => {
    const newId = Math.max(...items.map(i => i.id), 0) + 1
    setItems([...items, { id: newId, item_code: "", item_name: "", description: "", qty: 1, rate: 0, amount: 0 }])
  }

  const removeItem = (id: number) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id))
    }
  }

  const updateItem = (id: number, field: keyof QuotationItem, value: any) => {
    setItems(items.map(item => {
      if (item.id === id) {
        const updatedItem = { ...item, [field]: value }
        // Recalculate amount when qty or rate changes
        if (field === 'qty' || field === 'rate') {
          updatedItem.amount = updatedItem.qty * updatedItem.rate
        }
        return updatedItem
      }
      return item
    }))
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)

    try {
      // Validate items
      const validItems = items.filter(item =>
        (item.item_code || item.description) && item.qty > 0
      )

      if (validItems.length === 0) {
        alert('Please add at least one item with a valid item code/description and quantity')
        setLoading(false)
        return
      }

      // Prepare quotation data
      const quotationData: {
        quotation_to: string
        party_name: string
        transaction_date: string
        valid_till: string
        currency: string
        order_type: string
        items: Array<{
          item_code: string | undefined
          item_name: string
          description: string
          qty: number
          rate: number
          amount: number
        }>
        payment_terms_template?: string
        terms?: string
        opportunity?: string
        taxes_and_charges?: string
      } = {
        quotation_to: quotationTo,
        party_name: partyName,
        transaction_date: transactionDate,
        valid_till: validTill,
        currency: currency,
        order_type: orderType,
        items: validItems.map(item => ({
          item_code: item.item_code || undefined,
          item_name: item.item_name || item.item_code,
          description: item.description || item.item_name || item.item_code,
          qty: item.qty,
          rate: item.rate,
          amount: item.amount
        }))
      }

      // Add optional fields only if they have values
      if (paymentTermsTemplate && paymentTermsTemplate.trim()) {
        quotationData.payment_terms_template = paymentTermsTemplate.trim()
      }

      if (termsAndConditions && termsAndConditions.trim()) {
        quotationData.terms = termsAndConditions.trim()
      }

      if (opportunityReference && opportunityReference.trim()) {
        quotationData.opportunity = opportunityReference.trim()
      }

      if (taxTemplate && taxTemplate.trim() !== '' && taxTemplate !== 'none') {
        quotationData.taxes_and_charges = taxTemplate
      }

      // Send update request
      const response = await fetch(`/api/quotations/${encodeURIComponent(quotationId)}/update`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(quotationData)
      })

      const result = await response.json()

      if (!response.ok) {
        throw new Error(result.error || 'Failed to update quotation')
      }

      alert('Γ£à Quotation updated successfully!')
      router.push(`/crm/quotations/${encodeURIComponent(quotationId)}`)
    } catch (error: any) {
      console.error('Error updating quotation:', error)

      // Parse error message for better user feedback
      const errorMessage = error.message || 'Failed to update quotation'

      if (errorMessage.includes('Party')) {
        alert(`Γ¥î Error: ${errorMessage}\n\nThe customer/lead specified does not exist in ERPNext. Please create it first or use an existing party name.`)
      } else if (errorMessage.includes('Payment Terms')) {
        alert(`Γ¥î Error: ${errorMessage}\n\nThe payment terms template does not exist in ERPNext. Please leave it blank or use an existing template.`)
      } else {
        alert(`Γ¥î ${errorMessage}`)
      }
    } finally {
      setLoading(false)
    }
  }

  if (fetching) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 p-8 flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="h-8 w-8 animate-spin mx-auto mb-4 text-blue-600" />
          <p className="text-slate-600">Loading quotation data...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 p-8">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <Link href={`/crm/quotations/${encodeURIComponent(quotationId)}`}>
            <Button variant="ghost" className="gap-2 pl-0 hover:bg-transparent hover:text-blue-600 mb-4">
              <ArrowLeft className="h-4 w-4" /> Back to Quotation
            </Button>
          </Link>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
            Edit Quotation: {quotationId}
          </h1>
          <p className="text-slate-500 mt-1">
            Update the quotation details below
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Customer / Lead Information */}
          <Card>
            <CardHeader>
              <CardTitle>Customer / Lead Information</CardTitle>
            </CardHeader>
            <CardContent className="grid md:grid-cols-2 gap-4">
              <div className="grid gap-2">
                <Label htmlFor="quotationTo">Quotation To *</Label>
                <Select value={quotationTo} onValueChange={setQuotationTo}>
                  <SelectTrigger id="quotationTo">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Customer">Customer</SelectItem>
                    <SelectItem value="Lead">Lead</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="grid gap-2">
                <Label htmlFor="partyName">{quotationTo} Name *</Label>
                <Input
                  id="partyName"
                  value={partyName}
                  onChange={(e) => setPartyName(e.target.value)}
                  placeholder={`Enter ${quotationTo.toLowerCase()} name`}
                  required
                />
              </div>

              <div className="grid gap-2">
                <Label htmlFor="transactionDate">Transaction Date *</Label>
                <Input
                  id="transactionDate"
                  type="date"
                  value={transactionDate}
                  onChange={(e) => setTransactionDate(e.target.value)}
                  required
                />
              </div>

              <div className="grid gap-2">
                <Label htmlFor="validTill">Valid Till *</Label>
                <Input
                  id="validTill"
                  type="date"
                  value={validTill}
                  onChange={(e) => setValidTill(e.target.value)}
                  required
                />
              </div>

              <div className="grid gap-2">
                <Label htmlFor="currency">Currency *</Label>
                <Select value={currency} onValueChange={setCurrency}>
                  <SelectTrigger id="currency">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="INR">INR - Indian Rupee</SelectItem>
                    <SelectItem value="USD">USD - US Dollar</SelectItem>
                    <SelectItem value="EUR">EUR - Euro</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="grid gap-2">
                <Label htmlFor="orderType">Order Type</Label>
                <Select value={orderType} onValueChange={setOrderType}>
                  <SelectTrigger id="orderType">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Sales">Sales</SelectItem>
                    <SelectItem value="Maintenance">Maintenance</SelectItem>
                    <SelectItem value="Shopping Cart">Shopping Cart</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Items */}
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle>Items</CardTitle>
              <Button type="button" onClick={addItem} size="sm" className="gap-2">
                <Plus className="h-4 w-4" /> Add Item
              </Button>
            </CardHeader>
            <CardContent>
              <div className="border-t">
                {/* Header Row */}
                <div className="grid grid-cols-12 gap-2 bg-slate-50 dark:bg-slate-900 px-4 py-3 text-xs font-medium text-slate-500 border-b">
                  <div className="col-span-1 text-center">#</div>
                  <div className="col-span-4">Item / Description</div>
                  <div className="col-span-1 text-right">Qty *</div>
                  <div className="col-span-2 text-right">Rate *</div>
                  <div className="col-span-2 text-right">Amount</div>
                  <div className="col-span-2"></div>
                </div>

                {/* Item Rows */}
                <div className="space-y-4">
                  {items.map((item, index) => (
                    <div key={item.id} className="border rounded-lg overflow-hidden">
                      {/* Item Header */}
                      <div className="bg-slate-50 dark:bg-slate-900 p-4 border-b">
                        <div className="flex justify-between items-start">
                          <div className="flex-1">
                            <div className="flex items-center gap-2 mb-2">
                              <span className="text-sm text-slate-500">#{index + 1}</span>
                              {item.is_rental && (
                                <Badge className="bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200">
                                  Rental Item
                                </Badge>
                              )}
                            </div>
                            <div className="space-y-2">
                              <div>
                                <Label className="text-xs text-slate-500">Item Code</Label>
                                <ItemSearch
                                  value={item.item_code}
                                  onChange={(code, desc, name) => {
                                    setItems(prev => prev.map(i =>
                                      i.id === item.id
                                        ? { ...i, item_code: code, item_name: name || code, description: desc || i.description }
                                        : i
                                    ))
                                  }}
                                />
                              </div>
                              <div>
                                <Label className="text-xs text-slate-500">Description</Label>
                                <Input
                                  placeholder="Description"
                                  value={item.description}
                                  onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                                  className="text-sm"
                                />
                              </div>
                            </div>
                          </div>
                          <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            onClick={() => removeItem(item.id)}
                            className="text-red-500 hover:text-red-700 hover:bg-red-50"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>

                      {/* Item Details */}
                      <div className="p-4">
                        <div className="grid grid-cols-3 gap-4 mb-4">
                          <div>
                            <Label className="text-xs text-slate-500">Quantity *</Label>
                            <Input
                              type="number"
                              min="0.01"
                              step="0.01"
                              value={item.qty}
                              onChange={(e) => updateItem(item.id, 'qty', parseFloat(e.target.value) || 0)}
                              className="text-sm"
                              required
                              disabled={item.is_rental}
                            />
                          </div>
                          <div>
                            <Label className="text-xs text-slate-500">Rate *</Label>
                            <Input
                              type="number"
                              min="0"
                              step="0.01"
                              value={item.rate}
                              onChange={(e) => updateItem(item.id, 'rate', parseFloat(e.target.value) || 0)}
                              className="text-sm"
                              required
                              disabled={item.is_rental}
                            />
                          </div>
                          <div>
                            <Label className="text-xs text-slate-500">Amount</Label>
                            <div className="h-9 flex items-center text-sm font-medium">
                              Γé╣{item.amount.toLocaleString('en-IN')}
                            </div>
                          </div>
                        </div>

                        {/* Rental Pricing Details & Components */}
                        {item.is_rental && (
                          <div className="border-t pt-4 mt-4 space-y-4">
                            {/* Rental Period Info */}
                            <div>
                              <h4 className="font-semibold text-sm mb-3 flex items-center gap-2">
                                <span>Rental Period</span>
                                <Badge variant="outline" className="text-xs">
                                  {item.rental_type ? item.rental_type.charAt(0).toUpperCase() + item.rental_type.slice(1) : 'N/A'}
                                </Badge>
                              </h4>
                              <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-sm">
                                <div>
                                  <p className="text-xs text-slate-500 mb-1">Duration</p>
                                  <p className="font-medium">{item.rental_duration || 'N/A'} {item.rental_type ? item.rental_type.charAt(0).toUpperCase() + item.rental_type.slice(1) : ''}</p>
                                </div>
                                <div>
                                  <p className="text-xs text-slate-500 mb-1">Start Date</p>
                                  <p className="font-medium">
                                    {item.rental_start_date ? new Date(item.rental_start_date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : 'N/A'}
                                  </p>
                                  {item.rental_start_time && <p className="text-xs text-slate-400">{item.rental_start_time}</p>}
                                </div>
                                <div>
                                  <p className="text-xs text-slate-500 mb-1">End Date</p>
                                  <p className="font-medium">
                                    {item.rental_end_date ? new Date(item.rental_end_date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : 'N/A'}
                                  </p>
                                  {item.rental_end_time && <p className="text-xs text-slate-400">{item.rental_end_time}</p>}
                                </div>
                                <div>
                                  <p className="text-xs text-slate-500 mb-1">Operator</p>
                                  {item.operator_included ? (
                                    <Badge className="text-xs bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200">Included</Badge>
                                  ) : (
                                    <Badge variant="outline" className="text-xs">Not Included</Badge>
                                  )}
                                </div>
                              </div>
                            </div>

                            {/* Editable Pricing Components */}
                            <div className="bg-blue-50/50 dark:bg-blue-950/20 rounded-lg p-4 border border-blue-200 dark:border-blue-800">
                              <h4 className="font-semibold text-sm mb-3 text-blue-900 dark:text-blue-100">Rental Cost Components</h4>
                              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                                <div>
                                  <Label className="text-xs text-blue-700 dark:text-blue-300">Base Cost</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.base_cost || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, base_cost: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-green-700 dark:text-green-300">Accommodation</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.accommodation_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, accommodation_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-purple-700 dark:text-purple-300">Usage</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.usage_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, usage_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-orange-700 dark:text-orange-300">Fuel</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.fuel_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, fuel_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-pink-700 dark:text-pink-300">Elongation</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.elongation_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, elongation_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-red-700 dark:text-red-300">Risk</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.risk_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, risk_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-indigo-700 dark:text-indigo-300">Commercial</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.commercial_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, commercial_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-teal-700 dark:text-teal-300">Incidental</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.incidental_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, incidental_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                                <div>
                                  <Label className="text-xs text-slate-700 dark:text-slate-300">Other</Label>
                                  <Input
                                    type="number"
                                    min="0"
                                    step="0.01"
                                    value={item.pricing_components?.other_charges || 0}
                                    onChange={(e) => {
                                      const newComponents = { ...item.pricing_components, other_charges: parseFloat(e.target.value) || 0 }
                                      const total = Object.values(newComponents).reduce((sum: number, val: any) => sum + (parseFloat(val) || 0), 0)
                                      updateItem(item.id, 'pricing_components', newComponents)
                                      updateItem(item.id, 'total_rental_cost', total)
                                      updateItem(item.id, 'rate', total)
                                      updateItem(item.id, 'amount', item.qty * total)
                                    }}
                                    className="text-sm h-8"
                                  />
                                </div>
                              </div>
                              <div className="mt-4 pt-3 border-t border-blue-200 dark:border-blue-700 flex justify-between items-center">
                                <span className="font-semibold text-sm text-slate-900 dark:text-white">Total Rental Cost</span>
                                <span className="text-lg font-bold text-blue-600 dark:text-blue-400">
                                  Γé╣{(item.total_rental_cost || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                </span>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>

                {/* Totals */}
                <div className="mt-6 border-t pt-4">
                  <div className="flex justify-end">
                    <div className="w-80 space-y-2 text-sm">
                      <div className="flex justify-between">
                        <span className="text-slate-500">Net Total:</span>
                        <span className="font-medium">Γé╣{netTotal.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                      </div>

                      {/* Dynamic tax breakdown */}
                      {selectedTaxTemplateDetails?.taxes && selectedTaxTemplateDetails.taxes.length > 0 ? (
                        <>
                          {selectedTaxTemplateDetails.taxes.map((tax: any, idx: number) => (
                            <div key={idx} className="flex justify-between text-xs">
                              <span className="text-slate-400">{tax.description || tax.account_head} ({tax.rate}%):</span>
                              <span className="font-medium">Γé╣{(netTotal * (tax.rate || 0) / 100).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                            </div>
                          ))}
                          <div className="flex justify-between">
                            <span className="text-slate-500">Total Taxes:</span>
                            <span className="font-medium">Γé╣{totalTaxes.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                          </div>
                        </>
                      ) : taxTemplate && taxTemplate !== 'none' ? (
                        <div className="flex justify-between">
                          <span className="text-slate-500">Taxes (Loading...):</span>
                          <span className="font-medium">Γé╣{totalTaxes.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                        </div>
                      ) : null}

                      <div className="flex justify-between text-lg font-bold border-t pt-2">
                        <span>Grand Total:</span>
                        <span className="text-slate-900 dark:text-white">Γé╣{grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Company & Bank Information (Read-only Display) */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Building2 className="h-5 w-5" />
                Company & Bank Information
              </CardTitle>
            </CardHeader>
            <CardContent className="grid md:grid-cols-2 gap-6">
              <div>
                <Label className="text-xs text-slate-500 uppercase tracking-wide mb-2 block">Company Details</Label>
                <div className="space-y-1 text-sm">
                  <p className="font-medium text-base">{companyInfo?.name || "Loading Company..."}</p>
                  <p className="text-xs text-slate-500">GSTIN: {companyInfo?.gstin || "Not Set"}</p>
                </div>
              </div>

              <div>
                <Label className="text-xs text-slate-500 uppercase tracking-wide mb-2 block">Bank Details</Label>
                {bankInfo ? (
                  <div className="space-y-1 text-xs">
                    <div className="flex justify-between"><span>Bank:</span> <span className="font-medium">{bankInfo.bank}</span></div>
                    <div className="flex justify-between"><span>A/C No:</span> <span className="font-medium">{bankInfo.bank_account_no}</span></div>
                    <div className="flex justify-between"><span>IFSC:</span> <span className="font-medium">{bankInfo.branch_code || "ΓÇö"}</span></div>
                  </div>
                ) : (
                  <p className="text-xs text-slate-400">Loading bank information...</p>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Additional Information */}
          <Card>
            <CardHeader>
              <CardTitle>Additional Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-2">
                <Label htmlFor="taxTemplate">Tax Template</Label>
                <Select value={taxTemplate} onValueChange={setTaxTemplate}>
                  <SelectTrigger id="taxTemplate">
                    <SelectValue placeholder="Select tax template (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">None</SelectItem>
                    {availableTaxTemplates.map(template => (
                      <SelectItem key={template.name} value={template.name}>
                        {template.title}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="grid gap-2">
                <Label htmlFor="paymentTerms">Payment Terms Template</Label>
                <Input
                  id="paymentTerms"
                  value={paymentTermsTemplate}
                  onChange={(e) => setPaymentTermsTemplate(e.target.value)}
                  placeholder="e.g., Net 30, 50% Advance"
                />
              </div>

              <div className="grid gap-2">
                <Label htmlFor="terms">Terms and Conditions</Label>
                <Textarea
                  id="terms"
                  value={termsAndConditions}
                  onChange={(e) => setTermsAndConditions(e.target.value)}
                  placeholder="Enter terms and conditions..."
                  rows={5}
                />
              </div>
            </CardContent>
          </Card>

          {/* Submit Buttons */}
          <div className="flex justify-end gap-4">
            <Link href={`/crm/quotations/${encodeURIComponent(quotationId)}`}>
              <Button type="button" variant="outline" disabled={loading}>
                Cancel
              </Button>
            </Link>
            <Button type="submit" disabled={loading} className="gap-2">
              {loading && <Loader2 className="h-4 w-4 animate-spin" />}
              {loading ? 'Updating...' : 'Update Quotation'}
            </Button>
          </div>
        </form>
      </div>
    </div>
  )
}

import { getQuotation } from "@/app/actions/crm"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { ArrowLeft, Calendar, FileText, Building2, Pencil, Printer, Clock, User } from "lucide-react"
import Link from "next/link"
import { DeleteQuotationButton } from "@/components/crm/delete-quotation-button"
import { RentalPricingBreakdown } from "@/components/crm/rental-pricing-breakdown"
import { QuotationActions } from "@/components/crm/quotation-actions"

export default async function QuotationDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params
  const quotationName = decodeURIComponent(id)
  
  let quotation
  try {
    quotation = await getQuotation(quotationName)
    
    // Additional null check
    if (!quotation) {
      throw new Error("Quotation not found")
    }
    
    // Debug: Log the quotation data to see what we're receiving
    console.log('=== QUOTATION DETAIL PAGE ===')
    console.log('Quotation items:', quotation.items?.length)
      // Ensure docstatus is present for Quotation type
      if (quotation && quotation.docstatus === undefined && (quotation as any).docstatus !== undefined) {
        quotation.docstatus = (quotation as any).docstatus;
      }
      quotation.items?.forEach((item: any, idx: number) => {
      console.log(`\nItem ${idx + 1}:`, item.item_code)
      console.log('  custom_is_rental:', item.custom_is_rental)
      console.log('  custom_rental_type:', item.custom_rental_type)
      console.log('  custom_rental_duration:', item.custom_rental_duration)
      console.log('  custom_rental_start_date:', item.custom_rental_start_date)
      console.log('  custom_rental_end_date:', item.custom_rental_end_date)
      console.log('  custom_base_rental_cost:', item.custom_base_rental_cost)
      console.log('  custom_accommodation_charges:', item.custom_accommodation_charges)
      console.log('  custom_rental_data:', item.custom_rental_data)
    })
  } catch (e) {
    console.error("Error fetching quotation:", e)
    return (
      <div className="p-8 flex flex-col gap-4">
        <h1 className="text-2xl font-bold">Quotation Not Found</h1>
        <p className="text-muted-foreground">The quotation "{quotationName}" could not be found.</p>
        <Link href="/crm/quotations">
          <Button variant="outline">Back to Quotations</Button>
        </Link>
      </div>
    )
  }

  // Status colors
  const statusColors: Record<string, string> = {
    'Draft': 'bg-slate-100 text-slate-800',
    'Open': 'bg-blue-100 text-blue-800',
    'Ordered': 'bg-green-100 text-green-800',
    'Lost': 'bg-red-100 text-red-800'
  }

  // Check if expired
  const isExpired = quotation.valid_till && new Date(quotation.valid_till) < new Date()

  return (
    <div suppressHydrationWarning className="p-8 space-y-6">
      {/* Back Button */}
      <Link href="/crm/quotations">
        <Button variant="ghost" className="gap-2 pl-0 hover:bg-transparent hover:text-blue-600">
          <ArrowLeft className="h-4 w-4" /> Back to Quotations
        </Button>
      </Link>

      {/* Header Section */}
      <div suppressHydrationWarning className="flex justify-between items-start">
        <div suppressHydrationWarning>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
            {quotation.name}
          </h1>
          <p className="text-slate-500">
            {quotation.quotation_to === 'Customer' ? 'Customer' : 'Lead'}: {quotation.customer_name || quotation.party_name}
          </p>
        </div>
        <div suppressHydrationWarning className="flex gap-2 items-center">
          <QuotationActions quotation={{
            ...quotation,
            docstatus: quotation.docstatus ?? 0
          }} />
          <Badge className={statusColors[quotation.status] || 'bg-slate-100 text-slate-800'}>
            {quotation.status}
          </Badge>
          {isExpired && quotation.status === 'Open' && (
            <Badge className="bg-orange-100 text-orange-800">Expired</Badge>
          )}
        </div>
      </div>

      {/* Info Cards */}
      <div suppressHydrationWarning className="grid md:grid-cols-3 gap-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-slate-500">Transaction Date</CardTitle>
            <Calendar className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div className="text-lg font-semibold">
              {quotation.transaction_date 
                ? new Date(quotation.transaction_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })
                : 'Not set'}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-slate-500">Valid Until</CardTitle>
            <Calendar className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div suppressHydrationWarning className={`text-lg font-semibold ${isExpired ? 'text-red-600' : ''}`}>
              {quotation.valid_till ? new Date(quotation.valid_till).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : 'Not set'}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-slate-500">Currency</CardTitle>
            <Building2 className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div suppressHydrationWarning className="text-lg font-semibold">{quotation.currency || 'INR'}</div>
          </CardContent>
        </Card>
      </div>

      {/* Items Table */}
      <Card>
        <CardHeader>
          <CardTitle>Items</CardTitle>
        </CardHeader>
        <CardContent>
          {quotation.items && quotation.items.length > 0 ? (
            <div suppressHydrationWarning className="space-y-4">
              {quotation.items.map((item: Record<string, any>, idx: number) => {
                const rentalData = (() => {
                  try {
                    if (item.custom_rental_data) {
                      return typeof item.custom_rental_data === 'string'
                        ? JSON.parse(item.custom_rental_data)
                        : item.custom_rental_data
                    }
                  } catch (err) {
                    console.error('Failed to parse rental data', err)
                  }
                  return null
                })()

                const parseNumber = (val: any) => {
                  const num = Number(val)
                  return Number.isFinite(num) ? num : 0
                }

                const pricingComponents = {
                  base_cost: parseNumber(item.custom_base_rental_cost ?? rentalData?.baseRentalCost ?? rentalData?.base_cost ?? item.pricing_components?.base_cost),
                  accommodation_charges: parseNumber(item.custom_accommodation_charges ?? rentalData?.accommodationCost ?? rentalData?.accommodation_charges ?? item.pricing_components?.accommodation_charges),
                  usage_charges: parseNumber(item.custom_usage_charges ?? rentalData?.usageCost ?? rentalData?.usage_charges ?? item.pricing_components?.usage_charges),
                  fuel_charges: parseNumber(item.custom_fuel_charges ?? rentalData?.fuelCost ?? rentalData?.fuel_charges ?? item.pricing_components?.fuel_charges),
                  elongation_charges: parseNumber(item.custom_elongation_charges ?? rentalData?.elongationCost ?? rentalData?.elongation_charges ?? item.pricing_components?.elongation_charges),
                  risk_charges: parseNumber(item.custom_risk_charges ?? rentalData?.riskCost ?? rentalData?.risk_charges ?? item.pricing_components?.risk_charges),
                  commercial_charges: parseNumber(item.custom_commercial_charges ?? rentalData?.commercialCost ?? rentalData?.commercial_charges ?? item.pricing_components?.commercial_charges),
                  incidental_charges: parseNumber(item.custom_incidental_charges ?? rentalData?.incidentalCost ?? rentalData?.incidental_charges ?? item.pricing_components?.incidental_charges),
                  other_charges: parseNumber(item.custom_other_charges ?? rentalData?.otherCost ?? rentalData?.other_charges ?? item.pricing_components?.other_charges),
                }

                const hasPricingComponents = Object.values(pricingComponents).some((val) => val > 0)
                const isRental = (
                  item.custom_is_rental ||
                  item.is_rental ||
                  item.custom_rental_type ||
                  item.rental_type ||
                  item.custom_rental_duration ||
                  item.rental_duration ||
                  hasPricingComponents
                )
                const totalRentalCost = parseNumber(
                  item.custom_total_rental_cost ??
                  rentalData?.totalCost ??
                  item.total_rental_cost ??
                  item.rate
                )
                
                return (
                  <div suppressHydrationWarning key={idx} className="border rounded-lg overflow-hidden">
                    {/* Item Header */}
                    <div suppressHydrationWarning className="bg-slate-50 dark:bg-slate-900 p-4 border-b">
                      <div suppressHydrationWarning className="flex justify-between items-start">
                        <div suppressHydrationWarning>
                          <h3 className="font-semibold text-lg">{item.item_name || item.item_code || 'N/A'}</h3>
                          <p className="text-sm text-slate-500 mt-1">{item.description || 'No description'}</p>
                        </div>
                        {isRental && (
                          <Badge className="bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200">
                            Rental
                          </Badge>
                        )}
                      </div>
                    </div>

                    {/* Standard Item Details */}
                    <div suppressHydrationWarning className="p-4 grid grid-cols-4 gap-4">
                      <div suppressHydrationWarning>
                        <p className="text-xs text-slate-500">Item Code</p>
                        <p className="font-medium">{item.item_code || 'N/A'}</p>
                      </div>
                      <div suppressHydrationWarning>
                        <p className="text-xs text-slate-500">Quantity</p>
                        <p className="font-medium">{item.qty || 0}</p>
                      </div>
                      <div suppressHydrationWarning>
                        <p className="text-xs text-slate-500">Rate</p>
                        <p className="font-medium">Γé╣{(item.rate || 0).toLocaleString('en-IN')}</p>
                      </div>
                      <div suppressHydrationWarning>
                        <p className="text-xs text-slate-500">Amount</p>
                        <p className="font-medium text-lg">Γé╣{(item.amount || 0).toLocaleString('en-IN')}</p>
                      </div>
                    </div>

                    {/* Rental Details */}
                    {isRental && (
                      <div suppressHydrationWarning className="border-t bg-gradient-to-br from-slate-50 to-blue-50/30 dark:from-slate-900/80 dark:to-blue-950/30 p-6">
                        <h4 className="font-semibold text-base mb-4 flex items-center gap-2 text-slate-800 dark:text-slate-200">
                          <Clock className="h-5 w-5 text-blue-600" />
                          Rental Details
                        </h4>
                        <div suppressHydrationWarning className="grid grid-cols-1 md:grid-cols-4 gap-6">
                          <div suppressHydrationWarning className="bg-white/60 dark:bg-slate-900/60 rounded-lg p-4 border border-slate-200 dark:border-slate-700">
                            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-2">Rental Type</p>
                            <Badge className="bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200">
                              {(() => {
                                const rentalType = item.custom_rental_type || item.rental_type || 'N/A'
                                if (typeof rentalType === 'string' && rentalType.length > 0 && !rentalType.includes('\n')) {
                                  return rentalType.charAt(0).toUpperCase() + rentalType.slice(1)
                                }
                                return 'N/A'
                              })()}
                            </Badge>
                          </div>
                          <div suppressHydrationWarning className="bg-white/60 dark:bg-slate-900/60 rounded-lg p-4 border border-slate-200 dark:border-slate-700">
                            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-2">Duration</p>
                            <p className="text-lg font-semibold text-slate-900 dark:text-white">
                              {item.custom_rental_duration || item.rental_duration || '0'}{' '}
                              <span className="text-sm font-normal text-slate-600 dark:text-slate-400">
                                {(() => {
                                  const rentalType = item.custom_rental_type || item.rental_type || ''
                                  if (typeof rentalType === 'string' && rentalType.length > 0 && !rentalType.includes('\n')) {
                                    return rentalType.charAt(0).toUpperCase() + rentalType.slice(1)
                                  }
                                  return ''
                                })()}
                              </span>
                            </p>
                          </div>
                          <div suppressHydrationWarning className="bg-white/60 dark:bg-slate-900/60 rounded-lg p-4 border border-slate-200 dark:border-slate-700">
                            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-2">Start Date</p>
                            <p className="font-semibold text-slate-900 dark:text-white">
                              {item.custom_rental_start_date || item.rental_start_date ? 
                                new Date(item.custom_rental_start_date || item.rental_start_date).toLocaleDateString('en-IN', { 
                                  day: '2-digit', 
                                  month: 'short', 
                                  year: 'numeric' 
                                }) : 
                                'N/A'}
                            </p>
                            {(item.custom_rental_start_time || item.rental_start_time) && (
                              <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">
                                {(item.custom_rental_start_time || item.rental_start_time).substring(0, 5)}
                              </p>
                            )}
                          </div>
                          <div suppressHydrationWarning className="bg-white/60 dark:bg-slate-900/60 rounded-lg p-4 border border-slate-200 dark:border-slate-700">
                            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-2">End Date</p>
                            <p className="font-semibold text-slate-900 dark:text-white">
                              {item.custom_rental_end_date || item.rental_end_date ? 
                                new Date(item.custom_rental_end_date || item.rental_end_date).toLocaleDateString('en-IN', { 
                                  day: '2-digit', 
                                  month: 'short', 
                                  year: 'numeric' 
                                }) : 
                                'N/A'}
                            </p>
                            {(item.custom_rental_end_time || item.rental_end_time) && (
                              <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">
                                {(item.custom_rental_end_time || item.rental_end_time).substring(0, 5)}
                              </p>
                            )}
                          </div>
                        </div>

                        {(item.custom_operator_included || item.operator_included) && (
                          <div className="mt-4 bg-white/60 dark:bg-slate-900/60 rounded-lg p-4 border border-green-200 dark:border-green-800 flex items-center gap-3">
                            <User className="h-5 w-5 text-green-600" />
                            <div>
                              <p className="text-sm font-semibold text-slate-900 dark:text-white">Operator Included</p>
                              {(item.custom_operator_name || item.operator_name) && (
                                <p className="text-xs text-slate-600 dark:text-slate-400">Assigned: {item.custom_operator_name || item.operator_name}</p>
                              )}
                            </div>
                          </div>
                        )}

                        {/* Rental Cost Breakdown - Always show for rental items */}
                        <div suppressHydrationWarning className="mt-6">
                          <RentalPricingBreakdown 
                            item={{
                              pricing_components: pricingComponents,
                              rental_type: item.custom_rental_type || item.rental_type,
                              rental_duration: item.custom_rental_duration || item.rental_duration,
                              rental_start_date: item.custom_rental_start_date || item.rental_start_date,
                              rental_end_date: item.custom_rental_end_date || item.rental_end_date,
                              rental_start_time: item.custom_rental_start_time || item.rental_start_time,
                              rental_end_time: item.custom_rental_end_time || item.rental_end_time,
                              requires_operator: item.custom_requires_operator || item.requires_operator,
                              operator_included: item.custom_operator_included || item.operator_included,
                              operator_name: item.custom_operator_name || item.operator_name,
                              total_rental_cost: totalRentalCost,
                            } as any}
                          />
                        </div>
                      </div>
                    )}
                  </div>
                )
              })}

              {/* Totals */}
              <div suppressHydrationWarning className="border rounded-lg bg-slate-50 dark:bg-slate-900 p-4">
                <div suppressHydrationWarning className="flex justify-end gap-12">
                  <div suppressHydrationWarning className="space-y-2 text-sm">
                    <div suppressHydrationWarning className="flex justify-between gap-8">
                      <span className="text-slate-500">Net Total:</span>
                      <span className="font-medium">Γé╣{(quotation.net_total || 0).toLocaleString('en-IN')}</span>
                    </div>
                    {(quotation.total_taxes_and_charges || 0) > 0 && (
                      <div suppressHydrationWarning className="flex justify-between gap-8">
                        <span className="text-slate-500">Taxes:</span>
                        <span className="font-medium">Γé╣{(quotation.total_taxes_and_charges || 0).toLocaleString('en-IN')}</span>
                      </div>
                    )}
                    <div suppressHydrationWarning className="flex justify-between gap-8 text-lg font-bold border-t pt-2">
                      <span>Grand Total:</span>
                      <span className="text-slate-900 dark:text-white">Γé╣{(quotation.grand_total || 0).toLocaleString('en-IN')}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="text-center py-12 text-slate-500">
              <FileText className="h-12 w-12 mx-auto mb-4 text-slate-300" />
              <p>No items added to this quotation.</p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Terms and Conditions */}
      {quotation.terms && (
        <Card>
          <CardHeader>
            <CardTitle>Terms and Conditions</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-slate-700 dark:text-slate-300 whitespace-pre-wrap">
              {quotation.terms}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Linked Opportunity */}
      {quotation.opportunity && (
        <Card>
          <CardHeader>
            <CardTitle>Linked Documents</CardTitle>
          </CardHeader>
          <CardContent>
            <Link 
              href={`/crm/opportunities/${encodeURIComponent(quotation.opportunity)}`}
              className="text-blue-600 hover:underline flex items-center gap-2"
            >
              <FileText className="h-4 w-4" />
              View Opportunity: {quotation.opportunity}
            </Link>
          </CardContent>
        </Card>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Plus, Trash2, Loader2, ArrowLeft, Calendar as CalendarIcon, Building2, Package, Wrench } from "lucide-react"
import { useRouter, useSearchParams } from "next/navigation"
import Link from "next/link"
import { ItemSearch } from "@/components/invoices/item-search"
import { getTaxTemplates, getTaxTemplate } from "@/app/actions/settings"
import { getCompanyDetails, getBankDetails, getQuotation } from "@/app/actions/crm"
import { getItemGroups } from "@/app/actions/invoices"
import { PricingRulesIndicator } from "@/components/pricing-rules/pricing-rules-indicator"
import { AppliedRulesSummary } from "@/components/pricing-rules/applied-rules-summary"
import { applyPricingRules } from "@/app/actions/apply-pricing-rules"
import { RentalPricingForm } from "@/components/crm/rental-pricing-form"
import { RentalPricingBreakdown } from "@/components/crm/rental-pricing-breakdown"
import { RentalItem, RentalPricingComponents, calculateTotalRentalCost, calculateRentalDuration } from "@/types/rental-pricing"

interface QuotationItem {
  id: number
  item_code: string
  item_name: string
  description: string
  item_category?: string

  // Standard pricing
  qty: number
  rate: number
  discount_percentage?: number
  amount: number

  // Rental pricing fields
  is_rental?: boolean
  rental_type?: 'hours' | 'days' | 'months'
  rental_duration?: number
  rental_start_date?: string
  rental_end_date?: string
  rental_start_time?: string
  rental_end_time?: string
  requires_operator?: boolean
  operator_included?: boolean
  operator_name?: string
  pricing_components?: RentalPricingComponents
  total_rental_cost?: number
}

export default function NewQuotationPage() {
  const [loading, setLoading] = useState(false)
  const [prefilling, setPrefilling] = useState(false)
  const router = useRouter()
  const searchParams = useSearchParams()
  const opportunityId = searchParams.get('opportunity')
  const fromQuotationName = searchParams.get('from')

  // Category filter state
  const [itemGroups, setItemGroups] = useState<string[]>([])
  const [selectedItemGroup, setSelectedItemGroup] = useState<string>('All')

  // Pricing rules state
  const [appliedPricingRules, setAppliedPricingRules] = useState<any[]>([])

  // Rental mode state
  const [isRentalMode, setIsRentalMode] = useState(false)
  const [expandedItemId, setExpandedItemId] = useState<number | null>(null)

  // Header Fields
  const [quotationTo, setQuotationTo] = useState("Customer") // Customer or Lead
  const [partyName, setPartyName] = useState("")
  const [transactionDate, setTransactionDate] = useState("")
  const [validTill, setValidTill] = useState("")
  const [currency, setCurrency] = useState("INR")
  const [orderType, setOrderType] = useState("Sales") // Sales, Maintenance, etc.
  const [opportunityReference, setOpportunityReference] = useState("")

  // Set dates on client side to avoid hydration mismatch
  useEffect(() => {
    if (!transactionDate) {
      setTransactionDate(new Date().toISOString().split('T')[0])
    }
    if (!validTill) {
      const date = new Date()
      date.setDate(date.getDate() + 30)
      setValidTill(date.toISOString().split('T')[0])
    }
  }, [])

  // Items State
  const [items, setItems] = useState<QuotationItem[]>([
    {
      id: 1,
      item_code: "",
      item_name: "",
      description: "",
      qty: 1,
      rate: 0,
      amount: 0,
      is_rental: false
    }
  ])

  // Additional Fields
  const [paymentTermsTemplate, setPaymentTermsTemplate] = useState("")
  const [termsAndConditions, setTermsAndConditions] = useState("")
  const [taxTemplate, setTaxTemplate] = useState("")
  const [availableTaxTemplates, setAvailableTaxTemplates] = useState<Array<{ name: string, title: string }>>([])
  const [selectedTaxTemplateDetails, setSelectedTaxTemplateDetails] = useState<any>(null)

  // Company and Bank Info (for display only)
  const [companyInfo, setCompanyInfo] = useState<{ name: string, gstin: string } | null>(null)
  const [bankInfo, setBankInfo] = useState<{ bank: string, bank_account_no: string, branch_code: string } | null>(null)

  // Fetch tax templates, company details, and bank details on mount
  useEffect(() => {
    getTaxTemplates().then(templates => {
      setAvailableTaxTemplates(templates)
    })

    getCompanyDetails().then(data => {
      if (data) setCompanyInfo(data)
    })

    getBankDetails().then(data => {
      if (data) setBankInfo(data)
    })

    getItemGroups().then(groups => {
      setItemGroups(['All', ...groups])
    })
  }, [])

  // Fetch selected tax template details when template changes
  useEffect(() => {
    if (taxTemplate && taxTemplate !== 'none') {
      getTaxTemplate(taxTemplate).then(details => {
        setSelectedTaxTemplateDetails(details)
      })
    } else {
      setSelectedTaxTemplateDetails(null)
    }
  }, [taxTemplate])

  // Prefill from quotation if 'from' parameter provided
  useEffect(() => {
    if (fromQuotationName) {
      setPrefilling(true)
      getQuotation(fromQuotationName)
        .then(quotation => {
          if (quotation) {
            // Set party info
            setQuotationTo(quotation.quotation_to || 'Customer')
            setPartyName(quotation.party_name || quotation.customer_name || '')
            setCurrency(quotation.currency || 'INR')

            // Set dates
            if (quotation.transaction_date) {
              setTransactionDate(quotation.transaction_date)
            }
            if (quotation.valid_till) {
              setValidTill(quotation.valid_till)
            }

            // Set items if available
            if (quotation.items && quotation.items.length > 0) {
              const prefillItems = quotation.items.map((item: any, index: number) => ({
                id: index + 1,
                item_code: item.item_code || '',
                item_name: item.item_name || item.item_code || '',
                description: item.description || item.item_name || '',
                qty: item.qty || 1,
                rate: item.rate || 0,
                amount: item.amount || (item.qty || 1) * (item.rate || 0),
                is_rental: item.is_rental || false
              }))
              setItems(prefillItems)
            }
          }
        })
        .catch(error => {
          console.error('Error fetching quotation:', error)
          alert('Failed to load quotation details')
        })
        .finally(() => setPrefilling(false))
    }
  }, [fromQuotationName])

  // Prefill from opportunity if provided
  useEffect(() => {
    if (opportunityId) {
      setPrefilling(true)
      fetch(`/api/opportunities/${encodeURIComponent(opportunityId)}`)
        .then(res => res.json())
        .then(data => {
          if (data.opportunity) {
            const opp = data.opportunity

            // Set party info
            setQuotationTo(opp.opportunity_from === 'Customer' ? 'Customer' : 'Lead')
            setPartyName(opp.party_name || '')
            setCurrency(opp.currency || 'INR')
            setOpportunityReference(opp.name)

            // Set items if available
            if (opp.items && opp.items.length > 0) {
              const prefillItems = opp.items.map((item: any, index: number) => ({
                id: index + 1,
                item_code: item.item_code || '',
                item_name: item.item_name || item.item_code || '',
                description: item.description || item.item_name || '',
                qty: item.qty || 1,
                rate: item.rate || 0,
                amount: (item.qty || 1) * (item.rate || 0)
              }))
              setItems(prefillItems)
            }
          }
        })
        .catch(error => {
          console.error('Error fetching opportunity:', error)
          alert('Failed to load opportunity details')
        })
        .finally(() => setPrefilling(false))
    }
  }, [opportunityId])

  // Calculations
  const calculateRowAmount = (qty: number, rate: number, discount?: number) => {
    const disc = discount || 0
    return qty * rate * (1 - disc / 100)
  }

  const updateItem = (id: number, field: keyof QuotationItem, value: any) => {
    setItems(items.map(item => {
      if (item.id === id) {
        const updatedItem = { ...item, [field]: value }
        if (field === 'qty' || field === 'rate' || field === 'discount_percentage') {
          updatedItem.amount = calculateRowAmount(updatedItem.qty, updatedItem.rate, updatedItem.discount_percentage)
        }
        return updatedItem
      }
      return item
    }))
  }

  // Auto-apply pricing rules when items, customer, or rates change
  const lastAppliedKey = useRef('')
  useEffect(() => {
    const itemsKey = items.map(i => `${i.item_code}-${i.qty}-${i.rate}`).join(',')
    const fullKey = `${partyName}|${transactionDate}|${itemsKey}`

    // Prevent infinite loops ΓÇö skip if we just applied rules and nothing changed
    if (fullKey === lastAppliedKey.current) return

    const applyRules = async () => {
      if (!transactionDate || items.length === 0 || !items.some(i => i.item_code && i.rate > 0)) {
        setAppliedPricingRules([])
        return
      }

      try {
        const result = await applyPricingRules({
          customer: quotationTo === 'Customer' ? partyName : undefined,
          transaction_date: transactionDate,
          items: items
            .filter(item => item.item_code)
            .map(item => ({
              item_code: item.item_code,
              qty: item.qty,
              rate: item.rate,
            })),
        })

        if (result.applied_rules.length > 0) {
          // Update items with discount percentage (keep original rate)
          const updatedItems = items.map(item => {
            const ruleItem = result.items.find(ri => ri.item_code === item.item_code)
            if (ruleItem && ruleItem.pricing_rule) {
              const disc = ruleItem.discount_percentage || 0
              return {
                ...item,
                discount_percentage: disc,
                amount: calculateRowAmount(item.qty, item.rate, disc),
              }
            }
            // Clear discount if no rule matches
            if (item.discount_percentage) {
              return { ...item, discount_percentage: 0, amount: calculateRowAmount(item.qty, item.rate, 0) }
            }
            return item
          })

          // Set the key BEFORE updating items to prevent re-trigger
          const newItemsKey = updatedItems.map(i => `${i.item_code}-${i.qty}-${i.rate}`).join(',')
          lastAppliedKey.current = `${partyName}|${transactionDate}|${newItemsKey}`
          setItems(updatedItems)

          // Track applied rules for display
          const appliedRulesDisplay = result.applied_rules.map(rule => {
            const ruleItem = result.items.find(ri => ri.pricing_rule === rule.rule_name)
            const item = items.find(i => i.item_code === ruleItem?.item_code)
            const originalRate = item?.rate || 0
            const finalRate = ruleItem?.rate || originalRate
            return {
              rule_name: rule.rule_name,
              rule_title: rule.rule_title || rule.rule_name,
              item_code: item?.item_code || '',
              item_name: item?.item_name || '',
              original_rate: originalRate,
              final_rate: finalRate,
              discount_percentage: rule.discount_percentage,
              discount_amount: rule.discount_amount,
              savings: (originalRate - finalRate) * (item?.qty || 1),
            }
          })
          setAppliedPricingRules(appliedRulesDisplay)
        } else {
          setAppliedPricingRules([])
        }
      } catch (error) {
        console.error('Failed to apply pricing rules:', error)
      }
    }

    // Debounce to avoid firing on every keystroke
    const timer = setTimeout(applyRules, 500)
    return () => clearTimeout(timer)
  }, [partyName, transactionDate, items.map(i => `${i.item_code}-${i.qty}-${i.rate}`).join(',')])

  const addItem = () => {
    const newId = Math.max(...items.map(i => i.id), 0) + 1
    setItems([...items, {
      id: newId,
      item_code: "",
      item_name: "",
      description: "",
      qty: 1,
      rate: 0,
      amount: 0,
      is_rental: false
    }])
  }

  const removeItem = (id: number) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id))
    }
  }

  // Totals
  const netTotal = items.reduce((sum, item) => sum + item.amount, 0)

  // Calculate taxes dynamically based on selected template
  const totalTaxes = selectedTaxTemplateDetails?.taxes?.reduce((sum: number, tax: any) => {
    return sum + (netTotal * (tax.rate || 0) / 100)
  }, 0) || 0

  const grandTotal = netTotal + totalTaxes

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!partyName) {
      alert(`Please select a ${quotationTo.toLowerCase()}`)
      return
    }

    if (!transactionDate || !validTill) {
      alert('Please ensure transaction date and valid till date are filled')
      return
    }

    // Validate items - require item_code to be selected from the dropdown
    const invalidItems = items.filter(item => {
      const hasItemCode = item.item_code && item.item_code.trim() !== ''
      const hasValidQty = item.qty > 0

      // Item must have a valid item_code (selected from dropdown) and valid quantity
      return !hasItemCode || !hasValidQty
    })

    if (invalidItems.length > 0) {
      console.log('Invalid items:', invalidItems)
      alert('Please select an item from the dropdown for each row, and ensure quantity is greater than 0 for all items')
      return
    }

    setLoading(true)

    try {
      const quotationData: any = {
        quotation_to: quotationTo,
        party_name: partyName,
        transaction_date: transactionDate,
        valid_till: validTill,
        currency: currency,
        order_type: orderType,
        items: items.map(item => {
          const baseItem: any = {
            item_code: item.item_code || undefined,
            item_name: item.item_name || item.description || item.item_code || 'Miscellaneous',
            description: item.description || item.item_name || item.item_code,
            qty: item.qty,
            rate: item.rate,
            discount_percentage: item.discount_percentage || 0,
            amount: item.amount
          }

          // Add rental fields if this is a rental item
          if (item.is_rental) {
            baseItem.is_rental = true
            baseItem.rental_type = item.rental_type
            baseItem.rental_duration = item.rental_duration
            baseItem.rental_start_date = item.rental_start_date
            baseItem.rental_end_date = item.rental_end_date
            if (item.rental_start_time) baseItem.rental_start_time = item.rental_start_time
            if (item.rental_end_time) baseItem.rental_end_time = item.rental_end_time
            baseItem.requires_operator = item.requires_operator
            baseItem.operator_included = item.operator_included
            if (item.operator_name) baseItem.operator_name = item.operator_name
            baseItem.pricing_components = item.pricing_components
            baseItem.total_rental_cost = item.total_rental_cost
          }

          return baseItem
        })
      }

      // Only add optional fields if they have values
      if (opportunityReference && opportunityReference.trim() !== '') {
        quotationData.opportunity = opportunityReference
      }

      if (paymentTermsTemplate && paymentTermsTemplate.trim() !== '') {
        quotationData.payment_terms_template = paymentTermsTemplate
      }

      if (termsAndConditions && termsAndConditions.trim() !== '') {
        quotationData.terms = termsAndConditions
      }

      if (taxTemplate && taxTemplate.trim() !== '' && taxTemplate !== 'none') {
        quotationData.taxes_and_charges = taxTemplate
      }

      console.log('Submitting quotation data:', quotationData)

      // Log rental items specifically
      const rentalItems = quotationData.items.filter((i: any) => i.is_rental)
      if (rentalItems.length > 0) {
        console.log('Rental items being submitted:', JSON.stringify(rentalItems, null, 2))
      }

      const response = await fetch('/api/quotations/create-new', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(quotationData)
      })

      if (!response.ok) {
        const error = await response.json()
        const errorMessage = typeof error === 'string' ? error : (error.error || error.message || 'Failed to create quotation')

        // Provide helpful error messages
        if (errorMessage.includes('Could not find Party')) {
          alert(`The ${quotationTo} "${partyName}" does not exist in ERPNext. Please create this ${quotationTo} first, or select a different party.`)
        } else if (errorMessage.includes('Payment Terms Template')) {
          alert('Invalid payment terms template. Please clear this field or enter a valid template name.')
        } else {
          alert(errorMessage)
        }

        throw new Error(errorMessage)
      }

      const result = await response.json()

      if (result.quotation?.name) {
        router.push(`/crm/quotations/${encodeURIComponent(result.quotation.name)}`)
      } else {
        router.push('/crm/quotations')
      }
    } catch (error: any) {
      console.error('Error creating quotation:', error)
      const errorMsg = typeof error === 'string' ? error : (error.message || 'Failed to create quotation')
      alert(errorMsg)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div suppressHydrationWarning className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 p-8">
      <div suppressHydrationWarning className="max-w-6xl mx-auto">
        {/* Header */}
        <div suppressHydrationWarning className="mb-6">
          <Link href="/crm/quotations">
            <Button variant="ghost" className="gap-2 pl-0 hover:bg-transparent hover:text-blue-600 mb-4">
              <ArrowLeft className="h-4 w-4" /> Back to Quotations
            </Button>
          </Link>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
            {opportunityId ? 'Create Quotation from Opportunity' : 'Create New Quotation'}
          </h1>
          <p className="text-slate-500 mt-1">
            {opportunityId
              ? `Creating quotation for opportunity ${opportunityId}`
              : 'Fill in the details below to create a new quotation'}
          </p>
        </div>

        {prefilling && (
          <Card className="mb-6 bg-blue-50 dark:bg-blue-950 border-blue-200 dark:border-blue-800">
            <CardContent className="py-4">
              <div className="flex items-center gap-2 text-blue-700 dark:text-blue-300">
                <Loader2 className="h-4 w-4 animate-spin" />
                <span>Loading opportunity details...</span>
              </div>
            </CardContent>
          </Card>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Customer/Lead Information */}
          <Card>
            <CardHeader>
              <CardTitle>Customer / Lead Information</CardTitle>
            </CardHeader>
            <CardContent className="grid md:grid-cols-2 gap-4">
              <div suppressHydrationWarning className="grid gap-2">
                <Label htmlFor="quotationTo">Quotation To *</Label>
                <Select value={quotationTo} onValueChange={setQuotationTo} disabled={!!opportunityId}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Customer">Customer</SelectItem>
                    <SelectItem value="Lead">Lead</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div suppressHydrationWarning className="grid gap-2">
                <Label htmlFor="partyName">{quotationTo} Name *</Label>
                <Input
                  id="partyName"
                  value={partyName}
                  onChange={(e) => setPartyName(e.target.value)}
                  placeholder={`Enter ${quotationTo.toLowerCase()} name`}
                  disabled={!!opportunityId}
                  required
                />
              </div>

              <div suppressHydrationWarning className="grid gap-2">
                <Label htmlFor="transactionDate">Transaction Date *</Label>
                <Input
                  id="transactionDate"
                  type="date"
                  value={transactionDate}
                  onChange={(e) => setTransactionDate(e.target.value)}
                  required
                />
              </div>

              <div suppressHydrationWarning className="grid gap-2">
                <Label htmlFor="validTill">Valid Till *</Label>
                <Input
                  id="validTill"
                  type="date"
                  value={validTill}
                  onChange={(e) => setValidTill(e.target.value)}
                  required
                />
              </div>

              <div suppressHydrationWarning className="grid gap-2">
                <Label htmlFor="orderType">Order Type</Label>
                <Select value={orderType} onValueChange={setOrderType}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Sales">Sales</SelectItem>
                    <SelectItem value="Maintenance">Maintenance</SelectItem>
                    <SelectItem value="Shopping Cart">Shopping Cart</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div suppressHydrationWarning className="grid gap-2">
                <Label htmlFor="currency">Currency</Label>
                <Select value={currency} onValueChange={setCurrency}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="INR">INR (Γé╣)</SelectItem>
                    <SelectItem value="USD">USD ($)</SelectItem>
                    <SelectItem value="EUR">EUR (Γé¼)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Pricing Rules Indicator */}
          {transactionDate && (
            <PricingRulesIndicator
              customer={quotationTo === "Customer" ? partyName : undefined}
              transactionDate={transactionDate}
              itemGroups={items.map(item => item.item_code).filter(Boolean)}
            />
          )}

          {/* Applied Pricing Rules Summary */}
          {appliedPricingRules.length > 0 && (
            <AppliedRulesSummary appliedRules={appliedPricingRules} />
          )}

          {/* Items */}
          <Card>
            <CardHeader>
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div className="flex items-center gap-3">
                  <CardTitle>Items</CardTitle>
                  <Button
                    type="button"
                    variant={isRentalMode ? "default" : "outline"}
                    size="sm"
                    onClick={() => setIsRentalMode(!isRentalMode)}
                    className="gap-2"
                  >
                    {isRentalMode ? (
                      <>
                        <Wrench className="h-4 w-4" />
                        Rental Mode
                      </>
                    ) : (
                      <>
                        <Package className="h-4 w-4" />
                        Standard Mode
                      </>
                    )}
                  </Button>
                </div>
                <div className="flex items-center gap-4">
                  <Label htmlFor="category-filter" className="text-sm font-normal whitespace-nowrap">Filter by Category:</Label>
                  <Select value={selectedItemGroup} onValueChange={setSelectedItemGroup}>
                    <SelectTrigger className="w-[200px] h-9">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="All">All Categories</SelectItem>
                      {itemGroups.filter(g => g !== 'All').map(group => (
                        <SelectItem key={group} value={group}>{group}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <Button type="button" onClick={addItem} size="sm" className="gap-2">
                    <Plus className="h-4 w-4" /> Add Item
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div suppressHydrationWarning className="border-t">
                {/* Header Row */}
                <div suppressHydrationWarning className="grid grid-cols-12 gap-2 bg-slate-50 dark:bg-slate-900 px-4 py-3 text-xs font-medium text-slate-500 border-b">
                  <div suppressHydrationWarning className="col-span-1 text-center">#</div>
                  <div suppressHydrationWarning className="col-span-3">Item / Description</div>
                  <div suppressHydrationWarning className="col-span-1 text-right">Qty *</div>
                  <div suppressHydrationWarning className="col-span-2 text-right">Rate *</div>
                  <div suppressHydrationWarning className="col-span-1 text-right">Disc %</div>
                  <div suppressHydrationWarning className="col-span-2 text-right">Amount</div>
                  <div suppressHydrationWarning className="col-span-2"></div>
                </div>

                {/* Item Rows */}
                <div suppressHydrationWarning className="divide-y">
                  {items.map((item, index) => (
                    <div key={item.id} className="space-y-3">
                      {/* Main Item Row */}
                      <div className="grid grid-cols-12 gap-2 px-4 py-2 items-start hover:bg-slate-50/50 dark:hover:bg-slate-900/50 group">
                        <div className="col-span-1 pt-2 text-center text-sm text-slate-400">
                          <span className="group-hover:hidden">{index + 1}</span>
                          <Trash2
                            className="h-4 w-4 mx-auto hidden group-hover:block text-red-500 cursor-pointer"
                            onClick={() => removeItem(item.id)}
                          />
                        </div>
                        <div className="col-span-3 space-y-1">
                          <div className="h-8">
                            <ItemSearch
                              value={item.item_code}
                              onChange={(code, desc, itemName) => {
                                setItems(prev => prev.map(i =>
                                  i.id === item.id
                                    ? { ...i, item_code: code, item_name: itemName || code, description: desc || i.description }
                                    : i
                                ))
                              }}
                              itemGroup={selectedItemGroup === 'All' ? undefined : selectedItemGroup}
                            />
                          </div>
                          <Input
                            placeholder="Description"
                            value={item.description}
                            onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                            className="h-7 text-xs text-muted-foreground border-dashed border-slate-200 dark:border-slate-800 bg-transparent"
                          />
                        </div>
                        <div className="col-span-1">
                          <Input
                            type="number"
                            min="0.01"
                            step="0.01"
                            value={item.qty}
                            onChange={(e) => updateItem(item.id, 'qty', parseFloat(e.target.value) || 0)}
                            className="h-8 text-sm text-right"
                            disabled={isRentalMode && item.is_rental}
                            required
                          />
                        </div>
                        <div className="col-span-2">
                          <Input
                            type="number"
                            min="0"
                            step="0.01"
                            value={item.rate}
                            onChange={(e) => updateItem(item.id, 'rate', parseFloat(e.target.value) || 0)}
                            className="h-8 text-sm text-right"
                            disabled={isRentalMode && item.is_rental}
                            required
                          />
                        </div>
                        <div className="col-span-1">
                          {item.discount_percentage ? (
                            <div className="h-8 flex items-center justify-end">
                              <span className="text-xs font-medium text-green-600 dark:text-green-400">{item.discount_percentage}%</span>
                            </div>
                          ) : (
                            <div className="h-8" />
                          )}
                        </div>
                        <div className="col-span-2 pt-2 text-right text-sm font-medium">
                          Γé╣{item.amount.toLocaleString('en-IN')}
                        </div>
                        <div className="col-span-2 pt-1 flex items-center justify-end gap-2">
                          {isRentalMode && (
                            <Button
                              type="button"
                              variant={item.is_rental ? "default" : "outline"}
                              size="sm"
                              onClick={() => {
                                const newIsRental = !item.is_rental
                                if (newIsRental) {
                                  // Initialize rental fields - batch all updates
                                  const today = new Date().toISOString().split('T')[0]
                                  const tomorrow = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString().split('T')[0]

                                  setItems(items.map(i => {
                                    if (i.id === item.id) {
                                      return {
                                        ...i,
                                        is_rental: true,
                                        rental_type: 'days',
                                        rental_start_date: today,
                                        rental_end_date: tomorrow,
                                        rental_duration: 1,
                                        pricing_components: i.pricing_components || {
                                          base_cost: 0,
                                          accommodation_charges: 0,
                                          usage_charges: 0,
                                          fuel_charges: 0,
                                          elongation_charges: 0,
                                          risk_charges: 0,
                                          commercial_charges: 0,
                                          incidental_charges: 0,
                                          other_charges: 0
                                        },
                                        requires_operator: false,
                                        operator_included: false
                                      }
                                    }
                                    return i
                                  }))
                                  setExpandedItemId(item.id)
                                } else {
                                  setItems(items.map(i => i.id === item.id ? { ...i, is_rental: false } : i))
                                  setExpandedItemId(null)
                                }
                              }}
                              className="h-7 text-xs gap-1"
                            >
                              <Wrench className="h-3 w-3" />
                              {item.is_rental ? 'Rental' : 'Enable Rental'}
                            </Button>
                          )}
                        </div>
                      </div>

                      {/* Rental Pricing Form (Expanded) */}
                      {isRentalMode && item.is_rental && expandedItemId === item.id && (
                        <div className="px-4 pb-4">
                          <RentalPricingForm
                            item={item as Partial<RentalItem>}
                            onChange={(updates) => {
                              console.log('[QuotationPage] Received updates from RentalPricingForm:', updates)
                              const rentalUpdates: Partial<QuotationItem> = {
                                ...updates,
                                rate: updates.total_rental_cost || item.rate,
                                amount: (item.qty || 1) * (updates.total_rental_cost || item.rate)
                              }

                              // Calculate duration if dates are provided
                              if (updates.rental_start_date && updates.rental_end_date && updates.rental_type) {
                                const duration = calculateRentalDuration(
                                  updates.rental_start_date,
                                  updates.rental_end_date,
                                  updates.rental_start_time,
                                  updates.rental_end_time,
                                  updates.rental_type
                                )
                                rentalUpdates.rental_duration = duration
                              }

                              setItems(items.map(i => i.id === item.id ? { ...i, ...rentalUpdates } : i))
                            }}
                            itemCategory={item.item_category || selectedItemGroup}
                          />
                        </div>
                      )}

                      {/* Rental Breakdown Summary (Collapsed) */}
                      {isRentalMode && item.is_rental && expandedItemId !== item.id && item.total_rental_cost && item.total_rental_cost > 0 && (
                        <div className="px-4 pb-2">
                          <div className="flex items-center justify-between p-2 bg-blue-50 dark:bg-blue-950 rounded border border-blue-200 dark:border-blue-800">
                            <div className="flex items-center gap-2 text-xs text-blue-900 dark:text-blue-100">
                              <Wrench className="h-3 w-3" />
                              <span>
                                Rental: {item.rental_duration} {item.rental_type}
                                {item.operator_included && ' ΓÇó Operator Included'}
                              </span>
                            </div>
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => setExpandedItemId(item.id)}
                              className="h-6 text-xs"
                            >
                              Edit
                            </Button>
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>

                {/* Totals */}
                <div className="mt-6 border-t pt-4">
                  <div className="flex justify-end">
                    <div className="w-80 space-y-2 text-sm">
                      <div className="flex justify-between">
                        <span className="text-slate-500">Net Total:</span>
                        <span className="font-medium">Γé╣{netTotal.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                      </div>

                      {/* Dynamic tax breakdown */}
                      {selectedTaxTemplateDetails?.taxes && selectedTaxTemplateDetails.taxes.length > 0 ? (
                        <>
                          {selectedTaxTemplateDetails.taxes.map((tax: any, idx: number) => (
                            <div key={idx} className="flex justify-between text-xs">
                              <span className="text-slate-400">{tax.description || tax.account_head} ({tax.rate}%):</span>
                              <span className="font-medium">Γé╣{(netTotal * (tax.rate || 0) / 100).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                            </div>
                          ))}
                          <div className="flex justify-between">
                            <span className="text-slate-500">Total Taxes:</span>
                            <span className="font-medium">Γé╣{totalTaxes.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                          </div>
                        </>
                      ) : taxTemplate && taxTemplate !== 'none' ? (
                        <div className="flex justify-between">
                          <span className="text-slate-500">Taxes (Loading...):</span>
                          <span className="font-medium">Γé╣{totalTaxes.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                        </div>
                      ) : null}

                      <div className="flex justify-between text-lg font-bold border-t pt-2">
                        <span>Grand Total:</span>
                        <span className="text-slate-900 dark:text-white">Γé╣{grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Company & Bank Information (Read-only Display) */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Building2 className="h-5 w-5" />
                Company & Bank Information
              </CardTitle>
            </CardHeader>
            <CardContent className="grid md:grid-cols-2 gap-6">
              <div>
                <Label className="text-xs text-slate-500 uppercase tracking-wide mb-2 block">Company Details</Label>
                <div className="space-y-1 text-sm">
                  <p className="font-medium text-base">{companyInfo?.name || "Loading Company..."}</p>
                  <p className="text-xs text-slate-500">GSTIN: {companyInfo?.gstin || "Not Set"}</p>
                </div>
              </div>

              <div>
                <Label className="text-xs text-slate-500 uppercase tracking-wide mb-2 block">Bank Details</Label>
                {bankInfo ? (
                  <div className="space-y-1 text-xs">
                    <div className="flex justify-between"><span>Bank:</span> <span className="font-medium">{bankInfo.bank}</span></div>
                    <div className="flex justify-between"><span>A/C No:</span> <span className="font-medium">{bankInfo.bank_account_no}</span></div>
                    <div className="flex justify-between"><span>IFSC:</span> <span className="font-medium">{bankInfo.branch_code || "ΓÇö"}</span></div>
                  </div>
                ) : (
                  <p className="text-xs text-slate-400">Loading bank information...</p>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Additional Information */}
          <Card>
            <CardHeader>
              <CardTitle>Additional Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-2">
                <Label htmlFor="taxTemplate">Sales Taxes and Charges Template</Label>
                <Select value={taxTemplate} onValueChange={setTaxTemplate}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select a tax template (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">None</SelectItem>
                    {availableTaxTemplates.map(template => (
                      <SelectItem key={template.name} value={template.name}>
                        {template.title || template.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className="text-xs text-slate-500">
                  Select a tax template or <Link href="/settings" className="text-blue-600 hover:underline">create one in Settings</Link>
                </p>
              </div>

              <div className="grid gap-2">
                <Label htmlFor="paymentTerms">Payment Terms Template</Label>
                <Input
                  id="paymentTerms"
                  value={paymentTermsTemplate}
                  onChange={(e) => setPaymentTermsTemplate(e.target.value)}
                  placeholder="e.g., Net 30, 50% Advance"
                />
              </div>

              <div className="grid gap-2">
                <Label htmlFor="terms">Terms and Conditions</Label>
                <Textarea
                  id="terms"
                  value={termsAndConditions}
                  onChange={(e) => setTermsAndConditions(e.target.value)}
                  placeholder="Enter terms and conditions..."
                  rows={5}
                />
              </div>
            </CardContent>
          </Card>

          {/* Submit Buttons */}
          <div className="flex justify-end gap-4">
            <Link href="/crm/quotations">
              <Button type="button" variant="outline" disabled={loading}>
                Cancel
              </Button>
            </Link>
            <Button type="submit" disabled={loading} className="gap-2">
              {loading && <Loader2 className="h-4 w-4 animate-spin" />}
              {loading ? 'Creating...' : 'Create Quotation'}
            </Button>
          </div>
        </form>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Plus, Trash2, Loader2, ArrowLeft, Building2 } from "lucide-react"
import { createInvoice, getCompanyDetails, getBankDetails, getCustomerDetails } from "@/app/actions/invoices"
import { useRouter, useSearchParams } from "next/navigation"
import Link from "next/link"
import { CustomerSearch } from "@/components/invoices/customer-search"
import { ItemSearch } from "@/components/invoices/item-search"
import { getTaxTemplates, getTaxTemplate } from "@/app/actions/settings"
import { getSalesOrder } from "@/app/actions/sales-orders"

interface InvoiceItem {
  id: number
  item_code: string
  description: string
  hsn_sac: string
  qty: number
  rate: number
  amount: number
}

export default function NewInvoicePage() {
  const [loading, setLoading] = useState(false)
  const [fetchingSO, setFetchingSO] = useState(false)
  const router = useRouter()
  const searchParams = useSearchParams()
  const salesOrderParam = searchParams.get('sales_order')
  const [linkedSalesOrder, setLinkedSalesOrder] = useState('')

  // Header Fields
  const [customer, setCustomer] = useState("")
  const [date, setDate] = useState(new Date().toISOString().split('T')[0])
  const [dueDate, setDueDate] = useState("")
  const [placeOfSupply, setPlaceOfSupply] = useState("27-Maharashtra")
  const [taxTemplate, setTaxTemplate] = useState("")
  const [availableTaxTemplates, setAvailableTaxTemplates] = useState<Array<{ name: string, title: string }>>([])
  const [selectedTaxTemplateDetails, setSelectedTaxTemplateDetails] = useState<any>(null)

  // Dynamic Data State
  const [companyInfo, setCompanyInfo] = useState<{ name: string, gstin: string } | null>(null)
  const [bankInfo, setBankInfo] = useState<{ bank: string, bank_account_no: string, branch_code: string } | null>(null)
  const [customerDetails, setCustomerDetails] = useState<{ tax_id?: string, primary_address?: string } | null>(null)

  // Items State
  const [items, setItems] = useState<InvoiceItem[]>([
    { id: 1, item_code: "", description: "", hsn_sac: "997319", qty: 1, rate: 0, amount: 0 }
  ])

  // Fetch Initial Data (Company & Bank)
  useEffect(() => {
    getCompanyDetails().then(data => {
      if (data) setCompanyInfo(data)
    })

    getBankDetails().then(data => {
      if (data) setBankInfo(data)
    })

    // Fetch available tax templates
    getTaxTemplates().then(templates => {
      setAvailableTaxTemplates(templates)
    })
  }, [])

  // Prefill from Sales Order if linked
  useEffect(() => {
    if (!salesOrderParam) return
    setFetchingSO(true)
    getSalesOrder(salesOrderParam).then(so => {
      if (!so) { setFetchingSO(false); return }
      setLinkedSalesOrder(so.name)
      setCustomer(so.customer_name || so.customer || '')
      if (so.taxes_and_charges) setTaxTemplate(so.taxes_and_charges)
      if (so.items && so.items.length > 0) {
        setItems(so.items.map((item: any, idx: number) => ({
          id: idx + 1,
          item_code: item.item_code || '',
          description: item.description || item.item_name || '',
          hsn_sac: item.hsn_sac || '',
          qty: item.qty || 1,
          rate: item.rate || 0,
          amount: (item.qty || 1) * (item.rate || 0)
        })))
      }
      setFetchingSO(false)
    }).catch(() => setFetchingSO(false))
  }, [salesOrderParam])

  // Fetch selected tax template details when template changes
  useEffect(() => {
    if (taxTemplate && taxTemplate !== 'none') {
      getTaxTemplate(taxTemplate).then(details => {
        setSelectedTaxTemplateDetails(details)
      })
    } else {
      setSelectedTaxTemplateDetails(null)
    }
  }, [taxTemplate])

  // Fetch Customer Data when selected
  useEffect(() => {
    if (customer) {
      getCustomerDetails(customer).then(data => {
        if (data) setCustomerDetails(data)
      })
    } else {
      setCustomerDetails(null)
    }
  }, [customer])

  // Calculations
  const calculateRowAmount = (qty: number, rate: number) => qty * rate

  const updateItem = (id: number, field: keyof InvoiceItem, value: any) => {
    setItems(items.map(item => {
      if (item.id === id) {
        const updatedItem = { ...item, [field]: value }
        if (field === 'qty' || field === 'rate') {
          updatedItem.amount = calculateRowAmount(updatedItem.qty, updatedItem.rate)
        }
        return updatedItem
      }
      return item
    }))
  }

  const addItem = () => {
    setItems([...items, {
      id: Date.now(), item_code: "", description: "", hsn_sac: "", qty: 1, rate: 0, amount: 0
    }])
  }

  const removeItem = (id: number) => {
    if (items.length > 1) setItems(items.filter(item => item.id !== id))
  }

  // Totals Logic - Calculate dynamically based on selected template
  const subTotal = items.reduce((sum, item) => sum + (item.amount || 0), 0)

  // Calculate taxes dynamically based on selected template
  const taxAmount = selectedTaxTemplateDetails?.taxes?.reduce((sum: number, tax: any) => {
    return sum + (subTotal * (tax.rate || 0) / 100)
  }, 0) || 0

  const grandTotal = subTotal + taxAmount

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)

    const payload: any = {
      customer,
      posting_date: date,
      due_date: dueDate,
      items,
      place_of_supply: placeOfSupply
    }

    // Add company if available
    if (companyInfo?.name) {
      payload.company = companyInfo.name
    }

    // Only add tax template if selected
    if (taxTemplate && taxTemplate.trim() !== '' && taxTemplate !== 'none') {
      payload.taxes_and_charges = taxTemplate
    }

    // Link to Sales Order if creating from one
    if (linkedSalesOrder) {
      payload.items = items.map(item => ({
        ...item,
        sales_order: linkedSalesOrder
      }))
    }

    const res = await createInvoice(payload)

    if (res.success && res.name) {
      router.push(`/invoices/${res.name}`)
      router.refresh()
    } else {
      alert("Error: " + (res.error || "Unknown error"))
    }
    setLoading(false)
  }

  return (
    <div className="max-w-5xl mx-auto p-8 space-y-6">
      {/* Top Bar */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Link href="/invoices">
            <Button variant="ghost" size="icon"><ArrowLeft className="h-4 w-4" /></Button>
          </Link>
          <div>
            <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">New GST Invoice</h1>
            <p className="text-slate-500">
              {linkedSalesOrder
                ? <>Creating invoice from Sales Order <span className="font-semibold text-blue-600">{linkedSalesOrder}</span></>
                : 'Create a compliant tax invoice'
              }
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" asChild><Link href="/invoices">Cancel</Link></Button>
          <Button onClick={handleSubmit} disabled={loading} className="bg-blue-600 hover:bg-blue-700 text-white min-w-[120px]">
            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            Save Invoice
          </Button>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">

        {/* Supplier & Customer Details */}
        <div className="grid md:grid-cols-2 gap-6 items-start">
          <Card className="h-full flex flex-col">
            <CardHeader className="pb-2"><CardTitle className="text-base text-slate-500">Bill To (Customer)</CardTitle></CardHeader>
            <CardContent className="space-y-4 flex-1">
              <div className="grid gap-2">
                <Label>Customer Name <span className="text-red-500">*</span></Label>
                <CustomerSearch value={customer} onChange={setCustomer} />

                {/* Dynamic Customer Info */}
                {customerDetails ? (
                  <div className="mt-2 text-xs text-slate-500 bg-slate-50 p-3 rounded border border-slate-100 space-y-1">
                    {customerDetails.tax_id && <p><strong>GSTIN:</strong> {customerDetails.tax_id}</p>}
                    {customerDetails.primary_address ? (
                      <p className="whitespace-pre-wrap">{customerDetails.primary_address}</p>
                    ) : (
                      <p className="italic text-slate-400">No primary address found.</p>
                    )}
                  </div>
                ) : (
                  <div className="mt-2 h-16 bg-slate-50/50 rounded border border-dashed border-slate-100 flex items-center justify-center text-xs text-slate-400">
                    Customer details will appear here
                  </div>
                )}
              </div>
              <div className="grid gap-2">
                <Label>Place of Supply</Label>
                <Select value={placeOfSupply} onValueChange={setPlaceOfSupply}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="27-Maharashtra">Maharashtra (27)</SelectItem>
                    <SelectItem value="29-Karnataka">Karnataka (29)</SelectItem>
                    <SelectItem value="07-Delhi">Delhi (07)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          <Card className="h-full flex flex-col">
            <CardHeader className="pb-2"><CardTitle className="text-base text-slate-500">Invoice Details</CardTitle></CardHeader>
            <CardContent className="space-y-4 flex-1">
              <div className="grid grid-cols-2 gap-4">
                <div className="grid gap-2">
                  <Label>Invoice Date</Label>
                  <Input type="date" value={date} onChange={(e) => setDate(e.target.value)} />
                </div>
                <div className="grid gap-2">
                  <Label>Due Date</Label>
                  <Input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)} />
                </div>
              </div>

              {/* Tax Template Selection */}
              <div className="grid gap-2">
                <Label>Tax Template</Label>
                <Select value={taxTemplate} onValueChange={setTaxTemplate}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select tax template (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">None</SelectItem>
                    {availableTaxTemplates.map(template => (
                      <SelectItem key={template.name} value={template.name}>
                        {template.title}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* DYNAMIC COMPANY DETAILS */}
              <div className="p-3 bg-slate-50 dark:bg-slate-900 rounded border text-sm text-slate-600 flex-1">
                <div className="flex gap-2 items-center mb-2">
                  <Building2 className="h-4 w-4 text-slate-400" />
                  <span className="font-semibold text-slate-800 dark:text-slate-200">
                    {companyInfo?.name || "Loading Company..."}
                  </span>
                </div>
                <div className="ml-6 space-y-1">
                  <p className="text-xs text-slate-500">GSTIN: {companyInfo?.gstin || "Not Set"}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Service Details Table */}
        <Card>
          <CardHeader className="flex flex-row items-center justify-between py-4">
            <CardTitle className="text-base font-semibold">Service / Equipment Details</CardTitle>
            <Button type="button" variant="outline" size="sm" onClick={addItem}>
              <Plus className="h-4 w-4 mr-2" /> Add Item
            </Button>
          </CardHeader>
          <CardContent className="p-0">
            <div className="border-t">
              <div className="grid grid-cols-12 gap-2 bg-slate-50 dark:bg-slate-900 px-4 py-3 text-xs font-medium text-slate-500 border-b">
                <div className="col-span-1 text-center">#</div>
                <div className="col-span-4">Description / Item</div>
                <div className="col-span-2">HSN/SAC</div>
                <div className="col-span-1 text-right">Qty</div>
                <div className="col-span-2 text-right">Rate (Γé╣)</div>
                <div className="col-span-2 text-right">Amount (Γé╣)</div>
              </div>

              <div className="divide-y">
                {items.map((item, index) => (
                  <div key={item.id} className="grid grid-cols-12 gap-2 px-4 py-2 items-start hover:bg-slate-50/50 group">
                    <div className="col-span-1 pt-2 text-center text-sm text-slate-400">
                      <span className="group-hover:hidden">{index + 1}</span>
                      <Trash2 className="h-4 w-4 mx-auto hidden group-hover:block text-red-500 cursor-pointer" onClick={() => removeItem(item.id)} />
                    </div>
                    <div className="col-span-4 space-y-1">
                      {/* Using ItemSearch Component Here */}
                      <div className="h-8">
                        <ItemSearch
                          value={item.item_code}
                          onChange={(code, desc) => {
                            updateItem(item.id, 'item_code', code)
                            if (desc) updateItem(item.id, 'description', desc)
                          }}
                        />
                      </div>
                      <Input
                        placeholder="Description"
                        value={item.description}
                        onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                        className="h-7 text-xs text-muted-foreground border-dashed border-slate-200 dark:border-slate-800 bg-transparent"
                      />
                    </div>
                    <div className="col-span-2">
                      <Input value={item.hsn_sac} onChange={(e) => updateItem(item.id, 'hsn_sac', e.target.value)} className="h-8 text-sm" placeholder="997319" />
                    </div>
                    <div className="col-span-1">
                      <Input type="number" value={item.qty} onChange={(e) => updateItem(item.id, 'qty', parseFloat(e.target.value) || 0)} className="h-8 text-sm text-right" />
                    </div>
                    <div className="col-span-2">
                      <Input type="number" value={item.rate} onChange={(e) => updateItem(item.id, 'rate', parseFloat(e.target.value) || 0)} className="h-8 text-sm text-right" />
                    </div>
                    <div className="col-span-2 pt-2 text-right text-sm font-medium">
                      Γé╣ {item.amount.toLocaleString('en-IN')}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Footer: GST Calculation & Totals */}
        <div className="grid md:grid-cols-2 gap-8 items-start">
          <div className="space-y-6">
            <Card>
              <CardHeader className="pb-2"><CardTitle className="text-sm">Bank Details</CardTitle></CardHeader>
              <CardContent className="text-sm space-y-1 text-slate-600">
                {/* DYNAMIC BANK DETAILS */}
                {bankInfo ? (
                  <>
                    <div className="flex justify-between"><span>Bank:</span> <span className="font-medium">{bankInfo.bank}</span></div>
                    <div className="flex justify-between"><span>A/C No:</span> <span className="font-medium">{bankInfo.bank_account_no}</span></div>
                    <div className="flex justify-between"><span>IFSC:</span> <span className="font-medium">{bankInfo.branch_code || "ΓÇö"}</span></div>
                  </>
                ) : (
                  <div className="text-slate-400 italic">No default bank account set.</div>
                )}
              </CardContent>
            </Card>
            <div className="text-xs text-slate-400 px-2">
              Declaration: We declare that this invoice shows the actual price of the goods described and all particulars are true and correct.
            </div>
          </div>

          <Card className="bg-slate-50/50 dark:bg-slate-900/50">
            <CardContent className="p-6 space-y-3">
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Subtotal</span>
                <span>Γé╣ {subTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
              </div>

              {/* Dynamic tax breakdown */}
              {selectedTaxTemplateDetails?.taxes && selectedTaxTemplateDetails.taxes.length > 0 ? (
                <>
                  {selectedTaxTemplateDetails.taxes.map((tax: any, idx: number) => (
                    <div key={idx} className="flex justify-between text-xs">
                      <span className="text-slate-400">{tax.description || tax.account_head} ({tax.rate}%)</span>
                      <span>Γé╣ {(subTotal * (tax.rate || 0) / 100).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                    </div>
                  ))}
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Total Tax</span>
                    <span>Γé╣ {taxAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                  </div>
                </>
              ) : taxTemplate && taxTemplate !== 'none' ? (
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Tax (Loading...)</span>
                  <span>Γé╣ {taxAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
              ) : null}

              <div className="flex justify-between items-center border-t pt-3 mt-2">
                <span className="font-bold text-lg">Grand Total</span>
                <span className="font-bold text-xl">Γé╣ {grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
              </div>
              <div className="text-right text-xs text-slate-400 pt-1">
                Amount in Words: (Auto-generated on save)
              </div>
            </CardContent>
          </Card>
        </div>

      </form>
    </div>
  )
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ArrowLeft, Percent, DollarSign, Calculator, Trash2, Loader2 } from "lucide-react";
import Link from "next/link";
import { getPricingRule, updatePricingRule, deletePricingRule, getCustomerGroups, getTerritories, getItemGroups } from "@/app/actions/pricing-rules";

export default function EditPricingRulePage({ params }: { params: Promise<{ name: string }> }) {
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [ruleName, setRuleName] = useState("");
  const [itemGroups, setItemGroups] = useState<string[]>([]);
  const [customerGroups, setCustomerGroups] = useState<string[]>([]);
  const [territories, setTerritories] = useState<string[]>([]);

  // Form state
  const [title, setTitle] = useState("");
  const [applyOn, setApplyOn] = useState("Item Group");
  const [itemGroup, setItemGroup] = useState("");
  const [rateOrDiscount, setRateOrDiscount] = useState("Discount Percentage");
  const [discountPercentage, setDiscountPercentage] = useState("");
  const [discountAmount, setDiscountAmount] = useState("");
  const [rate, setRate] = useState("");
  const [customerGroup, setCustomerGroup] = useState("");
  const [territory, setTerritory] = useState("");
  const [validFrom, setValidFrom] = useState("");
  const [validUpto, setValidUpto] = useState("");
  const [minQty, setMinQty] = useState("");
  const [maxQty, setMaxQty] = useState("");
  const [priority, setPriority] = useState("");

  useEffect(() => {
    async function loadData() {
      const { name } = await params;
      setRuleName(decodeURIComponent(name));
      
      try {
        const [rule, groups, custGroups, terr] = await Promise.all([
          getPricingRule(decodeURIComponent(name)),
          getItemGroups(),
          getCustomerGroups(),
          getTerritories(),
        ]);

        if (rule) {
          setTitle(rule.title);
          setApplyOn(rule.apply_on);
          // Extract item group from child table if exists
          setItemGroup(rule.item_groups && rule.item_groups.length > 0 ? rule.item_groups[0].item_group : "");
          setRateOrDiscount(rule.rate_or_discount);
          setDiscountPercentage(rule.discount_percentage?.toString() || "");
          setDiscountAmount(rule.discount_amount?.toString() || "");
          setRate(rule.rate?.toString() || "");
          setCustomerGroup(rule.customer_group || "");
          setTerritory(rule.territory || "");
          setValidFrom(rule.valid_from || "");
          setValidUpto(rule.valid_upto || "");
          setMinQty(rule.min_qty?.toString() || "");
          setMaxQty(rule.max_qty?.toString() || "");
          setPriority(rule.priority?.toString() || "");
        }

        setItemGroups(groups);
        setCustomerGroups(custGroups);
        setTerritories(terr);
      } catch (error) {
        console.error("Failed to load pricing rule:", error);
        alert("Failed to load pricing rule details");
      } finally {
        setLoading(false);
      }
    }

    loadData();
  }, [params]);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("rate_or_discount", rateOrDiscount);
      if (discountPercentage) formData.append("discount_percentage", discountPercentage);
      if (discountAmount) formData.append("discount_amount", discountAmount);
      if (rate) formData.append("rate", rate);
      if (customerGroup) formData.append("customer_group", customerGroup);
      if (territory) formData.append("territory", territory);
      if (validFrom) formData.append("valid_from", validFrom);
      if (validUpto) formData.append("valid_upto", validUpto);
      if (minQty) formData.append("min_qty", minQty);
      if (maxQty) formData.append("max_qty", maxQty);
      if (priority) formData.append("priority", priority);

      await updatePricingRule(ruleName, formData);
      router.push("/pricing-rules");
    } catch (error) {
      console.error("Failed to update pricing rule:", error);
      alert("Failed to update pricing rule. Please try again.");
    } finally {
      setSaving(false);
    }
  }

  async function handleDelete() {
    if (!confirm("Are you sure you want to delete this pricing rule? This action cannot be undone.")) {
      return;
    }

    setDeleting(true);
    try {
      await deletePricingRule(ruleName);
      router.push("/pricing-rules");
    } catch (error) {
      console.error("Failed to delete pricing rule:", error);
      alert("Failed to delete pricing rule. Please try again.");
      setDeleting(false);
    }
  }

  if (loading) {
    return (
      <div suppressHydrationWarning className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 p-8">
        <div suppressHydrationWarning className="max-w-4xl mx-auto">
          <div className="flex items-center justify-center py-20">
            <Loader2 className="h-8 w-8 animate-spin text-blue-600" />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div suppressHydrationWarning className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 p-8">
      <div suppressHydrationWarning className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div>
          <Link href="/pricing-rules">
            <Button variant="ghost" className="gap-2 pl-0 hover:bg-transparent hover:text-blue-600 mb-4">
              <ArrowLeft className="h-4 w-4" /> Back to Pricing Rules
            </Button>
          </Link>
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
                Edit Pricing Rule
              </h1>
              <p className="text-slate-500 mt-1">{ruleName}</p>
            </div>
            <Button
              variant="destructive"
              onClick={handleDelete}
              disabled={deleting}
              className="gap-2"
            >
              {deleting ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Deleting...
                </>
              ) : (
                <>
                  <Trash2 className="h-4 w-4" />
                  Delete Rule
                </>
              )}
            </Button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Basic Information */}
          <Card>
            <CardHeader>
              <CardTitle>Basic Information</CardTitle>
              <CardDescription>Rule name and application settings</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="title">Rule Name *</Label>
                <Input
                  id="title"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  required
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Apply On</Label>
                  <Input value={applyOn} disabled className="bg-slate-100 dark:bg-slate-800" />
                  <p className="text-xs text-slate-500">Cannot be changed after creation</p>
                </div>

                {applyOn === "Item Group" && (
                  <div className="space-y-2">
                    <Label>Item Group</Label>
                    <Input value={itemGroup || "All Groups"} disabled className="bg-slate-100 dark:bg-slate-800" />
                  </div>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Pricing Action */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calculator className="h-5 w-5 text-green-600" />
                Pricing Action
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="rate_or_discount">Action Type *</Label>
                <Select value={rateOrDiscount} onValueChange={setRateOrDiscount}>
                  <SelectTrigger id="rate_or_discount">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Discount Percentage">Discount Percentage</SelectItem>
                    <SelectItem value="Discount Amount">Discount Amount</SelectItem>
                    <SelectItem value="Rate">Rate Override</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {rateOrDiscount === "Discount Percentage" && (
                <div className="space-y-2">
                  <Label htmlFor="discount_percentage">Discount Percentage *</Label>
                  <div className="relative">
                    <Input
                      id="discount_percentage"
                      type="number"
                      step="0.01"
                      value={discountPercentage}
                      onChange={(e) => setDiscountPercentage(e.target.value)}
                      required
                    />
                    <Percent className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  </div>
                </div>
              )}

              {rateOrDiscount === "Discount Amount" && (
                <div className="space-y-2">
                  <Label htmlFor="discount_amount">Discount Amount *</Label>
                  <div className="relative">
                    <Input
                      id="discount_amount"
                      type="number"
                      step="0.01"
                      value={discountAmount}
                      onChange={(e) => setDiscountAmount(e.target.value)}
                      required
                    />
                    <DollarSign className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  </div>
                </div>
              )}

              {rateOrDiscount === "Rate" && (
                <div className="space-y-2">
                  <Label htmlFor="rate">New Rate *</Label>
                  <div className="relative">
                    <Input
                      id="rate"
                      type="number"
                      step="0.01"
                      value={rate}
                      onChange={(e) => setRate(e.target.value)}
                      required
                    />
                    <Calculator className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  </div>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Conditions */}
          <Card>
            <CardHeader>
              <CardTitle>Conditions</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="customer_group">Customer Group</Label>
                  <Select value={customerGroup} onValueChange={setCustomerGroup}>
                    <SelectTrigger id="customer_group">
                      <SelectValue placeholder="All Customers" />
                    </SelectTrigger>
                    <SelectContent>
                      {customerGroups.map((group) => (
                        <SelectItem key={group} value={group}>
                          {group}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="territory">Territory</Label>
                  <Select value={territory} onValueChange={setTerritory}>
                    <SelectTrigger id="territory">
                      <SelectValue placeholder="All Territories" />
                    </SelectTrigger>
                    <SelectContent>
                      {territories.map((terr) => (
                        <SelectItem key={terr} value={terr}>
                          {terr}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="min_qty">Minimum Quantity</Label>
                  <Input
                    id="min_qty"
                    type="number"
                    step="1"
                    value={minQty}
                    onChange={(e) => setMinQty(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="max_qty">Maximum Quantity</Label>
                  <Input
                    id="max_qty"
                    type="number"
                    step="1"
                    value={maxQty}
                    onChange={(e) => setMaxQty(e.target.value)}
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="valid_from">Valid From</Label>
                  <Input
                    id="valid_from"
                    type="date"
                    value={validFrom}
                    onChange={(e) => setValidFrom(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="valid_upto">Valid Until</Label>
                  <Input
                    id="valid_upto"
                    type="date"
                    value={validUpto}
                    onChange={(e) => setValidUpto(e.target.value)}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="priority">Priority</Label>
                <Input
                  id="priority"
                  type="number"
                  step="1"
                  value={priority}
                  onChange={(e) => setPriority(e.target.value)}
                />
                <p className="text-xs text-slate-500">
                  Higher priority rules are applied first
                </p>
              </div>
            </CardContent>
          </Card>

          {/* Actions */}
          <div className="flex items-center justify-between">
            <Link href="/pricing-rules">
              <Button type="button" variant="outline">
                Cancel
              </Button>
            </Link>
            <Button type="submit" disabled={saving} className="gap-2">
              {saving ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Saving...
                </>
              ) : (
                "Save Changes"
              )}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { ArrowLeft, Plus, Percent, DollarSign, Calculator, Users, MapPin, Calendar, Package } from "lucide-react";
import Link from "next/link";
import { createPricingRule, getCustomerGroups, getTerritories, getItemGroups } from "@/app/actions/pricing-rules";

export default function CreatePricingRulePage() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [itemGroups, setItemGroups] = useState<string[]>([]);
  const [customerGroups, setCustomerGroups] = useState<string[]>([]);
  const [territories, setTerritories] = useState<string[]>([]);

  // Form state
  const [title, setTitle] = useState("");
  const [applyOn, setApplyOn] = useState("Item Group");
  const [itemGroup, setItemGroup] = useState("");
  const [rateOrDiscount, setRateOrDiscount] = useState("Discount Percentage");
  const [discountPercentage, setDiscountPercentage] = useState("");
  const [discountAmount, setDiscountAmount] = useState("");
  const [rate, setRate] = useState("");
  const [customerGroup, setCustomerGroup] = useState("");
  const [territory, setTerritory] = useState("");
  const [validFrom, setValidFrom] = useState("");
  const [validUpto, setValidUpto] = useState("");
  const [minQty, setMinQty] = useState("");
  const [maxQty, setMaxQty] = useState("");
  const [priority, setPriority] = useState("");

  useEffect(() => {
    loadData();
  }, []);

  async function loadData() {
    try {
      console.log('[Pricing Rule Form] Loading data...');
      const [groups, custGroups, terr] = await Promise.all([
        getItemGroups(),
        getCustomerGroups(),
        getTerritories(),
      ]);
      console.log('[Pricing Rule Form] Item Groups loaded:', groups);
      console.log('[Pricing Rule Form] Customer Groups loaded:', custGroups);
      console.log('[Pricing Rule Form] Territories loaded:', terr);
      setItemGroups(groups);
      setCustomerGroups(custGroups);
      setTerritories(terr);
    } catch (error) {
      console.error("[Pricing Rule Form] Failed to load data:", error);
      setError("Failed to load form data. Please refresh the page.");
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(""); // Clear previous errors
    
    console.log('[Pricing Rule Form] Submit initiated');
    console.log('[Pricing Rule Form] Apply On:', applyOn);
    console.log('[Pricing Rule Form] Item Group:', itemGroup);
    
    // Client-side validation
    if (applyOn === "Item Group" && !itemGroup) {
      setError("Please select an Item Group");
      console.warn('[Pricing Rule Form] Validation failed: Item Group required');
      return;
    }
    
    setLoading(true);

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("apply_on", applyOn);
      if (itemGroup) formData.append("item_group", itemGroup);
      formData.append("rate_or_discount", rateOrDiscount);
      if (discountPercentage) formData.append("discount_percentage", discountPercentage);
      if (discountAmount) formData.append("discount_amount", discountAmount);
      if (rate) formData.append("rate", rate);
      if (customerGroup) formData.append("customer_group", customerGroup);
      if (territory) formData.append("territory", territory);
      if (validFrom) formData.append("valid_from", validFrom);
      if (validUpto) formData.append("valid_upto", validUpto);
      if (minQty) formData.append("min_qty", minQty);
      if (maxQty) formData.append("max_qty", maxQty);
      if (priority) formData.append("priority", priority);

      await createPricingRule(formData);
      router.push("/pricing-rules");
    } catch (error: any) {
      console.error("Failed to create pricing rule:", error);
      setError(error?.message || "Failed to create pricing rule. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div suppressHydrationWarning className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 p-8">
      <div suppressHydrationWarning className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div>
          <Link href="/pricing-rules">
            <Button variant="ghost" className="gap-2 pl-0 hover:bg-transparent hover:text-blue-600 mb-4">
              <ArrowLeft className="h-4 w-4" /> Back to Pricing Rules
            </Button>
          </Link>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
            Create Pricing Rule
          </h1>
          <p className="text-slate-500 mt-1">
            Set up automated conditional pricing for your business
          </p>
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-4">
            <p className="text-sm text-red-600 dark:text-red-400">{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Basic Information */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Package className="h-5 w-5 text-blue-600" />
                Basic Information
              </CardTitle>
              <CardDescription>Define the rule name and what it applies to</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="title">Rule Name *</Label>
                <Input
                  id="title"
                  placeholder="e.g., Heavy Equipment 10% Discount"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  required
                />
                <p className="text-xs text-slate-500">A descriptive name for this pricing rule</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="apply_on">Apply On *</Label>
                  <Select value={applyOn} onValueChange={setApplyOn}>
                    <SelectTrigger id="apply_on">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Item Group">Item Group</SelectItem>
                      <SelectItem value="Item Code">Item Code</SelectItem>
                      <SelectItem value="Brand">Brand</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                {applyOn === "Item Group" && (
                  <div className="space-y-2">
                    <Label htmlFor="item_group">Item Group *</Label>
                    <Select value={itemGroup} onValueChange={setItemGroup} required>
                      <SelectTrigger id="item_group" className={!itemGroup ? "border-red-300" : ""}>
                        <SelectValue placeholder={itemGroups.length === 0 ? "Loading..." : "Select an Item Group"} />
                      </SelectTrigger>
                      <SelectContent>
                        {itemGroups.length === 0 ? (
                          <div className="px-2 py-1 text-sm text-slate-500">Loading item groups...</div>
                        ) : (
                          itemGroups.map((group) => (
                            <SelectItem key={group} value={group}>
                              {group}
                            </SelectItem>
                          ))
                        )}
                      </SelectContent>
                    </Select>
                    <p className="text-xs text-slate-500">Required when applying rule to Item Group</p>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Pricing Action */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calculator className="h-5 w-5 text-green-600" />
                Pricing Action
              </CardTitle>
              <CardDescription>Define the discount or rate to apply</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="rate_or_discount">Action Type *</Label>
                <Select value={rateOrDiscount} onValueChange={setRateOrDiscount}>
                  <SelectTrigger id="rate_or_discount">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Discount Percentage">
                      <div className="flex items-center gap-2">
                        <Percent className="h-4 w-4" />
                        Discount Percentage
                      </div>
                    </SelectItem>
                    <SelectItem value="Discount Amount">
                      <div className="flex items-center gap-2">
                        <DollarSign className="h-4 w-4" />
                        Discount Amount
                      </div>
                    </SelectItem>
                    <SelectItem value="Rate">
                      <div className="flex items-center gap-2">
                        <Calculator className="h-4 w-4" />
                        Rate Override
                      </div>
                    </SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {rateOrDiscount === "Discount Percentage" && (
                <div className="space-y-2">
                  <Label htmlFor="discount_percentage">Discount Percentage *</Label>
                  <div className="relative">
                    <Input
                      id="discount_percentage"
                      type="number"
                      step="0.01"
                      placeholder="e.g., 10"
                      value={discountPercentage}
                      onChange={(e) => setDiscountPercentage(e.target.value)}
                      required
                    />
                    <Percent className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  </div>
                  <p className="text-xs text-slate-500">Enter the percentage discount to apply</p>
                </div>
              )}

              {rateOrDiscount === "Discount Amount" && (
                <div className="space-y-2">
                  <Label htmlFor="discount_amount">Discount Amount *</Label>
                  <div className="relative">
                    <Input
                      id="discount_amount"
                      type="number"
                      step="0.01"
                      placeholder="e.g., 500"
                      value={discountAmount}
                      onChange={(e) => setDiscountAmount(e.target.value)}
                      required
                    />
                    <DollarSign className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  </div>
                  <p className="text-xs text-slate-500">Enter the fixed discount amount</p>
                </div>
              )}

              {rateOrDiscount === "Rate" && (
                <div className="space-y-2">
                  <Label htmlFor="rate">New Rate *</Label>
                  <div className="relative">
                    <Input
                      id="rate"
                      type="number"
                      step="0.01"
                      placeholder="e.g., 1500"
                      value={rate}
                      onChange={(e) => setRate(e.target.value)}
                      required
                    />
                    <Calculator className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  </div>
                  <p className="text-xs text-slate-500">Enter the new rate to override the default price</p>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Conditions */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Users className="h-5 w-5 text-purple-600" />
                Conditions (Optional)
              </CardTitle>
              <CardDescription>Set conditions for when this rule applies</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="customer_group">Customer Group</Label>
                  <Select value={customerGroup} onValueChange={setCustomerGroup}>
                    <SelectTrigger id="customer_group">
                      <SelectValue placeholder="All Customers" />
                    </SelectTrigger>
                    <SelectContent>
                      {customerGroups.map((group) => (
                        <SelectItem key={group} value={group}>
                          {group}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="territory">Territory</Label>
                  <Select value={territory} onValueChange={setTerritory}>
                    <SelectTrigger id="territory">
                      <SelectValue placeholder="All Territories" />
                    </SelectTrigger>
                    <SelectContent>
                      {territories.map((terr) => (
                        <SelectItem key={terr} value={terr}>
                          {terr}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="min_qty">Minimum Quantity</Label>
                  <Input
                    id="min_qty"
                    type="number"
                    step="1"
                    placeholder="e.g., 10"
                    value={minQty}
                    onChange={(e) => setMinQty(e.target.value)}
                  />
                  <p className="text-xs text-slate-500">Rule applies when quantity exceeds this</p>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="max_qty">Maximum Quantity</Label>
                  <Input
                    id="max_qty"
                    type="number"
                    step="1"
                    placeholder="e.g., 100"
                    value={maxQty}
                    onChange={(e) => setMaxQty(e.target.value)}
                  />
                  <p className="text-xs text-slate-500">Rule applies when quantity is below this</p>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="valid_from">Valid From</Label>
                  <Input
                    id="valid_from"
                    type="date"
                    value={validFrom}
                    onChange={(e) => setValidFrom(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="valid_upto">Valid Until</Label>
                  <Input
                    id="valid_upto"
                    type="date"
                    value={validUpto}
                    onChange={(e) => setValidUpto(e.target.value)}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="priority">Priority</Label>
                <Input
                  id="priority"
                  type="number"
                  step="1"
                  placeholder="e.g., 1"
                  value={priority}
                  onChange={(e) => setPriority(e.target.value)}
                />
                <p className="text-xs text-slate-500">
                  Higher priority rules are applied first when multiple rules match
                </p>
              </div>
            </CardContent>
          </Card>

          {/* Actions */}
          <div className="flex items-center justify-between">
            <Link href="/pricing-rules">
              <Button type="button" variant="outline">
                Cancel
              </Button>
            </Link>
            <Button 
              type="submit" 
              disabled={loading || !title || (applyOn === "Item Group" && !itemGroup)} 
              className="gap-2"
            >
              {loading ? (
                "Creating..."
              ) : (
                <>
                  <Plus className="h-4 w-4" />
                  Create Pricing Rule
                </>
              )}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { getProfile, getTeam, getTaxTemplates, getCompany, getBankAccounts } from "@/app/actions/settings";
import { InviteUserDialog } from "@/components/settings/invite-user-dialog";
import { CreateTaxTemplateDialog } from "@/components/settings/create-tax-template-dialog";
import { EditCompanyDialog } from "@/components/settings/edit-company-dialog";
import { CreateBankAccountDialog } from "@/components/settings/create-bank-account-dialog";
import { CrmSetupSection } from "@/components/settings/crm-setup-section";

interface User {
  name: string;
  full_name: string;
  role_profile_name?: string;
  enabled: number;
  email?: string;
  first_name?: string;
}

interface TaxTemplate {
  name: string;
  title: string;
  company: string;
  is_default?: number;
}

interface Company {
  name: string;
  company_name?: string;
  abbr: string;
  tax_id?: string;
  country?: string;
}

interface BankAccount {
  name: string;
  bank: string;
  bank_account_no: string;
  branch_code?: string;
  is_default?: number;
}

export default function SettingsPage() {
  const [profile, setProfile] = useState<User | null>(null);
  const [team, setTeam] = useState<User[]>([]);
  const [taxTemplates, setTaxTemplates] = useState<TaxTemplate[]>([]);
  const [company, setCompany] = useState<Company | null>(null);
  const [bankAccounts, setBankAccounts] = useState<BankAccount[]>([]);
  const [isDark, setIsDark] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check initial theme
    setIsDark(document.documentElement.classList.contains("dark"));

    // Load all data
    Promise.all([
      getProfile().catch(() => null),
      getTeam().catch(() => []),
      getTaxTemplates().catch(() => []),
      getCompany().catch(() => null),
      getBankAccounts().catch(() => []),
    ]).then(([profileData, teamData, taxData, companyData, bankData]) => {
      setProfile(profileData);
      setTeam(teamData);
      setTaxTemplates(taxData);
      setCompany(companyData);
      setBankAccounts(bankData);
      setLoading(false);
    });
  }, []);

  const toggleTheme = () => {
    document.documentElement.classList.toggle("dark");
    setIsDark(!isDark);
  };

  const getInitials = (name?: string) => {
    if (!name) return "?";
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-slate-500 dark:text-slate-400">Loading settings...</div>
      </div>
    );
  }

  return (
    <main className="w-full min-h-screen overflow-y-auto bg-slate-50 dark:bg-midnight-blue">
      {/* Header */}
      <header className="p-8 pb-4">
        <div className="flex justify-between items-start">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Settings</h1>
            <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
              Manage your organization, profile, and team settings
            </p>
          </div>
          <div className="flex gap-3">
            <button className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
              View Logs
            </button>
            <button className="px-4 py-2 text-sm font-medium bg-primary text-white rounded-lg shadow-sm hover:bg-blue-600 transition-colors">
              Save Changes
            </button>
          </div>
        </div>
      </header>

      <div className="p-8 pt-4 w-full space-y-6">
        {/* Smart Configuration Assistant Banner */}
        <div className="relative overflow-hidden bg-gradient-to-r from-blue-600 to-indigo-700 rounded-2xl p-6 text-white shadow-xl shadow-blue-500/10">
          <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-xl flex items-center justify-center">
                <span className="material-symbols-outlined">psychology</span>
              </div>
              <div>
                <h3 className="font-bold text-lg">Smart Configuration Assistant</h3>
                <p className="text-blue-100 text-sm opacity-90">
                  AI-driven insights help you optimize your organizational workflow.
                </p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <div className="hidden sm:block text-right mr-2">
                <span className="text-xs text-blue-200 block uppercase font-semibold">Activity Trend</span>
                <div className="flex gap-1 items-end h-6 mt-1">
                  <div className="w-1 bg-white/30 h-2 rounded-full"></div>
                  <div className="w-1 bg-white/50 h-4 rounded-full"></div>
                  <div className="w-1 bg-white h-5 rounded-full"></div>
                  <div className="w-1 bg-white/40 h-3 rounded-full"></div>
                  <div className="w-1 bg-white h-6 rounded-full"></div>
                </div>
              </div>
              <button className="bg-white text-blue-600 px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:bg-blue-50 transition-colors flex items-center gap-2">
                <span className="material-symbols-outlined text-sm">security</span>
                Audit Security
              </button>
            </div>
          </div>
          <div className="absolute right-0 top-0 w-64 h-full opacity-10 pointer-events-none">
            <svg className="h-full w-full" viewBox="0 0 100 100">
              <path d="M0,50 Q25,0 50,50 T100,50" fill="none" stroke="white" strokeWidth="2"></path>
              <path d="M0,60 Q25,10 50,60 T100,60" fill="none" stroke="white" strokeWidth="2"></path>
            </svg>
          </div>
        </div>

        {/* KPI Cards - Matching Leads Page Styling */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl">
            <span className="text-slate-400 text-[12px] font-bold tracking-widest uppercase">
              Team Size
            </span>
            <div className="flex items-end justify-between mt-2">
              <span className="text-3xl font-bold text-white leading-none">{team.length}</span>
              <span className="text-emerald-400 text-[12px] flex items-center gap-1 font-medium bg-emerald-400/10 px-2 py-1 rounded-full">
                <span className="material-symbols-outlined text-[12px]">trending_up</span>
                +{team.filter((u) => u.enabled).length}
              </span>
            </div>
          </div>
          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl">
            <div className="flex items-center justify-between">
              <span className="text-slate-400 text-[12px] font-bold tracking-widest uppercase">
                System Health
              </span>
              <span className="flex h-2 w-2 rounded-full bg-emerald-500"></span>
            </div>
            <div className="flex items-end justify-between mt-2">
              <span className="text-3xl font-bold text-white leading-none">99.8%</span>
              <span className="text-slate-500 text-[12px]">Uptime</span>
            </div>
          </div>
          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl">
            <span className="text-slate-400 text-[12px] font-bold tracking-widest uppercase">
              Security Score
            </span>
            <div className="flex items-end justify-between mt-2">
              <span className="text-3xl font-bold text-white leading-none">A+</span>
              <div className="flex -space-x-2">
                <div className="w-6 h-6 rounded-full border-2 border-[#111827] bg-blue-500 flex items-center justify-center text-[8px] font-bold text-white">
                  MFA
                </div>
                <div className="w-6 h-6 rounded-full border-2 border-[#111827] bg-indigo-500 flex items-center justify-center text-[8px] font-bold text-white">
                  SSL
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Appearance Section */}
        <section className="bg-white dark:bg-navy-900 border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden shadow-sm">
          <div className="p-6">
            <div className="flex items-center gap-2 text-slate-900 dark:text-white mb-6">
              <span className="material-symbols-outlined text-slate-400">palette</span>
              <h2 className="font-semibold text-base">Appearance</h2>
            </div>
            <div className="flex items-center justify-between">
              <div>
                <div className="flex items-center gap-3">
                  <h3 className="text-sm font-medium text-slate-900 dark:text-white">Theme</h3>
                  <span className="bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">
                    Under Development
                  </span>
                </div>
                <p className="text-sm text-slate-500 dark:text-slate-400">
                  Switch between light and dark mode
                </p>
              </div>
              <button
                onClick={toggleTheme}
                className={`relative inline-flex h-8 w-14 items-center rounded-full transition-colors focus:outline-none ${
                  isDark ? "bg-primary" : "bg-slate-200"
                }`}
              >
                <span className="sr-only">Toggle theme</span>
                <span
                  className={`inline-block h-6 w-6 transform rounded-full bg-white shadow-md transition-transform flex items-center justify-center ${
                    isDark ? "translate-x-7" : "translate-x-1"
                  }`}
                >
                  {isDark ? (
                    <span className="material-symbols-outlined text-[16px] text-blue-600">
                      dark_mode
                    </span>
                  ) : (
                    <span className="material-symbols-outlined text-[16px] text-amber-500">
                      light_mode
                    </span>
                  )}
                </span>
              </button>
            </div>
          </div>
        </section>

        {/* CRM Setup Section */}
        <CrmSetupSection />

        {/* My Profile Section */}
        <section className="bg-white dark:bg-navy-900 border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden shadow-sm">
          <div className="p-6">
            <h2 className="text-sm font-bold text-slate-900 dark:text-white mb-4 uppercase tracking-wider">
              My Profile
            </h2>
            {profile ? (
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-slate-100 dark:bg-navy-800 rounded-full flex items-center justify-center text-slate-600 dark:text-slate-400 font-bold text-xl">
                  {getInitials(profile.first_name || profile.full_name)}
                </div>
                <div className="flex-1">
                  <h3 className="text-xl font-bold text-slate-900 dark:text-white">
                    {profile.full_name}
                  </h3>
                  <p className="text-sm text-slate-500 dark:text-slate-400">{profile.name}</p>
                  <div className="mt-2">
                    <span className="bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 text-xs px-2 py-1 rounded-full border border-slate-200 dark:border-slate-700">
                      {profile.role_profile_name || "System User"}
                    </span>
                  </div>
                </div>
              </div>
            ) : (
              <p className="text-sm text-slate-500 dark:text-slate-400">
                Please log in to view your profile.
              </p>
            )}
          </div>
        </section>

        {/* Company Settings */}
        <section className="bg-white dark:bg-navy-900 border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden shadow-sm">
          <div className="p-6 flex items-center justify-between border-b border-slate-100 dark:border-slate-800">
            <div className="flex items-center gap-2 text-slate-900 dark:text-white">
              <span className="material-symbols-outlined text-slate-400">business</span>
              <h2 className="font-semibold text-base">Company Settings</h2>
            </div>
            {company && (
              <EditCompanyDialog company={{
                ...company,
                company_name: company.company_name ?? ""
              }} />
            )}
          </div>
          <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
            {company ? (
              <>
                <div className="space-y-6">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">
                      Company Name
                    </p>
                    <p className="text-sm font-bold text-slate-900 dark:text-white">
                      {(company.company_name ?? company.name) ?? ""}
                    </p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">
                      GSTIN
                    </p>
                    <p className="text-sm font-bold text-slate-900 dark:text-white">
                      {company.tax_id || "Not Set"}
                    </p>
                  </div>
                </div>
                <div className="space-y-6">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">
                      Abbreviation
                    </p>
                    <p className="text-sm font-bold text-slate-900 dark:text-white">{company.abbr}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">
                      Country
                    </p>
                    <p className="text-sm font-bold text-slate-900 dark:text-white">
                      {company.country || "Not Set"}
                    </p>
                  </div>
                </div>
              </>
            ) : (
              <div className="col-span-2 p-8 text-center text-slate-500 border-dashed border-2 rounded-xl">
                <span className="material-symbols-outlined text-6xl text-slate-300 dark:text-slate-700 mb-3">
                  business
                </span>
                <p className="font-semibold">No company found</p>
                <p className="text-sm mt-1">Company needs to be set up in ERPNext first</p>
              </div>
            )}
          </div>
        </section>

        {/* Bank Accounts */}
        <section className="bg-white dark:bg-navy-900 border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden shadow-sm">
          <div className="p-6 flex items-center justify-between">
            <div className="flex items-center gap-2 text-slate-900 dark:text-white">
              <span className="material-symbols-outlined text-slate-400">account_balance</span>
              <h2 className="font-semibold text-base">Bank Accounts</h2>
            </div>
            <CreateBankAccountDialog />
          </div>
          <div className="px-6 pb-6">
            {bankAccounts.length === 0 ? (
