                              <div className="flex items-center gap-8 text-sm text-slate-500">
                                <span className="flex items-center gap-2">
                                  <span className="material-symbols-outlined text-[18px]">mail</span>
                                  {member.email}
                                </span>
                                <span className={`flex items-center gap-2 ${!member.last_login ? 'text-amber-600 font-medium' : ''}` }>
                                  <span className="material-symbols-outlined text-[18px]">history</span>
                                  Last login: {formatDate(member.last_login)}
                                </span>
                                {hasBrokenAccess && (
                                  <span className="flex items-center gap-1.5 text-amber-600 dark:text-amber-400 font-medium text-xs">
                                    <span className="material-symbols-outlined text-[14px]">info</span>
                                    Click &ldquo;Edit Permissions&rdquo; to assign a role
                                  </span>
                                )}
                              </div>
                            </div>

                            <div className="flex items-center gap-4">
                              <button
                                onClick={() => handleEditPermissions(member)}
                                className={`transition-colors flex items-center gap-2 text-sm font-semibold ${
                                  hasBrokenAccess
                                    ? 'text-amber-600 dark:text-amber-400 hover:text-amber-700'
                                    : 'text-slate-600 dark:text-slate-400 hover:text-primary'
                                }`}
                              >
                                <span className="material-symbols-outlined text-[20px]">
                                  {hasBrokenAccess ? 'assignment_ind' : 'admin_panel_settings'}
                                </span>
                                {hasBrokenAccess ? 'Fix Permissions' : 'Edit Permissions'}
                              </button>
                              {!isProtected && (
                                <button
                                  onClick={() =>
                                    handleRemoveMember(
                                      member.email,
                                      `${member.first_name} ${member.last_name || ""}`
                                    )
                                  }
                                  disabled={removingEmail === member.email}
                                  className="text-slate-400 hover:text-red-500 transition-colors flex items-center gap-2 text-sm font-semibold disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                  <span className="material-symbols-outlined text-[20px]">person_remove</span>
                                  {removingEmail === member.email ? "Removing..." : "Remove"}
                                </button>
                              )}
                            </div>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              </div>

              {/* Team Member Limits */}
              <div className="bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-6">
                <div className="flex flex-wrap items-center justify-between gap-4">
                  <div className="max-w-3xl">
                    <h4 className="text-sm font-bold text-slate-800 dark:text-slate-200">
                      Team Member Limits
                    </h4>
                    <p className="text-xs text-slate-500 mt-1">
                      Your current plan allows for 10 team members. You have used{" "}
                      {teamMembers.length} of your slots. Upgrade your plan to add more users
                      to your organization and unlock advanced permission controls.
                    </p>
                  </div>
                  <a
                    className="inline-flex items-center gap-1.5 text-sm font-bold text-primary hover:underline group"
                    href="#"
                  >
                    Upgrade Plan
                    <span className="material-symbols-outlined text-sm group-hover:translate-x-1 transition-transform">
                      arrow_forward
                    </span>
                  </a>
                </div>
              </div>
            </>
          ) : (
            <div className="flex items-center justify-center h-full">
              <div className="text-slate-500">Loading team members...</div>
            </div>
          )}
        </div>

      </main>
      </>)}
    </div>
  );
}

'use server'

import { cookies } from 'next/headers'

const BASE_URL = process.env.ERP_NEXT_URL || 'http://127.0.0.1:8080'
const API_KEY = process.env.ERP_API_KEY
const API_SECRET = process.env.ERP_API_SECRET

interface TenantInfo {
  name: string
  subdomain: string
  company_name: string
  owner_email: string
  site_url: string
  status: string
  creation: string
}

/**
 * Check if user is admin (has access to master site)
 */
export async function isAdmin(): Promise<boolean> {
  try {
    const cookieStore = await cookies()
    const userEmail = cookieStore.get('user_email')?.value
    
    // Simple check: admin user must be from localhost or have specific email
    if (!userEmail) return false;
    return userEmail === 'administrator' || userEmail.includes('@admin.')
  } catch {
    return false
  }
}

/**
 * List all tenant sites (admin only)
 */
export async function listAllTenants(): Promise<{ success: boolean; tenants?: TenantInfo[]; error?: string }> {
  if (!API_KEY || !API_SECRET) {
    return { success: false, error: 'API credentials not configured' }
  }

  try {
    const authHeader = `token ${API_KEY}:${API_SECRET}`
    const response = await fetch(`${BASE_URL}/api/resource/Tenant?fields=["*"]&limit_page_length=100`, {
      headers: {
        'Authorization': authHeader,
      },
    })

    if (!response.ok) {
      return { success: false, error: 'Failed to fetch tenants' }
    }

    const data = await response.json()
    return {
      success: true,
      tenants: data.data || [],
    }
  } catch (error: any) {
    return {
      success: false,
      error: error.message || 'Failed to list tenants',
    }
  }
}

/**
 * Get tenant site status from Docker
 */
export async function getTenantSiteStatus(siteName: string): Promise<{ 
  success: boolean
  exists?: boolean
  database?: string
  apps?: string[]
  error?: string 
}> {
  const { exec } = await import('child_process')
  const { promisify } = await import('util')
  const execAsync = promisify(exec)

  const DOCKER_COMPOSE_DIR = process.env.DOCKER_COMPOSE_DIR || '/home/ubuntu/frappe_docker'

  try {
    // Check if site exists
    const checkCmd = `cd ${DOCKER_COMPOSE_DIR} && docker compose exec -T backend ls sites/${siteName} 2>/dev/null`
    try {
      await execAsync(checkCmd)
    } catch {
      return { success: true, exists: false }
    }

    // Get site apps
    const appsCmd = `cd ${DOCKER_COMPOSE_DIR} && docker compose exec -T backend bash -c "cd /home/frappe/frappe-bench && bench --site ${siteName} list-apps"`
    const { stdout: appsOutput } = await execAsync(appsCmd)
    const apps = appsOutput.trim().split('\n').filter(Boolean)

    // Get database name from site config
    const dbName = siteName.replace(/[.-]/g, '_')

    return {
      success: true,
      exists: true,
      database: dbName,
      apps,
    }
  } catch (error: any) {
    return {
      success: false,
      error: error.message,
    }
  }
}

/**
 * Delete a tenant site (admin only)
 */
export async function deleteTenantSite(tenantName: string, siteName: string): Promise<{ 
  success: boolean
  error?: string 
}> {
  if (!(await isAdmin())) {
    return { success: false, error: 'Unauthorized: Admin access required' }
  }

  const { exec } = await import('child_process')
  const { promisify } = await import('util')
  const execAsync = promisify(exec)

  const DOCKER_COMPOSE_DIR = process.env.DOCKER_COMPOSE_DIR || '/home/ubuntu/frappe_docker'
  const DB_ROOT_PASSWORD = process.env.DB_ROOT_PASSWORD || 'admin'

  try {
    // Drop the site and database
    const dropCmd = `cd ${DOCKER_COMPOSE_DIR} && docker compose exec -T backend bash -c "cd /home/frappe/frappe-bench && bench drop-site ${siteName} --mariadb-root-password '${DB_ROOT_PASSWORD}' --force"`
    
    await execAsync(dropCmd, { timeout: 60000 })

    // Delete Tenant record from master site
    if (API_KEY && API_SECRET) {
      const authHeader = `token ${API_KEY}:${API_SECRET}`
      await fetch(`${BASE_URL}/api/resource/Tenant/${tenantName}`, {
        method: 'DELETE',
        headers: {
          'Authorization': authHeader,
        },
      })
    }

    return { success: true }
  } catch (error: any) {
    return {
      success: false,
      error: error.message || 'Failed to delete tenant site',
    }
  }
}

/**
 * Restart a tenant site
 */
export async function restartTenantSite(siteName: string): Promise<{ 
  success: boolean
  error?: string 
}> {
  if (!(await isAdmin())) {
    return { success: false, error: 'Unauthorized: Admin access required' }
  }

  const { exec } = await import('child_process')
  const { promisify } = await import('util')
  const execAsync = promisify(exec)

  const DOCKER_COMPOSE_DIR = process.env.DOCKER_COMPOSE_DIR || '/home/ubuntu/frappe_docker'

  try {
    // Restart the site (clears cache)
    const restartCmd = `cd ${DOCKER_COMPOSE_DIR} && docker compose exec -T backend bash -c "cd /home/frappe/frappe-bench && bench --site ${siteName} clear-cache"`
    
    await execAsync(restartCmd, { timeout: 30000 })

    return { success: true }
  } catch (error: any) {
    return {
      success: false,
      error: error.message || 'Failed to restart tenant site',
    }
  }
}

"use server";

import { frappeRequest } from "@/app/lib/api";

interface PricingRuleMatch {
  rule_name: string;
  rule_title?: string;
  discount_percentage?: number;
  discount_amount?: number;
  rate?: number;
  apply_on?: string;
}

type PricingRuleDoc = {
  name: string;
  title?: string;
  apply_on?: string;
  item_group?: string;
  rate_or_discount?: string;
  discount_percentage?: number;
  discount_amount?: number;
  rate?: number;
  customer?: string;
  customer_group?: string;
  territory?: string;
  min_qty?: number;
  max_qty?: number;
  valid_from?: string;
  valid_upto?: string;
  priority?: number;
  disable?: number;
};

async function fetchActivePricingRules(): Promise<PricingRuleDoc[]> {
  try {
    const rules = await frappeRequest(
      "frappe.client.get_list",
      "GET",
      {
        doctype: "Pricing Rule",
        fields: '["name","title","apply_on","rate_or_discount","discount_percentage","discount_amount","rate","customer","customer_group","territory","min_qty","max_qty","valid_from","valid_upto","priority","disable"]',
        filters: JSON.stringify([["disable", "=", 0]]),
        limit_page_length: 200,
      }
    );

    if (!Array.isArray(rules)) return [];

    // For Item Group rules, we need to fetch the child table item_groups
    const enriched = await Promise.all(
      rules.map(async (rule: any) => {
        if (rule.apply_on === "Item Group") {
          try {
            const full = await frappeRequest("frappe.client.get", "GET", {
              doctype: "Pricing Rule",
              name: rule.name,
            }) as any;
            return { ...rule, item_group: full?.item_groups?.[0]?.item_group || full?.item_group };
          } catch {
            return rule;
          }
        }
        return rule;
      })
    );

    return enriched;
  } catch (error) {
    console.error("Failed to fetch pricing rules list:", error);
    return [];
  }
}

// Fetch item_group for each item_code from ERPNext
async function getItemGroupMap(itemCodes: string[]): Promise<Record<string, string>> {
  const map: Record<string, string> = {};
  if (itemCodes.length === 0) return map;

  try {
    const items = await frappeRequest("frappe.client.get_list", "GET", {
      doctype: "Item",
      fields: '["name","item_group"]',
      filters: JSON.stringify([["name", "in", itemCodes]]),
      limit_page_length: 200,
    }) as { name: string; item_group: string }[];

    if (Array.isArray(items)) {
      items.forEach(item => { map[item.name] = item.item_group; });
    }
  } catch (err) {
    console.error("Failed to fetch item groups for items:", err);
  }
  return map;
}

// Apply pricing rules to quotation items
export async function applyPricingRules(params: {
  customer?: string;
  customer_group?: string;
  territory?: string;
  transaction_date: string;
  items: Array<{
    item_code: string;
    item_group?: string;
    qty: number;
    rate: number;
  }>;
}): Promise<{
  items: Array<{
    item_code: string;
    rate: number;
    discount_percentage?: number;
    discount_amount?: number;
    pricing_rule?: string;
  }>;
  applied_rules: PricingRuleMatch[];
}> {
  try {
    const rules = await fetchActivePricingRules();

    // Fetch item_group for each item_code so Item Group rules can match
    const itemCodes = params.items.map(i => i.item_code).filter(Boolean);
    const itemGroupMap = await getItemGroupMap(itemCodes);

    const appliedRules: PricingRuleMatch[] = [];
    const processedItems = params.items.map((item) => {
      const itemGroup = item.item_group || itemGroupMap[item.item_code];

      // Find matching rules for this item
      const matchingRules = rules.filter((rule) => {
        // Check if rule applies to this item
        if (rule.apply_on === "Item Group" && rule.item_group) {
          if (rule.item_group !== itemGroup) return false;
        }

        // Check customer conditions
        if (rule.customer && rule.customer !== params.customer) return false;
        if (rule.customer_group && rule.customer_group !== params.customer_group) return false;
        if (rule.territory && rule.territory !== params.territory) return false;

        // Check quantity conditions
        if (rule.min_qty && item.qty < rule.min_qty) return false;
        if (rule.max_qty && item.qty > rule.max_qty) return false;

        // Check date validity
        if (rule.valid_from && params.transaction_date < rule.valid_from) return false;
        if (rule.valid_upto && params.transaction_date > rule.valid_upto) return false;

        return true;
      });

      // Sort by priority (higher priority first)
      matchingRules.sort((a, b) => (b.priority || 0) - (a.priority || 0));

      // Apply the highest priority rule
      if (matchingRules.length > 0) {
        const rule = matchingRules[0];

        const ruleMatch: PricingRuleMatch = {
          rule_name: rule.name,
          rule_title: rule.title,
          apply_on: rule.apply_on,
        };

        let newRate = item.rate;
        let discountPercentage: number | undefined;
        let discountAmount: number | undefined;

        if (rule.rate_or_discount === "Discount Percentage" && rule.discount_percentage) {
          discountPercentage = rule.discount_percentage;
          newRate = item.rate * (1 - rule.discount_percentage / 100);
          ruleMatch.discount_percentage = rule.discount_percentage;
        } else if (rule.rate_or_discount === "Discount Amount" && rule.discount_amount) {
          discountAmount = rule.discount_amount;
          newRate = Math.max(0, item.rate - rule.discount_amount);
          ruleMatch.discount_amount = rule.discount_amount;
        } else if (rule.rate_or_discount === "Rate" && rule.rate) {
          newRate = rule.rate;
          ruleMatch.rate = rule.rate;
        }

        appliedRules.push(ruleMatch);

        return {
          item_code: item.item_code,
          rate: newRate,
          discount_percentage: discountPercentage,
          discount_amount: discountAmount,
          pricing_rule: rule.name,
        };
      }

      return {
        item_code: item.item_code,
        rate: item.rate,
      };
    });

    return {
      items: processedItems,
      applied_rules: appliedRules,
    };
  } catch (error) {
    console.error("Error applying pricing rules:", error);
    return {
      items: params.items.map((item) => ({
        item_code: item.item_code,
        rate: item.rate,
      })),
      applied_rules: [],
    };
  }
}

// Get applicable pricing rules preview (for UI display)
export async function getApplicablePricingRules(params: {
  customer?: string;
  customer_group?: string;
  territory?: string;
  transaction_date: string;
  item_groups?: string[];
}): Promise<PricingRuleMatch[]> {
  try {
    const rules = await fetchActivePricingRules();

    return rules
      .filter((rule) => {
        // Check customer conditions
        if (rule.customer && rule.customer !== params.customer) return false;
        if (rule.customer_group && rule.customer_group !== params.customer_group) return false;
        if (rule.territory && rule.territory !== params.territory) return false;

        // Check date validity
        if (rule.valid_from && params.transaction_date < rule.valid_from) return false;
        if (rule.valid_upto && params.transaction_date > rule.valid_upto) return false;

        // Check item groups if specified
        if (params.item_groups && params.item_groups.length > 0) {
          if (rule.apply_on === "Item Group" && rule.item_group) {
            if (!params.item_groups.includes(rule.item_group)) return false;
          }
        }

        return true;
      })
      .map((rule) => ({
        rule_name: rule.name,
        rule_title: rule.title,
        apply_on: rule.apply_on,
        discount_percentage: rule.discount_percentage,
        discount_amount: rule.discount_amount,
        rate: rule.rate,
      }));
  } catch (error) {
    console.error("Error getting applicable pricing rules:", error);
    return [];
  }
}

'use server'

import { frappeRequest } from "@/app/lib/api"
import { revalidatePath } from "next/cache"

export interface Booking {
  name: string
  customer: string
  customer_name: string
  transaction_date: string
  delivery_date: string
  grand_total: number
  status: string
  po_no: string
  items: any[]
  docstatus: number
  per_delivered: number
}

// 1. READ: List
export async function getBookings() {
  const baseFields = '["name", "customer_name", "transaction_date", "delivery_date", "grand_total", "status", "po_no", "per_delivered"]'
  try {
    // Try filtering to rental bookings by po_no prefix first
    const rentalBookings = await frappeRequest(
      'frappe.client.get_list',
      'GET',
      {
        doctype: 'Sales Order',
        fields: baseFields,
        filters: '[["po_no", "like", "RENT-%"]]',
        order_by: 'creation desc',
        limit_page_length: 100
      }
    ) as Booking[]

    if (rentalBookings && rentalBookings.length > 0) return rentalBookings

    // Fallback: return all Sales Orders if no RENT-% bookings found
    // (handles cases where po_no wasn't saved or order was created outside the app)
    const allBookings = await frappeRequest(
      'frappe.client.get_list',
      'GET',
      {
        doctype: 'Sales Order',
        fields: baseFields,
        order_by: 'creation desc',
        limit_page_length: 100
      }
    ) as Booking[]
    return allBookings || []
  } catch (error) {
    console.error("Failed to fetch bookings:", error)
    return []
  }
}

// 1b. Get Customer Booking History
export async function getCustomerBookingHistory(customerName: string) {
  try {
    const bookings = await frappeRequest(
      'frappe.client.get_list',
      'GET',
      {
        doctype: 'Sales Order',
        fields: '["name", "transaction_date", "delivery_date", "grand_total", "status", "po_no"]',
        filters: `[["customer_name", "=", "${customerName}"], ["po_no", "like", "RENT-%"]]`,
        order_by: 'creation desc',
        limit_page_length: 10
      }
    ) as any[]

    // Calculate total bookings and total spent
    const totalBookings = bookings.length
    const totalSpent = bookings.reduce((sum: number, booking: any) => sum + booking.grand_total, 0)
    const completedBookings = bookings.filter((b: any) => b.status === 'Completed').length

    return {
      bookings,
      stats: {
        totalBookings,
        totalSpent,
        completedBookings
      }
    }
  } catch (error) {
    console.error("Failed to fetch customer booking history:", error)
    return {
      bookings: [],
      stats: {
        totalBookings: 0,
        totalSpent: 0,
        completedBookings: 0
      }
    }
  }
}

// 1c. Get Item Rental Analytics
export async function getItemRentalAnalytics(itemCode: string) {
  try {
    // Get all Sales Orders with this item
    const salesOrders = await frappeRequest(
      'frappe.client.get_list',
      'GET',
      {
        doctype: 'Sales Order',
        fields: '["name", "customer_name", "transaction_date", "delivery_date", "grand_total", "status"]',
        filters: `[["po_no", "like", "RENT-${itemCode}%"]]`,
        order_by: 'creation desc',
      }
    ) as any[]

    const totalRentals = salesOrders.length
    const totalRevenue = salesOrders.reduce((sum: number, order: any) => sum + order.grand_total, 0)
    const averageRentalDays = salesOrders.reduce((sum: number, order: any) => {
      const start = new Date(order.transaction_date)
      const end = new Date(order.delivery_date)
      const days = Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24))
      return sum + days
    }, 0) / (totalRentals || 1)

    return {
      totalRentals,
      totalRevenue,
      averageRentalDays: Math.round(averageRentalDays),
      recentRentals: salesOrders.slice(0, 5)
    }
  } catch (error) {
    console.error("Failed to fetch item rental analytics:", error)
    return {
      totalRentals: 0,
      totalRevenue: 0,
      averageRentalDays: 0,
      recentRentals: []
    }
  }
}

// 1d. CREATE: Book Item/Equipment from Catalogue
export async function createBooking(formData: FormData) {
  const itemCode = formData.get('item_code') as string
  const customer = formData.get('customer') as string
  const startDate = formData.get('start_date') as string
  const endDate = formData.get('end_date') as string
  const rate = parseFloat(formData.get('rate') as string || '0')
  const projectName = formData.get('project_name') as string

  try {
    // Verify customer exists
    const customerDoc = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Customer',
      name: customer
    })

    if (!customerDoc) {
      throw new Error('Customer not found. Please create customer first.')
    }

    // Check for overlapping bookings on the same item
    const existingBookings = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Sales Order',
      filters: JSON.stringify([
        ['Sales Order Item', 'item_code', '=', itemCode],
        ['status', 'in', ['Draft', 'To Deliver and Bill', 'To Bill', 'To Deliver', 'On Hold']]
      ]),
      fields: JSON.stringify(['name', 'delivery_date', 'transaction_date']),
      limit_page_length: 0
    }) as any[]

    // Check for date overlaps
    const start = new Date(startDate)
    const end = new Date(endDate)

    for (const booking of existingBookings) {
      const bookingStart = new Date(booking.transaction_date)
      const bookingEnd = new Date(booking.delivery_date)

      // Check if dates overlap
      if (start <= bookingEnd && end >= bookingStart) {
        throw new Error(`${itemCode} is already booked from ${booking.transaction_date} to ${booking.delivery_date}. Please choose different dates.`)
      }
    }

    // Calculate total days and amount
    const days = Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1

    // Generate unique PO number with timestamp
    const timestamp = Date.now()
    const uniquePO = `RENT-${itemCode}-${timestamp}`

    const bookingDoc = {
      doctype: 'Sales Order',
      customer: customer,
      transaction_date: startDate,
      delivery_date: endDate,
      po_no: uniquePO,
      project: projectName || undefined,

      items: [{
        item_code: itemCode,
        description: `Rental of ${itemCode} from ${startDate} to ${endDate} (${days} days)${projectName ? ` - ${projectName}` : ''}`,
        qty: days,
        rate: rate,
        delivery_date: endDate
      }],

      remarks: `Equipment rental booking for ${days} days`,
      status: 'Draft'
    }

    const createdBooking = await frappeRequest('frappe.client.insert', 'POST', { doc: bookingDoc }) as { name: string }

    revalidatePath('/bookings')
    revalidatePath('/catalogue')
    return { success: true, bookingId: createdBooking.name }
  } catch (error: any) {
    console.error("Booking error:", error)
    return { error: error.message || 'Booking failed' }
  }
}

// 2. READ: Single Booking
export async function getBooking(id: string): Promise<Booking | null> {
  try {
    const booking = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Sales Order',
      name: decodeURIComponent(id)
    })
    return booking as Booking
  } catch (error) {
    return null
  }
}

// 3. ACTION: Mobilize (Send to Site with Operator)
export async function mobilizeAsset(formData: FormData) {
  const bookingId = formData.get('booking_id') as string
  const operatorName = formData.get('operator') as string

  try {
    const booking = await getBooking(bookingId)
    if (!booking) throw new Error("Booking not found")
    if (!booking.items || booking.items.length === 0) throw new Error("Booking has no items")

    const itemCode = booking.items[0].item_code

    // 0. Check if item has serial number tracking
    let hasSerialNo = false
    try {
      const existingItem = await frappeRequest('frappe.client.get', 'GET', {
        doctype: 'Item',
        name: itemCode,
        fields: JSON.stringify(['has_serial_no'])
      }) as any
      hasSerialNo = !!existingItem.has_serial_no
    } catch (itemErr: any) {
      console.warn(`Could not fetch item ${itemCode}, proceeding without serial tracking:`, itemErr.message)
    }

    let assetId = ""
    let sourceWarehouse = ""

    if (hasSerialNo) {
      // --- Serial-tracked item flow ---
      assetId = booking.items[0].serial_no || booking.items[0].serial_and_batch_bundle

      if (!assetId && booking.po_no && booking.po_no.startsWith('RENT-')) {
        assetId = booking.po_no.replace('RENT-', '')
      }
      if (!assetId) {
        assetId = `${itemCode}-${booking.name}`
      }

      // 1. Check if Serial No exists, create if it doesn't
      let asset: any = {}
      try {
        asset = await frappeRequest('frappe.client.get', 'GET', { doctype: 'Serial No', name: assetId }) as { warehouse?: string }
        sourceWarehouse = asset.warehouse || ""
      } catch (e: any) {
        console.log(`Serial No ${assetId} not found, explicitly creating it`)
        try {
          await frappeRequest('frappe.client.insert', 'POST', {
            doc: {
              doctype: 'Serial No',
              item_code: itemCode,
              serial_no: assetId,
              status: 'Active'
            }
          })
        } catch (err) {
          console.error('Failed to create missing Serial No:', err)
        }
      }

      // Self-Healing: If no warehouse, receipt it first
      if (!sourceWarehouse) {
        const warehouses = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Warehouse',
          filters: '[["is_group", "=", 0]]',
          limit_page_length: 1
        }) as any[]
        const defaultWh = warehouses[0]?.name || "Stores - ERP - A"

        await frappeRequest('frappe.client.insert', 'POST', {
          doc: {
            doctype: 'Stock Entry',
            stock_entry_type: 'Material Receipt',
            to_warehouse: defaultWh,
            items: [{
              item_code: itemCode,
              qty: 1,
              serial_no: assetId,
              basic_rate: 1000
            }],
            docstatus: 1
          }
        })
        sourceWarehouse = defaultWh
      }
    } else {
      // --- Non-serial item flow: ensure stock exists in a warehouse ---
      const warehouses = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Warehouse',
        filters: '[["is_group", "=", 0]]',
        limit_page_length: 1
      }) as any[]
      const defaultWh = warehouses[0]?.name || "Stores - ERP - A"

      // Check current stock level
      let hasStock = false
      try {
        const bins = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Bin',
          filters: JSON.stringify([['item_code', '=', itemCode], ['warehouse', '=', defaultWh]]),
          fields: JSON.stringify(['actual_qty']),
          limit_page_length: 1
        }) as any[]
        hasStock = bins.length > 0 && bins[0].actual_qty > 0
      } catch (e) {
        console.warn('Could not check stock level, will attempt receipt')
      }

      if (!hasStock) {
        try {
          await frappeRequest('frappe.client.insert', 'POST', {
            doc: {
              doctype: 'Stock Entry',
              stock_entry_type: 'Material Receipt',
              to_warehouse: defaultWh,
              items: [{
                item_code: itemCode,
                qty: booking.items[0].qty || 1,
                basic_rate: 1000
              }],
              docstatus: 1
            }
          })
        } catch (stockErr: any) {
          console.warn('Stock receipt failed, proceeding:', stockErr.message)
        }
      }
      sourceWarehouse = defaultWh
    }

    // 2. Create Delivery Note (With Operator Info)
    const deliveryDoc = {
      doctype: 'Delivery Note',
      customer: booking.customer,
      instructions: `Mobilized with Operator: ${operatorName || 'None assigned'}`,
      items: booking.items.map((item: any) => ({
        item_code: item.item_code,
        qty: item.qty,
        uom: item.uom || item.stock_uom || 'Nos',
        stock_uom: item.stock_uom || item.uom || 'Nos',
        so_detail: item.name,
        against_sales_order: booking.name,
        ...(hasSerialNo && assetId ? { serial_no: assetId } : {}),
        warehouse: sourceWarehouse
      })),
      docstatus: 1
    }

    await frappeRequest('frappe.client.insert', 'POST', { doc: deliveryDoc }) as { name: string }

    // 3. Update Asset Status to "Issued" (only for serial-tracked items)
    if (hasSerialNo && assetId) {
      try {
        await frappeRequest('frappe.client.set_value', 'PUT', {
          doctype: 'Serial No',
          name: assetId,
          fieldname: 'status',
          value: 'Issued'
        })
      } catch (e) {
        console.warn('Could not update serial no status:', e)
      }
    }

    // 4. Update Sales Order (Booking) status to reflect mobilization
    await frappeRequest('frappe.client.set_value', 'PUT', {
      doctype: 'Sales Order',
      name: booking.name,
      fieldname: 'status',
      value: 'To Bill'
    })

    revalidatePath(`/bookings/${bookingId}`)
    return { success: true }
  } catch (error: any) {
    console.error("Mobilize error:", error)
    return { error: error.message || 'Failed to mobilize asset' }
  }
}

// 4. ACTION: Return Asset
export async function returnAsset(bookingId: string) {
  try {
    const booking = await getBooking(bookingId)
    if (!booking) throw new Error("Booking not found")
    if (!booking.items || booking.items.length === 0) throw new Error("Booking has no items")

    const itemCode = booking.items[0].item_code

    // 0. Check if item has serial number tracking
    let hasSerialNo = false
    try {
      const existingItem = await frappeRequest('frappe.client.get', 'GET', {
        doctype: 'Item',
        name: itemCode,
        fields: JSON.stringify(['has_serial_no'])
      }) as any
      hasSerialNo = !!existingItem.has_serial_no
    } catch (itemErr: any) {
      console.warn(`Could not fetch item ${itemCode}, proceeding without serial tracking:`, itemErr.message)
    }

    // Find a warehouse
    let targetWarehouse = "Stores - ERP - A"
    try {
      const warehouses = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Warehouse',
        filters: '[["is_group", "=", 0]]',
        limit_page_length: 1
      }) as any[]
      if (warehouses.length > 0) targetWarehouse = warehouses[0].name
    } catch (e) { }

    if (hasSerialNo) {
      // --- Serial-tracked item flow ---
      let assetId = booking.items[0].serial_no || booking.items[0].serial_and_batch_bundle

      if (!assetId && booking.po_no && booking.po_no.startsWith('RENT-')) {
        assetId = booking.po_no.replace('RENT-', '')
      }
      if (!assetId) {
        assetId = `${itemCode}-${booking.name}`
      }

      // Check current asset status
      let asset: any = {}
      try {
        asset = await frappeRequest('frappe.client.get', 'GET', { doctype: 'Serial No', name: assetId }) as { warehouse?: string }
      } catch (e) {
        console.log(`Serial No ${assetId} not found in system during return, explicitly creating it`)
        try {
          await frappeRequest('frappe.client.insert', 'POST', {
            doc: {
              doctype: 'Serial No',
              item_code: itemCode,
              serial_no: assetId,
              status: 'Active'
            }
          })
        } catch (err) {
          console.error('Failed to create missing Serial No:', err)
        }
      }

      // Only create Material Receipt if asset is NOT already in a warehouse
      if (!asset.warehouse) {
        const stockEntry = {
          doctype: 'Stock Entry',
          stock_entry_type: 'Material Receipt',
          to_warehouse: targetWarehouse,
          items: [{
            item_code: itemCode,
            qty: 1,
            serial_no: assetId,
            basic_rate: 1000
          }],
          docstatus: 1
        }

        await frappeRequest('frappe.client.insert', 'POST', { doc: stockEntry })
      }

      // Update Serial No status to Active
      try {
        await frappeRequest('frappe.client.set_value', 'PUT', {
          doctype: 'Serial No',
          name: assetId,
          fieldname: 'status',
          value: 'Active'
        })
      } catch (e) {
        console.warn('Could not update serial no status:', e)
      }
    } else {
      // --- Non-serial item flow: receipt stock back ---
      try {
        await frappeRequest('frappe.client.insert', 'POST', {
          doc: {
            doctype: 'Stock Entry',
            stock_entry_type: 'Material Receipt',
            to_warehouse: targetWarehouse,
            items: [{
              item_code: itemCode,
              qty: booking.items[0].qty || 1,
              basic_rate: 1000
            }],
            docstatus: 1
          }
        })
      } catch (stockErr: any) {
        console.warn('Stock receipt on return failed, proceeding:', stockErr.message)
      }
    }

    // Properly close the Sales Order by updating both status and per_delivered
    await frappeRequest('frappe.client.set_value', 'PUT', {
      doctype: 'Sales Order',
      name: bookingId,
      fieldname: 'status',
      value: 'Completed'
    })

    await frappeRequest('frappe.client.set_value', 'PUT', {
      doctype: 'Sales Order',
      name: bookingId,
      fieldname: 'per_delivered',
      value: 100
    })

    revalidatePath(`/bookings/${bookingId}`)
    revalidatePath('/bookings')
    return { success: true }
  } catch (error: any) {
    console.error("Return error:", error)
    return { error: error.message || 'Failed to return asset' }
  }
}

