'use server'

import { frappeRequest } from "@/app/lib/api"
import { revalidatePath } from "next/cache"
import { canCreateLead, incrementUsage } from "./usage-limits"
import { headers } from "next/headers"
import { cookies } from "next/headers"

/**
 * Validates a territory name against ERPNextΓÇÖs actual Territory records.
 * Returns a valid territory name, or undefined if none can be found.
 * Never uses hardcoded fallbacks that may not exist on the site.
 */
async function resolveValidTerritory(preferredTerritory?: string): Promise<string | undefined> {
  try {
    if (preferredTerritory) {
      const check = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Territory',
        filters: JSON.stringify([['name', '=', preferredTerritory]]),
        fields: '["name"]',
        limit_page_length: 1
      }) as any[]
      if (check && check.length > 0) return check[0].name
    }
    const all = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Territory',
      fields: '["name"]',
      limit_page_length: 1
    }) as any[]
    return all && all.length > 0 ? all[0].name : undefined
  } catch (e) {
    return undefined
  }
}

// 7. DELETE: Delete Lead (only if not Converted)
export async function deleteLead(leadId: string) {
  try {
    // Only allow delete if not Converted
    const lead = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Lead',
      name: leadId
    }) as { status: string }

    if (lead.status === 'Converted') {
      throw new Error('Converted leads cannot be deleted')
    }

    await frappeRequest('frappe.client.delete', 'POST', {
      doctype: 'Lead',
      name: leadId
    })

    revalidatePath('/crm')
    revalidatePath('/crm/leads')
    return { success: true }
  } catch (error: any) {
    console.error('Delete lead error:', error)
    return { error: error.message || 'Failed to delete lead' }
  }
}

// 8. DELETE: Delete Opportunity (only if Open)
export async function deleteOpportunity(opportunityId: string) {
  try {
    // Only allow delete if status is Open
    const opp = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Opportunity',
      name: opportunityId
    }) as { status: string }

    if (opp.status !== 'Open') {
      throw new Error('Only Open opportunities can be deleted')
    }

    await frappeRequest('frappe.client.delete', 'POST', {
      doctype: 'Opportunity',
      name: opportunityId
    })

    revalidatePath('/crm')
    revalidatePath('/crm/opportunities')
    return { success: true }
  } catch (error: any) {
    console.error('Delete opportunity error:', error)
    return { error: error.message || 'Failed to delete opportunity' }
  }
}

export interface Lead {
  name: string
  lead_name: string
  email_id: string
  mobile_no: string
  status: string // Lead | Open | Replied | Opportunity | Quotation | Lost Quotation | Interested | Converted | Do Not Contact
  company_name: string
  job_title?: string
  territory?: string
  source?: string
  industry?: string
  creation?: string
}

export interface Opportunity {
  name: string
  opportunity_from: string // Lead or Customer
  party_name: string // Lead/Customer ID
  opportunity_type: string // Sales, Maintenance, etc
  status: string // Open | Quotation | Converted | Lost
  sales_stage: string // Prospecting | Qualification | Proposal | Negotiation | Won | Lost
  expected_closing: string
  probability: number // 0-100%
  opportunity_amount: number
  currency: string
  customer_name?: string
  contact_person?: string
  contact_email?: string
  territory?: string
  source?: string
  with_items: number // 0 or 1
  items?: any[]
  title?: string
  notes?: string
  order_lost_reason?: string
}

export interface Quotation {
  name: string
  quotation_to: string // Customer or Lead
  party_name: string
  customer_name?: string
  status: string // Draft | Open | Ordered | Lost
  docstatus?: number // 0 = Draft, 1 = Submitted, 2 = Cancelled
  valid_till: string
  grand_total: number
  net_total?: number
  total_taxes_and_charges?: number
  currency: string
  items: any[]
  opportunity?: string
  transaction_date?: string
  terms?: string
}

// ========== OPPORTUNITIES ==========

// Helper: Get tenant site name from request context
async function getTenantSiteName(): Promise<string> {
  const IS_PRODUCTION = process.env.NODE_ENV === 'production'
  const ROOT_DOMAIN = process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'
  const MASTER_SITE = process.env.FRAPPE_SITE_NAME || 'erp.localhost'

  const makeSiteName = (subdomain: string) =>
    IS_PRODUCTION ? `${subdomain}.${ROOT_DOMAIN}` : `${subdomain}.localhost`

  try {
    const headersList = await headers()
    const cookieStore = await cookies()

    // First check cookies
    const cookieTenant = cookieStore.get('tenant_subdomain')?.value
    if (cookieTenant) {
      return makeSiteName(cookieTenant)
    }

    // Then check X-Subdomain header (set by middleware)
    const headerSubdomain = headersList.get('X-Subdomain')
    if (headerSubdomain) {
      return makeSiteName(headerSubdomain)
    }

    // Check x-tenant-id header (injected by middleware for all routes incl. API)
    const tenantHeader = headersList.get('x-tenant-id')
    if (tenantHeader && tenantHeader !== 'master') {
      return makeSiteName(tenantHeader)
    }
    return MASTER_SITE
  } catch (error) {
    console.error('[DEBUG] Error getting tenant site name:', error)
    return MASTER_SITE
  }
}

// 1. READ: Get All Opportunities
export async function getOpportunities() {
  try {
    const response = await frappeRequest(
      'frappe.client.get_list',
      'GET',
      {
        doctype: 'Opportunity',
        fields: '["name", "opportunity_from", "party_name", "customer_name", "opportunity_type", "status", "sales_stage", "expected_closing", "probability", "opportunity_amount", "currency"]',
        order_by: 'creation desc',
        limit_page_length: 100
      }
    )
    return response as Opportunity[]
  } catch (error) {
    console.error("Failed to fetch opportunities:", error)
    return []
  }
}

// 2. READ: Get Single Opportunity
export async function getOpportunity(id: string): Promise<Opportunity | null> {
  try {
    const opportunity = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Opportunity',
      name: decodeURIComponent(id)
    })
    return opportunity as Opportunity
  } catch (error) {
    console.error("Failed to fetch opportunity:", error)
    return null
  }
}

// 3. UPDATE: Update Opportunity Sales Stage
export async function updateOpportunitySalesStage(opportunityId: string, salesStage: string, probability: number) {
  try {
    await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'Opportunity',
      name: opportunityId,
      fieldname: {
        sales_stage: salesStage,
        probability: probability
      }
    })

    revalidatePath('/crm')
    revalidatePath(`/crm/opportunities/${opportunityId}`)
    return { success: true }
  } catch (error: any) {
    console.error("Sales stage update error:", error)
    return { error: error.message || 'Failed to update sales stage' }
  }
}
// 4. READ: Get Opportunity Metadata (Types & Stages)
export async function getOpportunityMetadata() {
  try {
    const types = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Opportunity Type',
      fields: '["name"]',
      limit_page_length: 50
    }) as { name: string }[];

    const stages = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Sales Stage',
      fields: '["name"]',
      limit_page_length: 50
    }) as { name: string }[];

    return {
      types: types.map(t => t.name),
      stages: stages.map(s => s.name)
    };
  } catch (error) {
    console.error("Failed to fetch opportunity metadata:", error);
    return { types: [], stages: [] };
  }
}


// ========== LEADS ==========

// 1. READ: Fetch list of leads
export async function getLeads() {
  try {
    const response = await frappeRequest(
      'frappe.client.get_list',
      'GET',
      {
        doctype: 'Lead',
        fields: '["name", "lead_name", "email_id", "mobile_no", "status", "company_name", "job_title", "territory", "source", "creation"]',
        order_by: 'creation desc',
        limit_page_length: 100
      }
    )
    return response as Lead[]
  } catch (error) {
    console.error("Failed to fetch leads:", error)
    return []
  }
}

// 2. CREATE: Add a new lead (Expanded for Detailed View)
export async function createLead(data: any) {
  // Check usage limits first
  const headersList = await headers()
  const subdomain = headersList.get('X-Subdomain')

  if (subdomain) {
    const usageCheck = await canCreateLead(subdomain)
    if (!usageCheck.allowed) {
      return {
        error: usageCheck.message || 'Lead limit reached',
        limitReached: true,
        currentUsage: usageCheck.current,
        limit: usageCheck.limit
      }
    }
  }

  // Build the lead document with required fields
  const leadData: any = {
    doctype: 'Lead',
    // Details
    first_name: data.first_name,
    status: 'Lead', // Default status

    // Contact Info
    email_id: data.email_id,
    mobile_no: data.mobile_no,
  }

  // Fetch Default Company (Aggressive Search)
  let defaultCompany: string | undefined = undefined;
  try {
    // 1. Check Global Defaults
    let checkCompany = await frappeRequest('frappe.client.get_value', 'GET', {
      doctype: 'Global Defaults',
      fieldname: 'default_company'
    }) as { default_company?: string }
    defaultCompany = checkCompany?.default_company;

    if (!defaultCompany) {
      // 2. Check if any company exists
      const companies = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Company',
        fields: '["name"]',
        limit_page_length: 1
      }) as { name: string }[];

      if (companies && companies.length > 0) {
        defaultCompany = companies[0].name;
      } else if (data.company_name) {
        // 3. No company exists - create one from lead's company_name

        // Generate abbreviation from company name
        const abbr = data.company_name
          .replace(/[^a-zA-Z0-9]/g, '')
          .substring(0, 5)
          .toUpperCase() || 'COMP';

        try {
          // Ensure 'Transit' Warehouse Type exists
          try {
            const transitType = await frappeRequest('frappe.client.get_value', 'GET', {
              doctype: 'Warehouse Type',
              filters: { name: 'Transit' },
              fieldname: 'name'
            }) as { name?: string };
            if (!transitType || !transitType.name) {
              await frappeRequest('frappe.client.insert', 'POST', {
                doc: { doctype: 'Warehouse Type', name: 'Transit' }
              });
            }
          } catch (e) {
          }

          const newCompany = await frappeRequest('frappe.client.insert', 'POST', {
            doc: {
              doctype: 'Company',
              company_name: data.company_name,
              abbr: abbr,
              default_currency: 'INR',
              country: 'India'
            }
          }) as { name: string };

          defaultCompany = newCompany.name;

          // Set as default in Global Defaults
          try {
            await frappeRequest('frappe.client.set_value', 'POST', {
              doctype: 'Global Defaults',
              name: 'Global Defaults',
              fieldname: 'default_company',
              value: defaultCompany
            });
          } catch (e) {
          }
        } catch (e) {
          console.error('[createLead] Failed to create company:', e);
        }
      }
    }

    if (defaultCompany) {
      leadData.company = defaultCompany;
    }
  } catch (e) {
  }



  // Helper to safely get a valid Link field value
  const getValidLinkValue = async (doctype: string, value: string): Promise<string | undefined> => {
    if (!value) return undefined;
    try {
      // 1. Try exact match
      const exact = await frappeRequest('frappe.client.get_value', 'GET', {
        doctype,
        filters: { name: value },
        fieldname: 'name'
      }) as { name?: string };
      if (exact && exact.name) return exact.name;

      // 2. Try "like" match (useful for "Mr" vs "Mr.", or case sensitivity)
      const similar = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype,
        filters: { name: ['like', `%${value}%`] },
        limit_page_length: 1
      }) as any[];
      if (similar && similar.length > 0) return similar[0].name;
    } catch (e) {
    }
    return undefined;
  };

  // Add optional fields only if they have values
  if (data.salutation) leadData.salutation = await getValidLinkValue('Salutation', data.salutation);
  if (data.source) leadData.source = await getValidLinkValue('Lead Source', data.source);
  if (data.industry) leadData.industry = await getValidLinkValue('Industry Type', data.industry);

  if (data.middle_name) leadData.middle_name = data.middle_name
  if (data.last_name) leadData.last_name = data.last_name
  if (data.job_title) leadData.job_title = data.job_title
  if (data.gender) leadData.gender = data.gender
  if (data.phone) leadData.phone = data.phone
  if (data.website) leadData.website = data.website
  if (data.company_name) leadData.company_name = data.company_name
  if (data.no_of_employees) leadData.no_of_employees = data.no_of_employees
  if (data.annual_revenue) leadData.annual_revenue = data.annual_revenue
  if (data.market_segment) leadData.market_segment = data.market_segment
  if (data.territory) leadData.territory = data.territory
  if (data.fax) leadData.fax = data.fax

  // Add organization_slug if provided (for multi-tenancy)
  if (data.organization_slug) {
    leadData.organization_slug = data.organization_slug
  }

  try {
    await frappeRequest('frappe.client.insert', 'POST', {
      doc: leadData
    })

    // Increment usage counter
    if (subdomain) {
      await incrementUsage(subdomain, 'usage_leads')
    }

    revalidatePath('/crm')
    return { success: true }
  } catch (error: any) {
    console.error("Create lead error:", error)
    return { error: error.message || 'Failed to create lead' }
  }
}

// 3. UPDATE: Save detailed info (Used by the Edit Sheet)
export async function updateLead(leadId: string, formData: FormData) {
  const values: Record<string, any> = {}
  // Basic Info
  if (formData.has('lead_name')) values.lead_name = formData.get('lead_name')?.toString() || ""
  if (formData.has('company_name')) values.company_name = formData.get('company_name')?.toString() || ""
  if (formData.has('job_title')) values.job_title = formData.get('job_title')?.toString() || ""
  if (formData.has('industry')) values.industry = formData.get('industry')?.toString() || ""
  // Contact Info
  if (formData.has('email_id')) values.email_id = formData.get('email_id')?.toString() || ""
  if (formData.has('mobile_no')) values.mobile_no = formData.get('mobile_no')?.toString() || ""
  // Status & Source
  if (formData.has('status')) values.status = formData.get('status')?.toString() || "Open"
  if (formData.has('source')) values.source = formData.get('source')?.toString() || ""
  // Territory & Location
  if (formData.has('territory')) values.territory = formData.get('territory')?.toString() || ""
  if (formData.has('city')) values.city = formData.get('city')?.toString() || ""
  if (formData.has('country')) values.country = formData.get('country')?.toString() || ""
  // Notes
  if (formData.has('notes')) values.notes = formData.get('notes')?.toString() || ""

  try {
    await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'Lead',
      name: leadId,
      fieldname: values
    })

    revalidatePath(`/crm/${leadId}`)
    revalidatePath('/crm')
    return { success: true }
  } catch (error: any) {
    console.error("Update error:", error)
    return { error: error.message || 'Update failed' }
  }
}

