// 2. CONVERT: Create Customer from Lead
export async function convertLeadToCustomer(leadId: string) {
  try {
    // 1. Fetch Lead Details
    const lead = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Lead',
      name: leadId
    }) as Lead & { organization_slug?: string }

    if (!lead) throw new Error("Lead not found")

    // 2. Validate territory against ERPNext ΓÇö lead.territory may not exist on this site
    const resolvedTerritory = await resolveValidTerritory((lead as any).territory)

    // 3. Create Customer Object
    const customerData: any = {
      doctype: 'Customer',
      customer_name: lead.company_name || lead.lead_name,
      customer_type: lead.company_name ? 'Company' : 'Individual',
      email_id: lead.email_id,
      mobile_no: lead.mobile_no
    }
    if (resolvedTerritory) customerData.territory = resolvedTerritory

    // 4. Add organization_slug from the source lead for multi-tenancy
    if (lead.organization_slug) {
      customerData.organization_slug = lead.organization_slug
    }

    // 5. Save to ERPNext
    const customer = await frappeRequest('frappe.client.insert', 'POST', { doc: customerData }) as { name: string }

    // 5. Update Lead Status to 'Converted'
    await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'Lead',
      name: leadId,
      fieldname: 'status',
      value: 'Converted'
    })

    revalidatePath('/crm')
    return { success: true, customerId: customer.name }
  } catch (error: any) {
    return { error: error.message || 'Failed to convert lead' }
  }
}

// 3. CONVERT: Create Opportunity from Lead using native ERPNext method
export async function convertLeadToOpportunity(
  leadId: string,
  createCustomer: boolean = false,
  opportunityAmount: number = 0,
  opportunityType: string = 'Sales',
  salesStage: string = 'Qualification'
) {
  try {
    // 1. Fetch Lead details (needed for organization_slug)
    const lead = await frappeRequest('frappe.client.get', 'GET', {
      doctype: 'Lead',
      name: leadId
    }) as Lead & { organization_slug?: string, company?: string }

    if (!lead) {
      throw new Error("Lead not found")
    }
    // 2. Optionally create customer first if conversion source should be Customer
    if (createCustomer) {
      const customerResult = await convertLeadToCustomer(leadId)
      if (customerResult.error) {
        throw new Error(`Customer creation failed: ${customerResult.error}`)
      }
    }

    // 3. Ensure a Contact exists for this lead (by email or name)
    let contactPersonName: string | undefined = undefined;
    if (lead.email_id) {
      // Try to find contact by email
      const contactSearch = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Contact',
        fields: ['name'],
        filters: { email_id: lead.email_id },
        limit_page_length: 1
      }) as Array<{ name: string }>;
      if (contactSearch && contactSearch.length > 0) {
        contactPersonName = contactSearch[0].name;
      }
    }
    if (!contactPersonName && lead.lead_name) {
      // Try to find contact by name
      const contactSearch = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Contact',
        fields: ['name'],
        filters: { first_name: lead.lead_name },
        limit_page_length: 1
      }) as Array<{ name: string }>;
      if (contactSearch && contactSearch.length > 0) {
        contactPersonName = contactSearch[0].name;
      }
    }
    if (!contactPersonName) {
      // Create a new Contact for this lead
      const contactDoc = {
        doctype: 'Contact',
        first_name: lead.lead_name || 'Lead Contact',
        email_id: lead.email_id || undefined,
        phone: lead.mobile_no || undefined,
        organization_slug: lead.organization_slug || undefined
      };
      const createdContact = await frappeRequest('frappe.client.insert', 'POST', { doc: contactDoc }) as { name: string };
      contactPersonName = createdContact.name;
    }


    // 4. Validate and Fetch Opportunity Metadata (Type & Stage)
    let validOpportunityType: string | undefined = undefined;
    let validSalesStage: string | undefined = undefined;

    // Always fetch available types from database to validate
    try {
      const types = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Opportunity Type',
        fields: '["name"]',
        limit_page_length: 100
      }) as { name: string }[];

      if (types && types.length > 0) {
        // Check if provided type exists in database
        const typeNames = types.map(t => t.name);
        if (opportunityType && typeNames.includes(opportunityType)) {
          validOpportunityType = opportunityType;
        } else {
          // Use first available type as fallback
          validOpportunityType = types[0].name;
        }
      } else {
      }
    } catch (e) {
    }

    // Always fetch available stages from database to validate
    try {
      const stages = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Sales Stage',
        fields: '["name"]',
        limit_page_length: 100
      }) as { name: string }[];

      if (stages && stages.length > 0) {
        // Check if provided stage exists in database
        const stageNames = stages.map(s => s.name);
        if (salesStage && stageNames.includes(salesStage)) {
          validSalesStage = salesStage;
        } else {
          // Use first available stage as fallback
          validSalesStage = stages[0].name;
        }
      } else {
      }
    } catch (e) {
    }

    // 4.5 Fetch Default Company
    let defaultCompany = lead.company; // 1. Try to get from Lead

    if (!defaultCompany) {
      // 2. Try Global Defaults
      let checkCompany = await frappeRequest('frappe.client.get_value', 'GET', {
        doctype: 'Global Defaults',
        fieldname: 'default_company'
      }) as { default_company?: string }
      defaultCompany = checkCompany?.default_company;
    }

    if (!defaultCompany) {
      // If no global default, try to find any company
      const companies = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Company',
        fields: '["name"]',
        limit_page_length: 1
      }) as { name: string }[];
      if (companies && companies.length > 0) {
        defaultCompany = companies[0].name;
      }
    }

    if (!defaultCompany) {
    } else {
    }


    // 5. Always construct Opportunity doc from Lead data (no make_opportunity call)
    let opportunityDoc: any = {
      doctype: 'Opportunity',
      opportunity_from: createCustomer ? 'Customer' : 'Lead',
      party_name: createCustomer && lead.company_name ? lead.company_name : leadId,
      title: lead.company_name || lead.lead_name || `Opportunity from ${leadId}`,
      customer_name: lead.company_name || undefined,
      contact_person: contactPersonName,
      contact_email: lead.email_id || undefined,
      territory: lead.territory || undefined,
      source: lead.source || undefined,
      opportunity_amount: opportunityAmount || 0,
      with_items: 0,
      status: 'Open',
      company: defaultCompany, // Add Company field
      probability: 10,
      expected_closing: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: ''
    };

    // Only add sales_stage and opportunity_type if they exist in the database
    if (validSalesStage) {
      opportunityDoc.sales_stage = validSalesStage;
    }
    if (validOpportunityType) {
      opportunityDoc.opportunity_type = validOpportunityType;
    }

    // Remove the name field if it exists (it might be empty)
    if (opportunityDoc.name === undefined || opportunityDoc.name === null || opportunityDoc.name === '') {
      delete opportunityDoc.name
    }

    // 5. Add organization_slug from the source lead for multi-tenancy
    if (lead.organization_slug) {
      opportunityDoc.organization_slug = lead.organization_slug
    }

    // 6. If customer was created, update the opportunity_from to Customer
    if (createCustomer) {
      opportunityDoc.opportunity_from = 'Customer'
      // party_name should already be set to customer by make_opportunity if customer exists
    }

    // 7. Save the Opportunity
    const savedOpportunity = await frappeRequest('frappe.client.insert', 'POST', {
      doc: opportunityDoc
    }) as { name?: string }
    if (!savedOpportunity || !savedOpportunity.name) {
      throw new Error("Failed to save opportunity - no name returned")
    }

    const opportunityId = savedOpportunity.name
    // 8. Update Lead status to "Converted"
    await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'Lead',
      name: leadId,
      fieldname: 'status',
      value: 'Converted'
    })
    // 9. Revalidate paths to refresh UI
    revalidatePath('/crm')
    revalidatePath('/crm/leads')
    revalidatePath(`/crm/leads/${leadId}`)
    revalidatePath('/crm/opportunities')
    revalidatePath(`/crm/opportunities/${opportunityId}`)
    return { success: true, opportunityId }

  } catch (error: any) {
    console.error('[convertLeadToOpportunity] Error during conversion:', {
      message: error.message,
      stack: error.stack,
      fullError: error
    })
    return {
      error: error.message || 'Failed to convert lead to opportunity'
    }
  }
}

