// 2. CREATE: New Operator with License Info
export async function createOperator(formData: FormData) {
  try {
    // Extract form data
    const firstName = formData.get('first_name')?.toString() || ''
    const lastName = formData.get('last_name')?.toString() || ''
    const email = formData.get('email')?.toString() || ''
    const phone = formData.get('phone')?.toString() || ''
    const dateOfBirth = formData.get('date_of_birth')?.toString() || ''
    const licenseNumber = formData.get('license_number')?.toString() || ''
    const licenseExpiry = formData.get('license_expiry')?.toString() || ''
    const dateOfJoining = formData.get('date_of_joining')?.toString() || new Date().toISOString().split('T')[0]

    // Validate required fields
    if (!firstName.trim()) {
      throw new Error('First name is required')
    }
    if (!dateOfBirth) {
      throw new Error('Date of birth is required')
    }

    // Build operator data for ERPNext Employee doctype
    const operatorData = {
      doctype: 'Employee',
      first_name: firstName,
      last_name: lastName,
      employee_name: `${firstName} ${lastName}`.trim(),
      date_of_birth: dateOfBirth,
      date_of_joining: dateOfJoining,
      status: 'Active',
      cell_number: phone,
      email: email,

      // Store license info in bio field
      bio: licenseNumber ? `License: ${licenseNumber}${licenseExpiry ? ` | Expires: ${licenseExpiry}` : ''}` : ''
    }

    console.log('Creating operator with data:', operatorData)

    const response = await frappeRequest('frappe.client.insert', 'POST', { doc: operatorData })

    console.log('Operator created successfully:', response)

    revalidatePath('/operators')
    return { success: true, data: response }
  } catch (error: any) {
    console.error('Error creating operator:', error)
    const errorMessage = error.message || 'Failed to create operator'
    return { error: errorMessage, success: false }
  }
}

'use server'

import { frappeRequest } from '@/app/lib/api'
import { Organization, OrganizationMember, SubscriptionTier } from '@/types/subscription'

// Create Organization in ERPNext as a custom doctype
export async function createOrganization(data: {
  name: string
  slug: string
  ownerEmail: string
  plan?: SubscriptionTier
}) {
  try {
    // Format dates for ERPNext (YYYY-MM-DD HH:MM:SS)
    const formatDateForERPNext = (date: Date) => {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      const hours = String(date.getHours()).padStart(2, '0')
      const minutes = String(date.getMinutes()).padStart(2, '0')
      const seconds = String(date.getSeconds()).padStart(2, '0')
      return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`
    }

    const trialEndDate = new Date(Date.now() + 14 * 24 * 60 * 60 * 1000)
    const currentDate = new Date()

    const organization: Organization = {
      name: data.name,
      slug: data.slug,
      subscription: {
        plan: data.plan || 'free',
        status: 'trial',
        trial_end: formatDateForERPNext(trialEndDate)
      },
      usage: {
        users: 1,
        leads: 0,
        projects: 0,
        invoices: 0,
        storage: 0
      },
      owner: data.ownerEmail,
      created_at: formatDateForERPNext(currentDate),
      updated_at: formatDateForERPNext(currentDate)
    }

    const result = await frappeRequest('frappe.client.insert', 'POST', {
      doc: {
        doctype: 'Organization',
        organization_name: organization.name,
        slug: organization.slug,
        subscription_plan: organization.subscription.plan,
        subscription_status: organization.subscription.status,
        trial_end: organization.subscription.trial_end,
        current_period_start: organization.created_at,
        current_period_end: organization.subscription.trial_end,
        owner_email: organization.owner,
        usage_users: 1,
        usage_leads: 0,
        usage_projects: 0,
        usage_invoices: 0,
        usage_storage: 0
      }
    })

    // Create organization member entry for owner
    await frappeRequest('frappe.client.insert', 'POST', {
      doc: {
        doctype: 'Organization Member',
        member_name: data.ownerEmail.split('@')[0],
        email: data.ownerEmail,
        role: 'owner',
        organization_slug: organization.slug
      }
    })

    return { success: true, organization: result }
  } catch (error: any) {
    console.error('Error creating organization:', error)
    return { success: false, error: error.message }
  }
}

