  }
}

// Track usage
export async function updateUsage(
  organizationSlug: string,
  usageType: 'users' | 'leads' | 'projects' | 'invoices' | 'storage',
  increment: number = 1
) {
  try {
    const org = await getOrganization(organizationSlug)
    if (!org) {
      return { success: false, error: 'Organization not found' }
    }

    const fieldMap = {
      users: 'usage_users',
      leads: 'usage_leads',
      projects: 'usage_projects',
      invoices: 'usage_invoices',
      storage: 'usage_storage'
    }

    const currentValue = (org as any)[fieldMap[usageType]] || 0
    const newValue = currentValue + increment

    const result = await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'Organization',
      name: (org as any).name,
      fieldname: {
        [fieldMap[usageType]]: newValue
      }
    }) as { name: string }

    return { success: true, usage: newValue }
  } catch (error: any) {
    return { success: false, error: error.message }
  }
}

// Check if organization can perform action
export async function canPerformAction(
  organizationSlug: string,
  actionType: 'users' | 'leads' | 'projects' | 'invoices' | 'storage',
  requiredAmount: number = 1
): Promise<{ allowed: boolean; reason?: string }> {
  try {
    const org = await getOrganization(organizationSlug)
    if (!org) {
      return { allowed: false, reason: 'Organization not found' }
    }

    const { SUBSCRIPTION_PLANS } = await import('@/types/subscription')
    const plan = SUBSCRIPTION_PLANS[(org as any).subscription_plan as SubscriptionTier]
    
    const limitMap = {
      users: plan.features.maxUsers,
      leads: plan.features.maxLeads,
      projects: plan.features.maxProjects,
      invoices: plan.features.maxInvoices,
      storage: plan.features.maxStorage
    }

    const usageMap = {
      users: (org as any).usage_users || 0,
      leads: (org as any).usage_leads || 0,
      projects: (org as any).usage_projects || 0,
      invoices: (org as any).usage_invoices || 0,
      storage: (org as any).usage_storage || 0
    }

    const limit = limitMap[actionType]
    const currentUsage = usageMap[actionType]

    if (limit === -1) {
      return { allowed: true } // unlimited
    }

    if (currentUsage + requiredAmount > limit) {
      return {
        allowed: false,
        reason: `You have reached your ${actionType} limit (${limit}). Please upgrade your plan.`
      }
    }

    return { allowed: true }
  } catch (error: any) {
    return { allowed: false, reason: error.message }
  }
}

"use server";

import { frappeRequest } from "@/app/lib/api";
import { revalidatePath } from "next/cache";

interface PricingRule {
  name: string;
  title: string;
  apply_on: string;
  items?: { item_code: string }[];
  item_groups?: { item_group: string }[];
  brands?: { brand: string }[];
  selling?: number;
  buying?: number;
  rate_or_discount: string;
  discount_percentage?: number;
  discount_amount?: number;
  rate?: number;
  price_or_product_discount: string;
  customer?: string;
  customer_group?: string;
  customers?: { customer: string }[];
  customer_groups?: { customer_group: string }[];
  territory?: string;
  valid_from?: string;
  valid_upto?: string;
  min_qty?: number;
  max_qty?: number;
  disable?: number;
  priority?: number;
}

// Get all pricing rules
export async function getPricingRules(): Promise<PricingRule[]> {
