      fieldname: {
        status: formData.get('status'),
        priority: formData.get('priority'),
        expected_end_date: formData.get('end_date'),
        percent_complete: parseInt(formData.get('percent_complete') as string) || 0
      }
    })
    revalidatePath(`/projects/${projectId}`)
