'use server'

/**
 * ============================================================================
 * PRODUCTION-GRADE SALES ORDER TO INVOICE WORKFLOW
 * ERPNext Integration for Nexus ERP SaaS
 * ============================================================================
 *
 * STATUS MAPPING (ERPNext fields)
 *
 * ERPNext exposes two related, user-facing fields on Sales Order:
 * - `delivery_status`: Not Delivered | Partly Delivered | Fully Delivered | Closed | Not Applicable
 * - `billing_status`: Not Billed | Partly Billed | Fully Billed | Closed
 *
 * Internally ERPNext also calculates `per_delivered` and `per_billed` (0-100%). The combined
 * values determine `status` (eg. "To Deliver and Bill", "To Bill", "To Deliver", "Completed").
 *
 * Key mappings we use for eligibility:
 * - Fully billed: `billing_status === 'Fully Billed'` OR `per_billed >= 100`
 * - No delivery required (services): `delivery_status === 'Not Applicable'` ΓåÆ can invoice based on billing
 * - Deliveries present: require `per_delivered > 0` (or `delivery_status` != 'Not Delivered') to create invoice
 * - Terminal states: `Cancelled`, `On Hold`, `Closed` ΓåÆ never eligible
 *
 * INVOICE ELIGIBILITY RULES:
 * Γ£ô Can invoice: billing_status != 'Fully Billed' AND (delivery_status !== 'Not Delivered' OR delivery_status === 'Not Applicable')
 * Γ£ù Cannot invoice: billing_status = 'Fully Billed' OR per_billed >= 100
 * Γ£ù Cannot invoice: status in ['Draft', 'Cancelled', 'On Hold', 'Closed'] or docstatus != 1
 *
 * WORKFLOW PROGRESSION:
 * 1. Create SO (Draft, docstatus=0)
 * 2. Submit SO (docstatus=1, status="To Deliver and Bill")
 * 3. (Optional) Create Delivery Note for items
 * 4. Mark "Ready for Invoice" (keep status, enable invoice creation)
 * 5. Create Invoice from SO
 * 6. ERPNext updates per_billed, status recalculates
 * 7. If per_billed=100: statusΓåÆ"To Deliver" or "Completed"
 * 8. Submit Invoice ΓåÆ Payment collection
 *
 * KEY: Status is NOT manually updated - it's CALCULATED by ERPNext
 * We only READ the status, never SET it except for explicit transitions
 * ============================================================================
 */

import { frappeRequest } from "@/app/lib/api"
import { revalidatePath } from "next/cache"

/**
 * Validates a territory name against ERPNext's actual Territory records.
 * Returns a valid territory name, or undefined if none can be found.
 * Never uses hardcoded fallbacks like 'All Territories' or 'Asia' that may not exist.
 */
async function resolveValidTerritory(preferredTerritory?: string): Promise<string | undefined> {
  try {
    if (preferredTerritory) {
      // Check if this specific territory actually exists in ERPNext
      const check = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Territory',
        filters: JSON.stringify([['name', '=', preferredTerritory]]),
        fields: '["name"]',
        limit_page_length: 1
      }) as any[]
      if (check && check.length > 0) {
        return check[0].name // Confirmed valid
      }
    }
    // Fall back to the first territory that actually exists
    const all = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Territory',
      fields: '["name"]',
      limit_page_length: 1
    }) as any[]
    return all && all.length > 0 ? all[0].name : undefined
  } catch (e) {
    return undefined
  }
}

