  try {
    // ΓöÇΓöÇ Resolve Lead ΓåÆ Customer ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // When a quotation is created for a Lead (quotation_to = 'Lead'), the form
    // populates `customer` with the Lead ID (e.g. CRM-LEAD-2026-00002).
    // ERPNext requires a Customer record ΓÇö so we resolve it here.
    let resolvedCustomer = data.customer
    let resolvedCustomerName = data.customer_name

    if (data.customer && data.customer.startsWith('CRM-LEAD-')) {
      const leadId = data.customer

      try {
        // 1. Fetch the lead to get details
        const lead = await frappeRequest('frappe.client.get', 'GET', {
          doctype: 'Lead',
          name: leadId
        }) as any

        if (lead) {
          // 2. Look for an existing Customer that was created from this lead
          //    (ERPNext stores lead_name on Customer when converted)
          const existingCustomers = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Customer',
            filters: JSON.stringify([
              ['customer_name', 'in', [
                lead.company_name || '',
                lead.lead_name || '',
                lead.customer_name || ''
              ].filter(Boolean)]
            ]),
            fields: '["name", "customer_name"]',
            limit_page_length: 1
          }) as any[]

          if (existingCustomers && existingCustomers.length > 0) {
            resolvedCustomer = existingCustomers[0].name
            resolvedCustomerName = existingCustomers[0].customer_name
          } else {
            // 3. No existing customer ΓÇö create one from this lead

            // Validate territory against ERPNext ΓÇö the lead's territory value may not exist on this site
            const validTerritory = await resolveValidTerritory(lead.territory)

            const customerData: any = {
              doctype: 'Customer',
              customer_name: lead.company_name || lead.lead_name,
              customer_type: lead.company_name ? 'Company' : 'Individual',
              email_id: lead.email_id,
              mobile_no: lead.mobile_no
            }
            if (validTerritory) customerData.territory = validTerritory
            if (lead.organization_slug) customerData.organization_slug = lead.organization_slug

            const newCustomer = await frappeRequest('frappe.client.insert', 'POST', {
              doc: customerData
            }) as any

            resolvedCustomer = newCustomer.name
            resolvedCustomerName = newCustomer.customer_name

            // Update lead status to Converted
            try {
              await frappeRequest('frappe.client.set_value', 'POST', {
                doctype: 'Lead',
                name: leadId,
                fieldname: 'status',
                value: 'Converted'
              })
            } catch (e) {
            }
          }
        }
      } catch (leadResolveError: any) {
        console.error('[createSalesOrder] Failed to resolve lead to customer:', leadResolveError)
        return { error: `Cannot create Sales Order: the quotation was made for a Lead (${leadId}) which has not been converted to a Customer. Error: ${leadResolveError.message}` }
      }
    }
    // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

    // ΓöÇΓöÇ Resolve default warehouse for stock items ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // ERPNext requires a warehouse for stock items on Sales Orders.
    let defaultWarehouse: string | undefined = undefined
    try {
      // Try to get default warehouse from Stock Settings
      const stockSettings = await frappeRequest('frappe.client.get_value', 'GET', {
        doctype: 'Stock Settings',
        fieldname: 'default_warehouse'
      }) as any
      defaultWarehouse = stockSettings?.default_warehouse
    } catch (e) {
    }
    if (!defaultWarehouse) {
      try {
        // Fallback: get the first available non-group warehouse
        const warehouses = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Warehouse',
          filters: JSON.stringify([['is_group', '=', 0]]),
          fields: '["name"]',
          limit_page_length: 1
        }) as any[]
        if (warehouses && warehouses.length > 0) {
          defaultWarehouse = warehouses[0].name
        }
      } catch (e) {
      }
    }
    // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

    // Process items to preserve rental data if present
    const processedItems = (data.items || []).map((item: any) => {
      const baseItem: any = {
        item_code: item.item_code,
        item_name: item.item_name,
        description: item.description,
        qty: item.qty,
        uom: item.uom || 'Nos',
        rate: item.rate,
        amount: item.amount,
        delivery_date: item.delivery_date || data.delivery_date
      }
      // Include warehouse ΓÇö use form value or default
      if (item.warehouse || defaultWarehouse) {
        baseItem.warehouse = item.warehouse || defaultWarehouse
      }

      // Map rental data to ERPNext custom fields if present (from frontend or quotation)
      if (item.rental_type || item.rental_duration || item.custom_is_rental || item.custom_rental_type) {
        baseItem.custom_is_rental = 1
        // Capitalize rental_type for ERPNext Select field (days -> Days, hours -> Hours, months -> Months)
        const rentalType = item.rental_type || item.custom_rental_type
        if (rentalType && typeof rentalType === 'string') {
          baseItem.custom_rental_type = rentalType.charAt(0).toUpperCase() + rentalType.slice(1)
        }
        baseItem.custom_rental_duration = item.rental_duration || item.custom_rental_duration
        baseItem.custom_rental_start_date = item.rental_start_date || item.custom_rental_start_date
        baseItem.custom_rental_end_date = item.rental_end_date || item.custom_rental_end_date
        baseItem.custom_rental_start_time = item.rental_start_time || item.custom_rental_start_time
        baseItem.custom_rental_end_time = item.rental_end_time || item.custom_rental_end_time
        baseItem.custom_requires_operator = item.requires_operator || item.custom_requires_operator ? 1 : 0
        baseItem.custom_operator_included = item.operator_included || item.custom_operator_included ? 1 : 0
        if (item.operator_name || item.custom_operator_name) {
          baseItem.custom_operator_name = item.operator_name || item.custom_operator_name
        }

        // Map pricing components to ERPNext custom fields
        baseItem.custom_base_rental_cost = item.base_cost || item.custom_base_rental_cost || 0
        baseItem.custom_accommodation_charges = item.accommodation_charges || item.custom_accommodation_charges || 0
        baseItem.custom_usage_charges = item.usage_charges || item.custom_usage_charges || 0
        baseItem.custom_fuel_charges = item.fuel_charges || item.custom_fuel_charges || 0
        baseItem.custom_elongation_charges = item.elongation_charges || item.custom_elongation_charges || 0
        baseItem.custom_risk_charges = item.risk_charges || item.custom_risk_charges || 0
        baseItem.custom_commercial_charges = item.commercial_charges || item.custom_commercial_charges || 0
        baseItem.custom_incidental_charges = item.incidental_charges || item.custom_incidental_charges || 0
        baseItem.custom_other_charges = item.other_charges || item.custom_other_charges || 0
        baseItem.custom_total_rental_cost = item.total_rental_cost || item.custom_total_rental_cost || 0
      }

      return baseItem
    })

    const orderData: any = {
      doctype: 'Sales Order',
      customer: resolvedCustomer,
      transaction_date: data.transaction_date || new Date().toISOString().split('T')[0],
      delivery_date: data.delivery_date,
      currency: data.currency || 'USD',
      items: processedItems
    }

    // Add optional fields
    if (resolvedCustomerName) orderData.customer_name = resolvedCustomerName
    if (data.quotation_no) orderData.quotation_no = data.quotation_no
    if (data.opportunity) orderData.opportunity = data.opportunity
    if (data.contact_email) orderData.contact_email = data.contact_email
    if (data.territory) {
      const validTerritory = await resolveValidTerritory(data.territory)
      if (validTerritory) orderData.territory = validTerritory
    }
    if (data.terms) orderData.terms = data.terms
    if (data.po_no) orderData.po_no = data.po_no
    if (data.po_date) orderData.po_date = data.po_date

    // Add tax template if specified
    if (data.taxes_and_charges) {
      orderData.taxes_and_charges = data.taxes_and_charges

      try {
        // Fetch the tax template to get the tax rows
        const taxTemplate = await frappeRequest('frappe.client.get', 'GET', {
          doctype: 'Sales Taxes and Charges Template',
          name: data.taxes_and_charges
        }) as { taxes?: any[] }

        // Add the tax rows to the sales order
        if (taxTemplate.taxes && taxTemplate.taxes.length > 0) {
          orderData.taxes = taxTemplate.taxes.map((tax: any, idx: number) => ({
            idx: idx + 1,
            doctype: 'Sales Taxes and Charges',
            charge_type: tax.charge_type,
            account_head: tax.account_head,
            description: tax.description,
            rate: tax.rate
          }))
        }
      } catch (taxError) {
        console.error('Error fetching tax template:', taxError)
        // Continue without taxes if template fetch fails
      }
    }

    const result = await frappeRequest('frappe.client.insert', 'POST', { doc: orderData })

    revalidatePath('/sales-orders')
    return { success: true, data: result }
  } catch (error: any) {
    console.error("Failed to create sales order:", error)
    return { error: error.message || 'Failed to create sales order' }
  }
}

