// ========== BANK ACCOUNT MANAGEMENT ==========

export interface BankAccount {
  name: string
  bank: string
  bank_account_no: string
  branch_code?: string // IFSC
  company: string
  is_default: number
}

// Get bank accounts for company
export async function getBankAccounts() {
  try {
    // First get company
    const companies = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Company',
      fields: '["name"]',
      limit_page_length: 1
    }) as any[];
    if (!companies || companies.length === 0) return []
    const companyName = companies[0].name

    const accounts = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Bank Account',
      fields: '["name", "bank", "bank_account_no", "branch_code", "company", "is_default"]',
      filters: `[["company", "=", "${companyName}"]]`,
      order_by: 'is_default desc, creation desc',
      limit_page_length: 10
    })
    return accounts as BankAccount[]
  } catch (error) {
    console.error("Failed to fetch bank accounts:", error)
    return []
  }
}

// Create bank account
export async function createBankAccount(data: {
  bank: string
  bank_account_no: string
  branch_code?: string
  is_default?: boolean
}) {
  try {
    // Get company name
    const companies = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'Company',
      fields: '["name"]',
      limit_page_length: 1
    }) as any[];
    if (!companies || companies.length === 0) {
      return { error: 'No company found. Please set up company first.' }
    }
    const companyName = companies[0].name

    // Ensure the Bank record exists (bank field is a Link to Bank doctype)
    try {
      const existingBanks = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Bank',
        fields: '["name"]',
        filters: JSON.stringify([['name', '=', data.bank]]),
        limit_page_length: 1
      }) as any[]
      if (!existingBanks || existingBanks.length === 0) {
        await frappeRequest('frappe.client.insert', 'POST', {
          doc: { doctype: 'Bank', bank_name: data.bank }
        })
      }
    } catch (e: any) {
      // Ignore duplicate errors ΓÇö bank already exists
      if (!e.message?.includes('Duplicate') && !e.message?.includes('already exists')) {
        console.warn('Could not create Bank record:', e.message)
      }
    }

    const doc = {
      doctype: 'Bank Account',
      account_name: data.bank_account_no, // Required ΓÇö becomes part of the doc name
      bank: data.bank,
      bank_account_no: data.bank_account_no,
      branch_code: data.branch_code || '',
      company: companyName,
      is_default: data.is_default ? 1 : 0,
      is_company_account: 1
    }

    await frappeRequest('frappe.client.insert', 'POST', { doc })
    revalidatePath('/settings')
    return { success: true }
  } catch (error: any) {
    console.error("Failed to create bank account:", error)
    return { error: error.message || 'Failed to create bank account' }
  }
}

// Update bank account
export async function updateBankAccount(name: string, data: {
  bank?: string
  bank_account_no?: string
  branch_code?: string
  is_default?: boolean
}) {
  try {
    await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'Bank Account',
      name: name,
      fieldname: {
        ...(data.bank && { bank: data.bank }),
        ...(data.bank_account_no && { bank_account_no: data.bank_account_no }),
        ...(data.branch_code !== undefined && { branch_code: data.branch_code }),
        ...(data.is_default !== undefined && { is_default: data.is_default ? 1 : 0 })
      }
    })
    revalidatePath('/settings')
    return { success: true }
  } catch (error: any) {
    console.error("Failed to update bank account:", error)
    return { error: error.message || 'Failed to update bank account' }
  }
}

'use server'

import { frappeRequest } from '@/app/lib/api'

/**
 * Setup CRM Master Data for a newly provisioned tenant
 * Creates default Opportunity Types and Sales Stages
 * 
 * This should be called after successful tenant provisioning
 * or can be run manually for existing tenants
 */

const DEFAULT_OPPORTUNITY_TYPES = ['Sales', 'Rental', 'Maintenance', 'Service']
const DEFAULT_SALES_STAGES = [
  'Prospecting',
  'Qualification', 
  'Needs Analysis',
  'Proposal',
  'Negotiation',
  'Won',
  'Lost'
]

interface SetupResult {
  success: boolean
  error?: string
  results?: {
    opportunityTypes: { created: number; existing: number; failed: number }
    salesStages: { created: number; existing: number; failed: number }
  }
}

export async function setupCrmMasterData(): Promise<SetupResult> {
  try {
    console.log('[CRM Setup] Starting CRM master data setup...')
    
    const results = {
      opportunityTypes: { created: 0, existing: 0, failed: 0 },
      salesStages: { created: 0, existing: 0, failed: 0 }
    }

    // Setup Opportunity Types
    for (const typeName of DEFAULT_OPPORTUNITY_TYPES) {
      try {
        const existing = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Opportunity Type',
          filters: { name: typeName },
          limit_page_length: 1
        }) as any[]

        if (existing && existing.length > 0) {
          console.log(`[CRM Setup] Opportunity Type "${typeName}" already exists`)
          results.opportunityTypes.existing++
          continue
        }

        await frappeRequest('frappe.client.insert', 'POST', {
          doc: {
            doctype: 'Opportunity Type',
            name: typeName
          }
        })
        
        console.log(`[CRM Setup] Created Opportunity Type: ${typeName}`)
        results.opportunityTypes.created++
      } catch (error: any) {
        console.error(`[CRM Setup] Failed to create Opportunity Type "${typeName}":`, error.message)
        results.opportunityTypes.failed++
      }
    }

    // Setup Sales Stages
    for (const stageName of DEFAULT_SALES_STAGES) {
      try {
        const existing = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Sales Stage',
          filters: { name: stageName },
          limit_page_length: 1
        }) as any[]

        if (existing && existing.length > 0) {
          console.log(`[CRM Setup] Sales Stage "${stageName}" already exists`)
          results.salesStages.existing++
          continue
        }

        await frappeRequest('frappe.client.insert', 'POST', {
          doc: {
            doctype: 'Sales Stage',
            stage_name: stageName
          }
        })
        
        console.log(`[CRM Setup] Created Sales Stage: ${stageName}`)
        results.salesStages.created++
      } catch (error: any) {
        console.error(`[CRM Setup] Failed to create Sales Stage "${stageName}":`, error.message)
        results.salesStages.failed++
      }
    }

    console.log('[CRM Setup] Setup complete:', results)

    return {
      success: true,
      results
    }

  } catch (error: any) {
    console.error('[CRM Setup] Error:', error)
    return {
      success: false,
      error: error.message
    }
  }
}

'use server'

/**
 * Setup script to create custom ERPNext doctypes for subscription management
 * Run this once to initialize the organization and subscription system
 */

import { frappeRequest } from '@/app/lib/api'

export async function setupERPNextDoctypes() {
  const results = {
    organization: { status: 'skipped', message: 'Already exists' },
    member: { status: 'skipped', message: 'Already exists' }
  }

  try {
    // Check if Organization already exists
    try {
      await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'DocType',
        filters: JSON.stringify({ name: 'Organization' }),
        limit_page_length: 1
      })
      results.organization = { status: 'exists', message: 'Organization DocType already exists' }
    } catch {
      // DocType doesn't exist, create it
      await frappeRequest('frappe.client.insert', 'POST', {
        doc: {
          doctype: 'DocType',
          name: 'Organization',
          module: 'Custom',
          custom: 1,
          is_submittable: 0,
          track_changes: 1,
          fields: [
            {
              fieldname: 'organization_name',
              label: 'Organization Name',
              fieldtype: 'Data',
              reqd: 1,
              in_list_view: 1
            },
            {
              fieldname: 'slug',
              label: 'Slug',
              fieldtype: 'Data',
              reqd: 1,
              unique: 1,
              in_list_view: 1
            },
            {
              fieldname: 'subscription_section',
              label: 'Subscription Details',
              fieldtype: 'Section Break'
            },
            {
              fieldname: 'subscription_plan',
              label: 'Subscription Plan',
              fieldtype: 'Select',
              options: 'free\npro\nenterprise',
              default: 'free',
              reqd: 1,
              in_list_view: 1
            },
            {
              fieldname: 'subscription_status',
              label: 'Subscription Status',
              fieldtype: 'Select',
              options: 'active\ntrial\ncancelled\nexpired',
              default: 'trial',
              reqd: 1,
              in_list_view: 1
            },
            {
              fieldname: 'trial_end',
              label: 'Trial End Date',
              fieldtype: 'Datetime'
            },
            {
              fieldname: 'current_period_start',
              label: 'Current Period Start',
              fieldtype: 'Datetime'
            },
