// Add organization context to existing doctypes
export async function linkOrganizationToExistingDocs() {
  const doctypes = ['Lead', 'Opportunity', 'Quotation', 'Sales Order', 'Sales Invoice', 'Project']
  const results: Record<string, any> = {}

  try {
    for (const doctype of doctypes) {
      try {
        // Check if field already exists
        const existing = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Custom Field',
          filters: JSON.stringify({ dt: doctype, fieldname: 'organization_slug' }),
          limit_page_length: 1
        }) as any[]

        if (existing && existing.length > 0) {
          results[doctype] = { status: 'exists', message: 'Field already exists' }
        } else {
          // Field doesn't exist, create it
          await frappeRequest('frappe.client.insert', 'POST', {
            doc: {
              doctype: 'Custom Field',
              dt: doctype,
              fieldname: 'organization_slug',
              label: 'Organization',
              fieldtype: 'Data',
              insert_after: 'naming_series'
            }
          })
          results[doctype] = { status: 'created', message: 'Field created successfully' }
        }
      } catch (error: any) {
        results[doctype] = { status: 'error', message: error.message }
      }
    }

    return { success: true, message: 'Setup completed', results }
  } catch (error: any) {
    return { success: false, error: error.message }
  }
}

'use server'

import { cookies } from 'next/headers'
import { redirect } from 'next/navigation'
import { provisionTenantSite, checkSubdomain, ProvisioningError } from '@/lib/provisioning-client'
import { masterRequest } from '@/app/lib/api'
import crypto from 'crypto'

/**
 * Social (Google) Onboarding ΓÇö Complete Workspace Setup
 * ======================================================
 * 
 * FLOW:
 * 1. User clicks "Sign in with Google" ΓåÆ NextAuth handles OAuth
 * 2. Google returns { email, name } ΓåÆ NextAuth creates session
 * 3. auth.ts signIn callback ΓåÆ checks if user has a tenant in Master DB
 *    - YES: redirect to `subdomain.avariq.in/dashboard`
 *    - NO:  redirect to `/onboarding` 
 * 4. /onboarding page ΓåÆ asks for Organization Name ΓåÆ calls this function
 * 5. This function provisions the site ΓåÆ redirects to new subdomain
 * 
 * WHY THIS IS SEPARATE FROM REGULAR SIGNUP:
 * - Google users don't provide a password on signup (we generate one)
 * - Google users already have verified email (no need for email verification)
 * - The auth token (NextAuth session) is already valid across subdomains
 *   (cookie domain is `.avariq.in`)
 */
export async function completeSocialOnboarding(data: {
  email: string
  name: string
  organizationName: string
}): Promise<{
  success: boolean
  redirectUrl?: string
  error?: string
}> {

  // ΓöÇΓöÇ Validate Org Name ΓöÇΓöÇ
  if (!data.organizationName || data.organizationName.length < 3) {
    return { success: false, error: 'Organization name must be at least 3 characters' }
  }

  // ΓöÇΓöÇ Check Subdomain Availability ΓöÇΓöÇ
  const subdomain = data.organizationName
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')

  try {
    const check = await checkSubdomain(subdomain)
    if (!check.available) {
      return { success: false, error: `"${subdomain}" is already taken. Choose a different organization name.` }
    }
  } catch (error) {
    console.error('[SocialOnboarding] Subdomain check failed:', error)
    // Continue anyway ΓÇö the provisioning service will catch duplicates
  }

  // ΓöÇΓöÇ Check if User Already Has a Tenant ΓöÇΓöÇ
  try {
    const existing = await masterRequest('frappe.client.get_list', 'GET', {
      doctype: 'SaaS Tenant',
      filters: JSON.stringify({ owner_email: data.email }),
      fields: JSON.stringify(['subdomain', 'site_url']),
      limit_page_length: 1,
    }) as any[]

    if (existing && existing.length > 0) {
      const existingTenant = existing[0]
      const rootDomain = process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'
      const redirectUrl = process.env.NODE_ENV === 'production'
        ? `https://${existingTenant.subdomain}.${rootDomain}/dashboard`
        : `http://${existingTenant.subdomain}.localhost:3000/dashboard`
      return { success: true, redirectUrl }
    }
  } catch (error) {
  }

  // ΓöÇΓöÇ Provision the Tenant via Provisioning Service ΓöÇΓöÇ
  const generatedPassword = crypto.randomBytes(20).toString('base64url')

  try {
    const result = await provisionTenantSite({
      organization_name: data.organizationName,
      admin_email: data.email,
      admin_password: generatedPassword,
      admin_full_name: data.name,
      plan_type: 'Free',
    })

    if (!result.success) {
      console.error('[SocialOnboarding] Provisioning failed:', result.error)
      return { success: false, error: result.error || 'Workspace creation failed' }
    }


    // ΓöÇΓöÇ Store API credentials for the new tenant ΓöÇΓöÇ
    if (result.api_key && result.api_secret) {
      const cookieStore = await cookies()
      const cookieOpts = {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax' as const,
        maxAge: 60 * 60 * 24 * 30,
        path: '/',
        domain: process.env.NODE_ENV === 'production'
          ? `.${process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'}`
          : undefined,
      }
      cookieStore.set('tenant_api_key', result.api_key, cookieOpts)
      cookieStore.set('tenant_api_secret', result.api_secret, cookieOpts)
      cookieStore.set('tenant_subdomain', result.subdomain || '', cookieOpts)
    }

    // ΓöÇΓöÇ Build Redirect URL ΓöÇΓöÇ
    const rootDomain = process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'
    const redirectUrl = process.env.NODE_ENV === 'production'
      ? `https://${result.subdomain}.${rootDomain}/dashboard`
      : `http://${result.subdomain}.localhost:3000/dashboard`

    return { success: true, redirectUrl }

  } catch (error) {
    if (error instanceof ProvisioningError) {
      console.error(`[SocialOnboarding] ProvisioningError: ${error.message}`)
      if (error.status === 503) {
        return { success: false, error: 'Service temporarily unavailable. Please try again.' }
      }
      return { success: false, error: error.message }
    }

    console.error('[SocialOnboarding] Unexpected error:', error)
    return { success: false, error: 'An unexpected error occurred' }
  }
}

/**
 * Check if a Google user already has a tenant.
 * Called from auth.ts signIn callback or from middleware.
 */
export async function lookupTenantByEmail(email: string): Promise<{
  hasTenant: boolean
  subdomain?: string
  siteUrl?: string
}> {
  try {
    const result = await masterRequest('frappe.client.get_list', 'GET', {
      doctype: 'SaaS Tenant',
      filters: JSON.stringify({ owner_email: email, status: 'Active' }),
      fields: JSON.stringify(['subdomain', 'site_url']),
      limit_page_length: 1,
    }) as any[]

    if (result && result.length > 0) {
      return {
        hasTenant: true,
        subdomain: result[0].subdomain,
        siteUrl: result[0].site_url,
      }
    }
    return { hasTenant: false }
  } catch {
    return { hasTenant: false }
  }
}

'use server'

import { frappeRequest } from '@/app/lib/api'
import { canInviteUser, incrementUsage } from './usage-limits'
import { headers, cookies } from 'next/headers'
import { sendInviteEmail } from '@/lib/email'

/**
 * Invite a team member to the current tenant
 * Creates a new user in the tenant's ERPNext site
 */
export async function inviteTeamMember(data: {
  email: string
  fullName: string
  role: string
}): Promise<{ success: boolean; error?: string; limitReached?: boolean; currentUsage?: number; limit?: number | 'unlimited'; tempPassword?: string }> {
  try {
    // Check usage limits first
    const headersList = await headers()
    const subdomain = headersList.get('x-tenant-id') || headersList.get('X-Subdomain')

    // Resolve inviter name + org name for the email (best-effort)
    let inviterName = 'Your team admin'
    let organizationName = 'your organization'
    let loginUrl = process.env.NEXT_PUBLIC_APP_URL || 'https://avariq.in'
    try {
      const cookieStore = await cookies()
      const inviterEmail = cookieStore.get('user_email')?.value
      if (inviterEmail) {
        const inviterData = await frappeRequest('frappe.client.get_value', 'GET', {
          doctype: 'User', filters: inviterEmail, fieldname: 'full_name'
        }) as { full_name?: string }
        if (inviterData?.full_name) inviterName = inviterData.full_name
      }
      const companies = await frappeRequest('frappe.client.get_list', 'GET', {
        doctype: 'Company', fields: '["company_name"]', limit_page_length: 1
      }) as { company_name: string }[]
      if (companies?.[0]?.company_name) organizationName = companies[0].company_name
      if (subdomain) {
        const rootDomain = process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'
        loginUrl = process.env.NODE_ENV === 'production'
          ? `https://${subdomain}.${rootDomain}/login`
          : `http://${subdomain}.localhost:3000/login`
      }
    } catch {
      // Non-fatal ΓÇö fall back to defaults above
    }
    if (subdomain) {
      const usageCheck = await canInviteUser(subdomain)
      if (!usageCheck.allowed) {
        return { 
          success: false,
          error: usageCheck.message || 'User limit reached',
          limitReached: true,
          currentUsage: usageCheck.current,
          limit: usageCheck.limit
        }
      }
    }
    
    // Check if user already exists (including disabled/removed users)
    const existingUsers = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'User',
      filters: `[["email", "=", "${data.email}"]]`,
      fields: '["name", "email", "enabled"]',
      limit_page_length: 1
    }) as any[]
    
    if (existingUsers && existingUsers.length > 0) {
      const existing = existingUsers[0]
      if (existing.enabled) {
        return {
          success: false,
          error: 'A user with this email already exists in your organization'
        }
      }
      // Previously removed (disabled) ΓÇö re-enable and update their role
      // Generate a fresh temp password so the admin can share access again
      const resetPassword = generateTempPassword()
      await frappeRequest('frappe.client.set_value', 'POST', {
        doctype: 'User', name: existing.email, fieldname: 'enabled', value: 1
      })
      await frappeRequest('frappe.client.set_value', 'POST', {
        doctype: 'User', name: existing.email, fieldname: 'new_password', value: resetPassword
      })
      // Re-assign proper roles via provisioning service (ignore_permissions)
      try {
        const { assignUserRoles } = await import('@/lib/provisioning-client')
        const roleNames = (ROLE_SETS[data.role] || ROLE_SETS.member)
        await assignUserRoles(subdomain!, existing.email, roleNames)
      } catch (roleErr: any) {
        console.warn('[inviteTeamMember] Role assignment via provisioning failed (non-fatal):', roleErr.message)
      }
      if (subdomain) await incrementUsage(subdomain, 'usage_users')

      // Send invite email (non-fatal)
      try {
        await sendInviteEmail({
          inviteeName: data.fullName,
          inviteeEmail: data.email,
          organizationName,
          inviterName,
          role: data.role,
          loginUrl,
          tempPassword: resetPassword,
        })
      } catch (emailErr: any) {
        console.warn('[inviteTeamMember] Email delivery failed (non-fatal):', emailErr.message)
      }

      return { success: true, tempPassword: resetPassword }
    }
    
    // Create user in ERPNext.
    // We generate a temp password and return it to the admin to share manually.
    // Frappe's send_welcome_email is disabled because its email link points to the
    // raw Frappe backend URL (127.0.0.1:8000), not our Next.js app.
    const tempPassword = generateTempPassword()
    const userData = {
      doctype: 'User',
      email: data.email,
      first_name: data.fullName,
      enabled: 1,
      send_welcome_email: 0,
      new_password: tempPassword,
      roles: getRolesForType(data.role),
    }
    
    await frappeRequest('frappe.client.insert', 'POST', {
      doc: userData
    })
    
    // Increment usage counter
    if (subdomain) {
      await incrementUsage(subdomain, 'usage_users')
    }

    // Send invite email (non-fatal ΓÇö temp password is also shown in the UI)
    try {
      await sendInviteEmail({
        inviteeName: data.fullName,
        inviteeEmail: data.email,
        organizationName,
        inviterName,
        role: data.role,
        loginUrl,
        tempPassword,
      })
    } catch (emailErr: any) {
      console.warn('[inviteTeamMember] Email delivery failed (non-fatal):', emailErr.message)
    }

    return { success: true, tempPassword }
  } catch (error: any) {
    console.error('Invite team member error:', error)
    return {
      success: false,
      error: error.message || 'Failed to invite team member'
    }
  }
}

/**
 * Get list of team members for current tenant
 */
export async function getTeamMembers(): Promise<any[]> {
  try {
    const users = await frappeRequest('frappe.client.get_list', 'GET', {
      doctype: 'User',
      filters: `[["enabled", "=", 1], ["name", "!=", "Administrator"], ["name", "!=", "Guest"]]`,
      fields: '["name", "email", "first_name", "last_name", "enabled", "creation", "last_login", "user_type", "role_profile_name"]',
      limit_page_length: 100
    }) as any[]
    
    if (!users || users.length === 0) return []

    // Map role_profile_name ΓåÆ roles and primary role (avoids querying Has Role child table
    // which triggers check_parent_permission and causes 403 errors in Frappe v15)
    const PROFILE_ROLES: Record<string, string[]> = {
      'Administrator': ['System Manager'],
      'System Manager': ['System Manager'],
      'Sales Manager': ['Sales Manager', 'Sales User'],
      'Sales User': ['Sales User'],
      'Accounts Manager': ['Accounts Manager', 'Accounts User'],
      'Accounts User': ['Accounts User'],
      'Projects Manager': ['Projects Manager', 'Projects User'],
      'Projects User': ['Projects User'],
      'Stock Manager': ['Stock Manager', 'Stock User'],
      'Stock User': ['Stock User'],
      'Standard User': ['Employee', 'Sales User'],
    }

    const PROFILE_PRIMARY: Record<string, string> = {
      'Administrator': 'System Manager',
      'System Manager': 'System Manager',
      'Sales Manager': 'Sales Manager',
      'Sales User': 'Sales User',
      'Accounts Manager': 'Accounts Manager',
      'Accounts User': 'Accounts User',
      'Projects Manager': 'Projects Manager',
      'Projects User': 'Projects User',
      'Stock Manager': 'Stock Manager',
      'Stock User': 'Stock User',
      'Standard User': 'Employee',
    }

    const { getAccessibleModules } = await import('@/lib/role-permissions')

    return users.map((u: any) => {
      const actualRoles = PROFILE_ROLES[u.role_profile_name] || []
      const primaryRole = PROFILE_PRIMARY[u.role_profile_name] || null
      const accessibleModules = getAccessibleModules(actualRoles)
      // A user is "broken" if they have no role profile set (no access will be granted)
      const hasBrokenRoles = !u.role_profile_name

      return {
        ...u,
        primary_role: primaryRole,
        actual_roles: actualRoles,
        modules_count: accessibleModules.length,
        has_broken_roles: hasBrokenRoles,
      }
    })
  } catch (error) {
    console.error('Failed to fetch team members:', error)
    return []
  }
}

/**
 * Remove a team member (disable user)
 */
export async function removeTeamMember(email: string): Promise<{ success: boolean; error?: string }> {
  try {
    // Don't allow removing Administrator
    if (email === 'Administrator' || email === 'administrator@example.com') {
      return {
        success: false,
        error: 'Cannot remove administrator user'
      }
    }
    
    // Disable the user instead of deleting (best practice)
    await frappeRequest('frappe.client.set_value', 'POST', {
      doctype: 'User',
      name: email,
      fieldname: 'enabled',
      value: 0
    })
    
    // Decrement usage counter
    const headersList = await headers()
    const subdomain = headersList.get('X-Subdomain')
    
    if (subdomain) {
      await incrementUsage(subdomain, 'usage_users', -1)
    }
    
    return { success: true }
  } catch (error: any) {
    console.error('Remove team member error:', error)
    return {
      success: false,
      error: error.message || 'Failed to remove team member'
    }
  }
}

/**
 * Update team member role
 */
export async function updateTeamMemberRole(
  email: string,
  role: string
): Promise<{ success: boolean; error?: string }> {
  try {
    const headersList = await headers()
    const subdomain = headersList.get('x-tenant-id') || headersList.get('X-Subdomain')
    if (!subdomain) {
      return { success: false, error: 'Could not determine tenant' }
    }

    // Use provisioning service to assign roles with ignore_permissions
    const { assignUserRoles } = await import('@/lib/provisioning-client')
    const roleNames = (ROLE_SETS[role] || ROLE_SETS.member)
    await assignUserRoles(subdomain, email, roleNames)

    return { success: true }
  } catch (error: any) {
    console.error('Update role error:', error)
    return {
      success: false,
      error: error.message || 'Failed to update role'
    }
  }
}

// Helpers

function generateTempPassword(): string {
  // 12-char readable password (no ambiguous chars like 0/O/1/l)
  const upper = 'ABCDEFGHJKMNPQRSTUVWXYZ'
  const lower = 'abcdefghjkmnpqrstuvwxyz'
  const digits = '23456789'
  const all = upper + lower + digits
  const rand = (set: string) => set[Math.floor(Math.random() * set.length)]
  // Guarantee at least one of each group, pad to 12
  const base = rand(upper) + rand(upper) + rand(lower) + rand(lower) + rand(digits) + rand(digits)
  const rest = Array.from({ length: 6 }, () => rand(all)).join('')
  // Shuffle
  return (base + rest).split('').sort(() => Math.random() - 0.5).join('')
}

/**
 * Maps each invitation role type to the full set of Frappe roles
 * the user needs on the tenant site.
 *
 * NOTE: We intentionally do NOT use role_profile_name because Frappe
 * silently overrides explicit roles when a profile is set.
 */
import { ROLE_SETS, getRolesForType, getPrimaryRoleForType } from '@/lib/role-sets'

'use server'

import { headers } from 'next/headers'

interface JoinTenantResult {
  success: boolean
  error?: string
  limitReached?: boolean
}

/**
 * Server Action: Join a Tenant as a new user
 * 
 * Called from tesla.avariq.in/signup.
 * 
 * Steps:
 * 1. Read x-tenant-id header (injected by middleware)
 * 2. Check SaaS Settings.max_users limit on the tenant site
 * 3. Check if user already exists
 * 4. Create User in ERPNext via frappe.client.insert
 * 
 * The tenant site name is derived from x-tenant-id header.
 */
export async function joinTenant(formData: FormData): Promise<JoinTenantResult> {
  try {
    const fullName = formData.get('fullName') as string
    const email = formData.get('email') as string
    const password = formData.get('password') as string

    // ΓöÇΓöÇ Validate inputs ΓöÇΓöÇ
    if (!fullName || !email || !password) {
      return { success: false, error: 'All fields are required.' }
    }

    if (password.length < 8) {
      return { success: false, error: 'Password must be at least 8 characters.' }
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!emailRegex.test(email)) {
      return { success: false, error: 'Invalid email address.' }
    }

    // ΓöÇΓöÇ Get tenant from middleware header ΓöÇΓöÇ
    const headersList = await headers()
    const tenantId = headersList.get('x-tenant-id')

    if (!tenantId || tenantId === 'master') {
      return {
        success: false,
        error: 'Cannot create user on the root domain. Please use a workspace URL.',
      }
    }

    // ΓöÇΓöÇ Resolve tenant site name ΓöÇΓöÇ
    const rootDomain = process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'
    const isProduction = process.env.NODE_ENV === 'production'
    const tenantSiteName = isProduction
      ? `${tenantId}.${rootDomain}`
      : `${tenantId}.localhost`

    const masterUrl = process.env.ERP_NEXT_URL || 'http://127.0.0.1:8080'
    const apiKey = process.env.ERP_API_KEY
    const apiSecret = process.env.ERP_API_SECRET

    if (!apiKey || !apiSecret) {
      console.error('[joinTenant] Missing master API credentials')
      return { success: false, error: 'Server configuration error.' }
    }

    const authHeader = `token ${apiKey}:${apiSecret}`

    // ΓöÇΓöÇ Step 1: Check user limit from SaaS Settings (fail-loud) ΓöÇΓöÇ
    let maxUsers: number
    try {
      const settingsRes = await fetch(
        `${masterUrl}/api/method/frappe.client.get_single_value`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: authHeader,
            'X-Frappe-Site-Name': tenantSiteName,
            Host: tenantSiteName,
          },
          body: JSON.stringify({
            doctype: 'SaaS Settings',
            field: 'max_users',
          }),
        },
      )
      if (!settingsRes.ok) {
        const errText = await settingsRes.text().catch(() => 'unknown')
        throw new Error(
          `Failed to fetch SaaS Settings from ${tenantSiteName}: ${settingsRes.status} ${errText}`
        )
      }
      const settingsData = await settingsRes.json()
      const val = settingsData.message
      if (typeof val !== 'number' || val <= 0) {
        throw new Error(
          `Invalid max_users value from SaaS Settings for ${tenantSiteName}: ${val}`
        )
      }
      maxUsers = val
    } catch (err: any) {
      console.error('[joinTenant] SaaS Settings fetch failed:', err)
      throw new Error(
        `Unable to verify workspace capacity. Please contact support. (${err.message})`
      )
    }

    // ΓöÇΓöÇ Step 2: Count existing users (fail-closed) ΓöÇΓöÇ
    let currentUserCount: number
    try {
      const countRes = await fetch(
        `${masterUrl}/api/method/frappe.client.get_count`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: authHeader,
            'X-Frappe-Site-Name': tenantSiteName,
            Host: tenantSiteName,
          },
          body: JSON.stringify({
            doctype: 'User',
            filters: { enabled: 1, user_type: 'System User' },
          }),
        },
      )
      if (!countRes.ok) {
        const errText = await countRes.text().catch(() => 'unknown')
        throw new Error(
          `Failed to count users on ${tenantSiteName}: ${countRes.status} ${errText}`
        )
      }
      const countData = await countRes.json()
      if (typeof countData.message !== 'number') {
        throw new Error(
          `Invalid user count response from ${tenantSiteName}: ${countData.message}`
        )
      }
      currentUserCount = countData.message
    } catch (err: any) {
      console.error('[joinTenant] User count fetch failed:', err)
      throw new Error(
        `Unable to verify current user count. Please try again later. (${err.message})`
      )
    }

    // NOTE: TOCTOU race condition exists between count check and user creation.
    // TODO: Replace with atomic server-side endpoint (e.g., "create_user_if_under_limit")
    // or distributed locking mechanism to ensure count + create happens atomically.
    if (currentUserCount >= maxUsers) {
      return {
        success: false,
        limitReached: true,
        error: `This workspace has reached its user limit (${maxUsers}). Ask the workspace admin to upgrade the plan.`,
      }
    }

    // ΓöÇΓöÇ Step 3: Check if user already exists ΓöÇΓöÇ
    try {
      const existsRes = await fetch(
        `${masterUrl}/api/method/frappe.client.get_count`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: authHeader,
            'X-Frappe-Site-Name': tenantSiteName,
            Host: tenantSiteName,
          },
          body: JSON.stringify({
            doctype: 'User',
            filters: { name: email },
          }),
        },
      )
      if (existsRes.ok) {
        const existsData = await existsRes.json()
        if (existsData.message && existsData.message > 0) {
          return {
            success: false,
            error: 'A user with this email already exists on this workspace.',
          }
        }
      }
    } catch (err) {
      console.warn('[joinTenant] User existence check failed:', err)
    }

    // ΓöÇΓöÇ Step 4: Validate and parse name ΓöÇΓöÇ
    const trimmedName = fullName.trim()
    if (!trimmedName) {
      return { success: false, error: 'Full name cannot be empty.' }
    }
    const nameParts = trimmedName.split(' ').filter(part => part.length > 0)
    if (nameParts.length === 0) {
      return { success: false, error: 'Please provide a valid full name.' }
    }
    const firstName = nameParts[0]
    const lastName = nameParts.slice(1).join(' ')

    // ΓöÇΓöÇ Step 5: Create user via frappe.client.insert ΓöÇΓöÇ

    const createRes = await fetch(
      `${masterUrl}/api/method/frappe.client.insert`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader,
          'X-Frappe-Site-Name': tenantSiteName,
          Host: tenantSiteName,
        },
        body: JSON.stringify({
          doc: {
            doctype: 'User',
            email,
            first_name: firstName,
            last_name: lastName || undefined,
            new_password: password,
            send_welcome_email: 0,
            user_type: 'System User',
            enabled: 1,
            roles: [
              { role: 'Self Registered' }, // Restricted default role; admin must promote
            ],
          },
        }),
      },
    )

    if (!createRes.ok) {
      const errData = await createRes.json().catch(() => ({}))
      const errMsg =
        errData?.exc_type === 'DuplicateEntryError'
          ? 'A user with this email already exists.'
          : errData?.message || 'Failed to create user account.'
      console.error('[joinTenant] User creation failed:', errData)
      return { success: false, error: errMsg }
    }

    const createdUser = await createRes.json()
    const userId = createdUser?.message?.name || 'unknown'
    console.log(`[joinTenant] Γ£à User created on tenant ${tenantId} (ID: ${userId})`)

    return { success: true }
  } catch (error: any) {
    console.error('[joinTenant] Unexpected error:', error)
    return {
      success: false,
      error: 'An unexpected error occurred. Please try again.',
    }
  }
}

'use server'

import { frappeRequest } from '@/app/lib/api'
import { PLAN_FEATURES, type SubscriptionPlan } from '@/types/tenant'

interface UsageCheck {
  allowed: boolean
  current: number
  limit: number | 'unlimited'
  message?: string
}

/**
 * Get current tenant subscription and usage from master DB
 */
async function getTenantUsage(subdomain: string) {
  try {
    const masterUrl = process.env.ERP_NEXT_URL || 'http://103.224.243.242:8080'
    const apiKey = process.env.ERP_API_KEY
    const apiSecret = process.env.ERP_API_SECRET
    
    const response = await fetch(`${masterUrl}/api/method/frappe.client.get_list`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `token ${apiKey}:${apiSecret}`
      },
      body: JSON.stringify({
        doctype: 'Tenant',
        filters: { subdomain },
        fields: ['plan', 'usage_users', 'usage_leads', 'usage_projects', 'usage_invoices', 'usage_storage'],
        limit_page_length: 1
      })
    })
    
    if (!response.ok) return null
    
    const result = await response.json()
    if (result.message && result.message.length > 0) {
      return result.message[0]
    }
    
    return null
  } catch (error) {
    console.error('Failed to get tenant usage:', error)
    return null
  }
}

/**
 * Check if user can create a new lead
 */
export async function canCreateLead(subdomain: string): Promise<UsageCheck> {
  const tenant = await getTenantUsage(subdomain)
  
  if (!tenant) {
    return { allowed: false, current: 0, limit: 0, message: 'Tenant not found' }
  }
  
  const plan = tenant.plan as SubscriptionPlan
  const features = PLAN_FEATURES[plan]
  const current = tenant.usage_leads || 0
  const limit = features.features.leads
  
  if (limit === 'unlimited') {
    return { allowed: true, current, limit }
  }
  
  if (current >= limit) {
    return {
      allowed: false,
      current,
      limit,
      message: `You've reached your limit of ${limit} leads on the ${features.name} plan. Upgrade to create more.`
    }
  }
  
  return { allowed: true, current, limit }
}

