import { NextRequest, NextResponse } from 'next/server'
import { frappeRequest } from '@/app/lib/api'
import { requireAuth } from '@/app/api/_lib/auth'

export const dynamic = 'force-dynamic'

// Default Opportunity Types for Equipment Rental business
const DEFAULT_OPPORTUNITY_TYPES = ['Sales', 'Rental', 'Maintenance', 'Service']

// Default Sales Stages with typical progression
const DEFAULT_SALES_STAGES = [
  'Prospecting',
  'Qualification', 
  'Needs Analysis',
  'Proposal',
  'Negotiation',
  'Won',
  'Lost'
]

export async function POST(req: NextRequest) {
  const auth = await requireAuth()
  if (!auth.authenticated) return auth.response

  try {
    
    const results = {
      opportunityTypes: { created: 0, existing: 0, failed: 0 },
      salesStages: { created: 0, existing: 0, failed: 0 }
    }

    // Setup Opportunity Types
    for (const typeName of DEFAULT_OPPORTUNITY_TYPES) {
      try {
        const existing = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Opportunity Type',
          filters: { name: typeName },
          limit_page_length: 1
        }) as any[]

        if (existing && existing.length > 0) {
          results.opportunityTypes.existing++
          continue
        }

        await frappeRequest('frappe.client.insert', 'POST', {
          doc: {
            doctype: 'Opportunity Type',
            name: typeName
          }
        })
        
        results.opportunityTypes.created++
      } catch (error: any) {
        console.error(`[CRM Setup] Failed to create Opportunity Type "${typeName}":`, error.message)
        results.opportunityTypes.failed++
      }
    }

    // Setup Sales Stages
    for (const stageName of DEFAULT_SALES_STAGES) {
      try {
        const existing = await frappeRequest('frappe.client.get_list', 'GET', {
          doctype: 'Sales Stage',
          filters: { name: stageName },
          limit_page_length: 1
        }) as any[]

        if (existing && existing.length > 0) {
          results.salesStages.existing++
          continue
        }

        await frappeRequest('frappe.client.insert', 'POST', {
          doc: {
            doctype: 'Sales Stage',
            stage_name: stageName
          }
        })
        
        results.salesStages.created++
      } catch (error: any) {
        console.error(`[CRM Setup] Failed to create Sales Stage "${stageName}":`, error.message)
        results.salesStages.failed++
      }
    }


    return NextResponse.json({
      success: true,
      message: 'CRM master data setup complete',
      results
    })

  } catch (error: any) {
    console.error('[CRM Setup] Error:', error)
    return NextResponse.json(
      { success: false, error: error.message },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { frappeRequest } from '@/app/lib/api'
import { getTenant } from '@/lib/tenant'
import { seedTenantDefaults } from '@/lib/provisioning-client'
import { requireAuth } from '@/app/api/_lib/auth'

/**
 * One-time tenant initialization endpoint.
 * Creates the Standard Selling Price List and sets it as default.
 * 
 * Hit this once per tenant: GET /api/setup/init
 * Requires authentication (user session or provisioning secret).
 */
export async function GET(request: NextRequest) {
    // Allow provisioning service calls with secret header
    const provSecret = request.headers.get('x-provisioning-secret')
    const expectedSecret = process.env.PROVISIONING_API_SECRET
    const hasProvAuth = expectedSecret && provSecret && provSecret === expectedSecret

    // Also allow tenant API key auth (from provisioning auto-init)
    const hasTenantKey = request.headers.get('x-tenant-api-key')

    if (!hasProvAuth && !hasTenantKey) {
      const auth = await requireAuth()
      if (!auth.authenticated) return auth.response
    }

    const results: Record<string, string> = {}

    // 1. Check if Price List already exists
    try {
        const existing = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Price List',
            filters: '[["selling","=","1"]]',
            fields: '["name"]',
            limit_page_length: 5
        }) as { name: string }[]

        if (existing?.length > 0) {
            results.price_list = `Already exists: ${existing.map(p => p.name).join(', ')}`
        } else {
            // Create it
            const created = await frappeRequest('frappe.client.insert', 'POST', {
                doc: {
                    doctype: 'Price List',
                    price_list_name: 'Standard Selling',
                    selling: 1,
                    buying: 0,
                    enabled: 1,
                    currency: 'INR'
                }
            }) as { name: string }
            results.price_list = `Created: ${created.name}`
        }
    } catch (e: any) {
        results.price_list = `Error: ${e.message}`
    }

    // 2. Set default in Selling Settings
    try {
        const settings = await frappeRequest('frappe.client.get_value', 'GET', {
            doctype: 'Selling Settings',
            fieldname: 'selling_price_list'
        }) as { selling_price_list?: string }

        if (!settings?.selling_price_list) {
            await frappeRequest('frappe.client.set_value', 'POST', {
                doctype: 'Selling Settings',
                name: 'Selling Settings',
                fieldname: 'selling_price_list',
                value: 'Standard Selling'
            })
            results.selling_settings = 'Set Standard Selling as default'
        } else {
            results.selling_settings = `Already set: ${settings.selling_price_list}`
        }
    } catch (e: any) {
        results.selling_settings = `Error: ${e.message}`
    }

    // 3. Ensure default Territory tree exists (root + at least one leaf)
    //    Territory requires System Manager permission to create via REST.
    //    Delegate to the provisioning service (runs with ignore_permissions=True).
    try {
        const existingTerritories = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Territory',
            fields: '["name"]',
            limit_page_length: 5
        }) as { name: string }[]

        if (existingTerritories && existingTerritories.length > 0) {
            results.territory = `Already exists: ${existingTerritories.map(t => t.name).join(', ')}`
        } else {
            // Seed via provisioning service (bypasses permission checks)
            try {
                const subdomain = await getTenant()
                const seedResult = await seedTenantDefaults(subdomain)
                results.territory = `Seeded: ${seedResult.result.territory}`
            } catch (seedErr: any) {
                results.territory = `Missing ΓÇö provisioning service unavailable: ${seedErr.message}`
            }
        }
    } catch (e: any) {
        results.territory = `Error: ${e.message}`
    }
    // 4. Ensure default Modes of Payment exist
    try {
        const existingModes = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Mode of Payment',
            fields: '["name"]',
            limit_page_length: 5
        }) as { name: string }[]

        if (existingModes && existingModes.length > 0) {
            results.modes_of_payment = `Already exists: ${existingModes.map(m => m.name).join(', ')}`
        } else {
            const defaultModes = ['Cash', 'Bank Transfer', 'UPI', 'Cheque', 'NEFT', 'RTGS']
            const created: string[] = []
            for (const modeName of defaultModes) {
                try {
                    await frappeRequest('frappe.client.insert', 'POST', {
                        doc: {
                            doctype: 'Mode of Payment',
                            mode_of_payment: modeName,
                            type: modeName === 'Cash' ? 'Cash' : 'Bank'
                        }
                    })
                    created.push(modeName)
                } catch (e: any) {
                    // Skip if already exists (race condition or partial run)
                    if (!e.message?.includes('Duplicate')) {
                        console.warn(`Failed to create Mode of Payment "${modeName}":`, e.message)
                    }
                }
            }
            results.modes_of_payment = `Created: ${created.join(', ')}`
        }
    } catch (e: any) {
        results.modes_of_payment = `Error: ${e.message}`
    }

    // 5. Ensure default Customer Groups exist
    //    Customer Group tree requires System Manager permission to create via REST.
    //    Delegate to the provisioning service (runs with ignore_permissions=True).
    try {
        const existingGroups = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Customer Group',
            fields: '["name"]',
            filters: JSON.stringify([['is_group', '=', 0]]),
            limit_page_length: 5
        }) as { name: string }[]

        if (existingGroups && existingGroups.length > 0) {
            results.customer_groups = `Already exists: ${existingGroups.map(g => g.name).join(', ')}`
        } else {
            // Seed via provisioning service (bypasses permission checks)
            try {
                const subdomain = await getTenant()
                const seedResult = await seedTenantDefaults(subdomain)
                results.customer_groups = `Seeded: ${seedResult.result.customer_group}`
            } catch (seedErr: any) {
                results.customer_groups = `Missing ΓÇö provisioning service unavailable: ${seedErr.message}`
            }
        }
    } catch (e: any) {
        results.customer_groups = `Error: ${e.message}`
    }

    // 6. Ensure default Item Groups exist
    try {
        const existingItemGroups = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Item Group',
            fields: '["name"]',
            filters: JSON.stringify([['is_group', '=', 0]]),
            limit_page_length: 5
        }) as { name: string }[]

        if (existingItemGroups && existingItemGroups.length > 0) {
            results.item_groups = `Already exists: ${existingItemGroups.map(g => g.name).join(', ')}`
        } else {
            // Ensure root group exists
            let rootGroup = 'All Item Groups'
            try {
                const roots = await frappeRequest('frappe.client.get_list', 'GET', {
                    doctype: 'Item Group',
                    fields: '["name"]',
                    filters: JSON.stringify([['is_group', '=', 1]]),
                    limit_page_length: 1
                }) as { name: string }[]
                if (roots?.[0]?.name) rootGroup = roots[0].name
                else {
                    const r = await frappeRequest('frappe.client.insert', 'POST', {
                        doc: { doctype: 'Item Group', item_group_name: 'All Item Groups', is_group: 1 }
                    }) as { name: string }
                    rootGroup = r.name
                }
            } catch (e) { /* root may already exist */ }

            const leafGroups = ['Crane', 'Service', 'Spare Parts', 'Equipment', 'Consumables']
            const created: string[] = []
            for (const groupName of leafGroups) {
                try {
                    await frappeRequest('frappe.client.insert', 'POST', {
                        doc: { doctype: 'Item Group', item_group_name: groupName, parent_item_group: rootGroup, is_group: 0 }
                    })
                    created.push(groupName)
                } catch (e: any) {
                    if (!e.message?.includes('Duplicate')) console.warn(`Item Group "${groupName}":`, e.message)
                }
            }
            results.item_groups = `Created: ${created.join(', ')}`
        }
    } catch (e: any) {
        results.item_groups = `Error: ${e.message}`
    }

    // 7. Provision default Employee Designations
    try {
        const defaultDesignations = ['Operator', 'Senior Operator', 'Supervisor', 'Technician', 'Site Engineer']
        const existingDesignations = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Designation',
            fields: '["name"]',
            limit_page_length: 100
        }) as { name: string }[]
        const existingNames = (existingDesignations || []).map(d => d.name)
        const created: string[] = []
        for (const desig of defaultDesignations) {
            if (!existingNames.includes(desig)) {
                try {
                    await frappeRequest('frappe.client.insert', 'POST', {
                        doc: { doctype: 'Designation', designation_name: desig }
                    })
                    created.push(desig)
                } catch (e: any) {
                    if (!e.message?.includes('Duplicate') && !e.message?.includes('already exists')) {
                        console.warn(`Designation "${desig}":`, e.message)
                    }
                }
            }
        }
        results.designations = created.length > 0 ? `Created: ${created.join(', ')}` : 'All designations already exist'
    } catch (e: any) {
        results.designations = `Error: ${e.message}`
    }

    // 7a. Provision default Role Profiles
    try {
        const defaultRoleProfiles = [
            { name: 'Administrator', roles: ['System Manager', 'All'] },
            { name: 'Standard User', roles: ['Employee'] },
            { name: 'Sales User', roles: ['Employee', 'Sales User'] },
            { name: 'Sales Manager', roles: ['Employee', 'Sales Manager', 'Sales User'] },
            { name: 'Projects User', roles: ['Employee', 'Projects User'] },
            { name: 'Projects Manager', roles: ['Employee', 'Projects Manager', 'Projects User'] },
            { name: 'Accounts User', roles: ['Employee', 'Accounts User'] },
            { name: 'Accounts Manager', roles: ['Employee', 'Accounts Manager', 'Accounts User'] }
        ]

        const existingProfiles = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Role Profile',
            fields: '["name"]',
            limit_page_length: 100
        }) as { name: string }[]
        const existingNames = (existingProfiles || []).map(p => p.name)

        const created: string[] = []
        for (const profile of defaultRoleProfiles) {
            if (!existingNames.includes(profile.name)) {
                try {
                    await frappeRequest('frappe.client.insert', 'POST', {
                        doc: {
                            doctype: 'Role Profile',
                            role_profile: profile.name,
                            roles: profile.roles.map(r => ({ role: r }))
                        }
                    })
                    created.push(profile.name)
                } catch (e: any) {
                    if (!e.message?.includes('Duplicate') && !e.message?.includes('already exists')) {
                        console.warn(`Role Profile "${profile.name}":`, e.message)
                    }
                }
            }
        }
        results.role_profiles = created.length > 0 ? `Created: ${created.join(', ')}` : 'All Role Profiles already exist'
    } catch (e: any) {
        results.role_profiles = `Error: ${e.message}`
    }

    // 7a. Provision default Gender values (required for Employee doctype)
    try {
        const defaultGenders = ['Male', 'Female', 'Other']
        const existingGenders = await frappeRequest('frappe.client.get_list', 'GET', {
            doctype: 'Gender',
            fields: '["name"]',
            limit_page_length: 100
        }) as { name: string }[]
        const existingNames = (existingGenders || []).map(g => g.name)
        const created: string[] = []
        for (const gender of defaultGenders) {
            if (!existingNames.includes(gender)) {
                try {
                    await frappeRequest('frappe.client.insert', 'POST', {
                        doc: { doctype: 'Gender', gender: gender }
                    })
                    created.push(gender)
                } catch (e: any) {
                    if (!e.message?.includes('Duplicate') && !e.message?.includes('already exists')) {
                        console.warn(`Gender "${gender}":`, e.message)
                    }
                }
            }
        }
        results.genders = created.length > 0 ? `Created: ${created.join(', ')}` : 'All genders already exist'
    } catch (e: any) {
        results.genders = `Error: ${e.message}`
    }

    // 8. Ensure the API user has all required roles
    try {
        // Get current user
        const currentUser = await frappeRequest('frappe.auth.get_logged_user', 'GET', {}) as string
        if (currentUser && currentUser !== 'Administrator' && currentUser !== 'Guest') {
            const requiredRoles = [
                'System Manager',
                'Sales Manager', 'Sales User',
                'Stock Manager', 'Stock User',
                'Accounts Manager', 'Accounts User',
                'Projects Manager', 'Projects User',
                'HR Manager', 'HR User',
                'Quality Manager',
                'Manufacturing Manager', 'Manufacturing User',
            ]

            // Get user's existing roles
            let existingRoles: string[] = []
            try {
                const user = await frappeRequest('frappe.client.get', 'GET', {
                    doctype: 'User',
                    name: currentUser,
                }) as any
                existingRoles = (user?.roles || []).map((r: any) => r.role)
            } catch { /* ignore */ }

            const missingRoles = requiredRoles.filter(r => !existingRoles.includes(r))
            if (missingRoles.length === 0) {
                results.user_roles = `All roles already assigned to ${currentUser}`
            } else {
                // Add missing roles
                for (const role of missingRoles) {
                    try {
                        await frappeRequest('frappe.client.insert', 'POST', {
                            doc: {
                                doctype: 'Has Role',
                                parent: currentUser,
                                parenttype: 'User',
                                parentfield: 'roles',
                                role: role
                            }
                        })
                    } catch (e: any) {
                        // Ignore duplicate errors
                        if (!e.message?.includes('Duplicate') && !e.message?.includes('already exists')) {
                            console.warn(`Role "${role}":`, e.message)
                        }
                    }
                }
                results.user_roles = `Added roles to ${currentUser}: ${missingRoles.join(', ')}`
            }
        } else {
            results.user_roles = `Skipped: user is ${currentUser}`
        }
    } catch (e: any) {
        results.user_roles = `Error: ${e.message}`
    }

    // 9. Configure outbound email account for this tenant site
    // Uses a single shared SMTP account (env vars) ΓÇö standard SaaS pattern.
    // Required env vars:
    //   SMTP_HOST          e.g. smtp.sendgrid.net or smtp.gmail.com
    //   SMTP_PORT          e.g. 587 (TLS) or 465 (SSL)
    //   SMTP_USE_TLS       "1" for yes
    //   SMTP_EMAIL         the "from" address, e.g. no-reply@avariq.in
    //   SMTP_PASSWORD      SMTP password or app password
    //   SMTP_DISPLAY_NAME  e.g. "Avariq ERP"  (optional, defaults to SMTP_EMAIL)
    const smtpHost = process.env.SMTP_HOST
    const smtpPort = parseInt(process.env.SMTP_PORT || '587', 10)
    const smtpEmail = process.env.SMTP_EMAIL
    const smtpPassword = process.env.SMTP_PASSWORD
    const smtpTls = process.env.SMTP_USE_TLS !== '0'
    const smtpDisplayName = process.env.SMTP_DISPLAY_NAME || smtpEmail

    if (!smtpHost || !smtpEmail || !smtpPassword) {
        results.email = 'Skipped: SMTP_HOST / SMTP_EMAIL / SMTP_PASSWORD not set in environment'
    } else {
        // Email Account doctype requires System Manager. When setup/init is
        // triggered by a non-admin tenant user's cookies (rather than the
        // admin-key headers from update-credentials), this will always 403.
        // Check for admin-level headers that update-credentials passes.
        const hasAdminHeaders = request.headers.get('x-tenant-api-key') && request.headers.get('x-tenant-api-secret')
        if (!hasAdminHeaders) {
            results.email = 'Skipped: requires admin credentials (run via provisioning)'
        } else {
            try {
                const existingEmail = await frappeRequest('frappe.client.get_list', 'GET', {
                    doctype: 'Email Account',
                    filters: JSON.stringify([['enable_outgoing', '=', 1]]),
                    fields: '["name"]',
                    limit_page_length: 1
                }) as { name: string }[]

                if (existingEmail && existingEmail.length > 0) {
                    results.email = `Already configured: ${existingEmail[0].name}`
                } else {
                    await frappeRequest('frappe.client.insert', 'POST', {
                        doc: {
                            doctype: 'Email Account',
                            email_account_name: smtpDisplayName,
                            email_id: smtpEmail,
                            enable_outgoing: 1,
                            smtp_server: smtpHost,
                            smtp_port: smtpPort,
                            use_tls: smtpTls ? 1 : 0,
                            password: smtpPassword,
                            default_outgoing: 1,
                            enable_incoming: 0,
                        }
                    })
                    results.email = `Configured outgoing SMTP: ${smtpEmail} via ${smtpHost}:${smtpPort}`
                }
            } catch (e: any) {
                results.email = `Error configuring email: ${e.message}`
            }
        }
    }

    return NextResponse.json({ success: true, results })
}

import { NextRequest, NextResponse } from 'next/server'
import { headers } from 'next/headers'
import { requireAuth } from '@/app/api/_lib/auth'

export async function GET(request: NextRequest) {
  const auth = await requireAuth()
  if (!auth.authenticated) return auth.response

  try {
    const headersList = await headers()
    const subdomain = headersList.get('X-Subdomain')
    const tenantMode = headersList.get('X-Tenant-Mode')

    if (tenantMode === 'master' || !subdomain) {
      // On master site, return enterprise plan (admin access)
      return NextResponse.json({
        plan: 'enterprise',
        tenant: null
      })
    }

    // Fetch tenant info from master database
    const masterUrl = process.env.ERP_NEXT_URL || 'http://103.224.243.242:8080'
    const apiKey = process.env.ERP_API_KEY
    const apiSecret = process.env.ERP_API_SECRET

    const response = await fetch(`${masterUrl}/api/method/frappe.client.get_list`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `token ${apiKey}:${apiSecret}`
      },
      body: JSON.stringify({
        doctype: 'Tenant',
        filters: { subdomain },
        fields: ['name', 'plan', 'status', 'company_name'],
        limit_page_length: 1
      })
    })

    if (!response.ok) {
      throw new Error('Failed to fetch tenant info')
    }

    const result = await response.json()
    
    if (!result.message || result.message.length === 0) {
      return NextResponse.json({
        plan: 'free',
        tenant: null
      })
    }

    const tenant = result.message[0]

    return NextResponse.json({
      plan: tenant.plan || 'free',
      status: tenant.status,
      tenant: {
        name: tenant.company_name,
        subdomain
      }
    })

  } catch (error: any) {
    console.error('Get subscription error:', error)
    return NextResponse.json(
      { error: 'Failed to fetch subscription' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'

const BASE_URL = process.env.ERP_NEXT_URL || 'http://127.0.0.1:8080'
const API_KEY = process.env.ERP_API_KEY
const API_SECRET = process.env.ERP_API_SECRET
const MASTER_SITE_NAME = process.env.FRAPPE_SITE_NAME || 'erp.localhost'
const PROVISIONING_SECRET = process.env.PROVISIONING_API_SECRET

/**
 * API endpoint for provision script to update tenant API credentials
 * POST /api/tenant/update-credentials
 * Body: { tenantName, apiKey, apiSecret, ownerEmail?, siteUrl? }
 * Auth: Requires X-Provisioning-Secret header matching PROVISIONING_API_SECRET
 */
export async function POST(request: NextRequest) {
  try {
    // Server-to-server auth: verify provisioning secret
    const providedSecret = request.headers.get('x-provisioning-secret')
    if (!PROVISIONING_SECRET || !providedSecret || providedSecret !== PROVISIONING_SECRET) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { tenantName, apiKey, apiSecret, ownerEmail, siteUrl: providedSiteUrl } = await request.json()

    if (!tenantName || !apiKey || !apiSecret) {
      return NextResponse.json(
        { error: 'Missing required fields: tenantName, apiKey, apiSecret' },
        { status: 400 }
      )
    }

    if (!API_KEY || !API_SECRET) {
      return NextResponse.json(
        { error: 'Server configuration error: Master API credentials not found' },
        { status: 500 }
      )
    }

    const authHeader = `token ${API_KEY}:${API_SECRET}`
    const siteUrl = providedSiteUrl || `https://${tenantName}.avariq.in`


    // STEP 1: Find the tenant record by subdomain field (NOT by name)
    const searchParams = new URLSearchParams({
      doctype: 'SaaS Tenant',
      filters: JSON.stringify([['subdomain', '=', tenantName]]),
      fields: JSON.stringify(['name', 'subdomain', 'owner_email']),
      limit_page_length: '1'
    })

    const searchUrl = `${BASE_URL}/api/method/frappe.client.get_list?${searchParams}`

    const findResponse = await fetch(searchUrl, {
      method: 'GET',
      headers: {
        'Authorization': authHeader,
        'X-Frappe-Site-Name': MASTER_SITE_NAME,
      },
    })

    let tenantRecordName: string | null = null
    let shouldCreateRecord = false

    if (!findResponse.ok) {
      shouldCreateRecord = true
    } else {
      const findData = await findResponse.json()
      const tenants = findData.message || []

      if (tenants.length === 0) {
        shouldCreateRecord = true
      } else {
        tenantRecordName = tenants[0].name
      }
    }

    // STEP 2: UPSERT Logic - Update existing or Create new
    if (shouldCreateRecord) {
      // CREATE: Tenant record doesn't exist, create it now

      const createEndpoint = `${BASE_URL}/api/resource/SaaS Tenant`
      const createResponse = await fetch(createEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': authHeader,
          'X-Frappe-Site-Name': MASTER_SITE_NAME,
        },
        body: JSON.stringify({
          subdomain: tenantName,
          site_url: siteUrl,
          status: 'Active',
          api_key: apiKey,
          api_secret: apiSecret,
          owner_email: ownerEmail,
          site_config: JSON.stringify({
            created_at: new Date().toISOString(),
            provisioned: true
          })
        }),
      })

      if (!createResponse.ok) {
        const errorData = await createResponse.json()
        console.error('Γ¥î Failed to create tenant record:', errorData)

        // Don't fail provisioning just because metadata creation failed
        return NextResponse.json({
          success: true,
          warning: 'Site provisioned successfully but failed to create master DB record',
          error: errorData.exception || errorData.message
        }, { status: 207 }) // 207 Multi-Status
      }

      const createData = await createResponse.json()
      tenantRecordName = createData.data?.name || tenantName

    } else {
      // UPDATE: Tenant record exists, update with API credentials
      const updateEndpoint = `${BASE_URL}/api/resource/SaaS Tenant/${tenantRecordName}`


      const updateResponse = await fetch(updateEndpoint, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': authHeader,
          'X-Frappe-Site-Name': MASTER_SITE_NAME,
        },
        body: JSON.stringify({
          api_key: apiKey,
          api_secret: apiSecret,
          site_url: siteUrl,
          status: 'Active',
          ...(ownerEmail && { owner_email: ownerEmail }),
        }),
      })

      if (!updateResponse.ok) {
        const errorData = await updateResponse.json()
        console.error('Γ¥î Failed to update tenant:', errorData)

        // Don't fail provisioning just because metadata update failed
        return NextResponse.json({
          success: true,
          warning: 'Site provisioned successfully but failed to update master DB record',
          error: errorData.exception || errorData.message
        }, { status: 207 }) // 207 Multi-Status
      }

    }

    // ΓöÇΓöÇΓöÇ STEP 3: Auto-run setup/init on the tenant site to seed default data ΓöÇΓöÇΓöÇΓöÇ
    // This provisions: Price List, Territories, Modes of Payment, Customer Groups, Item Groups
    try {
      const initUrl = `${siteUrl}/api/setup/init`
      const initResponse = await fetch(initUrl, {
        method: 'GET',
        headers: {
          // Pass tenant API credentials so frappeRequest uses the right site
          'x-tenant-api-key': apiKey,
          'x-tenant-api-secret': apiSecret,
        },
        // Don't hang the response ΓÇö fire and check quickly
        signal: AbortSignal.timeout(30000)
      })
      if (initResponse.ok) {
        const initData = await initResponse.json()
      } else {
      }
    } catch (initErr: any) {
      // Non-fatal ΓÇö tenant works fine, init can be re-run manually
    }

    return NextResponse.json({
      success: true,
      message: 'Tenant API credentials saved successfully',
      tenantRecord: tenantRecordName,
      action: shouldCreateRecord ? 'created' : 'updated'
    })

  } catch (error: any) {
    console.error('Error in update-credentials API:', error)
    return NextResponse.json(
      { error: error.message || 'Internal server error' },
      { status: 500 }
    )
  }
}

/**
 * API Route: /api/user/roles
 * 
 * Fetches current user's roles from Frappe ERPNext backend.
 * Uses multiple fallback strategies:
 *   1. API key auth ΓåÆ frappe.client.get for User doc
 *   2. role_profile_name mapping
 *   3. Provisioning service (ignore_permissions) as last resort
 */

import { NextRequest, NextResponse } from 'next/server'
import { cookies } from 'next/headers'
import { frappeRequest, getTenantContext } from '@/app/lib/api'
import { requireAuth } from '@/app/api/_lib/auth'

export async function GET(request: NextRequest) {
  const auth = await requireAuth()
  if (!auth.authenticated) return auth.response

  try {
    const cookieStore = await cookies()
    const cookieEmail = cookieStore.get('user_email')?.value || cookieStore.get('user_id')?.value

    // Step 1: Determine the user's email
    let userEmail: string | null = null

    try {
      const userInfoResponse = await frappeRequest(
        'frappe.auth.get_logged_user',
        'GET'
      ) as any
      userEmail = userInfoResponse?.message || userInfoResponse || null
      if (typeof userEmail !== 'string' || !userEmail.includes('@')) {
        userEmail = null
      }
    } catch (authErr: any) {
    }

    // Fallback: use the email stored in cookies during login
    if (!userEmail && cookieEmail) {
      userEmail = cookieEmail
    }

    if (!userEmail) {
      throw new Error('No user logged in')
    }


    // Step 2: Fetch roles from Frappe User doc
    let roles: string[] = []
    let roleProfileName: string | null = null

    try {
      const userDoc = await frappeRequest(
        'frappe.client.get',
        'POST',
        {
          doctype: 'User',
          name: userEmail,
        }
      ) as any

      const user = userDoc?.message || userDoc
      roleProfileName = user?.role_profile_name || null


      if (Array.isArray(user?.roles)) {
        roles = user.roles
          .map((r: any) => r.role || r.name)
          .filter((r: string) => r && r !== 'All')
      }
    } catch (getErr: any) {
    }

    // Step 3: If roles are empty but role_profile_name is set, derive roles
    if (roles.length === 0 && roleProfileName) {
      const PROFILE_ROLES: Record<string, string[]> = {
        'Administrator': ['System Manager'],
        'System Manager': ['System Manager'],
        'Sales Manager': ['Sales Manager', 'Sales User'],
        'Sales User': ['Sales User'],
        'Accounts Manager': ['Accounts Manager', 'Accounts User'],
        'Accounts User': ['Accounts User'],
        'Projects Manager': ['Projects Manager', 'Projects User'],
        'Projects User': ['Projects User'],
        'Standard User': ['Employee', 'Sales User'],
      }
      roles = PROFILE_ROLES[roleProfileName] || []
    }

    // Step 4: If STILL empty, use provisioning service (ignore_permissions)
    if (roles.length === 0) {
      try {
        const context = await getTenantContext()
        if (context.subdomain) {
          const { getUserRoles } = await import('@/lib/provisioning-client')
          const provRoleData = await getUserRoles(context.subdomain, userEmail)
          roles = provRoleData.roles || []
          roleProfileName = provRoleData.role_profile_name || null

          // If provisioning returned a profile name but no roles, derive
          if (roles.length === 0 && roleProfileName) {
            const PROFILE_ROLES: Record<string, string[]> = {
              'Administrator': ['System Manager'],
              'Sales Manager': ['Sales Manager', 'Sales User'],
              'Sales User': ['Sales User'],
              'Standard User': ['Employee', 'Sales User'],
            }
            roles = PROFILE_ROLES[roleProfileName] || []
          }
        }
      } catch (provErr: any) {
      }
    }

    // Step 5: Last resort ΓÇö user has zero roles somehow (corrupted state).
    // Give them the minimum Sales User access so the app is usable.
    // Login normalization will assign proper roles on next login.
    if (roles.length === 0) {
      roles = ['Sales User']
    }


    return NextResponse.json({
      success: true,
      roles,
      roleProfileName,
      user: {
        name: userEmail,
        email: userEmail,
      },
    })
  } catch (error: any) {
    console.error('[API /user/roles] Failed to fetch roles:', error)

    return NextResponse.json(
      {
        success: false,
        error: error.message || 'Failed to fetch user roles',
        roles: [],
      },
      { status: 500 }
    )
  }
}

'use client'

import { useEffect, useState, Suspense } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'

/**
 * OAuth Callback Handler
 * Handles the redirect from Frappe OAuth provider
 * Exchanges authorization code for access token
 */
function AuthCallbackContent() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const [error, setError] = useState<string | null>(null)
  const [isProcessing, setIsProcessing] = useState(true)

  useEffect(() => {
    const handleCallback = async () => {
      try {
        // 1. Get authorization code from URL
        const code = searchParams.get('code')
        const state = searchParams.get('state')
        const errorParam = searchParams.get('error')
        const errorDescription = searchParams.get('error_description')

        // 2. Check for OAuth errors
        if (errorParam) {
          throw new Error(errorDescription || errorParam)
        }

        if (!code) {
          throw new Error('Authorization code not found in callback URL')
        }

        // 3. Verify state parameter (CSRF protection)
        const savedState = sessionStorage.getItem('oauth_state')
        if (state && savedState && state !== savedState) {
          throw new Error('Invalid state parameter - possible CSRF attack')
        }

        // 4. Exchange code for token
        const tokenResponse = await fetch('/api/auth/token', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ code }),
        })

        if (!tokenResponse.ok) {
          const errorData = await tokenResponse.json()
          throw new Error(errorData.error || 'Failed to exchange code for token')
        }

        const tokenData = await tokenResponse.json()

        // 5. Store tokens securely
        localStorage.setItem('access_token', tokenData.access_token)
        
        if (tokenData.refresh_token) {
          localStorage.setItem('refresh_token', tokenData.refresh_token)
        }
        
        if (tokenData.expires_in) {
          const expiresAt = Date.now() + tokenData.expires_in * 1000
          localStorage.setItem('token_expires_at', expiresAt.toString())
        }

        // 6. Store user info if provided
        if (tokenData.user_info) {
          localStorage.setItem('user_info', JSON.stringify(tokenData.user_info))
        }

        // 7. Clean up state
        sessionStorage.removeItem('oauth_state')

        // 8. Redirect to dashboard or original destination
        const redirectTo = sessionStorage.getItem('auth_redirect') || '/dashboard'
        sessionStorage.removeItem('auth_redirect')
        
        router.push(redirectTo)
      } catch (err) {
        console.error('OAuth callback error:', err)
        setError(err instanceof Error ? err.message : 'Authentication failed')
        setIsProcessing(false)
      }
    }

    handleCallback()
  }, [searchParams, router])

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50">
        <div className="w-full max-w-md p-8 bg-white rounded-lg shadow-lg">
          <div className="flex items-center justify-center w-12 h-12 mx-auto mb-4 bg-red-100 rounded-full">
            <svg
              className="w-6 h-6 text-red-600"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          </div>
          
          <h1 className="mb-2 text-2xl font-bold text-center text-gray-900">
            Authentication Failed
          </h1>
          
          <p className="mb-6 text-center text-gray-600">
            {error}
          </p>
          
          <div className="flex gap-3">
            <button
              onClick={() => router.push('/login')}
              className="flex-1 px-4 py-2 text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition"
            >
              Try Again
            </button>
            
            <button
              onClick={() => router.push('/')}
              className="flex-1 px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition"
            >
              Go Home
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-50">
      <div className="w-full max-w-md p-8 bg-white rounded-lg shadow-lg">
        <div className="flex items-center justify-center mb-6">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
        </div>
        
        <h1 className="mb-2 text-2xl font-bold text-center text-gray-900">
          Completing Authentication
        </h1>
        
        <p className="text-center text-gray-600">
          Please wait while we log you in...
        </p>
      </div>
    </div>
  )
}

export default function AuthCallbackPage() {
  return (
    <Suspense fallback={
      <div className="flex items-center justify-center min-h-screen bg-gray-50">
        <div className="w-full max-w-md p-8 bg-white rounded-lg shadow-lg">
          <div className="flex items-center justify-center mb-6">
            <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
          </div>
          <h1 className="mb-2 text-2xl font-bold text-center text-gray-900">
            Loading...
          </h1>
        </div>
      </div>
    }>
      <AuthCallbackContent />
    </Suspense>
  )
}

