            <Button type="submit" className="w-full" disabled={loading}>
              {loading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Creating accountΓÇª
                </>
              ) : (
                'Create Account'
              )}
            </Button>
          </form>

          <p className="mt-6 text-center text-sm text-muted-foreground">
            Already have an account?{' '}
            <a href="/login" className="text-primary hover:underline font-medium">
              Sign in
            </a>
          </p>
        </CardContent>
      </Card>
    </div>
  )
}

import NextAuth from "next-auth"
import Google from "next-auth/providers/google"

/**
 * NextAuth Configuration for Nexus ERP Multi-Tenant SaaS
 * =======================================================
 * 
 * AUTH FLOW:
 * 
 * [Google OAuth]
 *   1. User clicks "Sign in with Google"
 *   2. Google returns { email, name, image }
 *   3. signIn callback fires:
 *      - Calls Master DB to check if email owns a tenant
 *      - YES ΓåÆ sets hasTenant=true, tenantSubdomain in token
 *      - NO  ΓåÆ sets hasTenant=false (user needs onboarding)
 *   4. redirect callback sends user to correct location:
 *      - Has tenant ΓåÆ `subdomain.avariq.in/dashboard`
 *      - No tenant  ΓåÆ `/onboarding` (to create workspace)
 * 
 * COOKIE STRATEGY:
 *   Session cookie domain is `.avariq.in` (production) so it works
 *   across all tenant subdomains. User authenticates once on avariq.in,
 *   and the session is valid on tesla.avariq.in, spacex.avariq.in, etc.
 */

const ROOT_DOMAIN = process.env.NEXT_PUBLIC_ROOT_DOMAIN || 'avariq.in'
const IS_PRODUCTION = process.env.NODE_ENV === 'production'
const MASTER_SITE = process.env.FRAPPE_SITE_NAME || 'erp.localhost'
const ERP_URL = process.env.ERP_NEXT_URL || 'http://127.0.0.1:8080'

// ΓöÇΓöÇ Providers ΓöÇΓöÇ
const providers: any[] = []
if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
  providers.push(
    Google({
      clientId: process.env.GOOGLE_CLIENT_ID,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET,
      authorization: {
        params: {
          prompt: "consent",
          access_type: "offline",
          response_type: "code",
        },
      },
    })
  )
}

// ΓöÇΓöÇ Helper: Lookup tenant by email in Master DB ΓöÇΓöÇ
async function lookupTenantInMasterDB(email: string): Promise<{
  hasTenant: boolean
  subdomain?: string
}> {
  try {
    const apiKey = process.env.ERP_API_KEY
    const apiSecret = process.env.ERP_API_SECRET
    if (!apiKey || !apiSecret) return { hasTenant: false }

    const params = new URLSearchParams({
      doctype: 'SaaS Tenant',
      filters: JSON.stringify({ owner_email: email, status: 'Active' }),
      fields: JSON.stringify(['subdomain']),
      limit_page_length: '1',
    })

    const response = await fetch(
      `${ERP_URL}/api/method/frappe.client.get_list?${params}`,
      {
        headers: {
          'Authorization': `token ${apiKey}:${apiSecret}`,
          'X-Frappe-Site-Name': MASTER_SITE,
        },
        // No cache ΓÇö always check fresh
        cache: 'no-store',
      }
    )

    if (!response.ok) return { hasTenant: false }

    const data = await response.json()
    const tenants = data.message || data.data || []

    if (tenants.length > 0) {
      return { hasTenant: true, subdomain: tenants[0].subdomain }
    }
    return { hasTenant: false }
  } catch (error) {
    console.error('[Auth] Master DB tenant lookup failed:', error)
    return { hasTenant: false }
  }
}

// ΓöÇΓöÇ Callbacks ΓöÇΓöÇ
const callbacks = {
  async signIn({ user }: any) {
    if (!user.email) return false
    // Allow all Google sign-ins ΓÇö routing happens in redirect callback
    return true
  },

  async jwt({ token, user, trigger, session }: any) {
    // On initial sign-in, look up tenant in Master DB
    if (user) {
      token.email = user.email
      token.name = user.name
      token.picture = user.image

      const lookup = await lookupTenantInMasterDB(user.email)
      token.hasTenant = lookup.hasTenant
      token.tenantSubdomain = lookup.subdomain || null
    }

    // Allow manual updates (e.g., after provisioning completes)
    if (trigger === 'update' && session) {
      if (session.hasTenant !== undefined) token.hasTenant = session.hasTenant
      if (session.tenantSubdomain) token.tenantSubdomain = session.tenantSubdomain
    }

    return token
  },

  async session({ session, token }: any) {
    if (session.user) {
      session.user.email = token.email as string
      session.user.name = token.name as string
      session.user.image = token.picture as string
    }
    // Attach tenant info to session (accessible client-side)
    session.hasTenant = token.hasTenant as boolean
    session.tenantSubdomain = token.tenantSubdomain as string | null
    return session
  },

  async redirect({ url, baseUrl }: any) {
    // Allow redirects to same-domain subdomains
    if (url.startsWith('/')) return `${baseUrl}${url}`

    try {
      const urlObj = new URL(url)
      if (urlObj.hostname.endsWith(ROOT_DOMAIN) || urlObj.hostname.includes('localhost')) {
        return url
      }
    } catch {
      // Invalid URL, fall through to baseUrl
    }

    return baseUrl
  },
}

// ΓöÇΓöÇ Cookie Configuration for Cross-Subdomain Auth ΓöÇΓöÇ
const useSecureCookies = IS_PRODUCTION
const cookiePrefix = useSecureCookies ? '__Secure-' : ''

export const { handlers, signIn, signOut, auth } = NextAuth({
  providers,
  callbacks,
  pages: {
    signIn: '/login',
    error: '/login',
  },
  cookies: {
    sessionToken: {
      name: `${cookiePrefix}next-auth.session-token`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: useSecureCookies,
        // CRITICAL: Dot-prefix domain allows cookie to work on ALL subdomains
        // e.g., `.avariq.in` ΓåÆ valid on tesla.avariq.in, spacex.avariq.in, etc.
        domain: useSecureCookies ? `.${ROOT_DOMAIN}` : undefined,
      },
    },
  },
} as any)

'use client'

import React, { useState, useRef, useEffect } from 'react'
import { usePathname } from 'next/navigation'
import { Sparkles, Send, Bot, User } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

export function FloatingAIChat() {
  const [open, setOpen] = useState(false)
  const pathname = usePathname()

  const [messages, setMessages] = useState<Message[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const messagesEndRef = useRef<HTMLDivElement>(null)

  // Auto-scroll to bottom of messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  // Hide on /agents page to avoid double chat, and on /bookings to avoid obscuring content
  if (pathname === '/agents' || pathname === '/bookings' || pathname.startsWith('/bookings/')) {
    return null
  }

  async function handleSend(userMessage: string) {
    if (!userMessage.trim() || isLoading) return;

    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          messages: [{ role: 'user', content: userMessage }],
          conversation_id: "",
        }),
      });

      if (!response.ok) throw new Error('Failed to send message');

      // Initialize assistant message
      setMessages(prev => [...prev, { role: 'assistant', content: '' }]);

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (!reader) return;

      let assistantMessage = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        assistantMessage += chunk;

        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1] = {
            role: 'assistant',
            content: assistantMessage
          };
          return newMessages;
        });
      }

    } catch (error) {
      console.error('Chat error:', error);
      setMessages(prev => [...prev, { role: 'assistant', content: "Sorry, I'm having trouble connecting to the AI right now." }]);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <>
      {/* Floating Button */}
      <Button
        onClick={() => setOpen(true)}
        aria-label="Open chat"
        className="fixed bottom-6 right-6 h-14 w-14 rounded-full shadow-2xl z-50 bg-gradient-to-br from-blue-600 via-blue-500 to-purple-600 hover:from-blue-700 hover:via-blue-600 hover:to-purple-700 border-0 transition-all duration-300 hover:scale-110"
        size="icon"
      >
        <Sparkles className="h-6 w-6 text-white" />
      </Button>

      {/* Chat Sheet */}
      <Sheet open={open} onOpenChange={setOpen}>
        <SheetContent side="right" className="w-full sm:max-w-lg p-0 flex flex-col h-full">
          <SheetHeader className="p-6 pb-4 border-b shrink-0">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="h-10 w-10 rounded-full bg-gradient-to-br from-blue-600 via-blue-500 to-purple-600 flex items-center justify-center">
                  <Sparkles className="h-5 w-5 text-white" />
                </div>
                <div>
                  <SheetTitle className="text-lg font-semibold">AI Assistant</SheetTitle>
                  <p className="text-sm text-gray-500">How can I help you today?</p>
                </div>
              </div>
            </div>
          </SheetHeader>

          <div className="flex-1 overflow-hidden flex flex-col">
            {/* Chat Messages Area */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              <div className="bg-gray-100 dark:bg-gray-800 rounded-xl p-4">
                <p className="text-sm text-gray-700 dark:text-gray-300">
                  ≡ƒæï Hello! I'm your AI assistant. I can help you with:
                </p>
                <ul className="text-sm text-gray-600 dark:text-gray-400 mt-2 space-y-1 ml-4 list-disc">
                  <li>Creating and managing opportunities</li>
                  <li>Generating quotations and invoices</li>
                  <li>Analyzing your sales pipeline</li>
                  <li>Answering questions about your data</li>
                </ul>
              </div>

              {messages.map((msg, idx) => (
                <div key={idx} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  {msg.role === 'assistant' && (
                    <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center shrink-0">
                      <Bot className="h-4 w-4 text-blue-600" />
                    </div>
                  )}

                  <div className={`rounded-2xl px-4 py-2 max-w-[80%] text-sm ${msg.role === 'user'
                      ? 'bg-blue-600 text-white'
                      : 'bg-gray-100 dark:bg-gray-800 text-gray-800 dark:text-gray-200'
                    }`}>
                    {msg.content}
                  </div>

                  {msg.role === 'user' && (
                    <div className="h-8 w-8 rounded-full bg-gray-200 flex items-center justify-center shrink-0">
                      <User className="h-4 w-4 text-gray-600" />
                    </div>
                  )}
                </div>
              ))}
              <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="border-t p-4 bg-white dark:bg-slate-950 shrink-0">
              <ChatInput onSend={handleSend} isLoading={isLoading} />
            </div>
          </div>
        </SheetContent>
      </Sheet>
    </>
  );
}

function ChatInput({ onSend, isLoading }: { onSend: (msg: string) => void, isLoading: boolean }) {
  const [message, setMessage] = useState("");

  function handleSend() {
    if (!message.trim() || isLoading) return;
    onSend(message);
    setMessage("");
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }

  return (
    <>
      <div className="flex gap-2">
        <input
          type="text"
          placeholder="Ask me anything..."
          className="flex-1 px-4 py-3 border border-gray-300 dark:border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm bg-transparent"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          onKeyDown={handleKeyDown}
          disabled={isLoading}
        />
        <Button
          className="px-6 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 disabled:opacity-50"
          onClick={handleSend}
          aria-label="Send message"
          disabled={isLoading}
        >
          {isLoading ? '...' : <Send className="h-4 w-4" />}
        </Button>
      </div>
      <p className="text-xs text-gray-500 mt-2 text-center">
        Press Enter to send
      </p>
    </>
  );
}

