'use client'

import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Trash2, Loader2 } from "lucide-react"
import { useRouter } from "next/navigation"

interface DeleteQuotationButtonProps {
  quotationId: string
  quotationStatus: string
}

export function DeleteQuotationButton({ quotationId, quotationStatus }: DeleteQuotationButtonProps) {
  const [deleting, setDeleting] = useState(false)
  const router = useRouter()

  // Only show delete button for Draft quotations
  if (quotationStatus !== 'Draft') {
    return null
  }

  const handleDelete = async () => {
    if (!confirm(`Are you sure you want to delete quotation ${quotationId}? This action cannot be undone.`)) {
      return
    }

    setDeleting(true)

    try {
      const response = await fetch(`/api/quotations/${encodeURIComponent(quotationId)}/delete`, {
        method: 'POST'
      })

      const result = await response.json()

      if (!response.ok) {
        throw new Error(result.error || 'Failed to delete quotation')
      }

      router.push('/crm/quotations')
    } catch (error: any) {
      console.error('Error deleting quotation:', error)
      alert(`Failed to delete quotation: ${error.message}`)
      setDeleting(false)
    }
  }

  return (
    <Button
      variant="destructive"
      size="sm"
      onClick={handleDelete}
      disabled={deleting}
      className="gap-2"
    >
      {deleting ? (
        <>
          <Loader2 className="h-4 w-4 animate-spin" />
          Deleting...
        </>
      ) : (
        <>
          <Trash2 className="h-4 w-4" />
          Delete
        </>
      )}
    </Button>
  )
}

'use client'

import { useState } from 'react'
import { DndContext, DragEndEvent, closestCorners } from '@dnd-kit/core'
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { updateLeadStatus, convertLeadToOpportunity, getOpportunityMetadata } from "@/app/actions/crm"
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { useToastHelpers } from "@/components/ui/toast"

// Define the columns for your pipeline (Updated with proper ERPNext Lead statuses)
const COLUMNS = [
  { id: 'Lead', title: 'New Lead', color: 'bg-gray-100 text-gray-700 border-gray-200' },
  { id: 'Open', title: 'Open', color: 'bg-blue-100 text-blue-700 border-blue-200' },
  { id: 'Replied', title: 'Replied', color: 'bg-cyan-100 text-cyan-700 border-cyan-200' },
  { id: 'Interested', title: 'Interested', color: 'bg-purple-100 text-purple-700 border-purple-200' },
  { id: 'Opportunity', title: 'Opportunity', color: 'bg-orange-100 text-orange-700 border-orange-200' },
  { id: 'Quotation', title: 'Quotation', color: 'bg-yellow-100 text-yellow-700 border-yellow-200' },
  { id: 'Converted', title: 'Converted', color: 'bg-green-100 text-green-700 border-green-200' },
  { id: 'Do Not Contact', title: 'Do Not Contact', color: 'bg-red-100 text-red-700 border-red-200' },
]

export function KanbanBoard({ leads }: { leads: any[] }) {
  const router = useRouter()
  const toast = useToastHelpers()
  // Optimistic UI: We update local state immediately while the server saves
  const [items, setItems] = useState(leads)

  // Conversion Dialog State
  const [isConversionDialogOpen, setIsConversionDialogOpen] = useState(false)
  const [pendingConversion, setPendingConversion] = useState<{ leadId: string, newStatus: string } | null>(null)
  const [isConverting, setIsConverting] = useState(false)
  const [opportunityAmount, setOpportunityAmount] = useState<number>(0)
  const [opportunityType, setOpportunityType] = useState<string>('Sales')
  const [salesStage, setSalesStage] = useState<string>('Qualification')
  const [metadata, setMetadata] = useState<{ types: string[], stages: string[] }>({ types: [], stages: [] })

  // Fetch metadata when dialog opens
  const handleConversionDialogOpen = async (open: boolean) => {
    setIsConversionDialogOpen(open)
    if (open && metadata.types.length === 0) {
      const data = await getOpportunityMetadata()
      setMetadata(data)
      if (data.types.length > 0) setOpportunityType(data.types[0])
      if (data.stages.length > 0) setSalesStage(data.stages[0])
    }
  }

  // Handle the drop event
  async function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event

    if (!over) return

    const leadId = active.id as string
    const newStatus = over.id as string // The column ID is the status

    // 1. Find the lead in our list
    const lead = items.find(l => l.name === leadId)
    if (!lead || lead.status === newStatus) return

    // Special handling for Opportunity conversion
    if (newStatus === 'Opportunity') {
      setPendingConversion({ leadId, newStatus })
      setPendingConversion({ leadId, newStatus })
      handleConversionDialogOpen(true)
      return
    }

    // 2. Optimistic Update (Update UI instantly)
    const originalStatus = lead.status
    setItems(items.map(l =>
      l.name === leadId ? { ...l, status: newStatus } : l
    ))

    // 3. Server Update (Save to ERPNext)
    const res = await updateLeadStatus(leadId, newStatus)

    if (!res.success) {
      // Revert if failed
      setItems(items.map(l =>
        l.name === leadId ? { ...l, status: originalStatus } : l
      ))
      alert("Failed to move card")
      router.refresh()
    }
  }

  async function confirmConversion() {
    if (!pendingConversion) return

    setIsConverting(true)
    try {
      // Perform the actual conversion logic
      const res = await convertLeadToOpportunity(
        pendingConversion.leadId,
        false, // createCustomer
        opportunityAmount,
        opportunityType,
        salesStage
      )

      if (res.success) {
        // Remove from board or move to 'Converted'? 
        // 'Opportunity' leads usually become 'Converted' in ERPNext status flow if they are fully converted,
        // OR they might stay as Lead-Opportunity if just a status change.
        // But usually convertLeadToOpportunity makes a NEW Document (Opportunity) and marks Lead as Converted.

        // Let's assume we want to show it as 'Converted' in the Lead Kanban, or remove it.
        // If we move it to 'Opportunity' column, it conceptually matches.

        setItems(items.map(l =>
          l.name === pendingConversion.leadId ? { ...l, status: 'Converted' } : l
        ))

        // In a real Kanban where we mix Leads and Opps, this would be complex. 
        // For a Lead Kanban, 'Converted' is the end state.
        toast.success("Lead converted to Opportunity successfully!")

        // Optional: Redirect to the new Opportunity?
        // if (res.opportunityId) router.push(`/crm/opportunities/${res.opportunityId}`)

        router.refresh()
      } else {
        toast.error(res.error || "Failed to convert lead")
      }
    } catch (e) {
      console.error(e)
      toast.error("An error occurred during conversion")
    } finally {
      setIsConverting(false)
      setIsConversionDialogOpen(false)
      setPendingConversion(null)
      setOpportunityAmount(0)
      setOpportunityType('Sales')
      setSalesStage('Qualification')
    }
  }

  return (
    <>
      <DndContext onDragEnd={handleDragEnd} collisionDetection={closestCorners}>
        <div className="flex h-full gap-4 overflow-x-auto pb-4">
          {COLUMNS.map((col) => (
            <div key={col.id} className="w-80 flex-shrink-0 flex flex-col gap-4">
              {/* Column Header */}
              <div className={`flex items-center justify-between p-2 rounded-lg border-t-4 ${col.color.split(' ')[0]} bg-white dark:bg-slate-800 shadow-sm`}>
                <span className="font-semibold text-sm text-slate-700 dark:text-slate-200">{col.title}</span>
                <Badge variant="secondary" className="bg-slate-100 dark:bg-slate-900">
                  {items.filter(l => l.status === col.id).length}
                </Badge>
              </div>

              {/* Drop Zone */}
              <KanbanColumn id={col.id} leads={items.filter(l => l.status === col.id)} />
            </div>
          ))}
        </div>
      </DndContext>

      {/* Conversion Confirmation Dialog */}
      <Dialog open={isConversionDialogOpen} onOpenChange={handleConversionDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Convert to Opportunity?</DialogTitle>
            <DialogDescription>
              This will create a new <strong>Opportunity</strong> record from this Lead and mark the Lead as <strong>Converted</strong>.
            </DialogDescription>
          </DialogHeader>
          <div className="py-4 space-y-4">
            <p className="text-sm text-slate-500">
              Do you want to proceed with creating an Opportunity? You can set the initial details below.
            </p>

            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Opportunity Type</Label>
                <Select value={opportunityType} onValueChange={setOpportunityType}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select type" />
                  </SelectTrigger>
                  <SelectContent>
                    {metadata.types.map(type => (
                      <SelectItem key={type} value={type}>{type}</SelectItem>
                    ))}
                    {metadata.types.length === 0 && <SelectItem value="Sales">Sales</SelectItem>}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Sales Stage</Label>
                <Select value={salesStage} onValueChange={setSalesStage}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select stage" />
                  </SelectTrigger>
                  <SelectContent>
                    {metadata.stages.map(stage => (
                      <SelectItem key={stage} value={stage}>{stage}</SelectItem>
                    ))}
                    {metadata.stages.length === 0 && <SelectItem value="Qualification">Qualification</SelectItem>}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Estimated Amount</Label>
                <Input
                  type="number"
                  min="0"
                  value={opportunityAmount}
                  onChange={(e) => setOpportunityAmount(parseFloat(e.target.value) || 0)}
                />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsConversionDialogOpen(false)} disabled={isConverting}>
              Cancel
            </Button>
            <Button onClick={confirmConversion} disabled={isConverting}>
              {isConverting ? "Converting..." : "Yes, Convert"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  )
}

// Sub-component for the Drop Zone
import { useDroppable } from '@dnd-kit/core'
import { useDraggable } from '@dnd-kit/core'

function KanbanColumn({ id, leads }: { id: string, leads: any[] }) {
  const { setNodeRef } = useDroppable({ id })

  return (
    <div ref={setNodeRef} className="flex-1 flex flex-col gap-3 min-h-[500px] p-1">
      {leads.map(lead => (
        <DraggableCard key={lead.name} lead={lead} />
      ))}
    </div>
  )
}

// Sub-component for the DraggableCard (unchanged mostly, just style tweaks)
function DraggableCard({ lead }: { lead: any }) {
  const { attributes, listeners, setNodeRef, transform, isDragging } = useDraggable({
    id: lead.name,
  })

  const style = transform ? {
    transform: `translate3d(${transform.x}px, ${transform.y}px, 0)`,
    zIndex: isDragging ? 50 : 1,
  } : undefined

  return (
    <div ref={setNodeRef} style={style} {...listeners} {...attributes}>
      <Card className={`cursor-grab hover:shadow-md transition-all active:cursor-grabbing border-l-4 ${isDragging ? 'opacity-50 ring-2 ring-blue-400' : ''}`} style={{ borderLeftColor: getStatusColor(lead.status) }}>
        <CardContent className="p-3 space-y-2">
          <div className="flex justify-between items-start">
            <Link href={`/crm/${lead.name}`} className="font-semibold text-sm text-slate-900 dark:text-white hover:text-blue-600 hover:underline line-clamp-1">
              {lead.lead_name}
            </Link>
          </div>
          <div className="text-xs text-slate-500 line-clamp-1">
            {lead.company_name || "Individual"}
          </div>
          {(lead.email_id || lead.mobile_no) && (
            <div className="pt-2 flex flex-wrap gap-2">
              {lead.email_id && <Badge variant="outline" className="text-[10px] h-5 px-1 font-normal text-slate-500 bg-slate-50">Γ£ë∩╕Å</Badge>}
              {lead.mobile_no && <Badge variant="outline" className="text-[10px] h-5 px-1 font-normal text-slate-500 bg-slate-50">≡ƒô₧</Badge>}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

// Helper function to get status color
function getStatusColor(status: string): string {
  const colors: Record<string, string> = {
    'Lead': '#9ca3af',
    'Open': '#60a5fa',
    'Replied': '#22d3ee',
    'Interested': '#a78bfa',
    'Opportunity': '#fb923c',
    'Quotation': '#fbbf24',
    'Converted': '#4ade80',
    'Do Not Contact': '#f87171'
  }
  return colors[status] || '#cbd5e1'
}

"use client"

import { useState, useMemo } from "react"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { updateLeadStatus, convertLeadToOpportunity, getOpportunityMetadata } from "@/app/actions/crm"
import { PageHeader } from "@/components/page-header"
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { useToastHelpers } from "@/components/ui/toast"
import { useUser } from "@/contexts/user-context"

interface Lead {
    name: string
    lead_name: string
    email_id: string
    mobile_no: string
    status: string
    company_name: string
    job_title?: string
    territory?: string
    source?: string
    industry?: string
}

interface LeadsContentWorkspaceProps {
    leads: Lead[]
}

// ERPNext lead statuses
const LEAD_STAGES = [
    "Lead",
    "Open",
    "Replied",
    "Opportunity",
    "Quotation",
    "Lost Quotation",
    "Interested",
    "Converted",
    "Do Not Contact"
]

// Mock AI score calculation (to be replaced with real AI service)
function calculateAIScore(lead: Lead): number {
    // Simple heuristic based on available data
    let score = 50
    if (lead.email_id) score += 10
    if (lead.mobile_no) score += 10
    if (lead.company_name) score += 15
    if (lead.job_title) score += 10
    if (lead.status === "Interested") score += 20
    if (lead.status === "Replied") score += 15
    if (lead.status === "Opportunity") score += 25
    return Math.min(100, score + Math.floor(Math.random() * 10))
}

// Helper function to get stage badge color
function getStageColor(stage: string): string {
    const colors: Record<string, string> = {
        'Lead': 'bg-gray-100 text-gray-700 dark:bg-gray-900/30 dark:text-gray-300',
        'Open': 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300',
        'Replied': 'bg-cyan-100 text-cyan-700 dark:bg-cyan-900/30 dark:text-cyan-300',
        'Interested': 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300',
        'Opportunity': 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300',
        'Quotation': 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300',
        'Lost Quotation': 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300',
        'Converted': 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300',
        'Do Not Contact': 'bg-slate-100 text-slate-700 dark:bg-slate-900/30 dark:text-slate-300'
    }
    return colors[stage] || 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300'
}

export function LeadsContentWorkspace({ leads }: LeadsContentWorkspaceProps) {
    const router = useRouter()
    const { canPerform } = useUser()

    const canCreate  = canPerform('crm', 'create')
    const canEdit    = canPerform('crm', 'edit')
    const canDelete  = canPerform('crm', 'delete')
    const canConvert = canPerform('crm', 'convert')

    const [viewMode, setViewMode] = useState<"list" | "grid">("list")
    const [searchQuery, setSearchQuery] = useState("")
    const [selectedStages, setSelectedStages] = useState<string[]>(["Lead", "Opportunity"])
    const [selectedSource, setSelectedSource] = useState("All Sources")
    const [selectedPriority, setSelectedPriority] = useState<"hot" | "warm" | "cold" | null>("hot")
    const [draggedLead, setDraggedLead] = useState<string | null>(null)
    // Removed local toast state in favor of useToast
    const toast = useToastHelpers()

    // Conversion Dialog State
    const [isConversionDialogOpen, setIsConversionDialogOpen] = useState(false)
    const [pendingConversion, setPendingConversion] = useState<{ leadName: string, newStatus: string } | null>(null)
    const [isConverting, setIsConverting] = useState(false)
    const [opportunityAmount, setOpportunityAmount] = useState<number>(0)
    const [opportunityType, setOpportunityType] = useState<string>('Sales')
    const [salesStage, setSalesStage] = useState<string>('Qualification')
    const [metadata, setMetadata] = useState<{ types: string[], stages: string[] }>({ types: [], stages: [] })

    // Fetch metadata when dialog opens
    const handleConversionDialogOpen = async (open: boolean) => {
        setIsConversionDialogOpen(open)
        if (open && metadata.types.length === 0) {
            const data = await getOpportunityMetadata()
            setMetadata(data)
            if (data.types.length > 0) setOpportunityType(data.types[0])
            if (data.stages.length > 0) setSalesStage(data.stages[0])
        }
    }



    // Enrich leads with AI scores
    const leadsWithScores = useMemo(() => {
        return leads.map(lead => ({
            ...lead,
            aiScore: calculateAIScore(lead)
        }))
    }, [leads])

    // Filter leads based on search, stages, and priority (only in table view)
    const filteredLeads = useMemo(() => {
        // In Kanban view, show all leads without filters
        if (viewMode === "grid") {
            return leadsWithScores
        }

        // In table view, apply all filters
        return leadsWithScores.filter(lead => {
            // Search filter
            const matchesSearch = searchQuery === "" ||
                lead.lead_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                lead.company_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
                lead.email_id?.toLowerCase().includes(searchQuery.toLowerCase())

            // Stage filter
            const matchesStage = selectedStages.length === 0 || selectedStages.includes(lead.status)

            // Priority filter (based on AI score)
            let matchesPriority = true
            if (selectedPriority === "hot") {
                matchesPriority = lead.aiScore >= 75
            } else if (selectedPriority === "warm") {
                matchesPriority = lead.aiScore >= 50 && lead.aiScore < 75
            } else if (selectedPriority === "cold") {
                matchesPriority = lead.aiScore < 50
            }

            return matchesSearch && matchesStage && matchesPriority
        })
    }, [leadsWithScores, searchQuery, selectedStages, selectedPriority, viewMode])

    // Calculate KPIs
    const kpis = useMemo(() => {
        const totalLeads = leads.length
        const convertedLeads = leads.filter(l => l.status === "Converted").length
        const conversionRate = totalLeads > 0 ? ((convertedLeads / totalLeads) * 100).toFixed(1) : "0.0"
        const avgScore = leadsWithScores.length > 0
            ? Math.round(leadsWithScores.reduce((sum, l) => sum + l.aiScore, 0) / leadsWithScores.length)
            : 0

        return {
            totalLeads,
            conversionRate: `${conversionRate}%`,
            avgScore,
            responseTime: "1.4 hrs" // Mock data
        }
    }, [leads, leadsWithScores])

    // Toggle stage selection
    const toggleStage = (stage: string) => {
        setSelectedStages(prev =>
            prev.includes(stage)
                ? prev.filter(s => s !== stage)
                : [...prev, stage]
        )
    }

    // Handle status change
    const handleStatusChange = async (leadName: string, newStatus: string) => {
        if (!canEdit) return

        // Special handling for Opportunity conversion
        if (newStatus === "Opportunity") {
            if (!canConvert) return
            setPendingConversion({ leadName, newStatus })
            handleConversionDialogOpen(true)
            return
        }

        try {
            const result = await updateLeadStatus(leadName, newStatus)
            if (result.success) {
                router.refresh()
                toast.success("Success", "Lead status updated")
            } else {
                toast.error("Error", "Failed to update lead status")
            }
        } catch (error) {
            console.error("Error updating lead status:", error)
            toast.error("Error", "Failed to update lead status")
        }
    }

    async function confirmConversion() {
        if (!pendingConversion) return

        setIsConverting(true)
        try {
            const res = await convertLeadToOpportunity(
                pendingConversion.leadName,
                false, // createCustomer
                opportunityAmount,
                opportunityType,
                salesStage
            )

            if (res.success) {
                toast.success("Success", "Lead converted to Opportunity successfully!")
                router.refresh()
            } else {
                toast.error("Error", res.error || "Failed to convert lead")
            }
        } catch (e) {
            console.error(e)
            toast.error("Error", "An error occurred during conversion")
        } finally {
            setIsConverting(false)
            setIsConversionDialogOpen(false)
            setPendingConversion(null)
            setOpportunityAmount(0)
            setOpportunityType('Sales')
            setSalesStage('Qualification')
        }
    }

    // Drag and drop handlers for Kanban

    const handleDragStart = (e: React.DragEvent, leadName: string, leadStatus: string) => {
        // Prevent dragging converted leads
        if (leadStatus === "Converted") {
            e.preventDefault()
            toast.error("Action Not Allowed", "Converted leads cannot be moved to other stages")
            return
        }
        setDraggedLead(leadName)
    }

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault()
    }

    const handleDrop = async (targetStage: string) => {
        if (!draggedLead) return

        // Prevent dropping into Converted stage
        if (targetStage === "Converted") {
            setDraggedLead(null)
            toast.error("Action Not Allowed", "Leads cannot be manually moved to Converted stage")
            return
        }

        const lead = leads.find(l => l.name === draggedLead)
        if (lead && lead.status !== targetStage) {
            await handleStatusChange(draggedLead, targetStage)
        }
        setDraggedLead(null)
    }

    return (
        <div className="bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-200 transition-colors duration-200 min-h-screen">
            <div className="flex min-h-screen">
                <main className="flex-1 flex flex-col h-screen overflow-hidden">
                    {/* Header */}
                    <PageHeader searchQuery={searchQuery} onSearchChange={setSearchQuery}>
                        <Link href="/crm">
                            <button className="bg-slate-700 hover:bg-slate-600 text-slate-200 px-5 py-2 rounded-lg flex items-center gap-2 text-sm font-semibold transition shadow-sm">
                                <span className="material-symbols-outlined text-lg">dashboard</span> Dashboard
                            </button>
                        </Link>
                        {canCreate && (
                            <Link href="/crm/new">
                                <button className="bg-[#3b82f6] hover:bg-blue-600 text-white px-5 py-2 rounded-lg flex items-center gap-2 text-sm font-semibold transition shadow-sm shadow-blue-500/20">
                                    <span className="material-symbols-outlined text-lg">add</span> New Lead
                                </button>
                            </Link>
                        )}
                    </PageHeader>

                    {/* Main Content */}
                    <div className="flex-1 overflow-y-auto p-8 space-y-8">
                        {/* KPI Cards */}
                        <div className="grid grid-cols-4 gap-6">
                            <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative group">
                                <div className="flex justify-between items-start mb-4">
                                    <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Total Leads</span>
                                    <div className="p-2 rounded-lg bg-blue-500/10 text-blue-400">
                                        <span className="material-symbols-outlined text-xl">trending_up</span>
                                    </div>
                                </div>
                                <div className="flex items-end gap-3">
                                    <span className="text-[28px] font-bold text-white leading-none">{kpis.totalLeads}</span>
                                    <span className="text-sm font-semibold text-blue-400 mb-1">+12%</span>
                                </div>
                                <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                    <div className="h-full bg-blue-500 w-[72%] rounded-full shadow-[0_0_8px_rgba(59,130,246,0.5)]"></div>
                                </div>
                            </div>

                            <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative group">
                                <div className="flex justify-between items-start mb-4">
                                    <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Conversion Rate %</span>
                                    <div className="p-2 rounded-lg bg-orange-500/10 text-orange-400">
                                        <span className="material-symbols-outlined text-xl">pie_chart</span>
                                    </div>
                                </div>
                                <div className="flex items-end gap-3">
                                    <span className="text-[28px] font-bold text-white leading-none">{kpis.conversionRate}</span>
                                    <span className="text-sm font-semibold text-emerald-400 mb-1 flex items-center gap-0.5">
                                        <span className="material-symbols-outlined text-xs">arrow_upward</span>4.2%
                                    </span>
                                </div>
                                <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                    <div className="h-full bg-orange-500 w-[45%] rounded-full shadow-[0_0_8px_rgba(249,115,22,0.5)]"></div>
                                </div>
                            </div>

                            <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative group">
                                <div className="flex justify-between items-start mb-4">
                                    <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Avg. Lead Score</span>
                                    <div className="p-2 rounded-lg bg-emerald-500/10 text-emerald-400">
                                        <span className="material-symbols-outlined text-xl">show_chart</span>
                                    </div>
                                </div>
                                <div className="flex items-end gap-3">
                                    <span className="text-[28px] font-bold text-white leading-none">{kpis.avgScore}</span>
                                    <span className="text-sm font-semibold text-slate-400 mb-1">100 AI Rating</span>
                                </div>
                                <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                    <div className="h-full bg-emerald-500 rounded-full shadow-[0_0_8px_rgba(16,185,129,0.5)]" style={{ width: `${kpis.avgScore}%` }}></div>
                                </div>
