                                                        <tr
                                                            key={lead.name}
                                                            className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition group"
                                                        >
                                                            <td className="px-6 py-4 cursor-pointer" onClick={() => router.push(`/crm/${encodeURIComponent(lead.name)}`)}>
                                                                <div className="flex items-center gap-3">
                                                                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-purple-500 flex items-center justify-center text-white text-sm font-bold">
                                                                        {lead.lead_name.charAt(0).toUpperCase()}
                                                                    </div>
                                                                    <div>
                                                                        <p className="text-[16px] font-semibold text-slate-900 dark:text-white">{lead.lead_name}</p>
                                                                        <p className="text-xs text-slate-400 font-medium">{lead.email_id}</p>
                                                                    </div>
                                                                </div>
                                                            </td>
                                                            <td className="px-6 py-4 text-center cursor-pointer" onClick={() => router.push(`/crm/${encodeURIComponent(lead.name)}`)}>
                                                                <p className="text-[13px] font-semibold text-slate-700 dark:text-slate-300">
                                                                    {lead.company_name || "Individual"}
                                                                </p>
                                                            </td>
                                                            <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                                                <div className="flex justify-center">
                                                                    <select
                                                                        className={`px-3 py-1.5 rounded-lg text-xs font-semibold border-0 transition-colors ${lead.status === "Converted" || !canEdit
                                                                            ? "cursor-not-allowed opacity-60"
                                                                            : "cursor-pointer"
                                                                            } ${getStageColor(lead.status)}`}
                                                                        value={lead.status}
                                                                        onChange={(e) => handleStatusChange(lead.name, e.target.value)}
                                                                        disabled={lead.status === "Converted" || !canEdit}
                                                                    >
                                                                        {LEAD_STAGES.map(stage => (
                                                                            <option key={stage} value={stage}>{stage}</option>
                                                                        ))}
                                                                    </select>
                                                                </div>
                                                            </td>
                                                            <td className="px-6 py-4 cursor-pointer" onClick={() => router.push(`/crm/${encodeURIComponent(lead.name)}`)}>
                                                                <div className="flex justify-end items-center gap-3">
                                                                    <div className="w-24 h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                                                        <div
                                                                            className={`h-full rounded-full ${lead.aiScore >= 75 ? "bg-emerald-500" : lead.aiScore >= 50 ? "bg-orange-500" : "bg-red-500"
                                                                                }`}
                                                                            style={{ width: `${lead.aiScore}%` }}
                                                                        ></div>
                                                                    </div>
                                                                    <span className={`text-xs font-bold ${lead.aiScore >= 75 ? "text-emerald-500" : lead.aiScore >= 50 ? "text-orange-500" : "text-red-500"
                                                                        }`}>
                                                                        {lead.aiScore}
                                                                    </span>
                                                                </div>
                                                            </td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    )}

                                    {/* Kanban View */}
                                    {viewMode === "grid" && (
                                        <div className="p-6 overflow-x-auto h-full">
                                            <div className="flex gap-6 min-w-max h-full">
                                                {LEAD_STAGES.map(stage => {
                                                    const stageLeads = filteredLeads.filter(l => l.status === stage)
                                                    return (
                                                        <div
                                                            key={stage}
                                                            className="flex flex-col gap-4 flex-shrink-0 w-80"
                                                            onDragOver={handleDragOver}
                                                            onDrop={() => handleDrop(stage)}
                                                        >
                                                            {/* Column Header */}
                                                            <div className="flex items-center justify-between px-2">
                                                                <h3 className="text-[12px] font-bold text-slate-900 dark:text-white uppercase tracking-wider flex items-center gap-2">
                                                                    {stage} <span className="px-2 py-0.5 bg-slate-200 dark:bg-slate-800 rounded text-[10px]">{stageLeads.length}</span>
                                                                </h3>
                                                                <button className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition">
                                                                    <span className="material-symbols-outlined text-lg">more_horiz</span>
                                                                </button>
                                                            </div>

                                                            {/* Lead Cards */}
                                                            <div className="flex-1 space-y-4 overflow-y-auto no-scrollbar pr-1">
                                                                {stageLeads.map(lead => {
                                                                    // Determine priority icon based on AI score
                                                                    const priorityIcon = lead.aiScore >= 75
                                                                        ? { icon: 'local_fire_department', color: 'text-orange-500' }
                                                                        : lead.aiScore >= 50
                                                                            ? { icon: 'wb_sunny', color: 'text-blue-400' }
                                                                            : { icon: 'ac_unit', color: 'text-slate-400' }

                                                                    const isConverted = lead.status === "Converted"
                                                                    const isDraggable = !isConverted && canEdit

                                                                    return (
                                                                        <div
                                                                            key={lead.name}
                                                                            className={`bg-white dark:bg-slate-900 p-5 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md transition group ${isConverted || !canEdit ? 'opacity-60 cursor-not-allowed' : 'cursor-move'
                                                                                }`}
                                                                            draggable={isDraggable}
                                                                            onDragStart={(e) => handleDragStart(e, lead.name, lead.status)}
                                                                            onClick={(e) => {
                                                                                // Prevent navigation if dragging
                                                                                if (!draggedLead) {
                                                                                    router.push(`/crm/${encodeURIComponent(lead.name)}`)
                                                                                }
                                                                            }}
                                                                        >
                                                                            {/* Lead Header */}
                                                                            <div className="flex justify-between items-start mb-3">
                                                                                <div>
                                                                                    <h4 className="text-[16px] font-bold text-[#3b82f6] mb-0.5">{lead.lead_name}</h4>
                                                                                    <p className="text-[12px] text-slate-500 font-medium">{lead.company_name || 'Individual'}</p>
                                                                                </div>
                                                                                <span className={`material-symbols-outlined ${priorityIcon.color} text-lg`}>
                                                                                    {priorityIcon.icon}
                                                                                </span>
                                                                            </div>

                                                                            {/* AI Score Section */}
                                                                            <div className="flex items-center gap-3 mt-4">
                                                                                {/* Avatar or Initials */}
                                                                                <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold text-[10px] flex-shrink-0">
                                                                                    {lead.lead_name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)}
                                                                                </div>

                                                                                {/* AI Score Bar */}
                                                                                <div className="flex-1">
                                                                                    <div className="flex justify-between items-center mb-1">
                                                                                        <span className="text-[10px] font-bold text-slate-400 uppercase">AI Score</span>
                                                                                        <span className={`text-[10px] font-bold ${lead.aiScore >= 75 ? 'text-emerald-500' :
                                                                                            lead.aiScore >= 50 ? 'text-orange-500' :
                                                                                                'text-red-500'
                                                                                            }`}>
                                                                                            {lead.aiScore}%
                                                                                        </span>
                                                                                    </div>
                                                                                    <div className="h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                                                                        <div
                                                                                            className={`h-full rounded-full ${lead.aiScore >= 75 ? 'bg-emerald-500' :
                                                                                                lead.aiScore >= 50 ? 'bg-orange-500' :
                                                                                                    'bg-red-500'
                                                                                                }`}
                                                                                            style={{ width: `${lead.aiScore}%` }}
                                                                                        ></div>
                                                                                    </div>
                                                                                </div>
                                                                            </div>
                                                                        </div>
                                                                    )
                                                                })}
                                                                {stageLeads.length === 0 && (
                                                                    <div className="text-center py-8 text-sm text-slate-400">No leads</div>
                                                                )}
                                                            </div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* AI Insights Panel - Hidden in Kanban view */}
                            {viewMode === "list" && (
                                <div className="col-span-3">
                                    <div className="bg-[#111827] text-white rounded-xl shadow-xl overflow-hidden h-full flex flex-col border border-slate-800">
                                        <div className="p-6 border-b border-white/10 flex justify-between items-center bg-slate-900/50">
                                            <div className="flex items-center gap-3">
                                                <span className="material-symbols-outlined text-yellow-400">bolt</span>
                                                <h3 className="text-[11px] font-bold uppercase tracking-widest">AI Insights</h3>
                                            </div>
                                            <span className="w-2 h-2 bg-emerald-500 rounded-full shadow-[0_0_8px_rgba(16,185,129,0.5)]"></span>
                                        </div>
                                        <div className="flex-1 p-6 space-y-6 overflow-y-auto">
                                            {/* Deal at Risk */}
                                            <div className="bg-white/5 border border-white/10 rounded-xl p-5 relative overflow-hidden group">
                                                <div className="flex items-center gap-2 mb-3">
                                                    <span className="material-symbols-outlined text-yellow-400 text-sm">warning</span>
                                                    <span className="text-[10px] font-bold uppercase text-yellow-400 tracking-tighter">Deal at Risk</span>
                                                </div>
                                                <h4 className="text-sm font-bold mb-2">Acme Corp HQ - Phase II</h4>
                                                <p className="text-[12px] text-slate-400 mb-5 leading-relaxed">
                                                    Decision maker hasn't opened proposal for 5 days. Competitive threat detected.
                                                </p>
                                                <button className="w-full bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold py-3 rounded-lg text-xs transition uppercase tracking-wider">
                                                    Priority Outreach
                                                </button>
                                            </div>

                                            {/* Recommended Actions */}
                                            <div>
                                                <div className="flex justify-between items-center mb-5">
                                                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Recommended Actions</p>
                                                    <button className="text-[10px] text-blue-400 font-bold hover:underline">VIEW ALL</button>
                                                </div>
                                                <div className="space-y-3">
                                                    <div className="bg-white/5 p-4 rounded-xl flex items-center gap-4 group cursor-pointer hover:bg-white/10 border border-transparent hover:border-white/10 transition-all">
                                                        <div className="w-10 h-10 rounded-full bg-blue-500/20 flex items-center justify-center text-blue-400">
                                                            <span className="material-symbols-outlined">alternate_email</span>
                                                        </div>
                                                        <div>
                                                            <p className="text-[13px] font-bold">Follow up - Globtel</p>
                                                            <p className="text-[11px] text-slate-500 font-medium">High velocity activity.</p>
                                                        </div>
                                                    </div>
                                                    <div className="bg-white/5 p-4 rounded-xl flex items-center gap-4 group cursor-pointer hover:bg-white/10 border border-transparent hover:border-white/10 transition-all">
                                                        <div className="w-10 h-10 rounded-full bg-emerald-500/20 flex items-center justify-center text-emerald-400">
                                                            <span className="material-symbols-outlined text-lg">check_circle_outline</span>
                                                        </div>
                                                        <div>
                                                            <p className="text-[13px] font-bold">Contract - Urban</p>
                                                            <p className="text-[11px] text-slate-500 font-medium">Review is complete.</p>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="p-6 bg-white/[0.02] border-t border-white/10">
                                            <div className="flex justify-between items-center mb-2">
                                                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Sales Velocity</span>
                                                <span className="text-xs font-bold text-emerald-500">+14.2%</span>
                                            </div>
                                            <p className="text-[11px] text-slate-400 italic font-medium">
                                                "Cycle time is accelerating by 2 days this month."
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>


                    </div>
                </main>
            </div>

            {/* Dark Mode Toggle */}
            <button
                className="fixed bottom-6 right-6 w-12 h-12 bg-white dark:bg-slate-800 rounded-full shadow-2xl flex items-center justify-center border border-slate-200 dark:border-slate-700 text-slate-500 hover:text-primary transition-all z-50 hover:scale-110 active:scale-95"
                onClick={() => {
                    document.documentElement.classList.toggle("dark")
                }}
            >
                <span className="material-symbols-outlined dark:hidden">dark_mode</span>
                <span className="material-symbols-outlined hidden dark:block text-yellow-400">light_mode</span>
            </button>

            <style jsx global>{`
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>


            {/* Conversion Confirmation Dialog */}
            <Dialog open={isConversionDialogOpen} onOpenChange={setIsConversionDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Convert to Opportunity?</DialogTitle>
                        <DialogDescription>
                            This will create a new <strong>Opportunity</strong> record from this Lead and mark the Lead as <strong>Converted</strong>.
                        </DialogDescription>
                    </DialogHeader>
                    <div className="py-4">
                        <p className="text-sm text-slate-500">
                            Do you want to proceed with creating an Opportunity?
                        </p>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsConversionDialogOpen(false)} disabled={isConverting}>
                            Cancel
                        </Button>
                        <Button onClick={confirmConversion} disabled={isConverting}>
                            {isConverting ? "Converting..." : "Yes, Convert"}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div >
    )
}

"use client"

import { useState, useMemo } from "react"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { Search, Filter, Grid, List as ListIcon, ArrowRight, TrendingUp, DollarSign, Zap, CheckCircle, AlertCircle, PauseCircle } from "lucide-react"
import { updateOpportunitySalesStage } from "@/app/actions/crm"
import { PageHeader } from "@/components/page-header"
import { useUser } from "@/contexts/user-context"

interface Opportunity {
  name: string
  opportunity_from: string
  party_name: string
  customer_name?: string
  opportunity_type: string
  status: string
  sales_stage: string
  expected_closing: string
  probability: number
  opportunity_amount: number
  currency: string
}

interface OpportunitiesClientProps {
  opportunities: Opportunity[]
}

const SALES_STAGES = [
  "Prospecting",
  "Qualification",
  "Proposal/Price Quote",
  "Negotiation/Review"
] as const

export function OpportunitiesClient({ opportunities }: OpportunitiesClientProps) {
  const router = useRouter()
  const { canPerform } = useUser()

  const canCreate = canPerform('crm', 'create')
  const canEdit   = canPerform('crm', 'edit')

  const [viewMode, setViewMode] = useState<"list" | "kanban">("list")
  const [searchQuery, setSearchQuery] = useState("")
  const [selectedStage, setSelectedStage] = useState("All Stages")
  const [currentPage, setCurrentPage] = useState(1)
  const ITEMS_PER_PAGE = 20

  // Filter opportunities
  const openOpportunities = opportunities.filter(opp => opp.status === "Open")
  const wonOpportunities = opportunities.filter(opp => opp.status === "Converted")

  // Calculate stats
  const totalOpenOpportunities = openOpportunities.length
  const wonThisMonth = wonOpportunities.length
  const avgProbability = openOpportunities.length > 0
    ? (openOpportunities.reduce((sum, opp) => sum + opp.probability, 0) / openOpportunities.length).toFixed(1)
    : "0.0"

  // Filtered opportunities for table
  const filteredOpportunities = useMemo(() => {
    let result = openOpportunities

    if (searchQuery) {
      const query = searchQuery.toLowerCase()
      result = result.filter(opp =>
        (opp.customer_name || opp.party_name || "").toLowerCase().includes(query) ||
        opp.opportunity_type.toLowerCase().includes(query)
      )
    }

    if (selectedStage !== "All Stages") {
      result = result.filter(opp => opp.sales_stage === selectedStage)
    }

    return result
  }, [openOpportunities, searchQuery, selectedStage])

  // Pagination calculations
  const totalPages = Math.ceil(filteredOpportunities.length / ITEMS_PER_PAGE)
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE
  const endIndex = startIndex + ITEMS_PER_PAGE
  const paginatedOpportunities = filteredOpportunities.slice(startIndex, endIndex)

  // Reset to page 1 when filters change
  useMemo(() => {
    setCurrentPage(1)
  }, [searchQuery, selectedStage])

  // Helper: Get owner initials (mock)
  const getOwnerInitials = (opp: Opportunity): string => {
    const owners = ["MD", "SJ", "EL", "AT", "KR", "LW"]
    return owners[Math.floor(Math.random() * owners.length)]
  }

  // Helper: Get owner name (mock)
  const getOwnerName = (initials: string): string => {
    const names: Record<string, string> = {
      "MD": "Marcus D.",
      "SJ": "Sarah J.",
      "EL": "Elena L.",
      "AT": "Alex T.",
      "KR": "Kevin R.",
      "LW": "Lisa W."
    }
    return names[initials] || "Unknown"
  }

  // Helper: Get AI status badge
  const getAIStatus = (opp: Opportunity) => {
    if (opp.probability >= 75) {
      return { icon: CheckCircle, text: "On Track", color: "text-green-600 dark:text-green-400 bg-green-500/10 border-green-500/20" }
    } else if (opp.probability >= 40) {
      return { icon: PauseCircle, text: "Stalled", color: "text-orange-600 dark:text-orange-400 bg-orange-500/10 border-orange-500/20" }
    } else {
      return { icon: AlertCircle, text: "At Risk", color: "text-red-600 dark:text-red-400 bg-red-500/10 border-red-500/20" }
    }
  }

  // Handle stage change
  const handleStageChange = async (opportunityId: string, newStage: string) => {
    if (!canEdit) return
    try {
      // Estimate probability based on stage
      const probabilityMap: Record<string, number> = {
        "Prospecting": 10,
        "Qualification": 30,
        "Proposal/Price Quote": 60,
        "Negotiation/Review": 80
      }
      const probability = probabilityMap[newStage] || 50

      await updateOpportunitySalesStage(opportunityId, newStage, probability)
      router.refresh() // Refresh to show updated data
    } catch (error) {
      console.error("Failed to update opportunity stage:", error)
    }
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] dark:bg-slate-950">
      {/* Header */}
      <PageHeader />

      <main className="flex-1 p-8 max-w-[1600px] mx-auto w-full">
        {/* KPI Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative">
            <div className="flex justify-between items-start mb-4">
              <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Open Opportunities</span>
              <div className="p-2 rounded-lg bg-blue-500/10 text-blue-400">
                <TrendingUp className="h-5 w-5" />
              </div>
            </div>
            <div className="flex items-end gap-3">
              <span className="text-[28px] font-bold text-white leading-none">{totalOpenOpportunities}</span>
              <span className="text-sm font-semibold text-blue-400 mb-1">+12%</span>
            </div>
            <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-blue-500 w-[72%] rounded-full shadow-[0_0_8px_rgba(59,130,246,0.5)]"></div>
            </div>
          </div>

          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative">
            <div className="flex justify-between items-start mb-4">
              <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Won This Month</span>
              <div className="p-2 rounded-lg bg-green-500/10 text-green-400">
                <DollarSign className="h-5 w-5" />
              </div>
            </div>
            <div className="flex items-end gap-3">
              <span className="text-[28px] font-bold text-white leading-none">{wonThisMonth}</span>
              <span className="text-sm font-semibold text-emerald-400 mb-1">Target: 40</span>
            </div>
            <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-green-500 w-[70%] rounded-full shadow-[0_0_8px_rgba(34,197,94,0.5)]"></div>
            </div>
          </div>

          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative">
            <div className="flex justify-between items-start mb-4">
              <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Avg. Probability</span>
              <div className="p-2 rounded-lg bg-yellow-500/10 text-yellow-400">
                <Zap className="h-5 w-5" />
              </div>
            </div>
            <div className="flex items-end gap-3">
              <span className="text-[28px] font-bold text-white leading-none">{avgProbability}%</span>
              <span className="text-sm font-semibold text-slate-400 mb-1">AI Rating</span>
            </div>
            <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-yellow-500 rounded-full shadow-[0_0_8px_rgba(234,179,8,0.5)]" style={{ width: `${avgProbability}%` }}></div>
            </div>
          </div>
        </div>

        {/* Tabs and Filters */}
        <div className="flex items-center justify-between mb-6 border-b border-slate-200 dark:border-slate-800 pb-1">
          <div className="flex space-x-10">
            <button
              onClick={() => setSelectedStage("All Stages")}
              className={`pb-4 text-[14px] font-bold ${selectedStage === "All Stages" ? "text-blue-600 border-b-2 border-blue-600" : "text-slate-500 hover:text-slate-800 dark:hover:text-white"} transition-colors`}
            >
              All Stages
            </button>
            {SALES_STAGES.map(stage => (
              <button
                key={stage}
                onClick={() => setSelectedStage(stage)}
                className={`pb-4 text-[14px] font-semibold ${selectedStage === stage ? "text-blue-600 border-b-2 border-blue-600" : "text-slate-500 hover:text-slate-800 dark:hover:text-white"} transition-colors`}
              >
                {stage}
              </button>
            ))}
          </div>
          <div className="flex items-center space-x-4 pb-4">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 h-4 w-4" />
              <input
                className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg h-10 pl-10 pr-3 text-sm outline-none w-64 font-medium text-slate-600 dark:text-slate-300 placeholder:text-slate-400"
                placeholder="Search deals..."
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <button className="flex items-center h-10 space-x-2 text-sm font-medium px-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors text-slate-600 dark:text-slate-300">
              <Filter className="h-4 w-4 text-slate-500" />
              <span>Filter</span>
            </button>
            <div className="flex bg-slate-100 dark:bg-slate-900 rounded-lg p-1 border border-slate-200 dark:border-slate-700 h-10 items-center">
              <button
                onClick={() => setViewMode("list")}
                className={`flex items-center justify-center space-x-2 px-5 h-8 rounded-md ${viewMode === "list" ? "bg-white dark:bg-slate-800 shadow-sm text-blue-600" : "text-slate-500 hover:text-slate-800 dark:hover:text-white"} text-sm font-bold transition-all`}
              >
                <ListIcon className="h-4 w-4" />
                <span>List</span>
              </button>
              <button
                onClick={() => setViewMode("kanban")}
                className={`flex items-center justify-center space-x-2 px-5 h-8 rounded-md ${viewMode === "kanban" ? "bg-white dark:bg-slate-800 shadow-sm text-blue-600" : "text-slate-500 hover:text-slate-800 dark:hover:text-white"} text-sm font-medium transition-all`}
              >
                <Grid className="h-4 w-4" />
                <span>Kanban</span>
              </button>
            </div>
          </div>
        </div>

        {/* Opportunities Table */}
        <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden mb-12">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 dark:bg-slate-900/50 border-b border-slate-200 dark:border-slate-800">
                <th className="px-8 py-5 text-xs font-bold uppercase tracking-[0.1em] text-slate-500 w-1/4">Deal Name</th>
                <th className="px-8 py-5 text-xs font-bold uppercase tracking-[0.1em] text-slate-500">Value</th>
                <th className="px-8 py-5 text-xs font-bold uppercase tracking-[0.1em] text-slate-500">Owner</th>
                <th className="px-8 py-5 text-xs font-bold uppercase tracking-[0.1em] text-slate-500">Stage & AI Status</th>
                <th className="px-8 py-5 text-xs font-bold uppercase tracking-[0.1em] text-slate-500 text-center">Status</th>
                <th className="px-8 py-5 text-xs font-bold uppercase tracking-[0.1em] text-slate-500 text-right">Probability</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {filteredOpportunities.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-8 py-12 text-center text-slate-500">
                    No opportunities found
                  </td>
                </tr>
              ) : (
                paginatedOpportunities.map((opp) => {
                  const ownerInitials = getOwnerInitials(opp)
                  const ownerName = getOwnerName(ownerInitials)
                  const aiStatus = getAIStatus(opp)
                  const AIStatusIcon = aiStatus.icon

                  return (
                    <tr key={opp.name} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors cursor-pointer" onClick={() => router.push(`/crm/opportunities/${opp.name}`)}>
                      <td className="px-8 py-6">
                        <p className="text-[16px] font-bold text-slate-900 dark:text-white mb-1">{opp.customer_name || opp.party_name}</p>
                        <p className="text-[14px] text-slate-500 font-medium">{opp.opportunity_type}</p>
                      </td>
                      <td className="px-8 py-6">
                        <span className="text-[16px] font-bold text-slate-900 dark:text-white">
                          ${(opp.opportunity_amount / 1000).toFixed(opp.opportunity_amount >= 1000000 ? 1 : 0)}{opp.opportunity_amount >= 1000000 ? 'M' : 'K'}
                        </span>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex items-center space-x-3">
                          <div className={`w-9 h-9 ${ownerInitials === "MD" ? "bg-blue-100 text-blue-600" : ownerInitials === "SJ" ? "bg-purple-100 text-purple-600" : "bg-amber-100 text-amber-600"} rounded-full flex items-center justify-center text-xs font-bold ring-2 ring-white dark:ring-slate-800`}>
                            {ownerInitials}
                          </div>
                          <span className="text-[14px] font-medium text-slate-600 dark:text-slate-400">{ownerName}</span>
                        </div>
                      </td>
                      <td className="px-8 py-6" onClick={(e) => e.stopPropagation()}>
                        <div className="flex items-center space-x-4">
                          <select
                            className={`px-3.5 py-1.5 bg-slate-100 dark:bg-slate-800 text-[11px] font-extrabold uppercase tracking-wide rounded-md border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 transition-colors ${canEdit ? "cursor-pointer hover:bg-slate-200 dark:hover:bg-slate-700" : "cursor-not-allowed opacity-60"}`}
                            value={opp.sales_stage}
                            onChange={(e) => handleStageChange(opp.name, e.target.value)}
                            disabled={!canEdit}
                          >
                            {SALES_STAGES.map(stage => (
                              <option key={stage} value={stage}>{stage.split('/')[0]}</option>
                            ))}
                          </select>
                          <span className={`px-3 py-1 ${aiStatus.color} text-[10px] font-bold uppercase rounded border flex items-center tracking-widest`}>
                            <AIStatusIcon className="h-3.5 w-3.5 mr-1.5" />
                            {aiStatus.text}
                          </span>
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <span className="px-4 py-1.5 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 text-[10px] font-bold uppercase rounded-full tracking-widest">
                          {opp.status}
                        </span>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-col items-end">
                          <div className="flex items-center space-x-4">
                            <div className="w-32 bg-slate-100 dark:bg-slate-800 h-2 rounded-full overflow-hidden">
                              <div
                                className={`h-full ${opp.probability >= 75 ? "bg-green-500" : opp.probability >= 40 ? "bg-blue-500" : "bg-orange-500"}`}
                                style={{ width: `${opp.probability}%` }}
                              ></div>
                            </div>
                            <span className="text-[16px] font-bold text-slate-700 dark:text-slate-300">{opp.probability}%</span>
                          </div>
                        </div>
                      </td>
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>

          {/* Pagination Controls */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between px-8 py-6 border-t border-slate-200 dark:border-slate-800">
              <div className="text-sm text-slate-600 dark:text-slate-400">
                Showing <span className="font-semibold text-slate-900 dark:text-white">{startIndex + 1}</span> to <span className="font-semibold text-slate-900 dark:text-white">{Math.min(endIndex, filteredOpportunities.length)}</span> of <span className="font-semibold text-slate-900 dark:text-white">{filteredOpportunities.length}</span> opportunities
              </div>
              <div className="flex items-center space-x-2">
                <button
                  onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                  disabled={currentPage === 1}
                  className="px-4 py-2 text-sm font-medium text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-700 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  Previous
                </button>
                <div className="flex items-center space-x-1">
                  {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                    let pageNum;
                    if (totalPages <= 5) {
                      pageNum = i + 1;
                    } else if (currentPage <= 3) {
                      pageNum = i + 1;
                    } else if (currentPage >= totalPages - 2) {
                      pageNum = totalPages - 4 + i;
                    } else {
                      pageNum = currentPage - 2 + i;
                    }
                    return (
                      <button
                        key={pageNum}
                        onClick={() => setCurrentPage(pageNum)}
                        className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${currentPage === pageNum
                            ? "bg-blue-600 text-white"
                            : "text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700"
                          }`}
                      >
                        {pageNum}
                      </button>
                    );
                  })}
                </div>
                <button
                  onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                  disabled={currentPage === totalPages}
                  className="px-4 py-2 text-sm font-medium text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-700 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  Next
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Won Opportunities Section */}
        <div className="mt-16">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center space-x-4">
              <div className="p-2 bg-green-500/10 text-green-500 rounded-full">
                <CheckCircle className="h-5 w-5" />
              </div>
              <h3 className="text-[14px] font-bold uppercase tracking-[0.2em] text-slate-400">
                Won Opportunities <span className="ml-3 text-slate-500 font-medium">{wonOpportunities.length} DEALS COMPLETED</span>
              </h3>
            </div>
            <button className="text-[12px] font-bold uppercase tracking-widest text-slate-500 hover:text-blue-600 transition-all flex items-center">
              View All Won Deals <ArrowRight className="h-4 w-4 ml-2" />
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {wonOpportunities.slice(0, 3).map((opp) => (
              <Link key={opp.name} href={`/crm/opportunities/${opp.name}`}>
                <div className="bg-[#111827] rounded-xl p-6 flex items-center justify-between border border-transparent hover:border-green-500/30 transition-all cursor-pointer group">
                  <div className="flex items-center space-x-5">
                    <div className="w-12 h-12 bg-green-500/10 rounded-full flex items-center justify-center text-green-500 group-hover:bg-green-500/20 transition-colors">
                      <DollarSign className="h-6 w-6" />
                    </div>
                    <div>
                      <h5 className="text-[15px] font-bold text-white uppercase tracking-tight">{opp.customer_name || opp.party_name}</h5>
                      <p className="text-[10px] text-slate-500 uppercase font-extrabold tracking-widest mt-0.5">{opp.opportunity_type}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-green-400 font-bold text-[18px]">
                      ${(opp.opportunity_amount / 1000).toFixed(0)}K
                    </div>
                    <div className="text-[9px] bg-green-500/10 text-green-500 px-2 py-0.5 rounded inline-block font-extrabold uppercase tracking-widest mt-1">
                      Converted
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </main>

      <footer className="p-8 border-t border-slate-200 dark:border-slate-800 text-center">
        <p className="text-[10px] text-slate-500 font-bold tracking-[0.3em] uppercase">Powered by AVARIQ Opportunity Intelligence Engine</p>
      </footer>
    </div>
  )
}

'use client'

import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Printer, FileText, Trash2, CheckCircle, X, Loader2 } from "lucide-react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { submitQuotation, cancelQuotation, deleteQuotation } from "@/app/actions/crm"

interface QuotationActionsProps {
  quotation: {
    name: string
    docstatus: number
    status: string
  }
}

export function QuotationActions({ quotation }: QuotationActionsProps) {
  const [loading, setLoading] = useState(false)
  const router = useRouter()

  const handleAction = async (action: 'submit' | 'cancel' | 'delete') => {
    let confirmMessage = ''
    
    if (action === 'submit') {
      confirmMessage = 'Submit this quotation? It will become read-only and ready for Sales Order creation.'
    } else if (action === 'cancel') {
      confirmMessage = 'Cancel this quotation? This action cannot be undone.'
    } else if (action === 'delete') {
      confirmMessage = 'Delete this quotation? This action cannot be undone.'
    }

    if (!confirm(confirmMessage)) {
      return
    }

    setLoading(true)
    try {
      let result
      if (action === 'submit') {
        result = await submitQuotation(quotation.name)
      } else if (action === 'cancel') {
        result = await cancelQuotation(quotation.name)
      } else {
        result = await deleteQuotation(quotation.name)
        if (result.success) {
          router.push('/crm/quotations')
          return
        }
      }
      
      if (result.error) {
        alert('Error: ' + result.error)
      } else {
        router.refresh()
      }
    } catch (error: any) {
      alert('Error: ' + error.message)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="flex items-center gap-2">
      {/* Print Button (Always Visible) */}
      <Link href={`/print/quotation/${encodeURIComponent(quotation.name)}`} target="_blank">
        <Button variant="outline" className="gap-2">
          <Printer className="h-4 w-4" /> Print
        </Button>
      </Link>

      {/* Edit Button (Only for Draft) */}
      {quotation.docstatus === 0 && (
        <Link href={`/crm/quotations/${encodeURIComponent(quotation.name)}/edit`}>
          <Button variant="outline" className="gap-2">
            <FileText className="h-4 w-4" />
            Edit
          </Button>
        </Link>
      )}

      {/* Submit Button (Only for Draft) */}
      {quotation.docstatus === 0 && (
        <Button 
          onClick={() => handleAction('submit')} 
          disabled={loading}
          className="bg-blue-600 hover:bg-blue-700 text-white gap-2"
        >
          {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4" />}
          Submit
        </Button>
      )}

      {/* Cancel Button (Only for Submitted) */}
      {quotation.docstatus === 1 && (
        <Button 
          onClick={() => handleAction('cancel')} 
          disabled={loading}
          variant="destructive"
          className="gap-2"
        >
          {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <X className="h-4 w-4" />}
          Cancel
        </Button>
      )}

      {/* Delete Button (Only for Draft) */}
      {quotation.docstatus === 0 && (
        <Button 
          onClick={() => handleAction('delete')} 
          disabled={loading}
          variant="destructive"
          className="gap-2"
        >
          {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
          Delete
        </Button>
      )}
    </div>
  )
}

"use client"

import { useState, useMemo } from "react"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { Search, Filter, TrendingUp, Wallet, Zap, User, Calendar, DollarSign, Package, ArrowRight } from "lucide-react"
import { PageHeader } from "@/components/page-header"


interface Quotation {
  name: string
  quotation_to: string
  party_name: string
  customer_name?: string
  status: string
  valid_till: string
  grand_total: number
  currency: string
  transaction_date?: string
  total_qty?: number
  contact_email?: string
}

interface Opportunity {
  name: string
  opportunity_from: string
  party_name: string
  customer_name?: string
  opportunity_type: string
  status: string
  sales_stage: string
  expected_closing: string
  probability: number
  opportunity_amount: number
  currency: string
}

interface QuotationsClientProps {
  quotations: Quotation[]
  opportunities: Opportunity[]
}

const STATUS_TABS = [
  { name: "All Quotations", filter: "all" },
  { name: "Ready for Quotation", filter: "ready" }
] as const

export function QuotationsClient({ quotations, opportunities }: QuotationsClientProps) {
  const router = useRouter()
  const [searchQuery, setSearchQuery] = useState("")
  const [selectedTab, setSelectedTab] = useState("all")
  const [statusFilter, setStatusFilter] = useState("all")
  const [dateFilter, setDateFilter] = useState("last30")
  const [currentPage, setCurrentPage] = useState(1)
  const ITEMS_PER_PAGE = 5

  // Calculate KPIs
  const totalQuotations = quotations.length
  const openQuotations = quotations.filter(q => ['Open', 'Sent'].includes(q.status)).length
  const totalValue = quotations.reduce((sum, q) => sum + (q.grand_total || 0), 0)

  // Filtered quotations
  const filteredQuotations = useMemo(() => {
    let result = quotations

    // Search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase()
      result = result.filter(q =>
        q.name.toLowerCase().includes(query) ||
        (q.customer_name || q.party_name || "").toLowerCase().includes(query) ||
        (q.contact_email || "").toLowerCase().includes(query)
      )
    }

    // Status filter
    if (statusFilter !== "all") {
      result = result.filter(q => q.status.toLowerCase() === statusFilter.toLowerCase())
    }

    // Tab filter
    if (selectedTab === "ready") {
      result = result.filter(q => q.status === 'Draft')
    }

    return result
  }, [quotations, searchQuery, statusFilter, selectedTab])

  // Pagination
  const totalPages = Math.ceil(filteredQuotations.length / ITEMS_PER_PAGE)
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE
  const endIndex = startIndex + ITEMS_PER_PAGE
  const paginatedQuotations = filteredQuotations.slice(startIndex, endIndex)

  // Reset to page 1 when filters change
  useMemo(() => {
    setCurrentPage(1)
  }, [searchQuery, statusFilter, selectedTab])

  // Helper: Get status badge styling
  const getStatusBadge = (status: string) => {
    const styles: Record<string, string> = {
      'Draft': 'bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-200',
      'Open': 'bg-blue-50 dark:bg-blue-900/40 text-blue-700 dark:text-blue-200 border border-blue-100 dark:border-blue-900',
      'Sent': 'bg-blue-50 dark:bg-blue-900/40 text-blue-700 dark:text-blue-200 border border-blue-100 dark:border-blue-900',
      'Cancelled': 'bg-slate-100 dark:bg-slate-800 text-slate-500 border border-slate-200 dark:border-slate-700',
      'Ordered': 'bg-green-50 dark:bg-green-900/40 text-green-700 dark:text-green-200 border border-green-100 dark:border-green-900'
    }
    return styles[status] || 'bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-200'
  }

  // Helper: Get AI insight badge
  const getAIInsight = (quotation: Quotation) => {
    if (quotation.status === 'Draft') {
      return {
        text: 'Follow-up Recommended',
        color: 'bg-yellow-50 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400 border border-yellow-200 dark:border-yellow-800'
      }
    } else if (quotation.status === 'Open' && quotation.grand_total > 25000) {
      return {
        text: 'High Win Probability',
        color: 'bg-emerald-50 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 border border-emerald-200 dark:border-emerald-800'
      }
    }
    return null
  }

  // Helper: Format currency
  const formatCurrency = (amount: number) => {
    if (amount >= 100000) {
      return `Γé╣${(amount / 100000).toFixed(1)}L`
    }
    return `Γé╣${amount.toLocaleString('en-IN')}`
  }

  // Helper: Calculate days remaining
  const getDaysRemaining = (validTill: string) => {
    const today = new Date()
    const validDate = new Date(validTill)
    const diffTime = validDate.getTime() - today.getTime()
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))

    if (diffDays < 0) {
      return { text: 'Expired', color: 'text-red-500' }
    } else if (diffDays < 7) {
      return { text: `${diffDays} days remaining`, color: 'text-orange-500' }
    }
    return { text: `${diffDays} days remaining`, color: 'text-slate-400' }
  }

  // Find opportunities in Proposal/Price Quote stage, Open status, and no draft quotation exists
  const draftQuotations = quotations.filter(q => q.status === 'Draft')
  const proposalOpportunities = opportunities.filter(
    opp => opp.sales_stage === 'Proposal/Price Quote' && opp.status === 'Open'
  )

  // Only use combined array for ready tab, otherwise just show quotations
  const readyQuotationsAndOpportunities = useMemo(() => {
    if (selectedTab !== "ready") return paginatedQuotations.map(q => ({ type: "quotation" as const, data: q }));
    // Combine paginated draft quotations and proposal opportunities (no deduplication by opportunity possible)
    return [
      ...paginatedQuotations.map(q => ({ type: "quotation" as const, data: q })),
      ...proposalOpportunities.map(o => ({ type: "opportunity" as const, data: o }))
    ];
  }, [selectedTab, paginatedQuotations, proposalOpportunities])

  return (
    <div className="min-h-screen bg-[#f8fafc] dark:bg-slate-950">
      {/* Header */}
      <PageHeader
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        searchPlaceholder="Search quotations, customers or ask AI..."
      />

      <main className="flex-1 overflow-y-auto p-10 space-y-10 w-full">
        {/* KPI Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative">
            <div className="flex justify-between items-start mb-4">
              <p className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Total Quotations</p>
              <div className="p-2 rounded-lg bg-blue-500/10 text-blue-500">
                <TrendingUp className="h-5 w-5" />
              </div>
            </div>
            <div className="flex items-end gap-3">
              <p className="text-[28px] font-bold text-white leading-none">{totalQuotations}</p>
              <span className="text-sm font-semibold text-blue-400 mb-1">+12%</span>
            </div>
            <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-blue-500 w-[72%] rounded-full shadow-[0_0_8px_rgba(59,130,246,0.5)]"></div>
            </div>
          </div>

          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative">
            <div className="flex justify-between items-start mb-4">
              <p className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Open Quotations</p>
              <div className="p-2 rounded-lg bg-emerald-500/10 text-emerald-500">
                <Wallet className="h-5 w-5" />
              </div>
            </div>
            <div className="flex items-end gap-3">
              <p className="text-[28px] font-bold text-white leading-none">{openQuotations}</p>
              <span className="text-sm font-semibold text-slate-400 mb-1">Target: 10</span>
            </div>
            <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-emerald-500 w-[50%] rounded-full shadow-[0_0_8px_rgba(34,197,94,0.5)]"></div>
            </div>
          </div>

          <div className="bg-[#111827] p-6 rounded-xl border border-slate-800 shadow-xl relative">
            <div className="flex justify-between items-start mb-4">
              <p className="text-[12px] font-bold text-slate-400 uppercase tracking-widest">Total Value</p>
              <div className="p-2 rounded-lg bg-yellow-400/10 text-yellow-400">
                <Zap className="h-5 w-5" />
              </div>
            </div>
            <div className="flex items-end gap-3">
              <p className="text-[28px] font-bold text-white leading-none">{formatCurrency(totalValue)}</p>
            </div>
            <div className="mt-5 h-1.5 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-yellow-400 w-[85%] rounded-full shadow-[0_0_8px_rgba(234,179,8,0.5)]"></div>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-slate-100 dark:border-slate-700">
            {/* Tabs */}
            <div className="flex items-center gap-10 mb-8 border-b border-slate-100 dark:border-slate-700">
              {STATUS_TABS.map((tab) => (
                <button
                  key={tab.filter}
                  onClick={() => setSelectedTab(tab.filter)}
                  className={`text-[16px] font-bold pb-4 transition-all ${selectedTab === tab.filter
                      ? 'text-slate-900 dark:text-white border-b-4 border-blue-600'
