// Animated Progress Ring for circular metrics
interface AnimatedProgressRingProps {
  percentage: number;
  size?: number;
  strokeWidth?: number;
  delay?: number;
  label?: string;
}

export function AnimatedProgressRing({ 
  percentage, 
  size = 120, 
  strokeWidth = 8,
  delay = 0,
  label = "" 
}: AnimatedProgressRingProps) {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const safePercentage = Math.min(Math.max(Number(percentage ?? 0), 0), 100);
  const offset = circumference - (safePercentage / 100) * circumference;

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.8 }}
      animate={{ opacity: 1, scale: 1 }}
      transition={{ delay, type: "spring", stiffness: 300, damping: 20 }}
      className="relative inline-flex items-center justify-center"
    >
      <svg width={size} height={size} className="transform -rotate-90">
        {/* Background circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke="#e2e8f0"
          strokeWidth={strokeWidth}
        />
        {/* Progress circle */}
        <motion.circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke="url(#progressGradient)"
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeDasharray={circumference}
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset: offset }}
          transition={{
            delay: delay + 0.2,
            duration: 1,
            ease: "easeOut",
          }}
        />
        <defs>
          <linearGradient id="progressGradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#0ea5e9" />
            <stop offset="100%" stopColor="#a855f7" />
          </linearGradient>
        </defs>
      </svg>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: delay + 0.5 }}
        className="absolute inset-0 flex flex-col items-center justify-center"
      >
        <span className="text-2xl font-bold text-slate-900 dark:text-white">
          {Math.round(safePercentage)}%
        </span>
        {label && (
          <span className="text-xs text-slate-500 dark:text-slate-400 mt-1">
            {label}
          </span>
        )}
      </motion.div>
    </motion.div>
  );
}

'use client'

import { useEffect, useState } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Progress } from '@/components/ui/progress'
import { Button } from '@/components/ui/button'
import { Users, FileText, FolderKanban, Receipt, AlertCircle } from 'lucide-react'
import { getUsageSummary } from '@/app/actions/usage-limits'

interface UsageSummary {
  plan: string
  planName: string
  usage: {
    users: { current: number; limit: number | 'unlimited' }
    leads: { current: number; limit: number | 'unlimited' }
    projects: { current: number; limit: number | 'unlimited' }
    invoices: { current: number; limit: number | 'unlimited' }
    storage: { current: number; limit: number | 'unlimited' }
  }
}

export function UsageWidget({ subdomain }: { subdomain: string }) {
  const [usage, setUsage] = useState<UsageSummary | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function fetchUsage() {
      try {
        const data = await getUsageSummary(subdomain)
        setUsage(data)
      } catch (error) {
        console.error('Failed to fetch usage:', error)
      } finally {
        setLoading(false)
      }
    }

    if (subdomain) {
      fetchUsage()
    }
  }, [subdomain])

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Usage & Limits</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground">Loading...</p>
        </CardContent>
      </Card>
    )
  }

  if (!usage) {
    return null
  }

  function getPercentage(current: number, limit: number | 'unlimited'): number {
    if (limit === 'unlimited') return 0
    return (current / limit) * 100
  }

  function isNearLimit(current: number, limit: number | 'unlimited'): boolean {
    if (limit === 'unlimited') return false
    return current >= limit * 0.8
  }

  const usageItems = [
    {
      icon: Users,
      label: 'Team Members',
      current: usage.usage.users.current,
      limit: usage.usage.users.limit,
      color: 'blue'
    },
    {
      icon: FileText,
      label: 'Leads',
      current: usage.usage.leads.current,
      limit: usage.usage.leads.limit,
      color: 'green'
    },
    {
      icon: FolderKanban,
      label: 'Projects',
      current: usage.usage.projects.current,
      limit: usage.usage.projects.limit,
      color: 'purple'
    },
    {
      icon: Receipt,
      label: 'Invoices',
      current: usage.usage.invoices.current,
      limit: usage.usage.invoices.limit,
      color: 'orange'
    }
  ]

  return (
    <Card>
      <CardHeader>
        <div className="flex justify-between items-start">
          <div>
            <CardTitle>Usage & Limits</CardTitle>
            <CardDescription>
              Current plan: <span className="font-semibold">{usage.planName}</span>
            </CardDescription>
          </div>
          <Button size="sm" variant="outline" asChild>
            <a href="/settings?tab=billing">Upgrade Plan</a>
          </Button>
        </div>
      </CardHeader>
      <CardContent className="space-y-6">
        {usageItems.map((item) => {
          const Icon = item.icon
          const percentage = getPercentage(item.current, item.limit)
          const nearLimit = isNearLimit(item.current, item.limit)
          const limitText = item.limit === 'unlimited' ? 'Γê₧' : item.limit

          return (
            <div key={item.label} className="space-y-2">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Icon className="h-4 w-4 text-muted-foreground" />
                  <span className="text-sm font-medium">{item.label}</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-sm">
                    {item.current} / {limitText}
                  </span>
                  {nearLimit && (
                    <AlertCircle className="h-4 w-4 text-orange-500" />
                  )}
                </div>
              </div>
              {item.limit !== 'unlimited' && (
                <Progress 
                  value={percentage} 
                  className={`h-2 ${nearLimit ? 'bg-orange-100' : ''}`}
                />
              )}
              {nearLimit && (
                <p className="text-xs text-orange-600">
                  You're approaching your limit. Consider upgrading.
                </p>
              )}
            </div>
          )
        })}
      </CardContent>
    </Card>
  )
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Loader2, AlertTriangle, ShieldCheck, Info } from "lucide-react";

export function AIRiskScore({ inspection }: { inspection: any }) {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  const calculateRisk = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/ai/risk-score', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          inputs: {
            inspection_data: JSON.stringify({
              status: inspection.status,
              remarks: inspection.remarks,
              type: inspection.inspection_type,
            })
          }
        })
      });

      if (!res.ok) {
        throw new Error('Failed to generate risk score');
      }

      const data = await res.json();
      setResult(data.result);
    } catch (err: any) {
      setError(err.message || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const getRiskColor = (score: number) => {
    if (score >= 80) return "text-red-500 bg-red-50 border-red-200 dark:bg-red-500/10 dark:border-red-500/20";
    if (score >= 50) return "text-amber-500 bg-amber-50 border-amber-200 dark:bg-amber-500/10 dark:border-amber-500/20";
    return "text-emerald-500 bg-emerald-50 border-emerald-200 dark:bg-emerald-500/10 dark:border-emerald-500/20";
  };

  const getRiskIcon = (score: number) => {
    if (score >= 80) return <AlertTriangle className="h-6 w-6 text-red-500" />;
    if (score >= 50) return <Info className="h-6 w-6 text-amber-500" />;
    return <ShieldCheck className="h-6 w-6 text-emerald-500" />;
  };

  return (
    <Card className="mt-6 border-indigo-100 dark:border-indigo-900/40 bg-indigo-50/30 dark:bg-indigo-950/20">
      <CardHeader className="pb-3 border-b border-indigo-50 dark:border-indigo-900/20">
        <div className="flex justify-between items-center">
          <CardTitle className="text-lg flex items-center gap-2 text-indigo-900 dark:text-indigo-300">
            <span className="material-symbols-outlined text-indigo-500">auto_awesome</span>
            AI Risk Assessment
          </CardTitle>
          {!result && !loading && (
            <Button 
                onClick={calculateRisk} 
                variant="outline" 
                size="sm"
                className="bg-white hover:bg-indigo-50 text-indigo-600 border-indigo-200 dark:bg-slate-900 dark:hover:bg-indigo-950/50 dark:border-indigo-800"
            >
              Analyze Risk
            </Button>
          )}
        </div>
      </CardHeader>
      <CardContent className="pt-4">
        {loading && (
          <div className="flex items-center justify-center p-6 text-indigo-500 gap-3">
            <Loader2 className="h-5 w-5 animate-spin" />
            <span className="text-sm font-medium">Neural engine analyzing inspection data...</span>
          </div>
        )}

        {error && (
          <div className="p-4 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm flex items-start gap-3 border border-red-100 dark:border-red-800/50">
            <AlertTriangle className="h-5 w-5 shrink-0" />
            <p>{error}</p>
          </div>
        )}

        {result && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <div className={`p-5 rounded-xl border flex items-center gap-4 ${getRiskColor(result?.risk_score || 0)}`}>
               <div className="bg-white/50 dark:bg-black/20 p-3 rounded-full shadow-sm">
                 {getRiskIcon(result?.risk_score || 0)}
               </div>
               <div className="flex-1">
                 <p className="text-sm font-bold uppercase tracking-wider opacity-80 mb-1">
                    Risk Score
                 </p>
                 <div className="flex items-end gap-2">
                    <span className="text-4xl font-black leading-none">{result?.risk_score || "--"}</span>
                    <span className="text-sm font-medium pb-1 opacity-70">/ 100</span>
                 </div>
               </div>
               <Button 
                  onClick={calculateRisk} 
                  variant="ghost" 
                  size="sm"
                  className="opacity-70 hover:opacity-100"
                >
                  Re-evaluate
                </Button>
            </div>

            {result?.recommendation && (
              <div className="p-4 bg-white dark:bg-slate-900 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm text-sm font-bold text-slate-700 dark:text-slate-300 uppercase tracking-widest text-center">
                 {result.recommendation}
              </div>
            )}

            {result?.critical_issues && result.critical_issues.length > 0 && (
                <div>
                    <h4 className="text-sm font-bold text-slate-900 dark:text-slate-100 mb-2 px-1 text-red-600 dark:text-red-400 flex items-center gap-2">
                       <AlertTriangle className="w-4 h-4" /> Detected Risk Factors
                    </h4>
                    <ul className="space-y-2">
                        {result.critical_issues.map((issue: string, i: number) => (
                            <li key={i} className="flex items-start gap-2 text-sm text-slate-700 dark:text-slate-300 bg-red-50/50 dark:bg-red-900/10 border border-red-100 dark:border-red-900/30 p-3 rounded-lg">
                                <span className="bg-red-100 text-red-700 dark:bg-red-500/20 dark:text-red-400 rounded-full w-5 h-5 flex items-center justify-center text-[10px] font-bold shrink-0 mt-0.5">{i + 1}</span>
                                {issue}
                            </li>
                        ))}
                    </ul>
                </div>
            )}
          </div>
        )}

        {!result && !loading && !error && (
            <div className="text-center p-6">
                <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm mx-auto">
                    Click "Analyze Risk" to evaluate this inspection and surface potential issues using our AI engine.
                </p>
            </div>
        )}
      </CardContent>
    </Card>
  );
}

'use client'

import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Plus, Trash2, Loader2, Info } from "lucide-react"
import { createInvoice, getItemGroups } from "@/app/actions/invoices"
import { useRouter } from "next/navigation"
import { useEffect } from "react"
import { ItemSearch } from "./item-search"
import { PricingRulesIndicator } from "@/components/pricing-rules/pricing-rules-indicator"
import { AppliedRulesSummary } from "@/components/pricing-rules/applied-rules-summary"
import { applyPricingRules } from "@/app/actions/apply-pricing-rules"

interface InvoiceItem {
  id: number
  item_code: string
  description: string
  hsn_sac: string
  qty: number
  rate: number
  amount: number
}

export function CreateInvoiceSheet() {
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [itemGroups, setItemGroups] = useState<string[]>([])
  const [selectedItemGroup, setSelectedItemGroup] = useState<string>('All')
  const [appliedPricingRules, setAppliedPricingRules] = useState<any[]>([])
  const router = useRouter()

  // Load item groups
  useEffect(() => {
    const loadGroups = async () => {
      const groups = await getItemGroups()
      setItemGroups(['All', ...groups])
    }
    if (open) loadGroups()
  }, [open])

  // Header Fields
  const [customer, setCustomer] = useState("")
  const [date, setDate] = useState(new Date().toISOString().split('T')[0])
  const [dueDate, setDueDate] = useState("")
  const [placeOfSupply, setPlaceOfSupply] = useState("27-Maharashtra")

  // Items State
  const [items, setItems] = useState<InvoiceItem[]>([
    { id: 1, item_code: "", description: "", hsn_sac: "997319", qty: 1, rate: 0, amount: 0 }
  ])

  // Calculations
  const calculateRowAmount = (qty: number, rate: number) => qty * rate

  const updateItem = (id: number, field: keyof InvoiceItem, value: any) => {
    setItems(items.map(item => {
      if (item.id === id) {
        const updatedItem = { ...item, [field]: value }
        if (field === 'qty' || field === 'rate') {
          updatedItem.amount = calculateRowAmount(updatedItem.qty, updatedItem.rate)
        }
        return updatedItem
      }
      return item
    }))
  }

  const addItem = () => {
    setItems([...items, { 
      id: Date.now(), item_code: "", description: "", hsn_sac: "", qty: 1, rate: 0, amount: 0 
    }])
  }

  const removeItem = (id: number) => {
    if (items.length > 1) setItems(items.filter(item => item.id !== id))
  }

  // Auto-apply pricing rules when items or customer changes
  useEffect(() => {
    const applyRules = async () => {
      if (!customer || !date || items.length === 0 || !items.some(i => i.item_code)) {
        setAppliedPricingRules([])
        return
      }

      try {
        const result = await applyPricingRules({
          customer,
          transaction_date: date,
          items: items
            .filter(item => item.item_code)
            .map(item => ({
              item_code: item.item_code,
              qty: item.qty,
              rate: item.rate,
            })),
        })

        if (result.applied_rules.length > 0) {
          // Update items with pricing rule adjustments
          const updatedItems = items.map(item => {
            const ruleItem = result.items.find(ri => ri.item_code === item.item_code)
            if (ruleItem && ruleItem.pricing_rule) {
              const originalRate = item.rate
              let finalRate = ruleItem.rate
              
              // Apply discount if specified
              if (ruleItem.discount_percentage) {
                finalRate = originalRate * (1 - ruleItem.discount_percentage / 100)
              } else if (ruleItem.discount_amount) {
                finalRate = originalRate - ruleItem.discount_amount
              }

              return {
                ...item,
                rate: finalRate,
                amount: calculateRowAmount(item.qty, finalRate),
              }
            }
            return item
          })
          setItems(updatedItems)

          // Track applied rules for display
          const appliedRulesDisplay = result.applied_rules.map(rule => {
            const item = items.find(i => i.item_code === result.items.find(ri => ri.pricing_rule === rule.rule_name)?.item_code)
            const ruleItem = result.items.find(ri => ri.pricing_rule === rule.rule_name)
            return {
              rule_name: rule.rule_name,
              rule_title: rule.rule_title,
              item_code: item?.item_code || '',
              item_name: item?.description || '',
              original_rate: item?.rate || 0,
              final_rate: ruleItem?.rate || item?.rate || 0,
              discount_percentage: rule.discount_percentage,
              discount_amount: rule.discount_amount,
              savings: item ? (item.rate - (ruleItem?.rate || item.rate)) * item.qty : 0,
            }
          })
          setAppliedPricingRules(appliedRulesDisplay)
        } else {
          setAppliedPricingRules([])
        }
      } catch (error) {
        console.error('Failed to apply pricing rules:', error)
      }
    }

    applyRules()
  }, [customer, date, items.map(i => `${i.item_code}-${i.qty}`).join(',')])

  // Totals Logic (GST 18%)
  const subTotal = items.reduce((sum, item) => sum + (item.amount || 0), 0)
  const cgst = subTotal * 0.09
  const sgst = subTotal * 0.09
  const grandTotal = subTotal + cgst + sgst

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)
    
    const payload = {
        customer,
        posting_date: date,
        due_date: dueDate,
        items
    }

    const res = await createInvoice(payload)
    
    if (res.success) {
      setOpen(false)
      router.refresh()
      // Reset form
      setCustomer("")
      setItems([{ id: Date.now(), item_code: "", description: "", hsn_sac: "997319", qty: 1, rate: 0, amount: 0 }])
    } else {
      alert("Error: " + res.error)
    }
    setLoading(false)
  }

  return (
    <Sheet open={open} onOpenChange={setOpen}>
      <SheetTrigger asChild>
        <Button className="bg-blue-600 hover:bg-blue-700 text-white gap-2">
          <Plus className="h-4 w-4" /> New Invoice
        </Button>
      </SheetTrigger>
      <SheetContent className="overflow-y-auto sm:max-w-[900px] w-full bg-slate-50 dark:bg-slate-950 border-l border-slate-200 dark:border-slate-800 p-0">
        
        {/* Sticky Header */}
        <div className="sticky top-0 z-10 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-6 py-4 flex justify-between items-center">
            <div>
                <SheetTitle className="text-xl font-bold text-slate-900 dark:text-white">New GST Invoice</SheetTitle>
                <div className="flex items-center gap-2 mt-1">
                    <span className="px-2 py-0.5 rounded text-xs font-medium bg-yellow-100 text-yellow-800">
                        Draft
                    </span>
                </div>
            </div>
            <Button type="submit" onClick={handleSubmit} disabled={loading} className="bg-slate-900 text-white hover:bg-slate-800 dark:bg-slate-100 dark:text-slate-900">
                {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Save Invoice
            </Button>
        </div>
        
        <div className="px-6 py-6 space-y-8">
          
          {/* Category Filter */}
          <div className="bg-white dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-800 p-4">
            <div className="flex items-center gap-4">
              <Label htmlFor="category-filter" className="text-sm font-medium whitespace-nowrap">Filter Items by Category:</Label>
              <Select value={selectedItemGroup} onValueChange={setSelectedItemGroup}>
                <SelectTrigger className="w-[250px]">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="All">All Categories</SelectItem>
                  {itemGroups.filter(g => g !== 'All').map(group => (
                    <SelectItem key={group} value={group}>{group}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <p className="text-xs text-slate-500">Items will be filtered by selected category</p>
            </div>
          </div>

          {/* Pricing Rules Indicator */}
          {customer && date && (
            <PricingRulesIndicator
              customer={customer}
              transactionDate={date}
              itemGroups={items.map(item => item.item_code).filter(Boolean)}
            />
          )}

          {/* Applied Pricing Rules Summary */}
          {appliedPricingRules.length > 0 && (
            <AppliedRulesSummary appliedRules={appliedPricingRules} />
          )}

          {/* Section 1: Customer Details */}
          <div className="bg-white dark:bg-slate-900 p-4 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm">
            <h3 className="text-sm font-semibold text-slate-900 dark:text-white mb-4 border-b pb-2 border-slate-100 dark:border-slate-800">Billing Details</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                
                <div className="grid gap-1.5 md:col-span-2">
                    <Label htmlFor="customer" className="text-xs text-slate-500">Customer Name <span className="text-red-500">*</span></Label>
                    <Input 
                        id="customer" 
                        value={customer} 
                        onChange={(e) => setCustomer(e.target.value)} 
                        placeholder="Search Customer..." 
                        className="bg-yellow-50/50 border-yellow-200 focus-visible:ring-yellow-200 text-slate-900 dark:text-slate-100" 
                    />
                </div>

                <div className="grid gap-1.5">
                    <Label htmlFor="date" className="text-xs text-slate-500">Invoice Date</Label>
                    <Input 
                        id="date" 
                        type="date" 
                        value={date} 
                        onChange={(e) => setDate(e.target.value)} 
                        className="bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800"
                    />
                </div>

                <div className="grid gap-1.5">
                    <Label className="text-xs text-slate-500">Place of Supply</Label>
                    <Select value={placeOfSupply} onValueChange={setPlaceOfSupply}>
                        <SelectTrigger className="h-9 bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="27-Maharashtra">Maharashtra (27)</SelectItem>
                            <SelectItem value="29-Karnataka">Karnataka (29)</SelectItem>
                            <SelectItem value="07-Delhi">Delhi (07)</SelectItem>
                        </SelectContent>
                    </Select>
                </div>

                <div className="grid gap-1.5">
                    <Label htmlFor="dueDate" className="text-xs text-slate-500">Due Date</Label>
                    <Input 
                        id="dueDate" 
                        type="date" 
                        value={dueDate} 
                        onChange={(e) => setDueDate(e.target.value)} 
                        className="bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800"
                    />
                </div>
            </div>
          </div>

          {/* Section 2: Service Details (Items) */}
          <div className="bg-white dark:bg-slate-900 p-4 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-sm font-semibold text-slate-900 dark:text-white">Service / Equipment Details</h3>
              <div className="flex items-center gap-2">
                <Label className="text-xs text-slate-500">Catalogue:</Label>
                <Select value={selectedItemGroup} onValueChange={setSelectedItemGroup}>
                  <SelectTrigger className="h-8 w-[200px] text-xs">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {itemGroups.map(group => (
                      <SelectItem key={group} value={group}>{group}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            
            <div className="border border-slate-200 dark:border-slate-800 rounded-md overflow-hidden">
                {/* Table Header */}
                <div className="grid grid-cols-12 gap-2 bg-slate-100 dark:bg-slate-800 text-xs font-medium text-slate-500 py-2 px-3 border-b border-slate-200 dark:border-slate-700">
                    <div className="col-span-1 text-center">#</div>
                    <div className="col-span-4">Description / Item</div>
                    <div className="col-span-2">HSN/SAC</div>
                    <div className="col-span-1 text-right">Qty</div>
                    <div className="col-span-2 text-right">Rate (Γé╣)</div>
                    <div className="col-span-2 text-right">Amount (Γé╣)</div>
                </div>

                {/* Table Rows */}
                <div className="divide-y divide-slate-100 dark:divide-slate-800 bg-white dark:bg-slate-900">
                    {items.map((item, index) => (
                        <div key={item.id} className="grid grid-cols-12 gap-2 px-3 py-2 items-start hover:bg-slate-50/50 dark:hover:bg-slate-800/50 group">
                            <div className="col-span-1 pt-2 text-center text-sm text-slate-400">
                                <span className="group-hover:hidden">{index + 1}</span>
                                <Trash2 className="h-4 w-4 mx-auto hidden group-hover:block text-red-500 cursor-pointer" onClick={() => removeItem(item.id)} />
                            </div>
                            <div className="col-span-4 space-y-1">
                                <ItemSearch 
                                    value={item.item_code}
                                    itemGroup={selectedItemGroup}
                                    onChange={(itemCode, description) => {
                                        updateItem(item.id, 'item_code', itemCode)
                                        if (description && !item.description) {
                                            updateItem(item.id, 'description', description)
                                        }
                                    }}
                                />
                                <Input 
                                    placeholder="Description" 
                                    value={item.description} 
                                    onChange={(e) => updateItem(item.id, 'description', e.target.value)} 
                                    className="h-7 text-xs text-muted-foreground border-dashed border-slate-200 dark:border-slate-800 bg-transparent" 
                                />
                            </div>
                            <div className="col-span-2">
                                <Input 
                                    value={item.hsn_sac} 
                                    onChange={(e) => updateItem(item.id, 'hsn_sac', e.target.value)} 
                                    className="h-8 text-sm border-slate-200 dark:border-slate-800 bg-transparent" 
                                    placeholder="997319" 
                                />
                            </div>
                            <div className="col-span-1">
                                <Input 
                                    type="number" 
                                    value={item.qty} 
                                    onChange={(e) => updateItem(item.id, 'qty', parseFloat(e.target.value) || 0)} 
                                    className="h-8 text-sm text-right border-slate-200 dark:border-slate-800 bg-transparent" 
                                />
                            </div>
                            <div className="col-span-2">
                                <Input 
                                    type="number" 
                                    value={item.rate} 
                                    onChange={(e) => updateItem(item.id, 'rate', parseFloat(e.target.value) || 0)} 
                                    className="h-8 text-sm text-right border-slate-200 dark:border-slate-800 bg-transparent" 
                                />
                            </div>
                            <div className="col-span-2 pt-2 text-right text-sm font-medium text-slate-700 dark:text-slate-300">
                                Γé╣ {item.amount.toLocaleString('en-IN')}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="mt-3">
                <Button type="button" variant="outline" size="sm" onClick={addItem} className="text-xs h-8 gap-1">
                    <Plus className="h-3 w-3" /> Add Item
                </Button>
            </div>
          </div>

          {/* Section 3: GST Calculation */}
          <div className="bg-white dark:bg-slate-900 p-6 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm">
             <div className="flex flex-col gap-3 max-w-sm ml-auto">
                <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Subtotal</span>
                    <span className="text-slate-900 dark:text-slate-200">Γé╣ {subTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
                <div className="flex justify-between text-sm text-slate-500">
                    <span>CGST (9%)</span>
                    <span>Γé╣ {cgst.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
                <div className="flex justify-between text-sm text-slate-500">
                    <span>SGST (9%)</span>
                    <span>Γé╣ {sgst.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
                <div className="flex justify-between items-center border-t border-slate-200 dark:border-slate-800 pt-3 mt-2">
                    <span className="font-bold text-slate-900 dark:text-white">Grand Total</span>
                    <span className="text-xl font-bold font-mono text-slate-900 dark:text-white">Γé╣ {grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
             </div>
          </div>

        </div>
      </SheetContent>
    </Sheet>
  )
}

'use client'

import * as React from "react"
import { Check, ChevronsUpDown } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import { searchCustomers } from "@/app/actions/invoices"

interface CustomerSearchProps {
  value: string
  onChange: (value: string) => void
}

export function CustomerSearch({ value, onChange }: CustomerSearchProps) {
  const [open, setOpen] = React.useState(false)
  const [customers, setCustomers] = React.useState<{ name: string, customer_name: string }[]>([])
  const [query, setQuery] = React.useState("")

  React.useEffect(() => {
    const fetchCustomers = async () => {
      // Use query or empty string if initial load
      const searchQuery = query || "" 
      const results = await searchCustomers(searchQuery)
      setCustomers(results)
    }
    
    // Debounce to prevent API flooding while typing
    const debounce = setTimeout(fetchCustomers, 300)
    return () => clearTimeout(debounce)
  }, [query])

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          role="combobox"
          aria-expanded={open}
          className="w-full justify-between bg-yellow-50/50 border-yellow-200 focus-visible:ring-yellow-200 text-left font-normal"
        >
          {value
            ? customers.find((customer) => customer.name === value)?.customer_name || value
            : "Search Customer..."}
          <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-full p-0">
        {/* FIX: Added shouldFilter={false} because we filter on the server side */}
        <Command shouldFilter={false}>
          <CommandInput placeholder="Search customer..." onValueChange={setQuery} />
          <CommandList>
            {customers.length === 0 && <CommandEmpty>No customer found.</CommandEmpty>}
            <CommandGroup>
              {customers.map((customer) => (
                <CommandItem
                  key={customer.name}
                  value={customer.name} // This is the ID
                  keywords={[customer.customer_name]} // Helps accessibility
                  onSelect={(currentValue) => {
                    // currentValue might be lowercased by cmdk, but we want the real ID
                    // Since we use the ID as the value, it should match.
                    // To be safe, we just use the customer object from the map scope
                    onChange(customer.name)
                    setOpen(false)
                  }}
                >
                  <Check
                    className={cn(
                      "mr-2 h-4 w-4",
                      value === customer.name ? "opacity-100" : "opacity-0"
                    )}
                  />
                  {customer.customer_name}
                </CommandItem>
              ))}
            </CommandGroup>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  )
}

'use client'

import { Button } from "@/components/ui/button"
import { Printer, CheckCircle, Ban, Loader2 } from "lucide-react"
import { submitInvoice, cancelInvoice } from "@/app/actions/invoices"
import { useState } from "react"
import { useRouter } from "next/navigation"
import { PaymentDialog } from "./payment-dialog"

export function InvoiceActions({ invoice }: { invoice: any }) {
  const [loading, setLoading] = useState(false)
  const router = useRouter()

  const handleAction = async (action: 'submit' | 'cancel') => {
    setLoading(true)
    const res = action === 'submit' 
      ? await submitInvoice(invoice.name)
      : await cancelInvoice(invoice.name)
    
    setLoading(false)
    if (res.success) {
      router.refresh()
    } else {
      alert("Error: " + res.error)
    }
  }

  const hasOutstanding = invoice.docstatus === 1 && 
    (invoice.outstanding_amount > 0 || invoice.status !== 'Paid')

  return (
    <div className="flex items-center gap-2">
        {/* Print Button (Always Visible) */}
        <a 
            href={`/print/invoice/${invoice.name}`}
            target="_blank"
            rel="noopener noreferrer"
        >
            <Button variant="outline" className="gap-2">
                <Printer className="h-4 w-4" /> Print PDF
            </Button>
        </a>

        {/* Payment Button (Only for Submitted with Outstanding) */}
        {hasOutstanding && <PaymentDialog invoice={invoice} />}

        {/* Submit Button (Only for Drafts) */}
        {invoice.docstatus === 0 && (
            <Button 
                onClick={() => handleAction('submit')} 
                disabled={loading}
                className="bg-blue-600 hover:bg-blue-700 text-white gap-2"
            >
                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4" />}
                Submit
            </Button>
        )}

        {/* Cancel Button (Only for Submitted) */}
        {invoice.docstatus === 1 && (
            <Button 
                onClick={() => handleAction('cancel')} 
                disabled={loading}
                variant="destructive"
                className="gap-2"
            >
                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Ban className="h-4 w-4" />}
                Cancel
            </Button>
        )}
    </div>
  )
}

'use client'

import React, { useState, useEffect } from 'react'
import { useSearchParams, useRouter } from 'next/navigation'
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Badge } from "@/components/ui/badge"
import { AnimatedCard, AnimatedButton } from "@/components/ui/animated"
import { Plus, Trash2, FileText, DollarSign, Percent, Package, Calendar, ChevronDown, ChevronUp } from "lucide-react"
import { createInvoice } from "@/app/actions/invoices"
import { getTaxTemplates, getTaxTemplateDetails, getWarehouses } from "@/app/actions/common"
import { getSalesOrder } from "@/app/actions/sales-orders"

interface InvoiceItem {
  item_code: string
  item_name?: string
  description: string
  qty: number
  uom: string
  rate: number
  discount_percentage: number
  amount: number
  warehouse: string
  
  // Rental fields
  rental_type?: string
  rental_duration?: number
  rental_start_date?: string
  rental_end_date?: string
  rental_start_time?: string
  rental_end_time?: string
  requires_operator?: boolean
  operator_included?: boolean
  operator_name?: string
  base_cost?: number
  accommodation_charges?: number
  usage_charges?: number
  fuel_charges?: number
  elongation_charges?: number
  risk_charges?: number
  commercial_charges?: number
  incidental_charges?: number
  other_charges?: number
  total_rental_cost?: number
}

interface TaxTemplate {
  name: string
  title: string
}

export default function InvoiceWithRentalForm() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const salesOrderParam = searchParams.get('sales_order')
  
  const [loading, setLoading] = useState(false)
  const [fetchingSalesOrder, setFetchingSalesOrder] = useState(false)
  const [taxTemplates, setTaxTemplates] = useState<TaxTemplate[]>([])
  const [warehouses, setWarehouses] = useState<string[]>([])
  const [expandedItems, setExpandedItems] = useState<Set<number>>(new Set())
  
  const [formData, setFormData] = useState({
    customer: '',
    customer_name: '',
    posting_date: new Date().toISOString().split('T')[0],
    due_date: '',
    currency: 'INR',
    terms: '',
    contact_email: '',
    territory: '',
    taxes_and_charges: '',
    sales_order_no: '',
    po_no: '',
    po_date: ''
  })

  const [items, setItems] = useState<InvoiceItem[]>([{
    item_code: '',
    item_name: '',
    description: '',
    qty: 1,
    uom: 'Nos',
    rate: 0,
    discount_percentage: 0,
    amount: 0,
    warehouse: ''
  }])

  // Fetch tax templates and warehouses
  useEffect(() => {
    const fetchData = async () => {
      const [templates, warehouseList] = await Promise.all([
        getTaxTemplates(),
        getWarehouses()
      ])
      setTaxTemplates(Array.isArray(templates) ? templates : [])
      setWarehouses(warehouseList)
    }
    fetchData()
  }, [])

  // Fetch sales order data if parameter exists
  useEffect(() => {
    const fetchSalesOrder = async () => {
      if (!salesOrderParam) return
      
      setFetchingSalesOrder(true)
      try {
        const salesOrder = await getSalesOrder(salesOrderParam)
        
        if (salesOrder) {
          setFormData({
            customer: salesOrder.customer || '',
            customer_name: salesOrder.customer_name || '',
            posting_date: new Date().toISOString().split('T')[0],
            due_date: salesOrder.delivery_date || '',
            currency: salesOrder.currency || 'INR',
            terms: salesOrder.terms || '',
            contact_email: salesOrder.contact_email || '',
            territory: salesOrder.territory || '',
            taxes_and_charges: salesOrder.taxes_and_charges || '',
            sales_order_no: salesOrder.name || '',
            po_no: salesOrder.po_no || '',
            po_date: salesOrder.po_date || ''
          })

          if (salesOrder.items && salesOrder.items.length > 0) {
            const invoiceItems = salesOrder.items.map((item: any) => {
              const baseItem = {
                item_code: item.item_code || '',
                item_name: item.item_name || '',
                description: item.description || '',
                qty: item.qty || 1,
                uom: item.uom || 'Nos',
                rate: item.rate || 0,
                discount_percentage: item.discount_percentage || 0,
                amount: item.amount || 0,
                warehouse: item.warehouse || ''
              }

              // Map rental data if present
              if (item.custom_rental_type || item.custom_rental_duration) {
                return {
                  ...baseItem,
                  rental_type: item.custom_rental_type || '',
                  rental_duration: item.custom_rental_duration || 0,
                  rental_start_date: item.custom_rental_start_date || '',
                  rental_end_date: item.custom_rental_end_date || '',
                  rental_start_time: item.custom_rental_start_time || '',
                  rental_end_time: item.custom_rental_end_time || '',
                  requires_operator: item.custom_requires_operator || false,
                  operator_included: item.custom_operator_included || false,
                  operator_name: item.custom_operator_name || '',
                  base_cost: item.custom_base_rental_cost || 0,
                  accommodation_charges: item.custom_accommodation_charges || 0,
                  usage_charges: item.custom_usage_charges || 0,
                  fuel_charges: item.custom_fuel_charges || 0,
                  elongation_charges: item.custom_elongation_charges || 0,
                  risk_charges: item.custom_risk_charges || 0,
                  commercial_charges: item.custom_commercial_charges || 0,
                  incidental_charges: item.custom_incidental_charges || 0,
                  other_charges: item.custom_other_charges || 0,
                  total_rental_cost: item.custom_total_rental_cost || 0
                }
              }

              return baseItem
            })
            setItems(invoiceItems)
          }
        }
      } catch (error) {
        console.error('Failed to fetch sales order:', error)
      } finally {
        setFetchingSalesOrder(false)
      }
    }

    fetchSalesOrder()
  }, [salesOrderParam])

  const calculateItemAmount = (item: InvoiceItem) => {
    const subtotal = item.qty * item.rate
    const discount = subtotal * (item.discount_percentage / 100)
    return subtotal - discount
  }

  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...items]
    newItems[index] = { ...newItems[index], [field]: value }
    
    if (['qty', 'rate', 'discount_percentage'].includes(field)) {
      newItems[index].amount = calculateItemAmount(newItems[index])
    }
    
    // Recalculate total rental cost when pricing components change
    if (field.includes('_cost') || field.includes('_charges')) {
      const item = newItems[index]
      const totalRentalCost = (
        (item.base_cost || 0) +
        (item.accommodation_charges || 0) +
        (item.usage_charges || 0) +
        (item.fuel_charges || 0) +
        (item.elongation_charges || 0) +
        (item.risk_charges || 0) +
        (item.commercial_charges || 0) +
        (item.incidental_charges || 0) +
        (item.other_charges || 0)
      )
      newItems[index].total_rental_cost = totalRentalCost
      newItems[index].rate = totalRentalCost
      newItems[index].amount = calculateItemAmount(newItems[index])
    }
    
    setItems(newItems)
  }

  const toggleItemExpansion = (index: number) => {
    const newExpanded = new Set(expandedItems)
    if (newExpanded.has(index)) {
      newExpanded.delete(index)
    } else {
      newExpanded.add(index)
    }
    setExpandedItems(newExpanded)
  }

  const addItem = () => {
    setItems([...items, {
      item_code: '',
      item_name: '',
      description: '',
      qty: 1,
      uom: 'Nos',
      rate: 0,
      discount_percentage: 0,
      amount: 0,
      warehouse: ''
    }])
  }

  const removeItem = (index: number) => {
    if (items.length > 1) {
      setItems(items.filter((_, i) => i !== index))
    }
  }

  const netTotal = items.reduce((sum, item) => sum + item.amount, 0)
  const totalQty = items.reduce((sum, item) => sum + item.qty, 0)
  
  // Calculate tax
  const [taxAmount, setTaxAmount] = useState(0)
  const [taxRate, setTaxRate] = useState(0)
  
  useEffect(() => {
    const fetchTaxRate = async () => {
      if (formData.taxes_and_charges && netTotal > 0) {
        try {
          const taxTemplate = await getTaxTemplateDetails(formData.taxes_and_charges) as any
          if (taxTemplate.taxes && taxTemplate.taxes.length > 0) {
            const totalRate = taxTemplate.taxes.reduce((sum: number, tax: any) => sum + (tax.rate || 0), 0)
            setTaxRate(totalRate)
            setTaxAmount((netTotal * totalRate) / 100)
          } else {
            setTaxRate(0)
            setTaxAmount(0)
          }
        } catch (error) {
          console.error('Error fetching tax template:', error)
          setTaxRate(0)
          setTaxAmount(0)
        }
      } else {
        setTaxRate(0)
        setTaxAmount(0)
      }
    }
    fetchTaxRate()
  }, [formData.taxes_and_charges, netTotal])
  
  const grandTotal = netTotal + taxAmount

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)

    try {
      const invoiceData = {
        ...formData,
        items: items.map(item => {
          const baseItem: any = {
            item_code: item.item_code,
            item_name: item.item_name || item.item_code,
            description: item.description,
            qty: item.qty,
            uom: item.uom,
            rate: item.rate,
            discount_percentage: item.discount_percentage,
            amount: item.amount,
            warehouse: item.warehouse
          }

          // Map rental data to ERPNext custom fields if present
          if (item.rental_type || item.rental_duration) {
            baseItem.custom_is_rental = 1
            baseItem.custom_rental_type = item.rental_type ? item.rental_type.charAt(0).toUpperCase() + item.rental_type.slice(1) : undefined
            baseItem.custom_rental_duration = item.rental_duration
            baseItem.custom_rental_start_date = item.rental_start_date
            baseItem.custom_rental_end_date = item.rental_end_date
            baseItem.custom_rental_start_time = item.rental_start_time
            baseItem.custom_rental_end_time = item.rental_end_time
            baseItem.custom_requires_operator = item.requires_operator ? 1 : 0
            baseItem.custom_operator_included = item.operator_included ? 1 : 0
            if (item.operator_name) baseItem.custom_operator_name = item.operator_name
            
            baseItem.custom_base_rental_cost = item.base_cost || 0
            baseItem.custom_accommodation_charges = item.accommodation_charges || 0
            baseItem.custom_usage_charges = item.usage_charges || 0
            baseItem.custom_fuel_charges = item.fuel_charges || 0
            baseItem.custom_elongation_charges = item.elongation_charges || 0
            baseItem.custom_risk_charges = item.risk_charges || 0
            baseItem.custom_commercial_charges = item.commercial_charges || 0
            baseItem.custom_incidental_charges = item.incidental_charges || 0
            baseItem.custom_other_charges = item.other_charges || 0
            baseItem.custom_total_rental_cost = item.total_rental_cost || 0
          }

          return baseItem
        })
      }

      const result = await createInvoice(invoiceData)
      
      if (result.error) {
        alert(result.error)
      } else {
        router.push('/invoices')
      }
    } catch (error) {
      console.error('Error creating invoice:', error)
      alert('Failed to create invoice')
    } finally {
      setLoading(false)
    }
  }

  if (fetchingSalesOrder) {
    return (
      <div className="p-8 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-slate-600">Loading sales order data...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="p-8 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">
            {salesOrderParam ? 'Create Invoice from Sales Order' : 'Create New Invoice'}
          </h1>
          <p className="text-slate-500 mt-1">
            {salesOrderParam ? `Based on ${salesOrderParam}` : 'Fill in the details below'}
          </p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Customer & Date Info */}
        <AnimatedCard>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="w-5 h-5" />
              Invoice Details
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="customer">Customer *</Label>
                <Input
                  id="customer"
                  required
                  value={formData.customer}
                  onChange={(e) => setFormData({...formData, customer: e.target.value})}
                  placeholder="Customer ID"
                />
              </div>
              <div>
                <Label htmlFor="customer_name">Customer Name</Label>
                <Input
                  id="customer_name"
                  value={formData.customer_name}
                  onChange={(e) => setFormData({...formData, customer_name: e.target.value})}
                  placeholder="Customer Name"
                />
              </div>
              <div>
                <Label htmlFor="posting_date">Posting Date *</Label>
                <Input
                  id="posting_date"
                  type="date"
                  required
                  value={formData.posting_date}
                  onChange={(e) => setFormData({...formData, posting_date: e.target.value})}
                />
              </div>
              <div>
                <Label htmlFor="due_date">Due Date</Label>
                <Input
                  id="due_date"
                  type="date"
                  value={formData.due_date}
                  onChange={(e) => setFormData({...formData, due_date: e.target.value})}
                />
              </div>
              <div>
                <Label htmlFor="taxes_and_charges">Tax Template</Label>
                <select
                  id="taxes_and_charges"
                  className="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 rounded-md"
                  value={formData.taxes_and_charges}
                  onChange={(e) => setFormData({...formData, taxes_and_charges: e.target.value})}
                >
                  <option value="">Select Tax Template</option>
                  {taxTemplates.map((template) => (
                    <option key={template.name} value={template.name}>
                      {template.title || template.name}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <Label htmlFor="territory">Territory</Label>
                <Input
                  id="territory"
                  value={formData.territory}
                  onChange={(e) => setFormData({...formData, territory: e.target.value})}
                  placeholder="Territory"
                />
              </div>
            </div>
          </CardContent>
        </AnimatedCard>

        {/* Items Section */}
        <AnimatedCard>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <Package className="w-5 h-5" />
                Items
                <Badge variant="secondary" className="ml-2">
                  Total Qty: {totalQty}
                </Badge>
              </CardTitle>
              <Button type="button" onClick={addItem} size="sm" variant="outline">
                <Plus className="w-4 h-4 mr-2" />
                Add Item
              </Button>
            </div>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-slate-200 dark:border-slate-700">
                    <th className="text-left py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">ITEM CODE *</th>
                    <th className="text-left py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">DESCRIPTION</th>
                    <th className="text-left py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">WAREHOUSE</th>
                    <th className="text-right py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">QTY *</th>
                    <th className="text-left py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">UOM</th>
                    <th className="text-right py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">RATE *</th>
                    <th className="text-right py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">DISC %</th>
                    <th className="text-right py-2 px-2 text-xs font-medium text-slate-600 dark:text-slate-400">AMOUNT</th>
                    <th className="py-2 px-2"></th>
                  </tr>
                </thead>
                <tbody>
                  {items.map((item, index) => {
                    const isRental = item.rental_type || item.rental_duration || item.base_cost
                    const hasBreakdown = (item.base_cost && item.base_cost > 0) || 
                                        (item.accommodation_charges && item.accommodation_charges > 0) ||
                                        (item.usage_charges && item.usage_charges > 0) ||
                                        (item.fuel_charges && item.fuel_charges > 0) ||
                                        (item.elongation_charges && item.elongation_charges > 0) ||
                                        (item.risk_charges && item.risk_charges > 0) ||
                                        (item.commercial_charges && item.commercial_charges > 0) ||
                                        (item.incidental_charges && item.incidental_charges > 0) ||
                                        (item.other_charges && item.other_charges > 0)
                    
                    return (
                      <React.Fragment key={index}>
                        <tr className="border-b border-slate-100 dark:border-slate-800">
                          <td className="py-2 px-2">
                            <Input
                              required
                              placeholder="Item code"
                              value={item.item_code}
                              onChange={(e) => updateItem(index, 'item_code', e.target.value)}
                              className="text-sm"
                            />
                          </td>
                          <td className="py-2 px-2">
                            <Input
                              placeholder="Description"
                              value={item.description}
                              onChange={(e) => updateItem(index, 'description', e.target.value)}
                              className="text-sm"
                            />
                          </td>
                          <td className="py-2 px-2">
                            <select
                              className="w-full px-2 py-1 text-sm bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded"
                              value={item.warehouse}
                              onChange={(e) => updateItem(index, 'warehouse', e.target.value)}
                            >
                              <option value="">Select</option>
                              {warehouses.map((wh) => (
                                <option key={wh} value={wh}>{wh}</option>
                              ))}
                            </select>
                          </td>
                          <td className="py-2 px-2">
                            <Input
                              type="number"
                              required
                              min="1"
                              value={item.qty}
                              onChange={(e) => updateItem(index, 'qty', parseFloat(e.target.value) || 0)}
                              className="text-sm text-right"
                            />
                          </td>
                          <td className="py-2 px-2">
                            <Input
                              placeholder="UOM"
                              value={item.uom}
                              onChange={(e) => updateItem(index, 'uom', e.target.value)}
                              className="text-sm"
                            />
                          </td>
                          <td className="py-2 px-2">
                            <Input
                              type="number"
                              required
                              min="0"
                              step="0.01"
                              value={item.rate}
                              onChange={(e) => updateItem(index, 'rate', parseFloat(e.target.value) || 0)}
                              className="text-sm text-right"
                            />
                          </td>
                          <td className="py-2 px-2">
                            <Input
                              type="number"
                              min="0"
                              max="100"
                              step="0.01"
                              value={item.discount_percentage}
                              onChange={(e) => updateItem(index, 'discount_percentage', parseFloat(e.target.value) || 0)}
                              className="text-sm text-right"
                            />
                          </td>
                          <td className="py-2 px-2 text-right font-medium text-slate-900 dark:text-white">
                            {item.amount.toFixed(2)}
                          </td>
                          <td className="py-2 px-2">
                            {items.length > 1 && (
                              <Button
                                type="button"
                                variant="ghost"
                                size="sm"
                                onClick={() => removeItem(index)}
                              >
                                <Trash2 className="w-4 h-4 text-red-500" />
                              </Button>
                            )}
                          </td>
                        </tr>
                        
                        {/* Rental Pricing Breakdown Row - Editable */}
                        {isRental && (
                          <tr className="border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/30">
                            <td colSpan={9} className="py-2 px-2">
                              <div className="space-y-2">
                                <Button
                                  type="button"
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => toggleItemExpansion(index)}
                                  className="w-full flex items-center justify-between text-xs font-medium text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800"
                                >
                                  <div className="flex items-center gap-2">
                                    <Package className="w-3.5 h-3.5" />
                                    <span>Rental Pricing Components</span>
                                    {item.rental_type && (
                                      <Badge variant="outline" className="text-xs">
                                        {item.rental_duration} {item.rental_type}
                                      </Badge>
                                    )}
                                    {hasBreakdown && (
                                      <Badge variant="secondary" className="text-xs">
                                        Γé╣{(item.total_rental_cost || 0).toLocaleString('en-IN')}
                                      </Badge>
                                    )}
                                  </div>
                                  {expandedItems.has(index) ? (
                                    <ChevronUp className="w-4 h-4" />
                                  ) : (
                                    <ChevronDown className="w-4 h-4" />
                                  )}
                                </Button>
                                
                                {expandedItems.has(index) && (
                                  <div className="bg-white dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700 p-4">
                                    <div className="grid grid-cols-3 gap-3">
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Base Cost *</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.base_cost || 0}
                                          onChange={(e) => updateItem(index, 'base_cost', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Accommodation</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.accommodation_charges || 0}
                                          onChange={(e) => updateItem(index, 'accommodation_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Usage Charges</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.usage_charges || 0}
                                          onChange={(e) => updateItem(index, 'usage_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Fuel Charges</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.fuel_charges || 0}
                                          onChange={(e) => updateItem(index, 'fuel_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Elongation</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.elongation_charges || 0}
                                          onChange={(e) => updateItem(index, 'elongation_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Risk Charges</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.risk_charges || 0}
                                          onChange={(e) => updateItem(index, 'risk_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Commercial</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.commercial_charges || 0}
                                          onChange={(e) => updateItem(index, 'commercial_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Incidental</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.incidental_charges || 0}
                                          onChange={(e) => updateItem(index, 'incidental_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                      <div>
                                        <Label className="text-xs text-slate-600 dark:text-slate-400">Other Charges</Label>
                                        <Input
                                          type="number"
                                          min="0"
                                          step="0.01"
                                          value={item.other_charges || 0}
                                          onChange={(e) => updateItem(index, 'other_charges', parseFloat(e.target.value) || 0)}
                                          className="mt-1 text-sm"
                                          placeholder="0.00"
                                        />
                                      </div>
                                    </div>
                                    
                                    <div className="mt-4 pt-3 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center">
                                      <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">Total Rental Cost</span>
                                      <span className="text-lg font-bold text-blue-600 dark:text-blue-400">
                                        Γé╣{(item.total_rental_cost || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                      </span>
                                    </div>
                                  </div>
                                )}
                              </div>
                            </td>
                          </tr>
                        )}
                      </React.Fragment>
                    )
                  })}
                </tbody>
              </table>
            </div>
          </CardContent>
        </AnimatedCard>

        {/* Summary & Submit */}
        <AnimatedCard>
          <CardContent className="pt-6">
            <div className="flex justify-between items-start">
              <div className="flex-1">
                <Label htmlFor="terms">Terms & Conditions</Label>
                <Textarea
                  id="terms"
                  value={formData.terms}
                  onChange={(e) => setFormData({...formData, terms: e.target.value})}
                  placeholder="Enter terms and conditions..."
                  rows={4}
                  className="mt-2"
                />
              </div>
              <div className="ml-8 min-w-[300px] space-y-3">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-600">Net Total:</span>
                  <span className="font-medium">Γé╣{netTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
                {taxRate > 0 && (
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-600">Taxes ({taxRate}%):</span>
                    <span className="font-medium">Γé╣{taxAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                  </div>
                )}
                <div className="flex justify-between text-lg font-bold pt-3 border-t border-slate-200">
                  <span>Grand Total:</span>
                  <span className="text-blue-600">Γé╣{grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                </div>
                <div className="flex gap-2 pt-4">
                  <Button
                    type="button"
                    variant="outline"
                    className="flex-1"
                    onClick={() => router.back()}
                    disabled={loading}
                  >
                    Cancel
                  </Button>
                  <AnimatedButton
                    type="submit"
                    className="flex-1"
                    disabled={loading || items.some(item => !item.item_code || item.qty <= 0)}
                  >
                    {loading ? (
                      <>
                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                        Creating...
                      </>
                    ) : (
                      <>
                        <FileText className="w-4 h-4 mr-2" />
                        Create Invoice
                      </>
                    )}
                  </AnimatedButton>
                </div>
              </div>
            </div>
          </CardContent>
        </AnimatedCard>
      </form>
    </div>
  )
}

"use client"

import { useState, useMemo } from "react"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { Search, Filter, Download, CheckCircle, Calendar, Receipt } from "lucide-react"
import { PageHeader } from "@/components/page-header"

interface Invoice {
  name: string
  customer_name: string
  grand_total: number
  status: string
  due_date: string
  currency: string
  docstatus?: number
}

interface SalesOrder {
  name: string
  customer: string
  customer_name?: string
  status: string
  delivery_status?: string
  grand_total: number
  currency: string
  transaction_date: string
  per_billed?: number
  per_delivered?: number
}

interface InvoicesClientProps {
  invoices: Invoice[]
  readyForInvoice: SalesOrder[]
}

export function InvoicesClient({ invoices, readyForInvoice }: InvoicesClientProps) {
  const router = useRouter()
  const [searchQuery, setSearchQuery] = useState("")
  const [currentPage, setCurrentPage] = useState(1)
  const ITEMS_PER_PAGE = 8

  // Calculate KPIs
  const totalInvoices = invoices.length
  const pendingInvoices = invoices.filter(inv => inv.status === 'Draft' || inv.status === 'Unpaid').length
  const overdueInvoices = invoices.filter(inv => {
    if (!inv.due_date) return false
    return new Date(inv.due_date) < new Date() && inv.status !== 'Paid' && inv.status !== 'Cancelled'
  }).length
  const totalCollected = invoices
    .filter(inv => inv.status === 'Paid')
    .reduce((sum, inv) => sum + (inv.grand_total || 0), 0)

  // Filtered invoices
  const filteredInvoices = useMemo(() => {
    let result = invoices

    if (searchQuery) {
      const query = searchQuery.toLowerCase()
      result = result.filter(inv =>
        inv.name.toLowerCase().includes(query) ||
        (inv.customer_name || "").toLowerCase().includes(query)
      )
    }

    return result
  }, [invoices, searchQuery])

  // Pagination
  const totalPages = Math.ceil(filteredInvoices.length / ITEMS_PER_PAGE)
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE
  const endIndex = startIndex + ITEMS_PER_PAGE
  const paginatedInvoices = filteredInvoices.slice(startIndex, endIndex)

  // Reset to page 1 when search changes
  useMemo(() => {
    setCurrentPage(1)
  }, [searchQuery])

  // Helper functions
  const formatCurrency = (amount: number, currency: string = 'INR') => {
    if (amount >= 100000) {
      return `${currency} ${(amount / 100000).toFixed(1)}L`
    }
    return `${currency} ${amount.toLocaleString('en-IN')}`
  }

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })
  }

  const getStatusBadge = (status: string) => {
    const styles: Record<string, string> = {
      'Paid': 'bg-slate-900 text-white dark:bg-slate-800',
      'Unpaid': 'bg-blue-100 text-blue-600',
      'Sent': 'bg-blue-100 text-blue-600',
      'Draft': 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400',
      'Cancelled': 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400',
      'Overdue': 'bg-red-100 text-red-600'
    }
    return styles[status] || 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400'
  }

  const getAIInsight = (invoice: Invoice) => {
    if (invoice.status === 'Paid') {
      return { label: 'LIKELY TO PAY', icon: 'verified', color: 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 border border-blue-100 dark:border-blue-800' }
    }
    if (invoice.due_date && new Date(invoice.due_date) < new Date() && invoice.status !== 'Paid') {
      return { label: 'HIGH RISK', icon: 'priority_high', color: 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 border border-red-100 dark:border-red-800' }
    }
    if (invoice.status === 'Sent' && invoice.grand_total > 100000) {
      return { label: 'LIKELY TO PAY', icon: 'verified', color: 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 border border-blue-100 dark:border-blue-800' }
    }
    return null
  }

  const getDaysOverdue = (dueDate: string, status: string) => {
    if (status === 'Paid' || status === 'Cancelled') return null
    const due = new Date(dueDate)
    const today = new Date()
    const diffTime = today.getTime() - due.getTime()
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))
    if (diffDays > 0) return diffDays
    return null
  }

  return (
    <div className="min-h-screen bg-[#F9FAFB] dark:bg-[#0F172A]">
      {/* Header */}
      <PageHeader
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        searchPlaceholder="Ask AI anything about your collections..."
      />

      <main className="max-w-[1600px] mx-auto p-6 lg:p-10">
        {/* Page Title */}
        <div className="mb-10">
          <h1 className="text-3xl font-bold mb-1">Invoices</h1>
          <p className="text-slate-500 dark:text-slate-400">Manage billing and collection intelligence across your enterprise.</p>
        </div>

        {/* KPI Cards */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
          <div className="bg-[#111827] p-7 rounded-2xl shadow-sm border border-slate-800">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[11px] font-bold text-slate-400 tracking-widest uppercase">Total Invoices</span>
              <Receipt className="h-5 w-5 text-blue-600" />
            </div>
            <div className="text-3xl font-bold text-white">{totalInvoices}</div>
            <div className="text-[10px] text-green-400 mt-3 flex items-center gap-1 font-medium">
              <span className="text-sm">Γåù</span> +12% from last month
            </div>
          </div>

          <div className="bg-[#111827] p-7 rounded-2xl shadow-sm border border-slate-800">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[11px] font-bold text-slate-400 tracking-widest uppercase">Pending</span>
              <span className="text-orange-400">ΓÅ▒</span>
            </div>
            <div className="text-3xl font-bold text-white">{pendingInvoices}</div>
            <div className="text-[10px] text-slate-400 mt-3 font-medium uppercase tracking-wider">Waiting for approval</div>
          </div>

          <div className="bg-[#111827] p-7 rounded-2xl shadow-sm border border-slate-800">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[11px] font-bold text-slate-400 tracking-widest uppercase">Overdue</span>
              <span className="text-red-500">ΓÜá</span>
            </div>
            <div className="text-3xl font-bold text-white">{overdueInvoices}</div>
            <div className="text-[10px] text-red-400 mt-3 flex items-center gap-1 font-medium">
              <span className="text-sm">ΓÜí</span> HIGH RISK IDENTIFIED
            </div>
          </div>

          <div className="bg-[#111827] p-7 rounded-2xl shadow-sm border border-slate-800">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[11px] font-bold text-slate-400 tracking-widest uppercase">Total Collected</span>
              <span className="text-green-500">≡ƒÆ░</span>
            </div>
            <div className="text-3xl font-bold text-white">{formatCurrency(totalCollected)}</div>
            <div className="text-[10px] text-slate-400 mt-3 font-medium uppercase tracking-wider">Current fiscal year</div>
          </div>
        </section>

        {/* Ready for Invoice Section */}
        {readyForInvoice && readyForInvoice.length > 0 && (
          <section className="bg-white dark:bg-[#111827] border border-slate-200 dark:border-slate-800 rounded-2xl p-8 mb-10 shadow-sm">
            <div className="flex items-center gap-2 mb-6">
              <div className="w-7 h-7 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                <CheckCircle className="h-4 w-4 text-blue-600" />
              </div>
              <h2 className="font-bold text-xl">Ready for Invoice</h2>
              <span className="bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 text-[10px] px-2.5 py-1 rounded-full font-bold ml-2">
                {readyForInvoice.length} SALES ORDER{readyForInvoice.length > 1 ? 'S' : ''}
              </span>
            </div>

            <div className="space-y-4">
              {readyForInvoice.map((order) => (
                <div key={order.name} className="border border-slate-200 dark:border-slate-800 rounded-xl p-6 flex flex-col lg:flex-row items-start lg:items-center justify-between gap-6 bg-slate-50/50 dark:bg-slate-900/30">
                  <div className="space-y-3">
                    <div className="flex flex-wrap items-center gap-3">
                      <span className="font-bold text-lg text-slate-900 dark:text-white">{order.name}</span>
                      <span className="bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 text-[11px] px-2.5 py-0.5 rounded border border-slate-200 dark:border-slate-700 font-semibold">
                        {order.status}
                      </span>
                      {order.delivery_status && (
                        <span className="bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 text-[11px] px-2.5 py-0.5 rounded border border-green-200 dark:border-green-800 font-semibold">
                          {order.delivery_status}
                        </span>
                      )}
                    </div>
                    <p className="text-slate-600 dark:text-slate-400">{order.customer_name || order.customer}</p>
                    <div className="flex items-center gap-6 text-sm text-slate-500">
                      <span className="flex items-center gap-1.5">
                        <Calendar className="h-4 w-4" /> {formatDate(order.transaction_date)}
                      </span>
                      <span className="flex items-center gap-1.5 font-bold text-slate-900 dark:text-white">
                        {formatCurrency(order.grand_total, order.currency)}
                      </span>
                    </div>
                  </div>
                  <Link href={`/invoices/new?sales_order=${encodeURIComponent(order.name)}`}>
                    <button className="bg-[#111827] dark:bg-white text-white dark:text-[#111827] px-8 py-3 rounded-xl text-sm font-bold hover:opacity-90 transition-all shadow-lg">
                      Create Invoice
                    </button>
                  </Link>
                </div>
              ))}
            </div>
          </section>
        )}

        {/* All Invoices Section */}
        <section className="mb-12">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
            <h2 className="text-2xl font-bold">All Invoices</h2>
            <div className="flex gap-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 h-4 w-4" />
                <input
                  className="pl-10 pr-4 py-2.5 bg-white dark:bg-[#111827] border border-slate-200 dark:border-slate-800 rounded-xl text-sm outline-none w-full md:w-72 focus:ring-1 focus:ring-blue-600 shadow-sm"
                  placeholder="Search invoices..."
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              <button className="bg-white dark:bg-[#111827] border border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-300 px-5 py-2 rounded-xl text-sm font-semibold hover:bg-slate-50 transition-colors">
                <Filter className="h-4 w-4" />
              </button>
            </div>
          </div>

          {/* Invoice Cards Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {paginatedInvoices.map((invoice) => {
              const aiInsight = getAIInsight(invoice)
              const daysOverdue = getDaysOverdue(invoice.due_date, invoice.status)

              return (
                <div
                  key={invoice.name}
                  className="bg-white dark:bg-[#111827] border border-slate-200 dark:border-slate-800 rounded-2xl p-7 hover:shadow-xl hover:border-blue-600/30 transition-all relative overflow-hidden group cursor-pointer"
                  onClick={() => router.push(`/invoices/${invoice.name}`)}
                >
                  <div className="absolute top-0 right-0 p-3 opacity-0 group-hover:opacity-100 transition-opacity flex gap-2">
                    <button className="p-2 bg-slate-100 dark:bg-slate-800 rounded-lg hover:text-blue-600 transition-colors shadow-sm" onClick={(e) => e.stopPropagation()}>
                      <Download className="h-4 w-4" />
                    </button>
                  </div>

                  <div className="flex items-start justify-between mb-5">
                    <div className="flex items-center gap-2">
                      <Receipt className="h-5 w-5 text-slate-400" />
                      <a className="font-bold text-blue-600 hover:underline text-sm" href={`/invoices/${invoice.name}`} onClick={(e) => e.stopPropagation()}>
                        {invoice.name}
                      </a>
                    </div>
                    <span className={`px-3 py-1 text-[10px] font-bold rounded-lg uppercase tracking-wider ${getStatusBadge(invoice.status)}`}>
                      {daysOverdue ? 'Overdue' : invoice.status}
                    </span>
                  </div>

                  <div className="mb-6">
                    <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mb-1.5">Customer</p>
                    <p className="font-bold text-slate-900 dark:text-white text-lg">{invoice.customer_name}</p>
                  </div>

                  <div className="flex items-end justify-between pt-4 border-t border-slate-100 dark:border-slate-800">
                    <div>
                      <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mb-1.5">Amount</p>
                      <p className="text-2xl font-bold text-slate-900 dark:text-white">{formatCurrency(invoice.grand_total, invoice.currency)}</p>
                      {daysOverdue ? (
                        <p className="text-[11px] text-red-500 mt-1 uppercase tracking-tight font-bold">Overdue by {daysOverdue} days</p>
                      ) : (
                        <p className="text-[11px] text-slate-400 mt-1 uppercase font-medium">
                          Due: {formatDate(invoice.due_date)}
                        </p>
                      )}
                    </div>
                    {aiInsight && (
                      <div className={`px-2.5 py-1.5 rounded-lg text-[10px] font-bold flex items-center gap-1.5 ${aiInsight.color}`}>
                        <span className="text-xs">{aiInsight.icon === 'verified' ? 'Γ£ô' : '!'}</span> {aiInsight.label}
                      </div>
                    )}
                  </div>
                </div>
              )
            })}
          </div>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-center gap-4 mt-12">
              <button
                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                disabled={currentPage === 1}
                className="px-5 py-2.5 bg-slate-100 dark:bg-slate-800 text-slate-400 rounded-xl text-sm font-bold cursor-not-allowed transition-colors disabled:opacity-50"
              >
                Previous
              </button>
              <div className="flex gap-2">
                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                  let pageNum = i + 1
                  if (totalPages > 5) {
                    if (currentPage <= 3) pageNum = i + 1
                    else if (currentPage >= totalPages - 2) pageNum = totalPages - 4 + i
                    else pageNum = currentPage - 2 + i
                  }
                  return (
                    <button
                      key={pageNum}
                      onClick={() => setCurrentPage(pageNum)}
                      className={`w-10 h-10 flex items-center justify-center rounded-xl text-sm font-bold ${currentPage === pageNum
                          ? 'bg-blue-600 text-white'
                          : 'text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800'
                        }`}
                    >
                      {pageNum}
                    </button>
                  )
                })}
              </div>
              <button
                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                disabled={currentPage === totalPages}
                className="px-5 py-2.5 bg-white dark:bg-[#111827] border border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-300 rounded-xl text-sm font-bold hover:bg-slate-50 transition-colors disabled:opacity-50"
              >
                Next
              </button>
            </div>
          )}
        </section>
      </main>
    </div>
  )
}

"use client";

import { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { FileText, Download } from "lucide-react";
import Link from "next/link";
import { DeleteInvoiceButton } from "@/components/invoices/delete-invoice-button";

interface Invoice {
  name: string;
  customer_name: string;
  due_date: string;
  grand_total: number;
  status: string;
  currency: string;
}

interface InvoicesGridProps {
  invoices: Invoice[];
  page: number;
  pageSize: number;
  total: number;
  onPageChange: (page: number) => void;
}

export function InvoicesGrid({ invoices, page, pageSize, total, onPageChange }: InvoicesGridProps) {
  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {invoices.map((inv) => (
          <Card key={inv.name} className="flex flex-col justify-between h-full">
            <CardContent className="p-5 flex flex-col gap-2">
              <div className="flex items-center gap-2 mb-2">
                <FileText className="h-5 w-5 text-slate-400" />
                <Link href={`/invoices/${inv.name}`} className="font-semibold text-blue-700 dark:text-blue-300 hover:underline">
                  {inv.name}
                </Link>
                <Badge className="ml-auto">{inv.status}</Badge>
              </div>
              <div className="text-slate-700 dark:text-slate-200 font-medium">{inv.customer_name}</div>
              <div className="text-xs text-slate-500 dark:text-slate-400">Due: {inv.due_date}</div>
              <div className="text-lg font-bold text-slate-900 dark:text-white mt-2">{inv.currency} {Number(inv.grand_total ?? 0).toLocaleString()}</div>
              <div className="flex gap-2 mt-3">
                <a href={`/print/invoice/${inv.name}`} target="_blank" className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
                  <Download className="h-4 w-4" />
                </a>
                <DeleteInvoiceButton id={inv.name} status={inv.status} />
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
      {/* Pagination Controls */}
      <div className="flex justify-center items-center gap-2 mt-4">
        <button
          className="px-3 py-1 rounded bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-slate-200 disabled:opacity-50"
          onClick={() => onPageChange(page - 1)}
          disabled={page === 1}
        >
          Previous
        </button>
        <span className="mx-2 text-sm">Page {page} of {totalPages}</span>
        <button
          className="px-3 py-1 rounded bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-slate-200 disabled:opacity-50"
          onClick={() => onPageChange(page + 1)}
          disabled={page === totalPages}
        >
          Next
        </button>
      </div>
    </div>
  );
}

'use client'

import * as React from "react"
import { Check, ChevronsUpDown } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import { Badge } from "@/components/ui/badge"
import { searchItems, getItemGroups } from "@/app/actions/invoices"

interface ItemSearchProps {
  value: string
  onChange: (value: string, description?: string, itemName?: string) => void
  itemGroup?: string // Optional filter by item group
}

export function ItemSearch({ value, onChange, itemGroup }: ItemSearchProps) {
  const [open, setOpen] = React.useState(false)
  const [items, setItems] = React.useState<{ item_code: string, item_name: string, description: string, item_group: string }[]>([])
  const [query, setQuery] = React.useState("")

  React.useEffect(() => {
    const fetchItems = async () => {
      const searchQuery = query || "" 
      const results = await searchItems(searchQuery, itemGroup)
      setItems(results)
    }
    const debounce = setTimeout(fetchItems, 300)
    return () => clearTimeout(debounce)
  }, [query, itemGroup])

  // Group items by item_group
  const groupedItems = React.useMemo(() => {
    const groups: Record<string, typeof items> = {}
    items.forEach(item => {
      const group = item.item_group || 'Other'
      if (!groups[group]) groups[group] = []
      groups[group].push(item)
    })
    return groups
  }, [items])

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          role="combobox"
          aria-expanded={open}
          className="w-full justify-between h-8 px-2 text-sm font-normal border-0 hover:bg-slate-100 dark:hover:bg-slate-800"
        >
          {value || <span className="text-slate-400">Select Item...</span>}
          <ChevronsUpDown className="ml-2 h-3 w-3 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[400px] p-0" align="start">
        <Command shouldFilter={false}>
          <CommandInput placeholder="Search items..." onValueChange={setQuery} />
          <CommandList>
            {items.length === 0 && <CommandEmpty>No item found.</CommandEmpty>}
            {Object.entries(groupedItems).map(([group, groupItems]) => (
              <CommandGroup key={group} heading={group}>
                {groupItems.map((item) => (
                  <CommandItem
                    key={item.item_code}
                    value={item.item_code}
                    keywords={[item.item_name, item.item_code]}
                    className="flex items-center justify-between"
                    onSelect={(currentValue) => {
                      onChange(item.item_code, item.description, item.item_name)
                      setOpen(false)
                    }}
                  >
                    <Check
                      className={cn(
                        "mr-2 h-4 w-4",
                        value === item.item_code ? "opacity-100" : "opacity-0"
                      )}
                    />
                    <div className="flex flex-col flex-1">
                      <div className="flex items-center gap-2">
                        <span className="font-medium">{item.item_code}</span>
                        <Badge variant="outline" className="text-xs">{item.item_group}</Badge>
                      </div>
                      <span className="text-xs text-muted-foreground">{item.item_name}</span>
                    </div>
                  </CommandItem>
                ))}
              </CommandGroup>
            ))}
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  )
}

'use client'

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { DollarSign, Loader2 } from "lucide-react"
import { createPaymentEntry } from "@/app/actions/invoices"
import { getModesOfPayment } from "@/app/actions/common"
import { useRouter } from "next/navigation"

export function PaymentDialog({ invoice }: { invoice: any }) {
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [paymentModes, setPaymentModes] = useState<string[]>([])
  const [loadingModes, setLoadingModes] = useState(false)
  const [formData, setFormData] = useState({
    paymentAmount: Number(invoice.outstanding_amount ?? invoice.grand_total ?? 0),
    paymentDate: new Date().toISOString().split('T')[0],
    modeOfPayment: '',
    referenceNo: '',
    referenceDate: new Date().toISOString().split('T')[0]
  })
  const router = useRouter()

  // Fetch modes from ERPNext when dialog opens
  useEffect(() => {
    if (!open) return
    setLoadingModes(true)
    getModesOfPayment().then(modes => {
      setPaymentModes(modes)
      if (modes.length > 0 && !formData.modeOfPayment) {
        setFormData(f => ({ ...f, modeOfPayment: modes[0] }))
      }
      setLoadingModes(false)
    }).catch(() => setLoadingModes(false))
  }, [open])

  const outstandingAmount = invoice.outstanding_amount || invoice.grand_total || 0

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()

    if (formData.paymentAmount <= 0) {
      alert('Payment amount must be greater than 0')
      return
    }

    if (formData.paymentAmount > outstandingAmount) {
      alert(`Payment amount cannot exceed outstanding amount of ${invoice.currency} ${outstandingAmount.toLocaleString()}`)
      return
    }

    setLoading(true)
    const result = await createPaymentEntry({
      invoiceName: invoice.name,
      paymentAmount: formData.paymentAmount,
      paymentDate: formData.paymentDate,
      modeOfPayment: formData.modeOfPayment,
      referenceNo: formData.referenceNo,
      referenceDate: formData.referenceDate
    })

    setLoading(false)

    if (result.error) {
      alert('Error: ' + result.error)
    } else {
      alert('Γ£à Payment entry created successfully!')
      setOpen(false)
      router.refresh()
    }
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button className="bg-green-600 hover:bg-green-700 text-white gap-2">
          <DollarSign className="h-4 w-4" />
          Record Payment
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px]">
        <form onSubmit={handleSubmit}>
          <DialogHeader>
            <DialogTitle>Record Payment</DialogTitle>
            <DialogDescription>
              Create a payment entry for invoice {invoice.name}
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-4">
            {/* Outstanding Amount Display */}
            <div className="p-4 bg-slate-50 dark:bg-slate-900 rounded-lg">
              <div className="text-sm text-slate-500">Outstanding Amount</div>
              <div className="text-2xl font-bold text-slate-900 dark:text-white">
                {invoice.currency} {outstandingAmount.toLocaleString()}
              </div>
            </div>

            {/* Payment Amount */}
            <div className="grid gap-2">
              <Label htmlFor="paymentAmount">Payment Amount *</Label>
              <Input
                id="paymentAmount"
                type="number"
                step="0.01"
                min="0"
                max={outstandingAmount}
                value={formData.paymentAmount}
                onChange={(e) => setFormData({ ...formData, paymentAmount: parseFloat(e.target.value) || 0 })}
                required
              />
            </div>

            {/* Payment Date */}
            <div className="grid gap-2">
              <Label htmlFor="paymentDate">Payment Date *</Label>
              <Input
                id="paymentDate"
                type="date"
                value={formData.paymentDate}
                onChange={(e) => setFormData({ ...formData, paymentDate: e.target.value })}
                required
              />
            </div>

            {/* Mode of Payment */}
            <div className="grid gap-2">
              <Label htmlFor="modeOfPayment">Mode of Payment *</Label>
              <Select
                value={formData.modeOfPayment}
                onValueChange={(value) => setFormData({ ...formData, modeOfPayment: value })}
                disabled={loadingModes}
              >
                <SelectTrigger>
                  <SelectValue placeholder={loadingModes ? 'Loading...' : 'Select mode'} />
                </SelectTrigger>
                <SelectContent>
                  {paymentModes.map((mode) => (
                    <SelectItem key={mode} value={mode}>
                      {mode}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Reference Number */}
            <div className="grid gap-2">
              <Label htmlFor="referenceNo">Reference No (Optional)</Label>
              <Input
                id="referenceNo"
                type="text"
                placeholder="Cheque/Transaction number"
                value={formData.referenceNo}
                onChange={(e) => setFormData({ ...formData, referenceNo: e.target.value })}
              />
            </div>

            {/* Reference Date */}
            <div className="grid gap-2">
              <Label htmlFor="referenceDate">Reference Date</Label>
              <Input
                id="referenceDate"
                type="date"
                value={formData.referenceDate}
                onChange={(e) => setFormData({ ...formData, referenceDate: e.target.value })}
              />
            </div>
          </div>

          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setOpen(false)} disabled={loading}>
              Cancel
            </Button>
            <Button type="submit" disabled={loading} className="bg-green-600 hover:bg-green-700">
              {loading ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  Creating...
                </>
              ) : (
                'Create Payment'
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

