      return { label: 'Cancelled', color: 'text-slate-400', bgColor: 'bg-slate-400' }
    } else {
      return { label: 'Draft', color: 'text-amber-500', bgColor: 'bg-amber-500' }
    }
  }

  const getFraudCheckStatus = (payment: PaymentEntry) => {
