                            <div className="flex items-center gap-2">
                              <Calendar className="h-4 w-4 text-slate-400" />
                              <span className="text-slate-500">Valid till: </span>
                              <span className="font-medium text-slate-900 dark:text-white">
                                {new Date(quotation.valid_till).toLocaleDateString('en-IN')}
                              </span>
                            </div>
                            <div>
                              <span className="text-slate-500">Value: </span>
                              <span className="font-bold text-green-700 dark:text-green-400">
                                Γé╣{(quotation.grand_total || 0).toLocaleString('en-IN')}
                              </span>
                            </div>
                          </div>

                          <div className="flex gap-3">
                            <Link href={`/sales-orders/new?quotation=${encodeURIComponent(quotation.name)}`}>
                              <button className="px-6 py-2.5 bg-green-600 hover:bg-green-700 text-white rounded-lg font-semibold flex items-center transition-colors">
                                <Package className="h-4 w-4 mr-2" />
                                Create Sales Order
                              </button>
                            </Link>
                            <Link href={`/crm/quotations/${encodeURIComponent(quotation.name)}`}>
                              <button className="px-6 py-2.5 border border-slate-200 dark:border-slate-700 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors font-medium">
                                View Quotation
                              </button>
                            </Link>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Plus, Loader2 } from 'lucide-react'
import { createBankAccount } from '@/app/actions/settings'

export function CreateBankAccountDialog() {
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [bankName, setBankName] = useState('')
  const [accountNumber, setAccountNumber] = useState('')
  const [ifscCode, setIfscCode] = useState('')
  const [isDefault, setIsDefault] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)

    try {
      const result = await createBankAccount({
        bank: bankName,
        bank_account_no: accountNumber,
        branch_code: ifscCode,
        is_default: isDefault
      })

      if (result.error) {
        alert(result.error)
      } else {
        setOpen(false)
        // Reset form
        setBankName('')
        setAccountNumber('')
        setIfscCode('')
        setIsDefault(false)
      }
    } catch (error: any) {
      alert(error.message || 'Failed to create bank account')
    } finally {
      setLoading(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button size="sm" className="gap-2">
          <Plus className="h-4 w-4" />
          Add Bank Account
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Add Bank Account</DialogTitle>
          <DialogDescription>
            Add a new bank account for your company
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="bankName">Bank Name *</Label>
            <Input
              id="bankName"
              value={bankName}
              onChange={(e) => setBankName(e.target.value)}
              placeholder="e.g., HDFC Bank, State Bank of India"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="accountNumber">Account Number *</Label>
            <Input
              id="accountNumber"
              value={accountNumber}
              onChange={(e) => setAccountNumber(e.target.value)}
              placeholder="Enter account number"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="ifscCode">IFSC Code</Label>
            <Input
              id="ifscCode"
              value={ifscCode}
              onChange={(e) => setIfscCode(e.target.value.toUpperCase())}
              placeholder="e.g., HDFC0001234"
              maxLength={11}
            />
            <p className="text-xs text-slate-500">11-character code for Indian banks</p>
          </div>

          <div className="flex items-center space-x-2">
            <input
              type="checkbox"
              id="isDefault"
              checked={isDefault}
              onChange={(e) => setIsDefault(e.target.checked)}
              className="h-4 w-4 rounded border-slate-300"
            />
            <Label htmlFor="isDefault" className="cursor-pointer">
              Set as default bank account
            </Label>
          </div>

          <div className="flex justify-end gap-3 pt-4">
            <Button type="button" variant="outline" onClick={() => setOpen(false)} disabled={loading}>
              Cancel
            </Button>
            <Button type="submit" disabled={loading}>
              {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {loading ? 'Adding...' : 'Add Bank Account'}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Plus, Trash2, Loader2 } from "lucide-react"
import { createTaxTemplate, getTaxAccounts } from "@/app/actions/settings"
import { useRouter } from "next/navigation"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

interface TaxRow {
  id: number
  charge_type: string
  account_head: string
  description: string
  rate: number
}

export function CreateTaxTemplateDialog() {
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [loadingAccounts, setLoadingAccounts] = useState(false)
  const router = useRouter()

  const [title, setTitle] = useState("")
  const [company, setCompany] = useState("AVARIQ")
  const [availableAccounts, setAvailableAccounts] = useState<Array<{name: string, account_name: string}>>([])
  const [taxRows, setTaxRows] = useState<TaxRow[]>([
    { id: 1, charge_type: "On Net Total", account_head: "", description: "", rate: 0 }
  ])

  // Fetch tax accounts when company changes
  useEffect(() => {
    if (company && open) {
      setLoadingAccounts(true)
      getTaxAccounts(company).then(accounts => {
        setAvailableAccounts(accounts)
        setLoadingAccounts(false)
      })
    }
  }, [company, open])

  const addTaxRow = () => {
    setTaxRows([...taxRows, { 
      id: Date.now(), 
      charge_type: "On Net Total", 
      account_head: "", 
      description: "", 
      rate: 0 
    }])
  }

  const removeTaxRow = (id: number) => {
    if (taxRows.length > 1) {
      setTaxRows(taxRows.filter(row => row.id !== id))
    }
  }

  const updateTaxRow = (id: number, field: keyof TaxRow, value: any) => {
    setTaxRows(taxRows.map(row => 
      row.id === id ? { ...row, [field]: value } : row
    ))
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!title.trim()) {
      alert("Please enter a template name")
      return
    }

    const invalidRows = taxRows.filter(row => 
      !row.account_head || !row.description || row.rate <= 0
    )

    if (invalidRows.length > 0) {
      alert("Please fill in all tax rows with valid data")
      return
    }

    setLoading(true)

    try {
      const result = await createTaxTemplate({
        title,
        company,
        taxes: taxRows.map(row => ({
          charge_type: row.charge_type,
          account_head: row.account_head,
          description: row.description,
          rate: row.rate
        }))
      })

      if (result.error) {
        alert(result.error)
      } else {
        setOpen(false)
        setTitle("")
        setTaxRows([{ id: 1, charge_type: "On Net Total", account_head: "", description: "", rate: 0 }])
        router.refresh()
      }
    } catch (error: any) {
      alert(error.message || "Failed to create tax template")
    } finally {
      setLoading(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button className="gap-2">
          <Plus className="h-4 w-4" />
          New Tax Template
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Create Tax Template</DialogTitle>
          <DialogDescription>
            Create a new sales tax template that can be applied to quotations and invoices
          </DialogDescription>
        </DialogHeader>
        
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid gap-4">
            <div className="grid gap-2">
              <Label htmlFor="title">Template Name *</Label>
              <Input
                id="title"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="e.g., In State GST 18%"
                required
              />
            </div>

            <div className="grid gap-2">
              <Label htmlFor="company">Company *</Label>
              <Input
                id="company"
                value={company}
                onChange={(e) => setCompany(e.target.value)}
                placeholder="Company name"
                required
              />
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <Label>Tax Charges</Label>
              <Button type="button" variant="outline" size="sm" onClick={addTaxRow}>
                <Plus className="h-4 w-4 mr-1" />
                Add Row
              </Button>
            </div>

            <div className="space-y-4">
              {taxRows.map((row, index) => (
                <div key={row.id} className="space-y-3 p-4 border rounded-lg bg-white dark:bg-slate-800">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium text-slate-900 dark:text-white">Tax Row {index + 1}</span>
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      onClick={() => removeTaxRow(row.id)}
                      disabled={taxRows.length === 1}
                    >
                      <Trash2 className="h-4 w-4 text-red-500" />
                    </Button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label className="text-sm">Account Head *</Label>
                      {loadingAccounts ? (
                        <div className="flex items-center gap-2 h-10 px-3 border rounded-md bg-slate-100 dark:bg-slate-900">
                          <Loader2 className="h-4 w-4 animate-spin" />
                          <span className="text-sm text-slate-500">Loading accounts...</span>
                        </div>
                      ) : availableAccounts.length > 0 ? (
                        <Select 
                          value={row.account_head} 
                          onValueChange={(value) => updateTaxRow(row.id, 'account_head', value)}
                        >
                          <SelectTrigger className="w-full">
                            <SelectValue placeholder="Select tax account" />
                          </SelectTrigger>
                          <SelectContent>
                            {availableAccounts.map(account => (
                              <SelectItem key={account.name} value={account.name}>
                                {account.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      ) : (
                        <Input
                          value={row.account_head}
                          onChange={(e) => updateTaxRow(row.id, 'account_head', e.target.value)}
                          placeholder="Enter account name"
                        />
                      )}
                    </div>
                  
                    <div className="space-y-2">
                      <Label className="text-sm">Description *</Label>
                      <Input
                        value={row.description}
                        onChange={(e) => updateTaxRow(row.id, 'description', e.target.value)}
                        placeholder="e.g., CGST @ 9%"
                      />
                    </div>

                    <div className="space-y-2">
                      <Label className="text-sm">Rate (%) *</Label>
                      <Input
                        type="number"
                        step="0.01"
                        value={row.rate || ''}
                        onChange={(e) => updateTaxRow(row.id, 'rate', parseFloat(e.target.value) || 0)}
                        placeholder="e.g., 9"
                      />
                    </div>

                    <div className="space-y-2">
                      <Label className="text-sm">Charge Type</Label>
                      <Select 
                        value={row.charge_type} 
                        onValueChange={(value) => updateTaxRow(row.id, 'charge_type', value)}
                      >
                        <SelectTrigger className="w-full">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="On Net Total">On Net Total</SelectItem>
                          <SelectItem value="On Previous Row Total">On Previous Row</SelectItem>
                          <SelectItem value="Actual">Actual</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="text-xs text-slate-600 dark:text-slate-400 space-y-1 bg-blue-50 dark:bg-blue-950 p-3 rounded border border-blue-200 dark:border-blue-800">
              <p className="font-semibold text-blue-900 dark:text-blue-100">Account Selection:</p>
              <p>Γ£ô Select tax accounts from the dropdown (fetched from your ERPNext Chart of Accounts)</p>
              <p>Γ£ô Common tax accounts: Look for "Output Tax CGST", "Output Tax SGST", "Output Tax IGST"</p>
              {availableAccounts.length === 0 && !loadingAccounts && (
                <p className="text-amber-700 dark:text-amber-400 mt-2">ΓÜá∩╕Å No tax accounts found. You may need to create them in ERPNext first.</p>
              )}
            </div>
          </div>

          <div className="flex justify-end gap-4">
            <Button type="button" variant="outline" onClick={() => setOpen(false)} disabled={loading}>
              Cancel
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Creating...
                </>
              ) : (
                "Create Template"
              )}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState } from "react"
import { setupCrmMasterData } from "@/app/actions/setup-crm"

export function CrmSetupSection() {
  const [isLoading, setIsLoading] = useState(false)
  const [result, setResult] = useState<{
    success: boolean
    message?: string
    results?: any
  } | null>(null)

  const handleSetup = async () => {
    setIsLoading(true)
    setResult(null)

    try {
      const setupResult = await setupCrmMasterData()
      
      if (setupResult.success && setupResult.results) {
        const { opportunityTypes, salesStages } = setupResult.results
        const totalCreated = opportunityTypes.created + salesStages.created
        const totalExisting = opportunityTypes.existing + salesStages.existing
        
        setResult({
          success: true,
          message: `Created ${totalCreated} records, ${totalExisting} already existed`,
          results: setupResult.results
        })
      } else {
        setResult({
          success: false,
          message: setupResult.error || 'Setup failed'
        })
      }
    } catch (error: any) {
      setResult({
        success: false,
        message: error.message || 'An error occurred'
      })
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <section className="bg-white dark:bg-navy-900 border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden shadow-sm">
      <div className="p-6">
        <div className="flex items-center gap-2 text-slate-900 dark:text-white mb-6">
          <span className="material-symbols-outlined text-slate-400">settings_suggest</span>
          <h2 className="font-semibold text-base">CRM Setup</h2>
        </div>
        
        <div className="space-y-4">
          <div>
            <h3 className="text-sm font-medium text-slate-900 dark:text-white mb-1">
              Initialize CRM Master Data
            </h3>
            <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">
              Set up default Opportunity Types and Sales Stages for your CRM module. 
              This creates standard values like &quot;Sales&quot;, &quot;Rental&quot;, &quot;Prospecting&quot;, &quot;Qualification&quot;, etc.
            </p>
          </div>

          {result && (
            <div className={`p-4 rounded-lg border ${
              result.success 
                ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800' 
                : 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800'
            }`}>
              <div className="flex items-start gap-3">
                <span className={`material-symbols-outlined text-lg ${
                  result.success ? 'text-emerald-600 dark:text-emerald-400' : 'text-red-600 dark:text-red-400'
                }`}>
                  {result.success ? 'check_circle' : 'error'}
                </span>
                <div className="flex-1">
                  <p className={`text-sm font-medium ${
                    result.success ? 'text-emerald-900 dark:text-emerald-100' : 'text-red-900 dark:text-red-100'
                  }`}>
                    {result.message}
                  </p>
                  {result.success && result.results && (
                    <div className="mt-2 text-xs text-slate-600 dark:text-slate-400 space-y-1">
                      <div>
                        Opportunity Types: {result.results.opportunityTypes.created} created, 
                        {' '}{result.results.opportunityTypes.existing} already existed
                        {result.results.opportunityTypes.failed > 0 && 
                          `, ${result.results.opportunityTypes.failed} failed`}
                      </div>
                      <div>
                        Sales Stages: {result.results.salesStages.created} created, 
                        {' '}{result.results.salesStages.existing} already existed
                        {result.results.salesStages.failed > 0 && 
                          `, ${result.results.salesStages.failed} failed`}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}

          <button
            onClick={handleSetup}
            disabled={isLoading}
            className="px-4 py-2 text-sm font-medium bg-primary text-white rounded-lg shadow-sm hover:bg-blue-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {isLoading ? (
              <>
                <span className="material-symbols-outlined text-sm animate-spin">progress_activity</span>
                Setting up...
              </>
            ) : (
              <>
                <span className="material-symbols-outlined text-sm">play_arrow</span>
                Run CRM Setup
              </>
            )}
          </button>
        </div>
      </div>
    </section>
  )
}

'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Pencil, Loader2 } from 'lucide-react'
import { updateCompany, type Company } from '@/app/actions/settings'

interface EditCompanyDialogProps {
  company: Company
}

export function EditCompanyDialog({ company }: EditCompanyDialogProps) {
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [companyName, setCompanyName] = useState(company.company_name || company.name)
  const [gstin, setGstin] = useState(company.tax_id || '')
  const [country, setCountry] = useState(company.country || 'India')

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)

    try {
      const result = await updateCompany({
        name: company.name,
        company_name: companyName,
        tax_id: gstin,
        country: country
      })

      if (result.error) {
        alert(result.error)
      } else {
        setOpen(false)
      }
    } catch (error: any) {
      alert(error.message || 'Failed to update company')
    } finally {
      setLoading(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm" className="gap-2">
          <Pencil className="h-4 w-4" />
          Edit Company
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Edit Company Details</DialogTitle>
          <DialogDescription>
            Update your company information for invoices and quotations
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="companyName">Company Name *</Label>
            <Input
              id="companyName"
              value={companyName}
              onChange={(e) => setCompanyName(e.target.value)}
              placeholder="Enter company name"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="gstin">GSTIN</Label>
            <Input
              id="gstin"
              value={gstin}
              onChange={(e) => setGstin(e.target.value)}
              placeholder="e.g., 29ABCDE1234F1Z5"
              maxLength={15}
            />
            <p className="text-xs text-slate-500">15-character GST Identification Number</p>
          </div>

          <div className="space-y-2">
            <Label htmlFor="country">Country</Label>
            <Input
              id="country"
              value={country}
              onChange={(e) => setCountry(e.target.value)}
