"use client";

import { motion, AnimatePresence } from "framer-motion";
import { X, CheckCircle, AlertCircle, Info, AlertTriangle } from "lucide-react";
import { cn } from "@/lib/utils";
import { createContext, useContext, useState, ReactNode, useCallback } from "react";

type ToastType = 'success' | 'error' | 'info' | 'warning';

interface Toast {
  id: string;
  type: ToastType;
  title: string;
  message?: string;
  duration?: number;
}

interface ToastContextType {
  addToast: (toast: Omit<Toast, 'id'>) => void;
  removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export function useToast() {
  const context = useContext(ToastContext);
  if (!context) {
    throw new Error('useToast must be used within ToastProvider');
  }
  return context;
}

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const addToast = useCallback((toast: Omit<Toast, 'id'>) => {
    const id = Math.random().toString(36).substring(7);
    const newToast = { ...toast, id };
    setToasts((prev) => [...prev, newToast]);

    // Auto remove after duration
    setTimeout(() => {
      removeToast(id);
    }, toast.duration || 5000);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts((prev) => prev.filter((toast) => toast.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ addToast, removeToast }}>
      {children}
      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </ToastContext.Provider>
  );
}

function ToastContainer({ toasts, removeToast }: { toasts: Toast[]; removeToast: (id: string) => void }) {
  return (
    <div className="fixed top-4 right-4 z-[9999] flex flex-col gap-2 pointer-events-none">
      <AnimatePresence>
        {toasts.map((toast) => (
          <ToastItem key={toast.id} toast={toast} onRemove={removeToast} />
        ))}
      </AnimatePresence>
    </div>
  );
}

function ToastItem({ toast, onRemove }: { toast: Toast; onRemove: (id: string) => void }) {
  const icons = {
    success: <CheckCircle className="h-5 w-5" />,
    error: <AlertCircle className="h-5 w-5" />,
    info: <Info className="h-5 w-5" />,
    warning: <AlertTriangle className="h-5 w-5" />,
  };

  const styles = {
    success: "bg-green-50 border-green-200 text-green-900 dark:bg-green-900/20 dark:border-green-800 dark:text-green-400",
    error: "bg-red-50 border-red-200 text-red-900 dark:bg-red-900/20 dark:border-red-800 dark:text-red-400",
    info: "bg-blue-50 border-blue-200 text-blue-900 dark:bg-blue-900/20 dark:border-blue-800 dark:text-blue-400",
    warning: "bg-orange-50 border-orange-200 text-orange-900 dark:bg-orange-900/20 dark:border-orange-800 dark:text-orange-400",
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: 300, scale: 0.8 }}
      animate={{ opacity: 1, x: 0, scale: 1 }}
      exit={{ opacity: 0, x: 300, scale: 0.8 }}
      transition={{ type: "spring", stiffness: 500, damping: 30 }}
      className={cn(
        "pointer-events-auto min-w-[300px] max-w-md rounded-lg border p-4 shadow-lg backdrop-blur-sm",
        styles[toast.type]
      )}
    >
      <div className="flex items-start gap-3">
        <div className="flex-shrink-0">
          {icons[toast.type]}
        </div>
        <div className="flex-1">
          <h4 className="font-semibold text-sm">{toast.title}</h4>
          {toast.message && (
            <p className="mt-1 text-sm opacity-90">{toast.message}</p>
          )}
        </div>
        <button
          onClick={() => onRemove(toast.id)}
          className="flex-shrink-0 rounded-md p-1 hover:bg-black/5 dark:hover:bg-white/10 transition-colors"
        >
          <X className="h-4 w-4" />
        </button>
      </div>
      
      {/* Progress bar */}
      <motion.div
        className="mt-2 h-1 bg-current opacity-20 rounded-full overflow-hidden"
        initial={{ width: "100%" }}
        animate={{ width: "0%" }}
        transition={{ duration: (toast.duration || 5000) / 1000, ease: "linear" }}
      />
    </motion.div>
  );
}

// Helper hook for common toast patterns
export function useToastHelpers() {
  const { addToast } = useToast();

  return {
    success: (title: string, message?: string) => 
      addToast({ type: 'success', title, message }),
    
    error: (title: string, message?: string) => 
      addToast({ type: 'error', title, message }),
    
    info: (title: string, message?: string) => 
      addToast({ type: 'info', title, message }),
    
    warning: (title: string, message?: string) => 
      addToast({ type: 'warning', title, message }),
    
    promise: async <T,>(
      promise: Promise<T>,
      messages: {
        loading: string;
        success: string;
        error: string;
      }
    ) => {
      const loadingId = Math.random().toString(36);
      addToast({ type: 'info', title: messages.loading });

      try {
        const result = await promise;
        addToast({ type: 'success', title: messages.success });
        return result;
      } catch (error) {
        addToast({ 
          type: 'error', 
          title: messages.error,
          message: error instanceof Error ? error.message : 'An error occurred'
        });
        throw error;
      }
    },
  };
}

'use client'

import React, { createContext, useContext, useEffect, useState } from 'react'
import { PLAN_FEATURES, type PlanFeatures, type SubscriptionPlan } from '@/types/tenant'

interface SubscriptionContextType {
  plan: SubscriptionPlan
  features: PlanFeatures
  isLoading: boolean
  hasPermission: (module: string) => boolean
  canUse: (feature: keyof PlanFeatures['features']) => boolean
  checkLimit: (feature: 'users' | 'leads' | 'projects' | 'invoices', currentCount: number) => boolean
}

const SubscriptionContext = createContext<SubscriptionContextType | undefined>(undefined)

interface SubscriptionProviderProps {
  children: React.ReactNode
  initialPlan?: SubscriptionPlan
}

export function SubscriptionProvider({ children, initialPlan = 'free' }: SubscriptionProviderProps) {
  const [plan, setPlan] = useState<SubscriptionPlan>(initialPlan)
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    // Fetch current tenant's subscription plan from API
    async function fetchPlan() {
      try {
        const response = await fetch('/api/subscription/current')
        if (response.ok) {
          const data = await response.json()
          setPlan(data.plan || 'free')
        }
      } catch (error) {
        console.error('Failed to fetch subscription plan:', error)
      } finally {
        setIsLoading(false)
      }
    }

    fetchPlan()
  }, [])

  const features = PLAN_FEATURES[plan]

  /**
   * Check if the current plan has access to a specific ERPNext module
   */
  const hasPermission = (module: string): boolean => {
    return features.modules.includes(module)
  }

  /**
   * Check if the current plan can use a specific feature
   */
  const canUse = (feature: keyof PlanFeatures['features']): boolean => {
    const featureValue = features.features[feature]
    
    // If feature is boolean, return it directly
    if (typeof featureValue === 'boolean') {
      return featureValue
    }
    
    // If feature is 'unlimited', return true
    if (featureValue === 'unlimited') {
      return true
    }
    
    // If feature is an array, check if it has items
    if (Array.isArray(featureValue)) {
      return featureValue.length > 0
    }
    
    // If feature is a number, return true (limit exists)
    if (typeof featureValue === 'number') {
      return featureValue > 0
    }
    
    return false
  }

  /**
   * Check if current usage is within plan limits
   */
  const checkLimit = (
    feature: 'users' | 'leads' | 'projects' | 'invoices',
    currentCount: number
  ): boolean => {
    const limit = features.features[feature]
    
    if (limit === 'unlimited') {
      return true
    }
    
    if (typeof limit === 'number') {
      return currentCount < limit
    }
    
    return false
  }

  return (
    <SubscriptionContext.Provider
      value={{
        plan,
        features,
        isLoading,
        hasPermission,
        canUse,
        checkLimit
      }}
    >
      {children}
    </SubscriptionContext.Provider>
  )
}

/**
 * Hook to access subscription context
 */
export function useSubscription() {
  const context = useContext(SubscriptionContext)
  if (!context) {
    throw new Error('useSubscription must be used within SubscriptionProvider')
  }
  return context
}

/**
 * HOC to protect components based on plan features
 */
export function withSubscription<P extends object>(
  Component: React.ComponentType<P>,
  requiredFeature: keyof PlanFeatures['features']
) {
  return function SubscriptionGuard(props: P) {
    const { canUse, isLoading } = useSubscription()

    if (isLoading) {
      return <div>Loading...</div>
    }

    if (!canUse(requiredFeature)) {
      return (
        <div className="p-6 text-center">
          <h3 className="text-lg font-semibold mb-2">Upgrade Required</h3>
          <p className="text-muted-foreground">
            This feature is not available on your current plan.
          </p>
          <button className="mt-4 px-4 py-2 bg-primary text-primary-foreground rounded-md">
            Upgrade Plan
          </button>
        </div>
      )
    }

    return <Component {...props} />
  }
}

/**
 * Component to show feature gate message
 */
export function FeatureGate({
  feature,
  children,
  fallback
}: {
  feature: keyof PlanFeatures['features']
  children: React.ReactNode
  fallback?: React.ReactNode
}) {
  const { canUse, isLoading } = useSubscription()

  if (isLoading) {
    return null
  }

  if (!canUse(feature)) {
    return fallback || (
      <div className="text-sm text-muted-foreground">
        Upgrade your plan to use this feature
      </div>
    )
  }

  return <>{children}</>
}

/**
 * Component to check usage limits
 */
export function UsageGuard({
  feature,
  currentCount,
  children,
  onLimitReached
}: {
  feature: 'users' | 'leads' | 'projects' | 'invoices'
  currentCount: number
  children: React.ReactNode
  onLimitReached?: () => void
}) {
  const { checkLimit, features } = useSubscription()
  const withinLimit = checkLimit(feature, currentCount)

  if (!withinLimit) {
    if (onLimitReached) {
      onLimitReached()
    }

    const limit = features.features[feature]
    return (
      <div className="p-4 border border-yellow-500 bg-yellow-50 rounded-md">
        <p className="text-sm text-yellow-800">
          You've reached your plan limit of {limit} {feature}. Upgrade to continue.
        </p>
      </div>
    )
  }

  return <>{children}</>
}

/**
 * User Context - Client-side user role and permission management
 * 
 * Provides user role state and permission checks throughout the app.
 * Integrates with Frappe ERPNext roles via API.
 */
'use client'

import { createContext, useContext, useEffect, useState, useCallback } from 'react'
import {
  canAccessModule,
  getAccessibleModules,
  getPrimaryRole,
  getPermissionLevel,
  canPerformAction,
  type PermissionLevel,
} from '@/lib/role-permissions'

interface UserContextType {
  roles: string[]
  loading: boolean
  error: string | null
  hasRole: (role: string) => boolean
  canAccess: (module: string) => boolean
  getPermission: (module: string) => PermissionLevel
  canPerform: (module: string, action: string) => boolean
  accessibleModules: string[]
  primaryRole: string
  refreshRoles: () => Promise<void>
}

const UserContext = createContext<UserContextType | null>(null)

export function UserProvider({ children }: { children: React.ReactNode }) {
  const [roles, setRoles] = useState<string[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const fetchRoles = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)
      const response = await fetch('/api/user/roles')
      
      if (!response.ok) {
        throw new Error('Failed to fetch user roles')
      }
      
      const data = await response.json()
      setRoles(data.roles || [])
    } catch (err: any) {
      console.error('[UserContext] Failed to fetch roles:', err)
      setError(err.message)
      setRoles([])
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchRoles()
  }, [fetchRoles])

  const hasRole = useCallback(
    (role: string) => roles.includes(role),
    [roles]
  )

  const canAccess = useCallback(
    (module: string) => canAccessModule(module, roles),
    [roles]
  )

  const getPermission = useCallback(
    (module: string) => getPermissionLevel(module, roles),
    [roles]
  )

  const canPerform = useCallback(
    (module: string, action: string) => canPerformAction(module, action, roles),
    [roles]
  )

  const accessibleModules = getAccessibleModules(roles)
  const primaryRole = getPrimaryRole(roles)

  const value: UserContextType = {
    roles,
    loading,
    error,
    hasRole,
    canAccess,
    getPermission,
    canPerform,
    accessibleModules,
    primaryRole,
    refreshRoles: fetchRoles,
  }

  return <UserContext.Provider value={value}>{children}</UserContext.Provider>
}

/**
 * Hook to access user role context
 * @throws if used outside UserProvider
 */
export function useUser() {
  const context = useContext(UserContext)
  if (!context) {
    throw new Error('useUser must be used within UserProvider')
  }
  return context
}

/**
 * Hook to check if user can access a specific module
 */
export function useCanAccessModule(module: string): boolean {
  const { canAccess } = useUser()
  return canAccess(module)
}

/**
 * Hook to check if user has a specific role
 */
export function useHasRole(role: string): boolean {
  const { hasRole } = useUser()
  return hasRole(role)
}

/**
 * Hook to check if user can perform an action on a module
 * e.g. useCanPerformAction('crm', 'create')
 */
export function useCanPerformAction(module: string, action: string): boolean {
  const { canPerform } = useUser()
  return canPerform(module, action)
}

/**
 * Backend API URL Resolver for Multi-Tenant SaaS
 * 
 * Dynamically resolves backend API URL based on current hostname
 * Supports local development and production environments
 * 
 * Examples:
 * - tenant1.localhost:3000 ΓåÆ api.tenant1.localhost:8080
 * - tenant2.example.com ΓåÆ api.tenant2.example.com
 * - localhost:3000 ΓåÆ api.localhost:8080 (default tenant)
 */

interface BackendConfig {
  protocol: 'http' | 'https'
  port?: number
  apiPrefix?: string
}

/**
 * Extracts tenant from current hostname
 * Returns subdomain or 'default' for apex domains
 */
function extractTenant(hostname: string): string {
  const host = hostname.split(':')[0]
  const parts = host.split('.')

  // subdomain.localhost ΓåÆ "subdomain"
  if (parts.length > 1 && parts[parts.length - 1] === 'localhost') {
    return parts[0]
  }

  // subdomain.example.com ΓåÆ "subdomain"
  if (parts.length > 2) {
    return parts[0]
  }

  // localhost or example.com ΓåÆ "default"
  return 'default'
}

/**
 * Resolves backend API URL based on current hostname
 * 
 * @param config - Optional configuration for protocol, port, and API prefix
 * @returns Backend API URL (e.g., "https://api.tenant1.example.com")
 */
export function getBackendURL(config?: BackendConfig): string {
  if (typeof window === 'undefined') {
    throw new Error('getBackendURL can only be called in browser environment')
  }

  const hostname = window.location.hostname
  const tenant = extractTenant(hostname)

  // Determine environment
  const isLocalhost = hostname.includes('localhost') || hostname === '127.0.0.1'

  // Default configuration
  const protocol = config?.protocol || (isLocalhost ? 'http' : 'https')
  const port = config?.port || (isLocalhost ? 8080 : undefined)
  const apiPrefix = config?.apiPrefix || 'api'

  // Build backend hostname
  let backendHostname: string

  if (isLocalhost) {
    // Local development: api.tenant.localhost
    if (tenant === 'default') {
      backendHostname = `${apiPrefix}.localhost`
    } else {
      backendHostname = `${apiPrefix}.${tenant}.localhost`
    }
  } else {
    // Production: api.tenant.example.com or api.example.com
    const parts = hostname.split('.')

    if (parts.length > 2) {
      // tenant.example.com ΓåÆ api.tenant.example.com
      parts[0] = apiPrefix
      backendHostname = parts.join('.')
    } else {
      // example.com ΓåÆ api.example.com
      backendHostname = `${apiPrefix}.${hostname}`
    }
  }

  // Construct full URL
  const portSuffix = port ? `:${port}` : ''
  return `${protocol}://${backendHostname}${portSuffix}`
}

/**
 * Get OAuth token from localStorage or sessionStorage
 * Checks token expiration before returning
 */
export function getAuthToken(): string | null {
  if (typeof window === 'undefined') return null

  // Get token and expiration
  const token = localStorage.getItem('access_token')
  const expiresAt = localStorage.getItem('token_expires_at')

  // If no token, return null
  if (!token) return null

  // Check if token is expired
  if (expiresAt && parseInt(expiresAt) <= Date.now()) {
    // Token expired, clear it
    localStorage.removeItem('access_token')
    localStorage.removeItem('token_expires_at')
    localStorage.removeItem('refresh_token')
    localStorage.removeItem('user_info')

    // Redirect to login if in browser
    if (typeof window !== 'undefined') {
      window.location.href = '/auth/login?redirect=' + encodeURIComponent(window.location.pathname)
    }

    return null
  }

  return token
}

/**
 * Check if user is authenticated
 */
export function isAuthenticated(): boolean {
  return getAuthToken() !== null
}

/**
 * Get stored user info
 */
export function getUserInfo(): any | null {
  if (typeof window === 'undefined') return null

  const userInfoStr = localStorage.getItem('user_info')
  if (!userInfoStr) return null

  try {
    return JSON.parse(userInfoStr)
  } catch {
    return null
  }
}

/**
 * Logout user (clear all tokens)
 */
export function logout() {
  if (typeof window === 'undefined') return

  localStorage.removeItem('access_token')
  localStorage.removeItem('refresh_token')
  localStorage.removeItem('token_expires_at')
  localStorage.removeItem('user_info')
  sessionStorage.clear()

  // Redirect to login
  window.location.href = '/auth/login'
}

/**
 * Error class for API-related errors
 */
export class APIError extends Error {
  constructor(
    message: string,
    public status?: number,
    public response?: any
  ) {
    super(message)
    this.name = 'APIError'
  }
}

/**
 * Authenticated API request wrapper
 * Automatically adds Authorization header with Bearer token
 * 
 * @param endpoint - API endpoint path (e.g., "/users/me" or "users/me")
 * @param options - Fetch options
 * @returns Parsed JSON response
 * @throws {APIError} When request fails or token is missing
 */
export async function apiRequest<T = any>(
  endpoint: string,
  options: RequestInit = {}
): Promise<T> {
  // Get auth token
  const token = getAuthToken()

  if (!token) {
    // If no token found, ensure we are logged out and redirect
    logout()
    throw new APIError('Authentication token not found. Please log in.', 401)
  }

  // Resolve backend URL
  const baseURL = getBackendURL()

  // Normalize endpoint (remove leading slash if present)
  const normalizedEndpoint = endpoint.startsWith('/') ? endpoint.slice(1) : endpoint
  const url = `${baseURL}/${normalizedEndpoint}`

  // Prepare headers
  const headers: HeadersInit = {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
    ...options.headers,
  }

  try {
    const response = await fetch(url, {
      ...options,
      headers,
    })

    // Handle non-JSON responses
    const contentType = response.headers.get('content-type')
    const isJSON = contentType?.includes('application/json')

    // Parse response
    const data = isJSON ? await response.json() : await response.text()

    // Handle error responses
    if (!response.ok) {
      const message = typeof data === 'object' && data.message
        ? data.message
        : typeof data === 'string'
          ? data
          : `Request failed with status ${response.status}`

      // Auto-logout on Auth failures
      if (response.status === 401 || response.status === 403) {
        logout()
      }

      // Auto-logout if Tenant is completely missing (404 on critical paths)
      // We need to be careful not to logout on simple "Resource not found" (like a missing project)
      // But "Tenant not found" usually comes from the middleware/gateway layers
      if (response.status === 404 && (
        message.toLowerCase().includes('tenant not found') ||
        message.toLowerCase().includes('site not found')
      )) {
        logout()
      }

      throw new APIError(message, response.status, data)
    }

    return data
  } catch (error) {
    // Re-throw APIErrors
    if (error instanceof APIError) {
      throw error
    }

    // Network or parsing errors
    if (error instanceof Error) {
      throw new APIError(
        `Network error: ${error.message}`,
        undefined,
        error
      )
    }

    throw new APIError('Unknown error occurred')
  }
}

/**
 * Convenience methods for common HTTP verbs
 */
export const api = {
  /**
   * GET request
   */
  get: <T = any>(endpoint: string, options?: RequestInit): Promise<T> => {
    return apiRequest<T>(endpoint, { ...options, method: 'GET' })
  },

  /**
   * POST request
   */
  post: <T = any>(endpoint: string, body?: any, options?: RequestInit): Promise<T> => {
    return apiRequest<T>(endpoint, {
      ...options,
      method: 'POST',
      body: body ? JSON.stringify(body) : undefined,
    })
  },

  /**
   * PUT request
   */
  put: <T = any>(endpoint: string, body?: any, options?: RequestInit): Promise<T> => {
    return apiRequest<T>(endpoint, {
      ...options,
      method: 'PUT',
      body: body ? JSON.stringify(body) : undefined,
    })
  },

  /**
   * PATCH request
   */
  patch: <T = any>(endpoint: string, body?: any, options?: RequestInit): Promise<T> => {
    return apiRequest<T>(endpoint, {
      ...options,
      method: 'PATCH',
      body: body ? JSON.stringify(body) : undefined,
    })
  },

  /**
   * DELETE request
   */
  delete: <T = any>(endpoint: string, options?: RequestInit): Promise<T> => {
    return apiRequest<T>(endpoint, { ...options, method: 'DELETE' })
  },
}

/**
 * Type definitions for common API responses
 */
export interface User {
  id: string
  email: string
  name: string
  tenant: string
}

export interface PaginatedResponse<T> {
  data: T[]
  total: number
  page: number
  pageSize: number
}

