 */
export async function deleteProject(id: string) {
  return api.delete(`/projects/${id}`)
}

'use client'

import { useState, useCallback } from 'react'
import { api, APIError, type User } from '@/lib/api-client'

/**
 * React Hook for API calls with loading and error states
 * Handles common patterns: loading, error, and success states
 */
export function useAPI<T = any>() {
  const [data, setData] = useState<T | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  
  const execute = useCallback(async (apiCall: () => Promise<T>) => {
    setLoading(true)
    setError(null)
    
    try {
      const result = await apiCall()
      setData(result)
      return result
    } catch (err) {
      if (err instanceof APIError) {
        setError(err.message)
      } else if (err instanceof Error) {
        setError(err.message)
      } else {
        setError('An unexpected error occurred')
      }
      throw err
    } finally {
      setLoading(false)
    }
  }, [])
  
  const reset = useCallback(() => {
    setData(null)
    setError(null)
    setLoading(false)
  }, [])
  
  return { data, loading, error, execute, reset }
}

/**
 * Hook for user authentication state
 */
export function useAuth() {
  const [user, setUser] = useState<User | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  
  const fetchUser = useCallback(async () => {
    setLoading(true)
    setError(null)
    
    try {
      const userData = await api.get<User>('/users/me')
      setUser(userData)
      return userData
    } catch (err) {
      if (err instanceof APIError) {
        if (err.status === 401) {
          setUser(null)
          setError('Not authenticated')
        } else {
          setError(err.message)
        }
      } else {
        setError('Failed to fetch user')
      }
      throw err
    } finally {
      setLoading(false)
    }
  }, [])
  
  const logout = useCallback(() => {
    // Clear token from storage
    localStorage.removeItem('access_token')
    sessionStorage.removeItem('access_token')
    setUser(null)
  }, [])
  
  return { user, loading, error, fetchUser, logout }
}

'use client'

import { cache } from 'react'

/**
 * Client-side hook to get tenant from hostname
 * Use this in Client Components
 * 
 * @returns tenant identifier
 */
export function useClientTenant(): string {
  if (typeof window === 'undefined') {
    return 'default'
  }

  const hostname = window.location.hostname
  return extractTenantFromHostname(hostname)
}

/**
 * Extracts tenant identifier from hostname
 * Supports:
 * - tenant1.localhost -> "tenant1"
 * - tenant2.example.com -> "tenant2"
 * - localhost -> "default"
 * - example.com -> "default"
 */
function extractTenantFromHostname(hostname: string): string {
  // Remove port if present
  const host = hostname.split(':')[0]

  // Split by dots
  const parts = host.split('.')

  // If it's a subdomain (more than 2 parts, or localhost with subdomain)
  if (parts.length >= 2) {
    // Check if it's subdomain.localhost
    if (parts[parts.length - 1] === 'localhost' && parts.length > 1) {
      return parts[0] // Return subdomain
    }
    // Check if it's subdomain.domain.com
    if (parts.length > 2) {
      return parts[0] // Return subdomain
    }
  }

  // Default tenant for localhost or apex domain
  return 'default'
}

import { execSync } from 'child_process';
import path from 'path';

const BASE_URL = process.env.ERP_NEXT_URL || 'http://127.0.0.1:8080';
const API_KEY = process.env.ERP_API_KEY;
const API_SECRET = process.env.ERP_API_SECRET;
const SITES_DIR = process.env.FRAPPE_SITES_DIR || '/home/frappe/frappe-bench/sites';

async function getAllTenants() {
  const authHeader = `token ${API_KEY}:${API_SECRET}`;
  const response = await fetch(`${BASE_URL}/api/resource/Tenant?fields=["name","subdomain","site_url"]&limit_page_length=1000`, {
    headers: { 'Authorization': authHeader },
  });
  const data = await response.json();
  if (typeof data === 'object' && data && 'data' in data && Array.isArray((data as any).data)) {
    return (data as any).data;
  }
  return [];
}

function siteFolderExists(siteUrl: string) {
  if (!siteUrl) return false;
  // Extract subdomain or site name from URL
  let siteName = siteUrl.replace(/^https?:\/\//, '').replace(/[:/].*$/, '');
  try {
    execSync(`ls ${path.join(SITES_DIR, siteName)}`);
    return true;
  } catch {
    return false;
  }
}

async function deleteTenant(tenantName: string) {
  const authHeader = `token ${API_KEY}:${API_SECRET}`;
  await fetch(`${BASE_URL}/api/resource/Tenant/${tenantName}`, {
    method: 'DELETE',
    headers: { 'Authorization': authHeader },
  });
}

(async () => {
  const tenants = await getAllTenants();
  let deleted = 0;
  for (const tenant of tenants) {
    if (!siteFolderExists(tenant.site_url)) {
      console.log(`Deleting orphaned tenant: ${tenant.name} (${tenant.site_url})`);
      await deleteTenant(tenant.name);
      deleted++;
    }
  }
  console.log(`Cleanup complete. Deleted ${deleted} orphaned tenants.`);
})();

